class HttpError extends Error {
  constructor(status, message, details) {
    super(message);
    this.status = status;
    this.details = details;
  }
}

class AgentError extends HttpError {
  constructor(status, code, message, details = null, retryable = false) {
    super(status, message, details);
    this.code = code;
    this.retryable = Boolean(retryable);
  }
}

function nowIso() {
  return new Date().toISOString();
}

function createId(prefix) {
  return `${prefix}_${Date.now().toString(36)}_${crypto.randomBytes(4).toString("hex")}`;
}

const planningTokenizerCache = new Map();

function getPlanningTokenizer(encodingName = "cl100k_base") {
  const name = String(encodingName || "cl100k_base");
  if (planningTokenizerCache.has(name)) return planningTokenizerCache.get(name);
  try {
    const tokenizer = getEncoding(name);
    planningTokenizerCache.set(name, tokenizer);
    return tokenizer;
  } catch (error) {
    console.warn(`[tokenizer] ${name} 加载失败，已退回内部估算`, error);
    planningTokenizerCache.set(name, null);
    return null;
  }
}

function planningTokenizerNameForModel(model) {
  const value = String(model || "").toLowerCase();
  if (!value) return "cl100k_base";
  if (/(^|[^a-z0-9])(gpt-5|gpt-4\.1|gpt-4o|o1|o3|o4|o200k)([^a-z0-9]|$)/i.test(value)) return "o200k_base";
  if (/deepseek|qwen|claude|gemini|glm|kimi|yi|mistral|llama|grok|doubao|ernie|hunyuan/.test(value)) return "cl100k_base";
  return "cl100k_base";
}

function createNovelProjectFolderPath(novelOrId, title = "") {
  const id = typeof novelOrId === "object" ? String(novelOrId.id || "") : String(novelOrId || "");
  const rawTitle = typeof novelOrId === "object" ? String(novelOrId.title || "") : String(title || "");
  const safeTitle = sanitizeNovelFolderName(rawTitle || "未命名小说");
  const safeId = sanitizeNovelFolderName(id || createId("novel"));
  return path.join(NOVEL_PROJECTS_DIR, `${safeTitle}-${safeId}`);
}

function sanitizeNovelFolderName(value) {
  const normalized = String(value || "")
    .trim()
    .replace(/[<>:"/\\|?*\u0000-\u001f]/g, "_")
    .replace(/\s+/g, " ")
    .replace(/[. ]+$/g, "");
  return (normalized || "未命名小说").slice(0, 64);
}

function sanitizeFileName(value) {
  return String(value || "item")
    .trim()
    .replace(/[<>:"/\\|?*\u0000-\u001f]/g, "_")
    .replace(/\s+/g, "_")
    .replace(/[. ]+$/g, "")
    .slice(0, 96) || "item";
}

function loadProviderAdapterRegistry() {
  const fallback = [
    {
      id: "openai_chat_completions",
      aliases: ["chat_completions", "chat/completions"],
      label: "OpenAI Chat Completions 兼容",
      endpointKind: "chat_completions",
      endpointPath: "/chat/completions",
      capabilities: { tools: true, stream: true, jsonSchema: false, maxContextTokens: 0, errorCodeMapping: {} }
    },
    {
      id: "openai_responses",
      aliases: ["responses"],
      label: "OpenAI Responses 兼容",
      endpointKind: "responses",
      endpointPath: "/responses",
      capabilities: { tools: true, stream: true, jsonSchema: true, maxContextTokens: 0, errorCodeMapping: {} }
    }
  ];
  const loaded = [];
  try {
    if (fsSync.existsSync(PROVIDER_ADAPTER_DIR)) {
      const files = fsSync.readdirSync(PROVIDER_ADAPTER_DIR, { withFileTypes: true })
        .filter((entry) => entry.isFile() && entry.name.endsWith(".json"))
        .map((entry) => path.join(PROVIDER_ADAPTER_DIR, entry.name));
      for (const filePath of files) {
        const parsed = JSON.parse(fsSync.readFileSync(filePath, "utf8"));
        loaded.push(normalizeProviderAdapterManifest(parsed, filePath));
      }
    }
  } catch (error) {
    console.warn("[provider-adapters]", error);
  }
  const adapters = {};
  const aliases = {};
  for (const manifest of [...fallback, ...loaded].map((item) => normalizeProviderAdapterManifest(item)).filter(Boolean)) {
    adapters[manifest.id] = Object.freeze(manifest);
    aliases[manifest.id] = manifest.id;
    for (const alias of manifest.aliases || []) {
      const key = String(alias || "").trim();
      if (key) aliases[key] = manifest.id;
    }
  }
  return {
    adapters: Object.freeze(adapters),
    aliases: Object.freeze(aliases)
  };
}

function normalizeProviderAdapterManifest(value, filePath = "") {
  const source = value && typeof value === "object" ? value : {};
  const id = String(source.id || "").trim();
  if (!id) return null;
  const endpointKind = source.endpointKind === "responses" ? "responses" : "chat_completions";
  const endpointPath = String(source.endpointPath || (endpointKind === "responses" ? "/responses" : "/chat/completions")).trim();
  return {
    id,
    aliases: uniqueStrings([...(Array.isArray(source.aliases) ? source.aliases : []), source.endpointKind, source.endpointPath]).filter(Boolean),
    label: String(source.label || id),
    endpointKind,
    endpointPath,
    capabilities: normalizeProviderCapabilities(source.capabilities, endpointKind === "responses"
      ? { tools: true, stream: true, jsonSchema: true, maxContextTokens: 0, errorCodeMapping: {} }
      : { tools: true, stream: true, jsonSchema: false, maxContextTokens: 0, errorCodeMapping: {} }),
    manifestPath: filePath ? path.relative(ROOT_DIR, filePath).replace(/\\/g, "/") : ""
  };
}

