function getPlanningToolCatalog(novel) {
  const registry = getPlanningToolRegistry();
  const mode = getPlanningAgentPermissionMode(novel);
  const settings = getPlanningAgentToolSettings(novel);
  return {
    permissionMode: mode,
    toolSettings: settings,
    permissionPolicy: normalizeAgentPermissionPolicy(novel?.planning?.agentPermissionPolicy),
    protocols: ["skillOps", "tool_calls"],
    subAgentProfiles: getPlanningSubAgentProfilesCatalog(),
    customTools: getPlanningCustomToolCatalog(),
    mcpTools: getPlanningMcpToolCatalog(),
    tools: Object.values(registry).map((tool) => {
      const availability = evaluatePlanningToolAvailability(tool, mode, settings);
      const jsonSchema = planningToolJsonSchema(tool.type);
      return {
        type: tool.type,
        name: tool.name || tool.type,
        label: tool.label,
        risk: tool.risk,
        category: planningToolCatalogCategory(tool),
        bucket: tool.bucket,
        requiresWeb: tool.requiresWeb,
        requiresShell: tool.requiresShell,
        requiresFileWrite: tool.requiresFileWrite,
        requiresCustomTools: tool.requiresCustomTools,
        requiresMcp: tool.requiresMcp,
        permission: tool.permission,
        retry: tool.retry,
        display: tool.display,
        resultSchema: tool.resultSchema,
        enabled: availability.enabled,
        blockedReason: availability.blockedReason,
        inputSchema: planningToolInputSchema(tool.type),
        jsonSchema,
        nativeTool: planningToolNativeDefinition(tool, jsonSchema)
      };
    })
  };
}

function getPlanningNativeTools(novel, endpointKind = "chat_completions") {
  const catalog = getPlanningToolCatalog(novel);
  return (catalog.tools || [])
    .filter((tool) => tool.enabled && tool.nativeTool)
    .slice(0, PLANNING_NATIVE_TOOL_LIMIT)
    .map((tool) => convertPlanningNativeToolForEndpoint(tool.nativeTool, endpointKind));
}

function convertPlanningNativeToolForEndpoint(tool, endpointKind) {
  if (endpointKind !== "responses") return tool;
  const fn = tool?.function || {};
  return {
    type: "function",
    name: fn.name || tool.name,
    description: fn.description || tool.description || "",
    parameters: strictPlanningNativeToolParameters(fn.parameters || tool.parameters || { type: "object", properties: {} }),
    strict: fn.strict === true || tool.strict === true
  };
}

// Responses 严格工具协议要求所有 properties 都出现在 required 中；
// 这里仅转换发给模型的 schema，后端内部仍使用 planningToolJsonSchema 做真实校验。
function strictPlanningNativeToolParameters(schema) {
  return strictPlanningJsonSchemaNode(schema || { type: "object", properties: {} }, { root: true });
}

function strictPlanningJsonSchemaNode(schema, options = {}) {
  const source = schema && typeof schema === "object" && !Array.isArray(schema) ? schema : {};
  if (!options.root && isFreeformObjectJsonSchema(source)) {
    return strictPlanningFreeformJsonStringSchema(source, options);
  }
  const clone = JSON.parse(JSON.stringify(source));
  const originalRequired = new Set(Array.isArray(source.required) ? source.required : []);
  const node = { ...clone };
  delete node.anyOf;
  delete node.oneOf;
  delete node.allOf;
  const typeList = normalizeJsonSchemaTypeList(node.type, node.properties ? "object" : Array.isArray(node.items) || node.items ? "array" : "");
  const hasObjectType = typeList.includes("object") || (!typeList.length && node.properties && typeof node.properties === "object");
  const hasArrayType = typeList.includes("array") || (!typeList.length && Object.hasOwn(node, "items"));
  if (hasObjectType) {
    const properties = node.properties && typeof node.properties === "object" && !Array.isArray(node.properties)
      ? node.properties
      : {};
    const strictProperties = {};
    for (const [key, value] of Object.entries(properties)) {
      strictProperties[key] = strictPlanningJsonSchemaNode(value, {
        root: false,
        optional: !originalRequired.has(key)
      });
    }
    node.type = normalizeJsonSchemaTypeValue(typeList.length ? typeList : ["object"], Boolean(options.optional));
    node.properties = strictProperties;
    node.required = Object.keys(strictProperties);
    node.additionalProperties = false;
  } else {
    node.type = normalizeJsonSchemaTypeValue(typeList, Boolean(options.optional));
  }
  if (hasArrayType) {
    node.items = strictPlanningJsonSchemaNode(node.items || {}, { root: false });
  }
  if (options.optional) {
    addNullToJsonSchemaEnum(node);
  }
  if (options.root) {
    const rootTypes = normalizeJsonSchemaTypeList(node.type, "object").filter((type) => type !== "null");
    node.type = rootTypes.length === 1 ? rootTypes[0] : rootTypes;
    if (!node.properties || typeof node.properties !== "object" || Array.isArray(node.properties)) node.properties = {};
    node.required = Object.keys(node.properties);
    node.additionalProperties = false;
  }
  return node;
}

// OpenAI strict schema 很难表达“任意 JSON 对象”。
// 这类字段在原生工具层改为 JSON 字符串，执行前再按内部 schema 解析回对象。
function isFreeformObjectJsonSchema(schema) {
  if (!schema || typeof schema !== "object" || Array.isArray(schema)) return false;
  const types = normalizeJsonSchemaTypeList(schema.type, schema.properties ? "object" : "");
  const isObject = types.includes("object") || (!types.length && Object.hasOwn(schema, "additionalProperties"));
  const properties = schema.properties && typeof schema.properties === "object" && !Array.isArray(schema.properties)
    ? schema.properties
    : {};
  return isObject && Object.keys(properties).length === 0 && schema.additionalProperties !== false;
}

function strictPlanningFreeformJsonStringSchema(schema, options = {}) {
  const description = [
    String(schema.description || "").trim(),
    "这是自由结构对象；请以 JSON 对象字符串传入，后端会按内部工具 schema 解析和校验。"
  ].filter(Boolean).join(" ");
  const result = {
    type: normalizeJsonSchemaTypeValue(["string"], Boolean(options.optional)),
    description
  };
  if (options.optional) addNullToJsonSchemaEnum(result);
  return result;
}

function normalizeJsonSchemaTypeList(value, fallback = "") {
  const list = Array.isArray(value) ? value : value ? [value] : fallback ? [fallback] : [];
  return Array.from(new Set(list.map((type) => String(type || "").trim()).filter(Boolean)));
}

function normalizeJsonSchemaTypeValue(types, nullable) {
  const list = normalizeJsonSchemaTypeList(types);
  const next = Array.from(new Set([...list, ...(nullable ? ["null"] : [])]));
  if (next.length === 0) return nullable ? ["string", "null"] : "string";
  return next.length === 1 ? next[0] : next;
}

function addNullToJsonSchemaEnum(node) {
  if (Array.isArray(node.enum) && !node.enum.includes(null)) {
    node.enum = [...node.enum, null];
  }
}

function evaluatePlanningToolAvailability(tool, mode, settings) {
  if (tool.requiresWeb && !settings.webEnabled) return { enabled: false, blockedReason: "联网工具未开启" };
  if (tool.requiresShell && !settings.shellEnabled) return { enabled: false, blockedReason: "Shell 工具未开启" };
  if (tool.requiresCustomTools && !settings.customToolsEnabled) return { enabled: false, blockedReason: "自定义工具未开启" };
  if (tool.requiresMcp && !settings.mcpEnabled) return { enabled: false, blockedReason: "MCP 工具未开启" };
  if (mode === "read_only" && tool.risk !== "read") return { enabled: false, blockedReason: "只读模式禁止写入和命令" };
  if (mode === "ask_high_risk" && ["high", "dangerous"].includes(tool.risk)) return { enabled: true, blockedReason: "执行前需要确认或证据检查" };
  if (mode === "auto_edit" && tool.risk === "dangerous") return { enabled: true, blockedReason: "危险工具执行前需要确认" };
  return { enabled: true, blockedReason: "" };
}

function planningToolCatalogCategory(tool) {
  if (["search", "searchContextAssets", "readContextAsset", "readMessageAttachment", "inspectNovelDiagnostics", "runQualityGate", "applyArchivePatch", "upsertMemory", "patchMemory", "retireMemory", "upsertLorebook", "patchLorebook", "deleteLorebook", "updateCharacterCard", "markArchiveRecord", "patchArchiveRecord", "deleteArchiveRecord", "upsertProseDraft", "patchProseDraft", "annotateTurn", "updateAiSlot", "addProviderModel", "generateRoleplayConfigDraft", "generatePrewritePlan", "runRoleplayTurn", "reviewLatestTurn", "adaptRoleplayToProse", "postwriteProse", "runNormalWritingWorkflow", "runChapterWorkflow"].includes(tool.type)) return "novel_domain";
  if (["searchFiles", "searchLocalFiles", "readLocalFile", "listFiles", "globFiles", "grepFiles", "indexLocalFiles", "readFile", "writeFile", "previewPatchFile", "applyPatch", "patchFile", "revertPatch", "revertFilePatch", "previewPatchSet", "applyPatchSet", "revertPatchSet"].includes(tool.type)) return "local_files";
  if (["webFetch", "webSearch"].includes(tool.type)) return "web";
  if (["runShell", "startShellSession", "writeShellSession", "readShellSession", "stopShellSession", "startShellJob", "listShellJobs", "readShellJob", "stopShellJob"].includes(tool.type)) return "shell";
  if (["spawnSubAgent"].includes(tool.type)) return "agent";
  return "external";
}

function planningToolInputSchema(type) {
  const schemas = {
    search: { required: ["query"], optional: ["scope", "limit", "retrievalMode"] },
    searchContextAssets: { required: ["query"], optional: ["kind", "limit"] },
    readContextAsset: { required: ["assetId"], optional: ["maxChars"] },
    readMessageAttachment: { optional: ["fileId", "name", "index", "maxChars"] },
    searchFiles: { required: ["query"], optional: ["limit", "sourceId", "retrievalMode"] },
    searchLocalFiles: { required: ["query"], optional: ["limit", "sourceId", "retrievalMode"] },
    readLocalFile: { requiredAny: ["path", "relativePath"], optional: ["sourceId", "maxChars"] },
    listFiles: { optional: ["path", "sourceId", "limit"] },
    globFiles: { required: ["pattern"], optional: ["path", "sourceId", "limit"] },
    grepFiles: { requiredAny: ["query", "pattern"], optional: ["path", "sourceId", "limit", "regex"] },
    indexLocalFiles: { optional: ["path", "sourceId", "limit", "maxDepth", "maxCharsPerFile", "buildVector"] },
    readFile: { requiredAny: ["path", "relativePath"], optional: ["sourceId", "maxChars"] },
    writeFile: { required: ["path"], requiredAny: ["text", "content"], optional: ["append", "overwrite"] },
    applyPatch: { required: ["path"], optional: ["find", "replace", "replaceAll", "patches", "text", "content", "createIfMissing"] },
    previewPatchFile: { required: ["path"], optional: ["find", "replace", "replaceAll", "patches", "text", "content", "createIfMissing"] },
    patchFile: { required: ["path"], optional: ["find", "replace", "replaceAll", "patches", "text", "content", "createIfMissing"] },
    revertPatch: { required: ["patchId"], optional: ["force"] },
    revertFilePatch: { required: ["patchId"], optional: ["force"] },
    previewPatchSet: { required: ["files"], optional: ["reason"] },
    applyPatchSet: { required: ["files"], optional: ["reason"] },
    revertPatchSet: { required: ["patchSetId"], optional: ["force"] },
    runShell: { required: ["command"], optional: ["cwd", "timeoutMs"] },
    startShellSession: { optional: ["cwd", "command", "timeoutMs"] },
    writeShellSession: { required: ["sessionId", "command"], optional: ["timeoutMs", "waitForCompletion"] },
    readShellSession: { required: ["sessionId"], optional: ["maxChars"] },
    stopShellSession: { required: ["sessionId"], optional: ["force"] },
    startShellJob: { required: ["command"], optional: ["cwd", "name", "timeoutMs"] },
    listShellJobs: { optional: ["status", "limit"] },
    readShellJob: { required: ["jobId"], optional: ["maxChars"] },
    stopShellJob: { required: ["jobId"], optional: ["force"] },
    webFetch: { required: ["url"], optional: ["maxChars"] },
    webSearch: { required: ["query"], optional: ["limit", "provider", "cacheTtlMinutes", "freshness"] },
    spawnSubAgent: { required: ["task"], optional: ["profile", "context", "name", "background"] },
    inspectNovelDiagnostics: { optional: ["scope", "limit"] },
    runQualityGate: { optional: ["scope", "mode", "action"] },
    generatePrewritePlan: { optional: ["intent", "query", "chapterLabel", "workflowId", "mode", "forceNew"] },
    runRoleplayTurn: { optional: ["workflowId", "reason"] },
    reviewLatestTurn: { optional: ["turnId", "targetId", "workflowId", "reason"] },
    adaptRoleplayToProse: { optional: ["workflowId", "reason"] },
    postwriteProse: { optional: ["proseId", "id", "workflowId", "reason"] },
    runNormalWritingWorkflow: { optional: ["intent", "query", "chapterLabel", "workflowId", "steps", "forceNew", "reviewReason"] },
    runChapterWorkflow: { optional: ["intent", "query", "chapterLabel", "workflowId", "steps", "forceNew", "forceReview", "reviewReason"] },
    applyArchivePatch: { optional: ["patch", "archivePatch", "archiveDiagnostics", "premise", "background", "outline", "style", "characters", "scenes", "clues"] },
    customTool: { required: ["name"], optional: ["input"] },
    mcpTool: { required: ["server", "name"], optional: ["input"] }
  };
  return schemas[type] || { optional: ["reason", "evidenceSearchId", "requireHumanApproval"] };
}

function planningToolNativeDefinition(tool, jsonSchema = null) {
  return {
    type: "function",
    function: {
      name: tool.type,
      description: planningToolDescription(tool.type, tool.label),
      parameters: strictPlanningNativeToolParameters(jsonSchema || planningToolJsonSchema(tool.type)),
      strict: true
    }
  };
}

