async function executePlanningReadMessageAttachmentOp(novel, op, context = {}) {
  void novel;
  const attachments = normalizePlanningMessageAttachments(context.messageAttachments || context.attachments);
  const files = attachments.files || [];
  if (!files.length) {
    throw new AgentError(404, "attachment.not_found", "本轮消息没有可读取的拖入文件", { tool: "readMessageAttachment" }, true);
  }
  const fileId = String(op.fileId || op.id || "").trim();
  const fileName = String(op.name || op.filename || "").trim();
  const index = clampInteger(op.index, 1, PLANNING_MESSAGE_ATTACHMENT_FILE_LIMIT, 0);
  const file = (fileId ? files.find((item) => String(item.id || "") === fileId) : null)
    || (fileName ? files.find((item) => String(item.name || item.label || "") === fileName) : null)
    || (index ? files[index - 1] : null)
    || (files.length === 1 ? files[0] : null);
  if (!file) {
    throw new AgentError(404, "attachment.not_found", "没有找到指定的拖入文件，请用附件 id、文件名或序号重新读取", {
      requested: { fileId, name: fileName, index },
      available: files.map((item, itemIndex) => ({
        id: item.id,
        name: item.name || item.label || `拖入文件 ${itemIndex + 1}`
      }))
    }, true);
  }
  const text = String(file.text || "");
  const maxChars = clampInteger(op.maxChars, 1000, PLANNING_MESSAGE_ATTACHMENT_TEXT_CHARS, Math.min(PLANNING_MESSAGE_ATTACHMENT_TEXT_CHARS, Math.max(16000, text.length || 16000)));
  const limitedText = limitText(text, maxChars);
  const name = file.name || file.label || "拖入文件";
  const warnings = [];
  if (!text) warnings.push("这个附件没有可读取的文本内容");
  if (file.truncated) warnings.push("附件在进入后端时已被截断，只能读取已保存部分");
  if (limitedText.length < text.length) warnings.push(`本次只读取前 ${limitedText.length} 字符，完整附件已保留为本轮证据引用`);
  return {
    type: "readMessageAttachment",
    id: `message_attachment:${file.id || hashText(name)}`,
    query: name,
    scope: "message_attachments",
    count: 1,
    warnings,
    name,
    fileId: file.id,
    size: Number(file.size || 0),
    originalChars: Number(file.originalChars || text.length || 0),
    truncated: Boolean(file.truncated),
    materialType: inferPlanningAttachmentMaterialType(file, context.userMessage || context.queryText || ""),
    results: [{
      id: `message_attachment:${file.id || hashText(name)}`,
      title: name,
      source: {
        type: "message_attachment",
        id: file.id || name,
        sourceId: "current_message",
        name: "本轮拖入文件"
      },
      score: 1,
      text: limitedText,
      relativePath: name,
      size: Number(file.size || 0),
      originalChars: Number(file.originalChars || text.length || 0),
      truncated: Boolean(file.truncated)
    }]
  };
}

