function isPlanningWorkspacePreflightType(type) {
  return ["writeFile", "previewPatchFile", "applyPatch", "patchFile", "revertPatch", "revertFilePatch", "previewPatchSet", "applyPatchSet", "revertPatchSet", "runShell", "startShellSession", "startShellJob"].includes(String(type || ""));
}

async function preflightPlanningWorkspaceOp(novel, op, type, context = {}) {
  if (type === "revertPatch" || type === "revertFilePatch") {
    const history = await readFilePatchHistory(novel, op.patchId);
    const historyPath = String(history.path || "").trim();
    if (!historyPath) {
      throw new AgentError(400, "tool.invalid_arguments", "patch 历史缺少可回滚路径", { patchId: op.patchId }, false);
    }
    const targetPath = path.resolve(historyPath);
    const workspace = getNovelDefaultAgentFolder(novel);
    const external = !isPathInsideOrSame(workspace, targetPath);
    const stat = await fs.stat(targetPath).catch(() => null);
    return createPlanningWorkspacePreflight({
      type,
      query: history.id,
      target: {
        type,
        workspace,
        path: targetPath,
        relativePath: external ? path.basename(targetPath) : path.relative(workspace, targetPath).replace(/\\/g, "/"),
        exists: Boolean(stat),
        mode: "revert",
        external
      },
      matched: [{
        id: `${external ? "external_file" : "local_file"}:${targetPath}`,
        title: external ? targetPath : path.relative(workspace, targetPath).replace(/\\/g, "/"),
        source: { type: "local_file", id: targetPath, sourceId: external ? "external_approved" : "default_agent_folder", name: external ? "待批准外部路径" : "Agent 工作区" },
        score: 1
      }]
    });
  }

  if (type === "runShell" || type === "startShellSession" || type === "startShellJob") {
    const target = type === "startShellSession"
      ? await resolvePlanningShellSessionCwd(novel, op, { forPreflight: true })
      : await resolvePlanningShellCwd(novel, op, { forPreflight: true });
    return createPlanningWorkspacePreflight({
      type,
      query: target.command || target.cwd,
      target: {
        type,
        workspace: target.workspace,
        cwd: target.cwd,
        relativePath: target.relativePath,
        command: limitText(target.command || op.command || "", 240),
        external: target.external
      },
      matched: [{
        id: target.external ? `external_dir:${target.cwd}` : `local_dir:${target.relativePath || "."}`,
        title: target.external ? target.cwd : target.relativePath || ".",
        source: { type: "local_directory", id: target.cwd, sourceId: target.external ? "external_approved" : "default_agent_folder", name: target.external ? "待批准外部路径" : "Agent 工作区" },
        score: 1
      }]
    });
  }

  if (["previewPatchSet", "applyPatchSet", "revertPatchSet"].includes(type)) {
    return preflightPlanningPatchSetOp(novel, op, type, context);
  }

  const target = await resolveNovelAgentWritePath(novel, op, { forPreflight: true });
  const stat = await fs.stat(target.path).catch(() => null);
  if (stat?.isDirectory()) {
    throw new AgentError(400, "tool.invalid_target", "文件写入目标是文件夹，请提供具体文件路径", {
      path: target.path,
      relativePath: target.relativePath
    }, true);
  }
  if (["previewPatchFile", "applyPatch", "patchFile"].includes(type) && !stat && op.createIfMissing !== true) {
    throw new AgentError(404, "tool.target_not_found", `${type} 目标文件不存在，请先 listFiles/globFiles 定位，或明确 createIfMissing:true`, {
      path: target.path,
      relativePath: target.relativePath
    }, true);
  }
  if (type === "writeFile" && stat && op.append !== true && op.overwrite !== true && op.allowOverwrite !== true) {
    throw new AgentError(409, "tool.file_overwrite_requires_explicit", "writeFile 会覆盖已有文件；请先 readFile 确认内容，或明确 overwrite:true / 改用 patchFile", {
      path: target.path,
      relativePath: target.relativePath,
      size: stat.size
    }, true);
  }
  return createPlanningWorkspacePreflight({
    type,
    query: target.relativePath,
    target: {
      type,
      workspace: target.workspace || target.rootPath,
      path: target.path,
      relativePath: target.relativePath,
      exists: Boolean(stat),
      mode: type === "previewPatchFile" ? "preview" : op.append === true ? "append" : ["applyPatch", "patchFile"].includes(type) ? "patch" : "write",
      external: target.external
    },
    matched: stat ? [{
      id: target.external ? `external_file:${target.path}` : `local_file:${target.relativePath}`,
      title: target.external ? target.path : target.relativePath,
      source: { type: "local_file", id: target.path, sourceId: target.external ? "external_approved" : "default_agent_folder", name: target.external ? "待批准外部路径" : "Agent 工作区" },
      score: 1
    }] : []
  });
}

async function preflightPlanningPatchSetOp(novel, op, type, context = {}) {
  const workspace = getNovelDefaultAgentFolder(novel);
  const targets = [];
  const files = type === "revertPatchSet"
    ? (await readPatchSetHistory(novel, op.patchSetId)).files.map((file) => ({ path: file.path, relativePath: file.relativePath }))
    : normalizePatchSetFiles(op.files);
  if (files.length === 0) {
    throw new AgentError(400, "tool.invalid_arguments", `${type} 必须提供 files`, { type }, true);
  }
  for (const fileOp of files) {
    const target = await resolveNovelAgentWritePath(novel, fileOp, { forPreflight: true });
    const stat = await fs.stat(target.path).catch(() => null);
    if (stat?.isDirectory()) {
      throw new AgentError(400, "tool.invalid_target", "补丁集目标包含文件夹，请提供具体文件路径", {
        path: target.path,
        relativePath: target.relativePath
      }, true);
    }
    if (["previewPatchSet", "applyPatchSet"].includes(type) && !stat && fileOp.createIfMissing !== true) {
      throw new AgentError(404, "tool.target_not_found", `${type} 目标文件不存在，请先 listFiles/globFiles 定位，或明确 createIfMissing:true`, {
        path: target.path,
        relativePath: target.relativePath
      }, true);
    }
    targets.push({
      type,
      workspace,
      path: target.path,
      relativePath: target.relativePath,
      exists: Boolean(stat),
      mode: type === "previewPatchSet" ? "preview_patch_set" : type === "revertPatchSet" ? "revert_patch_set" : "apply_patch_set",
      external: target.external,
      fileOp
    });
  }
  const externalTargets = targets.filter((target) => target.external);
  if (externalTargets.length > 0) {
    const matched = externalTargets.map((target) => ({
      id: `external_file:${target.path}`,
      title: target.path,
      source: { type: "local_file", id: target.path, sourceId: "external_approved", name: "待批准外部路径" },
      score: 1
    }));
    const deniedTarget = externalTargets.find((target) => evaluateAgentDirectoryPolicy(novel, target.path, planningExternalAccessKind(type), context) === "deny");
    if (deniedTarget) {
      throw new AgentError(403, "permission.policy_denied", "目录权限策略拒绝访问工作区之外的路径", {
        path: deniedTarget.path,
        access: planningExternalAccessKind(type)
      }, false);
    }
    const unapprovedTargets = externalTargets.filter((target) => evaluateAgentDirectoryPolicy(novel, target.path, planningExternalAccessKind(type), context) !== "allow");
    if (unapprovedTargets.length > 0) {
      op.externalAccess = {
        path: commonDirectoryPath(unapprovedTargets.map((target) => target.path)),
        workspace,
        operation: type,
        reason: "补丁集包含当前小说 Agent 工作区之外的文件，需要人工确认后才能访问"
      };
      await requestPlanningHumanApproval(novel, op, type, matched, context);
    }
    for (const target of externalTargets) {
      markExternalPathApproved(target.fileOp, target.path);
      markExternalPathApproved(op, target.path);
    }
  }
  return createPlanningWorkspacePreflight({
    type,
    query: `${type}:${targets.length}`,
    target: {
      type,
      workspace,
      fileCount: targets.length,
      external: externalTargets.length > 0,
      mode: type
    },
    matched: targets.map((target) => ({
      id: target.external ? `external_file:${target.path}` : `local_file:${target.relativePath}`,
      title: target.external ? target.path : target.relativePath,
      source: { type: "local_file", id: target.path, sourceId: target.external ? "external_approved" : "default_agent_folder", name: target.external ? "已批准外部路径" : "Agent 工作区" },
      score: 1
    })),
    warnings: externalTargets.length > 0 ? ["补丁集包含工作区外路径，已要求人工确认。"] : []
  });
}

function createPlanningWorkspacePreflight({ type, query, target, matched = [], warnings = [], scope = "workspace" }) {
  return {
    type: "preflight",
    opType: type,
    evidenceSearchId: "",
    autoSearch: false,
    query: query || "",
    scope,
    target,
    matched,
    warnings
  };
}

function getWindowsJobObjectSandboxMeta(extra = {}) {
  if (!PLANNING_WINDOWS_JOB_OBJECT_ENABLED) {
    return {
      enabled: false,
      mode: process.platform === "win32" ? "disabled_by_env" : "not_windows",
      ...extra
    };
  }
  return {
    enabled: true,
    mode: "windows_job_object",
    memoryLimitMb: PLANNING_WINDOWS_JOB_MEMORY_MB,
    cpuRatePercent: PLANNING_WINDOWS_JOB_CPU_RATE_PERCENT,
    activeProcessLimit: PLANNING_WINDOWS_JOB_ACTIVE_PROCESS_LIMIT,
    killOnJobClose: true,
    ...extra
  };
}

function buildWindowsJobObjectShellWrapper(command, cwd, options = {}) {
  const timeoutMs = clampInteger(options.timeoutMs, 1000, 24 * 60 * 60 * 1000, PLANNING_SHELL_TIMEOUT_MS);
  const memoryBytes = BigInt(PLANNING_WINDOWS_JOB_MEMORY_MB) * 1024n * 1024n;
  const cpuRate = Math.min(10000, Math.max(500, Math.round(PLANNING_WINDOWS_JOB_CPU_RATE_PERCENT * 100)));
  const activeProcessLimit = PLANNING_WINDOWS_JOB_ACTIVE_PROCESS_LIMIT;
  fsSync.mkdirSync(SHELL_WRAPPER_DIR, { recursive: true });
  const wrapperId = createId("windows_job");
  const scriptPath = path.join(SHELL_WRAPPER_DIR, `${sanitizeFileName(wrapperId)}.ps1`);
  // 这里用 PowerShell 承载一小段 C#，原因是 Node 没有原生 Job Object API。
  // 它会创建 Job Object、设置 kill-on-close、进程数、内存和 CPU rate，再把真实命令放进 job。
  const script = `
$ErrorActionPreference = 'Stop'
[Console]::OutputEncoding = [System.Text.Encoding]::UTF8
Add-Type -TypeDefinition @"
using System;
using System.Runtime.InteropServices;

namespace RoleplayNovelStudio {
  [StructLayout(LayoutKind.Sequential)]
  public struct IO_COUNTERS {
    public UInt64 ReadOperationCount;
    public UInt64 WriteOperationCount;
    public UInt64 OtherOperationCount;
    public UInt64 ReadTransferCount;
    public UInt64 WriteTransferCount;
    public UInt64 OtherTransferCount;
  }

  [StructLayout(LayoutKind.Sequential)]
  public struct JOBOBJECT_BASIC_LIMIT_INFORMATION {
    public Int64 PerProcessUserTimeLimit;
    public Int64 PerJobUserTimeLimit;
    public UInt32 LimitFlags;
    public UIntPtr MinimumWorkingSetSize;
    public UIntPtr MaximumWorkingSetSize;
    public UInt32 ActiveProcessLimit;
    public Int64 Affinity;
    public UInt32 PriorityClass;
    public UInt32 SchedulingClass;
  }

  [StructLayout(LayoutKind.Sequential)]
  public struct JOBOBJECT_EXTENDED_LIMIT_INFORMATION {
    public JOBOBJECT_BASIC_LIMIT_INFORMATION BasicLimitInformation;
    public IO_COUNTERS IoInfo;
    public UIntPtr ProcessMemoryLimit;
    public UIntPtr JobMemoryLimit;
    public UIntPtr PeakProcessMemoryUsed;
    public UIntPtr PeakJobMemoryUsed;
  }

  [StructLayout(LayoutKind.Sequential)]
  public struct JOBOBJECT_CPU_RATE_CONTROL_INFORMATION {
    public UInt32 ControlFlags;
    public UInt32 CpuRate;
  }

  public static class JobObjectRunner {
    const int JobObjectExtendedLimitInformation = 9;
    const int JobObjectCpuRateControlInformation = 15;
    const UInt32 JOB_OBJECT_LIMIT_KILL_ON_JOB_CLOSE = 0x00002000;
    const UInt32 JOB_OBJECT_LIMIT_ACTIVE_PROCESS = 0x00000008;
    const UInt32 JOB_OBJECT_LIMIT_JOB_MEMORY = 0x00000200;
    const UInt32 JOB_OBJECT_CPU_RATE_CONTROL_ENABLE = 0x1;
    const UInt32 JOB_OBJECT_CPU_RATE_CONTROL_HARD_CAP = 0x4;

    [DllImport("kernel32.dll", CharSet = CharSet.Unicode)]
    static extern IntPtr CreateJobObject(IntPtr lpJobAttributes, string lpName);

    [DllImport("kernel32.dll")]
    static extern bool SetInformationJobObject(IntPtr hJob, int infoType, IntPtr lpJobObjectInfo, uint cbJobObjectInfoLength);

    [DllImport("kernel32.dll")]
    static extern bool AssignProcessToJobObject(IntPtr job, IntPtr process);

    [DllImport("kernel32.dll")]
    static extern bool CloseHandle(IntPtr hObject);

    [DllImport("kernel32.dll")]
    static extern bool TerminateJobObject(IntPtr hJob, uint exitCode);

    public static IntPtr CreateConfiguredJob(ulong memoryBytes, uint cpuRate, uint activeProcessLimit) {
      IntPtr job = CreateJobObject(IntPtr.Zero, null);
      if (job == IntPtr.Zero) throw new InvalidOperationException("CreateJobObject failed");

      JOBOBJECT_EXTENDED_LIMIT_INFORMATION limits = new JOBOBJECT_EXTENDED_LIMIT_INFORMATION();
      limits.BasicLimitInformation.LimitFlags = JOB_OBJECT_LIMIT_KILL_ON_JOB_CLOSE | JOB_OBJECT_LIMIT_ACTIVE_PROCESS | JOB_OBJECT_LIMIT_JOB_MEMORY;
      limits.BasicLimitInformation.ActiveProcessLimit = activeProcessLimit;
      limits.JobMemoryLimit = (UIntPtr)memoryBytes;
      int limitsLength = Marshal.SizeOf(typeof(JOBOBJECT_EXTENDED_LIMIT_INFORMATION));
      IntPtr limitsPtr = Marshal.AllocHGlobal(limitsLength);
      try {
        Marshal.StructureToPtr(limits, limitsPtr, false);
        if (!SetInformationJobObject(job, JobObjectExtendedLimitInformation, limitsPtr, (uint)limitsLength)) {
          throw new InvalidOperationException("SetInformationJobObject limit failed");
        }
      } finally {
        Marshal.FreeHGlobal(limitsPtr);
      }

      JOBOBJECT_CPU_RATE_CONTROL_INFORMATION cpu = new JOBOBJECT_CPU_RATE_CONTROL_INFORMATION();
      cpu.ControlFlags = JOB_OBJECT_CPU_RATE_CONTROL_ENABLE | JOB_OBJECT_CPU_RATE_CONTROL_HARD_CAP;
      cpu.CpuRate = cpuRate;
      int cpuLength = Marshal.SizeOf(typeof(JOBOBJECT_CPU_RATE_CONTROL_INFORMATION));
      IntPtr cpuPtr = Marshal.AllocHGlobal(cpuLength);
      try {
        Marshal.StructureToPtr(cpu, cpuPtr, false);
        SetInformationJobObject(job, JobObjectCpuRateControlInformation, cpuPtr, (uint)cpuLength);
      } finally {
        Marshal.FreeHGlobal(cpuPtr);
      }
      return job;
    }

    public static void Assign(IntPtr job, IntPtr processHandle) {
      if (!AssignProcessToJobObject(job, processHandle)) {
        throw new InvalidOperationException("AssignProcessToJobObject failed");
      }
    }

    public static void Terminate(IntPtr job, uint exitCode) {
      if (job != IntPtr.Zero) TerminateJobObject(job, exitCode);
    }

    public static void Close(IntPtr handle) {
      if (handle != IntPtr.Zero) CloseHandle(handle);
    }
  }
}
"@
$command = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String($env:ROLEPLAY_JOB_COMMAND_B64))
$cwd = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String($env:ROLEPLAY_JOB_CWD_B64))
$job = [IntPtr]::Zero
try {
  $job = [RoleplayNovelStudio.JobObjectRunner]::CreateConfiguredJob([UInt64]${memoryBytes.toString()}, [UInt32]${cpuRate}, [UInt32]${activeProcessLimit})
  [RoleplayNovelStudio.JobObjectRunner]::Assign($job, [System.Diagnostics.Process]::GetCurrentProcess().Handle)
  Set-Location -LiteralPath $cwd
  & ([ScriptBlock]::Create($command))
  $__agentNativeExit = $LASTEXITCODE
  if ($null -ne $__agentNativeExit) { exit ([int]$__agentNativeExit) }
  if ($?) { exit 0 } else { exit 1 }
} finally {
  if ($job -ne [IntPtr]::Zero) { [RoleplayNovelStudio.JobObjectRunner]::Close($job) }
}
`;
  fsSync.writeFileSync(scriptPath, script, "utf8");
  return {
    file: "powershell.exe",
    args: ["-NoLogo", "-NoProfile", "-ExecutionPolicy", "Bypass", "-File", scriptPath],
    env: {
      ROLEPLAY_JOB_COMMAND_B64: Buffer.from(String(command || ""), "utf8").toString("base64"),
      ROLEPLAY_JOB_CWD_B64: Buffer.from(String(cwd || ROOT_DIR), "utf8").toString("base64")
    },
    meta: getWindowsJobObjectSandboxMeta({ timeoutMs, wrapperPath: scriptPath })
  };
}

function createPlanningShellExecutionSpec(command, cwd, options = {}) {
  if (PLANNING_WINDOWS_JOB_OBJECT_ENABLED && options.interactive !== true) {
    return buildWindowsJobObjectShellWrapper(command, cwd, options);
  }
  const shell = process.platform === "win32" ? "powershell.exe" : (process.env.SHELL || "bash");
  const args = process.platform === "win32"
    ? ["-NoLogo", "-NoProfile", "-ExecutionPolicy", "Bypass", "-Command", command]
    : ["-lc", command];
  return {
    file: shell,
    args,
    meta: getWindowsJobObjectSandboxMeta({ fallback: true, timeoutMs: options.timeoutMs || 0 })
  };
}

function isPlanningLocalPathPreflightType(type) {
  return ["readLocalFile", "listFiles", "globFiles", "grepFiles", "indexLocalFiles", "readFile", "writeFile", "previewPatchFile", "applyPatch", "patchFile", "revertPatch", "revertFilePatch", "previewPatchSet", "applyPatchSet", "revertPatchSet", "runShell", "startShellSession", "startShellJob"].includes(String(type || ""));
}

function attachExternalAccessSummary(op, preflight) {
  const target = preflight?.target || {};
  op.externalAccess = {
    path: target.path || "",
    cwd: target.cwd || "",
    workspace: target.workspace || "",
    operation: preflight.opType || op.type || "",
    reason: "目标位于当前小说 Agent 工作区之外，需要人工确认后才能访问"
  };
}

async function approveExternalPathPreflightIfNeeded(novel, op, type, preflight, context) {
  if (!preflight?.target?.external) return false;
  attachExternalAccessSummary(op, preflight);
  const targetPath = preflight.target.path || preflight.target.cwd;
  const directoryDecision = evaluateAgentDirectoryPolicy(novel, targetPath, planningExternalAccessKind(type), context);
  if (directoryDecision === "deny") {
    throw new AgentError(403, "permission.policy_denied", "目录权限策略拒绝访问工作区之外的路径", {
      path: targetPath,
      access: planningExternalAccessKind(type)
    }, false);
  }
  if (directoryDecision === "allow") {
    markExternalPathApproved(op, targetPath);
    return true;
  }
  await requestPlanningHumanApproval(novel, op, type, preflight.matched || [], context);
  markExternalPathApproved(op, targetPath);
  return true;
}

async function preflightPlanningExternalReadOp(novel, op, type) {
  const targetPath = getExternalPathCandidate(novel, { ...op, type }, type);
  if (!targetPath) return null;
  assertNotFilesystemRoot(targetPath, "外部读取目标");
  const stat = await fs.stat(targetPath).catch(() => null);
  if (!stat) {
    throw new AgentError(404, "tool.target_not_found", "外部读取目标不存在，请先确认绝对路径", {
      path: targetPath
    }, true);
  }
  if (["readLocalFile", "readFile"].includes(type) && !stat.isFile()) {
    throw new AgentError(400, "tool.invalid_target", "读取文件工具需要指向具体文本文件", {
      path: targetPath
    }, true);
  }
  if (["listFiles", "globFiles", "grepFiles", "indexLocalFiles"].includes(type) && !stat.isDirectory()) {
    throw new AgentError(400, "tool.invalid_target", "目录型工具需要指向文件夹", {
      path: targetPath
    }, true);
  }
  if (stat.isFile() && !isLocalTextFile(targetPath)) {
    throw new AgentError(403, "permission.file_type_forbidden", "外部读取当前只允许 UTF-8 文本资料类型", {
      path: targetPath
    }, false);
  }
  return createPlanningWorkspacePreflight({
    type,
    query: targetPath,
    scope: "external_path",
    target: {
      type,
      workspace: getNovelDefaultAgentFolder(novel),
      path: targetPath,
      relativePath: path.basename(targetPath),
      exists: true,
      external: true,
      mode: stat.isDirectory() ? "read_directory" : "read_file"
    },
    matched: [{
      id: `${stat.isDirectory() ? "external_dir" : "external_file"}:${targetPath}`,
      title: targetPath,
      source: { type: stat.isDirectory() ? "local_directory" : "local_file", id: targetPath, sourceId: "external_approved", name: "待批准外部路径" },
      score: 1
    }]
  });
}

async function preflightPlanningSkillOp(store, novel, op, type, report, context) {
  if (isPlanningLocalPathPreflightType(type)) {
    if (isPlanningWorkspacePreflightType(type)) {
      const preflight = await preflightPlanningWorkspaceOp(novel, op, type, context);
      const approvedExternal = await approveExternalPathPreflightIfNeeded(novel, op, type, preflight, context);
      if (!approvedExternal && (op.requireHumanApproval === true || op.humanApproval === true)) {
        await requestPlanningHumanApproval(novel, op, type, preflight.matched || [], context);
      }
      return preflight;
    }
    const preflight = await preflightPlanningExternalReadOp(novel, op, type);
    if (preflight) {
      await approveExternalPathPreflightIfNeeded(novel, op, type, preflight, context);
      return preflight;
    }
  }
  if (!PLANNING_SKILL_HIGH_RISK_OPS.has(type)) {
    return null;
  }
  const evidenceSearchId = String(op.evidenceSearchId || op.evidence_search_id || "").trim();
  const reused = evidenceSearchId ? findPlanningSearchEvidence(report, evidenceSearchId) : null;
  if (evidenceSearchId && !reused) {
    const warning = `preflight 没有找到 evidenceSearchId 对应检索结果，已改为自动重新检索：${evidenceSearchId}`;
    report.warnings.push(warning);
    appendPlanningRunDiagnostic(novel, context.run?.id, {
      type: "tool_preflight",
      code: "tool.preflight_evidence_missing",
      category: "conflict",
      message: warning,
      retryable: true,
      details: {
        tool: type,
        evidenceSearchId,
        suggestedFix: "模型下次应使用本轮 search/read 返回的真实证据 id；本次已由后端自动补检索。"
      }
    });
  }
  const validEvidenceSearchId = reused ? evidenceSearchId : "";
  const search = reused || await executePlanningSearchOp(store, novel, {
    type: "search",
    query: buildPlanningPreflightQuery(op, type, context),
    scope: planningPreflightScope(type),
    limit: 8,
    retrievalMode: "bm25"
  }, context);
  if (!reused) {
    search.internal = true;
    report.searches.push(search);
  }
  const target = summarizePlanningSkillOpTarget(op, type);
  let matched = selectPlanningPreflightMatches(search, op, type);
  if (matched.length === 0) {
    matched = selectDirectPlanningPreflightMatches(store, novel, op, type);
  }
  const required = planningPreflightRequiresEvidence(type);
  if (required && matched.length === 0) {
    throw new HttpError(409, `高风险操作 ${type} 缺少可匹配证据，请先检索并确认目标`, {
      target,
      searchId: search.id || "",
      query: search.query,
      scope: search.scope,
      count: search.count
    });
  }
  if (required && matched.length > 1 && planningPreflightRequiresUniqueTarget(type)) {
    throw new HttpError(409, `高风险操作 ${type} 命中多个候选，请改用更精确的 id 或 evidenceSearchId`, {
      target,
      candidates: matched.map((item) => ({
        id: item.id,
        title: item.title,
        source: item.source
      }))
    });
  }
  if (op.requireHumanApproval === true || op.humanApproval === true) {
    await requestPlanningHumanApproval(novel, op, type, matched, context);
  }
  return {
    type: "preflight",
    opType: type,
    evidenceSearchId: validEvidenceSearchId || search.id || "",
    autoSearch: !reused,
    query: search.query,
    scope: search.scope,
    target,
    matched: matched.map((item) => ({
      id: item.id,
      title: item.title,
      source: item.source,
      score: item.score
    })),
    warnings: search.warnings || []
  };
}

async function requestPlanningHumanApproval(novel, op, type, matched, context) {
  const run = context.run;
  if (!run) {
    throw new HttpError(409, "当前操作要求人工确认，但没有可等待的 Agent 运行上下文");
  }
  const approval = normalizePlanningApproval({
    id: createId("approval"),
    runId: run.id,
    step: context.agentStep || 0,
    status: "pending",
    reason: buildPlanningApprovalReason(type, op),
    riskLevel: "high",
    operations: [op],
    createdAt: nowIso(),
    expiresAt: new Date(Date.now() + PLANNING_APPROVAL_TTL_MS).toISOString()
  });
  appendPlanningRunApproval(novel, run.id, approval);
  appendPlanningRunDiagnostic(novel, run.id, {
    type: "approval",
    code: "human.approval_required",
    message: approval.reason,
    retryable: false,
    details: {
      approvalId: approval.id,
      matched: (matched || []).map((item) => ({ id: item.id, title: item.title, source: item.source }))
    }
  });
  schedulePlanningRunLivePersist(run.id);
  broadcastPlanningRunSse(run.id, {
    kind: "approval_required",
    run: getPlanningRunStatus(novel, run.id),
    approval: sanitizePlanningRunForClient({ approvals: [approval] }).approvals[0]
  });
  const decision = await waitForPlanningApproval(run, approval);
  if (decision !== "approved") {
    throw new AgentError(409, "human.approval_rejected", `人工确认未通过：${type}`, { approvalId: approval.id }, false);
  }
  Object.defineProperty(op, "__humanApprovalGranted", {
    value: true,
    enumerable: false,
    configurable: true
  });
}

function waitForPlanningApproval(run, approval) {
  return new Promise((resolve, reject) => {
    const timer = setTimeout(() => {
      planningAgentApprovalQueue.delete(approval.id);
      markPlanningApprovalExpired(run.id, approval.id);
      resolve("expired");
    }, PLANNING_APPROVAL_TTL_MS);
    const finish = (decision) => {
      clearTimeout(timer);
      resolve(decision);
    };
    planningAgentApprovalQueue.set(approval.id, {
      runId: run.id,
      resolve: finish,
      createdAt: Date.now()
    });
    run.abortController?.signal?.addEventListener("abort", () => {
      clearTimeout(timer);
      planningAgentApprovalQueue.delete(approval.id);
      reject(Object.assign(new Error("策划 Agent 已终止"), { code: "PLANNING_RUN_CANCELLED" }));
    }, { once: true });
  });
}

function markPlanningApprovalExpired(runId, approvalId) {
  const entry = planningAgentLiveStores.get(runId);
  if (!entry?.store) return;
  const novel = entry.store.novels.find((item) => (item.planning?.runs || []).some((run) => run.id === runId));
  if (!novel) return;
  const runRecord = getPlanningRunRecord(novel, runId);
  if (!runRecord) return;
  const approvals = (runRecord.approvals || []).map((approval) => {
    if (approval.id !== approvalId || approval.status !== "pending") return approval;
    return normalizePlanningApproval({
      ...approval,
      status: "expired",
      decidedAt: nowIso()
    });
  });
  upsertPlanningRunRecord(novel, {
    id: runId,
    approvals,
    events: [createPlanningRunEvent("approval_expired", "approval_expired", "人工确认已超时", { approvalId })]
  });
  schedulePlanningRunLivePersist(runId);
}

function findPlanningSearchEvidence(report, evidenceSearchId) {
  return (report.searches || []).find((search) => {
    if (search.id && search.id === evidenceSearchId) return true;
    return (search.results || []).some((result) => result.id === evidenceSearchId || result.source?.id === evidenceSearchId);
  }) || null;
}

function planningPreflightRequiresEvidence(type) {
  return !["annotateTurn", "generatePrewritePlan", "runRoleplayTurn", "reviewLatestTurn", "adaptRoleplayToProse", "postwriteProse", "runNormalWritingWorkflow", "runChapterWorkflow", "writeFile", "applyPatch", "patchFile", "revertPatch", "revertFilePatch", "previewPatchSet", "applyPatchSet", "revertPatchSet", "runShell", "startShellSession", "writeShellSession", "stopShellSession", "startShellJob", "listShellJobs", "readShellJob", "stopShellJob", "customTool", "mcpTool"].includes(type);
}

function planningPreflightRequiresUniqueTarget(type) {
  return !["updateAiSlot"].includes(type);
}

function buildPlanningApprovalReason(type, op) {
  const registry = getPlanningToolRegistry();
  const tool = registry[type] || null;
  const access = op?.externalAccess && typeof op.externalAccess === "object" ? op.externalAccess : null;
  const accessKind = planningExternalAccessKind(type);
  const target = access?.path || access?.cwd || planningProgressTargetFromOperation(op);
  if (access && target) {
    if (accessKind === "read") return `允许读取外部资料：${limitText(target, 160)}`;
    if (accessKind === "write") return `允许修改工作区外文件：${limitText(target, 160)}`;
    if (accessKind === "shell") return `允许运行外部目录命令：${limitText(target, 160)}`;
  }
  if (accessKind === "shell") {
    return `允许运行命令：${limitText(String(op?.command || op?.cmd || type || ""), 160)}`;
  }
  return `${planningToolProgressActionName(type, tool)}需要确认`;
}

function planningPreflightScope(type) {
  if (["patchMemory", "retireMemory"].includes(type)) return "memory";
  if (["patchLorebook", "deleteLorebook"].includes(type)) return "lorebook";
  if (["updateCharacterCard"].includes(type)) return "characters";
  if (["markArchiveRecord", "patchArchiveRecord", "deleteArchiveRecord"].includes(type)) return "archives";
  if (["patchProseDraft"].includes(type)) return "drafts";
  if (["annotateTurn", "reviewLatestTurn", "runRoleplayTurn"].includes(type)) return "roleplay";
  if (["adaptRoleplayToProse", "postwriteProse", "runNormalWritingWorkflow"].includes(type)) return "prose";
  if (["updateAiSlot"].includes(type)) return "providers";
  return "all";
}

function buildPlanningPreflightQuery(op, type, context) {
  const parts = [
    type,
    op.memoryId,
    op.entryId,
    op.characterId,
    op.turnId,
    op.proseId,
    op.id,
    op.name,
    op.characterName,
    op.key,
    op.title,
    op.subject,
    op.field,
    op.collection,
    op.slot,
    op.providerId,
    op.model,
    context.queryText
  ];
  return uniqueStrings(parts.map((item) => String(item || "").trim()).filter(Boolean)).join(" ");
}

function summarizePlanningSkillOpTarget(op, type) {
  return {
    type,
    id: String(op.memoryId || op.entryId || op.characterId || op.turnId || op.proseId || op.id || ""),
    name: String(op.name || op.characterName || op.key || op.title || ""),
    subject: String(op.subject || ""),
    field: String(op.field || ""),
    collection: String(op.collection || op.target || op.kind || ""),
    slot: String(op.slot || op.role || ""),
    providerId: String(op.providerId || ""),
    model: String(op.model || "")
  };
}

function selectPlanningPreflightMatches(search, op, type) {
  const results = Array.isArray(search?.results) ? search.results : [];
  const expectedTypes = planningPreflightExpectedSourceTypes(type);
  const targetId = String(op.memoryId || op.entryId || op.characterId || op.turnId || op.proseId || op.id || "").trim();
  const targetName = String(op.name || op.characterName || op.key || op.title || "").trim();
  const subject = String(op.subject || "").trim();
  const field = String(op.field || "").trim();
  const providerId = String(op.providerId || "").trim();
  const model = String(op.model || "").trim();
  return results.filter((result) => {
    const sourceType = String(result.source?.type || "");
    if (expectedTypes.length > 0 && !expectedTypes.includes(sourceType)) return false;
    if (targetId && (result.id === targetId || result.source?.id === targetId || String(result.id || "").includes(targetId))) return true;
    const haystack = [
      result.id,
      result.title,
      result.text,
      result.source?.id
    ].map((item) => String(item || "").toLowerCase()).join("\n");
    if (providerId && haystack.includes(providerId.toLowerCase())) return true;
    if (model && haystack.includes(model.toLowerCase())) return true;
    if (targetName && haystack.includes(targetName.toLowerCase())) return true;
    if (subject && field && haystack.includes(subject.toLowerCase()) && haystack.includes(field.toLowerCase())) return true;
    if (type === "updateAiSlot" && (providerId || model)) return true;
    return false;
  });
}

function selectDirectPlanningPreflightMatches(store, novel, op, type) {
  const scope = planningPreflightScope(type);
  const documents = filterPlanningSearchDocuments(collectPlanningSearchDocuments(store, novel), scope);
  const directResults = documents.map((document) => ({
    id: document.id,
    title: document.title,
    source: document.source,
    score: 1,
    text: limitText(document.text, 800)
  }));
  return selectPlanningPreflightMatches({ results: directResults }, op, type);
}

function planningPreflightExpectedSourceTypes(type) {
  if (["patchMemory", "retireMemory"].includes(type)) return ["memory"];
  if (["patchLorebook", "deleteLorebook"].includes(type)) return ["lorebook"];
  if (["updateCharacterCard"].includes(type)) return ["character_card"];
  if (["markArchiveRecord", "patchArchiveRecord", "deleteArchiveRecord"].includes(type)) return ["archive", "memory"];
  if (["patchProseDraft"].includes(type)) return ["prose_part"];
  if (["annotateTurn", "reviewLatestTurn", "runRoleplayTurn"].includes(type)) return ["roleplay_turn"];
  if (["adaptRoleplayToProse", "postwriteProse"].includes(type)) return ["prose_part", "roleplay_turn"];
  if (["runNormalWritingWorkflow"].includes(type)) return ["prose_part", "archive", "memory", "lorebook"];
  if (["updateAiSlot"].includes(type)) return ["provider_config", "ai_role_config"];
  return [];
}

function filterPlanningSearchDocuments(documents, scope) {
  const value = String(scope || "all").trim();
  if (value === "active_project") {
    const excluded = new Set(["planning_chat", "planning_skill_ops", "provider_config", "ai_role_config"]);
    return documents
      .filter((document) => isDocumentVisibleTo(document, "planner", ""))
      .filter((document) => !excluded.has(document.source?.type || ""));
  }
  const allowed = {
    archives: ["archive"],
    archive: ["archive"],
    memory: ["memory"],
    memories: ["memory"],
    lorebook: ["lorebook"],
    world: ["lorebook"],
    characters: ["character_card"],
    character: ["character_card"],
    planning: ["planning_chat", "planning_skill_ops"],
    roleplay: ["roleplay_turn"],
    turns: ["roleplay_turn"],
    review: ["review"],
    reviews: ["review"],
    prose: ["prose_part"],
    drafts: ["prose_part", "roleplay_config_draft"],
    providers: ["provider_config", "ai_role_config"],
    provider: ["provider_config", "ai_role_config"],
    models: ["provider_config", "ai_role_config"],
    model: ["provider_config", "ai_role_config"],
    config: ["provider_config", "ai_role_config", "roleplay_config_draft"]
  }[value] || null;
  const visible = documents.filter((document) => isDocumentVisibleTo(document, "planner", ""));
  if (!allowed) return visible;
  return visible.filter((document) => allowed.includes(document.source?.type || ""));
}

function executePlanningUpsertMemoryOp(novel, op, context) {
  const raw = op.item && typeof op.item === "object" ? op.item : op;
  validatePlanningMemoryWrite(raw, context);
  const item = upsertMemoryItem(novel, {
    ...raw,
    source: raw.source || { type: context.sourceType || "planning_skill", id: context.sourceId || "" }
  });
  recordEvent(novel, "planning_skill_memory_upserted", { memoryId: item.id, subject: item.subject, field: item.field });
  return item;
}

function validatePlanningMemoryWrite(raw, context = {}) {
  const item = normalizeMemoryItem(raw);
  const missing = [];
  if (!item.subject) missing.push("subject");
  if (!item.field) missing.push("field");
  if (!item.value) missing.push("value");
  if (!item.visibility.length) missing.push("visibility");
  if (!item.evidence.length) missing.push("evidence");
  if (missing.length > 0) {
    throw new AgentError(400, "memory.write_contract_missing", `记忆写入缺少必要字段：${missing.join("、")}`, {
      missing,
      expected: "subject、field、value、visibility、evidence"
    }, true);
  }
  if (item.value.length > 1800) {
    throw new AgentError(400, "memory.value_too_large", "记忆 value 过长，不能把整段资料或正文摘要直接写入记忆；请压成单条结构化事实", {
      valueChars: item.value.length
    }, true);
  }
  const violations = collectMemoryItemWriteViolations({
    ...item,
    source: {
      ...item.source,
      type: context.sourceType || item.source?.type || ""
    }
  });
  if (violations.length > 0) {
    const first = violations[0];
    throw new AgentError(400, first.code, `记忆写入被拒绝：${first.message}`, {
      violations,
      expected: "长期记忆只能写单条稳定事实；档案块、模板占位、运行审计和测试输出应留在档案、世界书、RAG 证据或审计层"
    }, true);
  }
}

function executePlanningPatchMemoryOp(novel, op, context) {
  const item = findMemoryItemForSkillOp(novel, op);
  if (!item) {
    throw new HttpError(404, "没有找到要编辑的记忆");
  }
  const patch = op.patch && typeof op.patch === "object" ? op.patch : {};
  const patches = Array.isArray(op.patches) ? op.patches : [];
  let next = structuredCloneSafe(item);
  if (Object.keys(patch).length > 0) {
    next = applyAllowedObjectPatch(next, patch, PLANNING_SKILL_MEMORY_PATCH_FIELDS);
  }
  for (const itemPatch of patches.slice(0, 20)) {
    next = applyAllowedPathPatch(next, itemPatch, PLANNING_SKILL_MEMORY_PATCH_FIELDS);
  }
  next = normalizeMemoryItem({
    ...item,
    ...next,
    id: item.id,
    source: item.source,
    updatedAt: nowIso()
  });
  validatePlanningMemoryWrite(next, context);
  if (!next.value) {
    throw new HttpError(400, "记忆内容不能为空");
  }
  const index = novel.memory.items.findIndex((memory) => memory.id === item.id);
  novel.memory.items[index] = next;
  retireConflictingMemoryItems(novel, next);
  novel.memory.updatedAt = nowIso();
  recordEvent(novel, "planning_skill_memory_patched", {
    memoryId: next.id,
    sourceId: context.sourceId || ""
  });
  return next;
}

function findMemoryItemForSkillOp(novel, op) {
  novel.memory = normalizeMemory(novel.memory);
  const id = String(op.memoryId || op.id || "").trim();
  if (id) {
    return (novel.memory.items || []).find((memory) => memory.id === id) || null;
  }
  const subject = String(op.subject || "").trim().toLowerCase();
  const field = String(op.field || "").trim().toLowerCase();
  if (!subject || !field) return null;
  return (novel.memory.items || []).find((memory) => {
    return String(memory.subject || "").trim().toLowerCase() === subject
      && String(memory.field || "").trim().toLowerCase() === field
      && memory.status !== "outdated";
  }) || null;
}

function validatePlanningLorebookWrite(raw) {
  const entry = normalizeLorebookEntry(raw);
  const missing = [];
  if (!entry.name) missing.push("name");
  if (!entry.content) missing.push("content");
  if (entry.matchMode !== "always" && entry.keys.length === 0) missing.push("keys");
  if (missing.length > 0) {
    throw new AgentError(400, "lorebook.write_contract_missing", `世界书写入缺少必要字段：${missing.join("、")}`, {
      missing,
      expected: "name、content，以及非 always 条目的 keys"
    }, true);
  }
  if (entry.content.length > 5000) {
    throw new AgentError(400, "lorebook.content_too_large", "单条世界书内容过长，请拆成多个关键词触发条目或放入本地资料/RAG 证据层", {
      contentChars: entry.content.length
    }, true);
  }
}

function executePlanningUpsertLorebookOp(novel, op, context) {
  const raw = op.entry && typeof op.entry === "object" ? op.entry : op;
  validatePlanningLorebookWrite(raw);
  const existing = findLorebookEntryForSkillOp(novel, raw);
  const entry = upsertLorebookEntry(novel, {
    ...(existing || {}),
    ...raw,
    id: existing?.id || raw.id,
    source: raw.source || { type: context.sourceType || "planning_skill", id: context.sourceId || "" }
  });
  recordEvent(novel, "planning_skill_lorebook_upserted", { lorebookId: entry.id, name: entry.name });
  return entry;
}

function executePlanningPatchLorebookOp(novel, op, context) {
  const entry = findLorebookEntryForSkillOp(novel, op);
  if (!entry) {
    throw new HttpError(404, "没有找到要编辑的世界书条目");
  }
  const patch = op.patch && typeof op.patch === "object" ? op.patch : {};
  const patches = Array.isArray(op.patches) ? op.patches : [];
  let next = structuredCloneSafe(entry);
  if (Object.keys(patch).length > 0) {
    next = applyAllowedObjectPatch(next, patch, PLANNING_SKILL_LOREBOOK_PATCH_FIELDS);
  }
  for (const itemPatch of patches.slice(0, 20)) {
    next = applyAllowedPathPatch(next, itemPatch, PLANNING_SKILL_LOREBOOK_PATCH_FIELDS);
  }
  validatePlanningLorebookWrite({
    ...entry,
    ...next
  });
  const updated = upsertLorebookEntry(novel, {
    ...entry,
    ...next,
    id: entry.id,
    source: entry.source || { type: context.sourceType || "planning_skill", id: context.sourceId || "" },
    createdAt: entry.createdAt,
    updatedAt: nowIso()
  });
  recordEvent(novel, "planning_skill_lorebook_patched", {
    lorebookId: updated.id,
    name: updated.name,
    sourceId: context.sourceId || ""
  });
  return updated;
}

function executePlanningDeleteLorebookOp(novel, op, context) {
  const entry = findLorebookEntryForSkillOp(novel, op);
  const reason = String(op.reason || "").trim();
  if (!entry) {
    throw new HttpError(404, "没有找到要删除的世界书条目");
  }
  if (!reason) {
    throw new HttpError(400, "删除世界书条目必须说明 reason");
  }
  novel.lorebook = normalizeLorebook(novel.lorebook);
  novel.lorebook.entries = novel.lorebook.entries.filter((item) => item.id !== entry.id);
  novel.lorebook.updatedAt = nowIso();
  recordEvent(novel, "planning_skill_lorebook_deleted", {
    lorebookId: entry.id,
    name: entry.name,
    reason
  });
  return { id: entry.id, name: entry.name };
}

function findLorebookEntryForSkillOp(novel, raw) {
  const id = String(raw.id || raw.entryId || "").trim();
  const entries = normalizeLorebook(novel.lorebook).entries;
  if (id) {
    const byId = entries.find((entry) => entry.id === id);
    if (byId) return byId;
  }
  const name = String(raw.name || raw.title || "").trim().toLowerCase();
  if (!name) return null;
  return entries.find((entry) => String(entry.name || "").trim().toLowerCase() === name) || null;
}

function executePlanningUpdateCharacterCardOp(novel, op) {
  const character = findCharacterForSkillOp(novel, op);
  if (!character) {
    throw new HttpError(404, "没有找到要编辑的角色卡");
  }
  const patch = op.patch && typeof op.patch === "object" ? op.patch : op;
  const allowed = [
    "description",
    "personality",
    "scenario",
    "firstMessage",
    "exampleDialog",
    "systemPrompt",
    "postHistoryInstructions",
    "lorebook",
    "tags",
    "providerId",
    "model",
    "temperature"
  ];
  const next = { ...character };
  for (const key of allowed) {
    if (Object.hasOwn(patch, key)) next[key] = patch[key];
  }
  Object.assign(character, normalizeCharacter({
    ...next,
    id: character.id,
    name: character.name,
    roleType: character.roleType,
    createdAt: character.createdAt,
    updatedAt: nowIso()
  }));
  projectCharacterToMemory(novel, character, { type: "planning_skill", id: op.sourceId || "" });
  recordEvent(novel, "planning_skill_character_updated", { characterId: character.id, name: character.name });
  return character;
}

function findCharacterForSkillOp(novel, op) {
  const id = String(op.characterId || op.id || "").trim();
  if (id) {
    const byId = novel.characters.find((character) => character.id === id);
    if (byId) return byId;
  }
  return findCharacterByName(novel, op.name || op.characterName);
}

function executePlanningMarkArchiveRecordOp(novel, op) {
  const collection = normalizeArchiveCollectionName(op.collection || op.target || op.kind);
  const key = String(op.key || op.name || op.title || "").trim().toLowerCase();
  if (!collection) {
    throw new HttpError(400, "档案集合必须是 characters、scenes 或 clues");
  }
  if (!key) {
    throw new HttpError(400, "档案条目标记缺少 key/name/title");
  }
  const patch = op.patch && typeof op.patch === "object" ? op.patch : {};
  const list = Array.isArray(novel.archives[collection]) ? [...novel.archives[collection]] : [];
  const index = list.findIndex((item) => archiveRecordKey(item) === key);
  if (index < 0) {
    throw new HttpError(404, `没有找到档案条目：${op.key || op.name || op.title}`);
  }
  list[index] = {
    ...list[index],
    ...patch,
    status: String(op.status || patch.status || list[index].status || "active"),
    updatedAt: nowIso()
  };
  novel.archives = normalizeArchives({
    ...novel.archives,
    [collection]: list,
    updatedAt: nowIso()
  }, novel.scenario, novel.characters);
  recordEvent(novel, "planning_skill_archive_marked", { collection, key });
  return { collection, key, status: list[index].status };
}

function executePlanningPatchArchiveRecordOp(novel, op) {
  const collection = normalizeArchiveCollectionName(op.collection || op.target || op.kind);
  const key = String(op.key || op.name || op.title || "").trim().toLowerCase();
  if (!collection) {
    throw new HttpError(400, "档案集合必须是 characters、scenes 或 clues");
  }
  if (!key) {
    throw new HttpError(400, "档案路径编辑缺少 key/name/title");
  }
  const patches = Array.isArray(op.patches) ? op.patches : [];
  if (patches.length === 0) {
    throw new HttpError(400, "档案路径编辑缺少 patches");
  }
  const list = Array.isArray(novel.archives[collection]) ? [...novel.archives[collection]] : [];
  const index = list.findIndex((item) => archiveRecordKey(item) === key);
  if (index < 0) {
    throw new HttpError(404, `没有找到档案条目：${op.key || op.name || op.title}`);
  }
  let record = { ...list[index] };
  for (const patch of patches.slice(0, 20)) {
    record = applySafeRecordPatch(record, patch);
  }
  record.updatedAt = nowIso();
  list[index] = record;
  novel.archives = normalizeArchives({
    ...novel.archives,
    [collection]: list,
    updatedAt: nowIso()
  }, novel.scenario, novel.characters);
  recordEvent(novel, "planning_skill_archive_patched", { collection, key, patchCount: patches.length });
  return { collection, key, patchCount: patches.length };
}

function applySafeRecordPatch(record, patch) {
  const op = String(patch?.op || "set").trim();
  const path = normalizeSafePatchPath(patch?.path);
  if (path.length === 0) {
    throw new HttpError(400, "patch.path 不能为空");
  }
  const next = structuredCloneSafe(record);
  const parent = ensurePatchParent(next, path);
  const key = path[path.length - 1];
  if (op === "remove") {
    if (Array.isArray(parent)) {
      const index = Number(key);
      if (Number.isInteger(index) && index >= 0 && index < parent.length) parent.splice(index, 1);
    } else {
      delete parent[key];
    }
    return next;
  }
  if (op === "append") {
    const current = parent[key];
    const list = Array.isArray(current) ? current : current === undefined ? [] : [current];
    parent[key] = uniqueStrings([...list, ...(Array.isArray(patch.value) ? patch.value : [patch.value])]);
    return next;
  }
  parent[key] = sanitizePatchValue(patch.value);
  return next;
}

function applyAllowedObjectPatch(record, patch, allowedFields) {
  const next = structuredCloneSafe(record);
  for (const [key, value] of Object.entries(patch || {})) {
    if (!allowedFields.has(key)) continue;
    next[key] = sanitizePatchValue(value);
  }
  return next;
}

function applyAllowedPathPatch(record, patch, allowedFields) {
  const path = normalizeSafePatchPath(patch?.path);
  if (path.length === 0) {
    throw new HttpError(400, "patch.path 不能为空");
  }
  if (!allowedFields.has(path[0])) {
    throw new HttpError(400, `不允许通过 skillOps 编辑字段：${path[0]}`);
  }
  return applySafeRecordPatch(record, patch);
}

function normalizeSafePatchPath(path) {
  const raw = Array.isArray(path) ? path : String(path || "").split(".");
  return raw
    .map((item) => String(item || "").trim())
    .filter(Boolean)
    .slice(0, 6);
}

function ensurePatchParent(target, path) {
  let current = target;
  for (const segment of path.slice(0, -1)) {
    if (Array.isArray(current)) {
      const index = Number(segment);
      if (!Number.isInteger(index) || index < 0 || index > current.length) {
        throw new HttpError(400, `非法数组路径：${segment}`);
      }
      if (!current[index] || typeof current[index] !== "object") current[index] = {};
      current = current[index];
    } else {
      if (!current[segment] || typeof current[segment] !== "object") current[segment] = {};
      current = current[segment];
    }
  }
  return current;
}

function sanitizePatchValue(value) {
  if (value === null || value === undefined) return "";
  if (typeof value === "string") return value.trim();
  if (typeof value === "number" || typeof value === "boolean") return value;
  if (Array.isArray(value)) return value.map(sanitizePatchValue).filter((item) => item !== "");
  if (typeof value === "object") {
    const result = {};
    for (const [key, item] of Object.entries(value)) {
      const safeKey = String(key || "").trim();
      if (!safeKey) continue;
      result[safeKey] = sanitizePatchValue(item);
    }
    return result;
  }
  return String(value || "").trim();
}

function structuredCloneSafe(value) {
  return JSON.parse(JSON.stringify(value || {}));
}

function executePlanningDeleteArchiveRecordOp(novel, op) {
  const collection = normalizeArchiveCollectionName(op.collection || op.target || op.kind);
  const key = String(op.key || op.name || op.title || "").trim().toLowerCase();
  const reason = String(op.reason || "").trim();
  if (!collection) {
    throw new HttpError(400, "档案集合必须是 characters、scenes 或 clues");
  }
  if (!key) {
    throw new HttpError(400, "删除档案条目缺少 key/name/title");
  }
  if (!reason) {
    throw new HttpError(400, "删除档案条目必须说明 reason");
  }
  const list = Array.isArray(novel.archives[collection]) ? [...novel.archives[collection]] : [];
  const index = list.findIndex((item) => archiveRecordKey(item) === key);
  if (index < 0) {
    throw new HttpError(404, `没有找到档案条目：${op.key || op.name || op.title}`);
  }
  const [removed] = list.splice(index, 1);
  novel.archives = normalizeArchives({
    ...novel.archives,
    [collection]: list,
    updatedAt: nowIso()
  }, novel.scenario, novel.characters);
  recordEvent(novel, "planning_skill_archive_deleted", { collection, key, reason });
  return { collection, key, removed: removed.name || removed.title || removed.key || key };
}

function normalizeArchiveCollectionName(value) {
  const text = String(value || "").trim();
  if (["characters", "character"].includes(text)) return "characters";
  if (["scenes", "scene"].includes(text)) return "scenes";
  if (["clues", "clue"].includes(text)) return "clues";
  return "";
}

function executePlanningRetireMemoryOp(novel, op) {
  const id = String(op.memoryId || op.id || "").trim();
  const status = String(op.status || "outdated").trim() === "contradicted" ? "contradicted" : "outdated";
  const item = id
    ? (novel.memory.items || []).find((memory) => memory.id === id)
    : (novel.memory.items || []).find((memory) => {
        return String(memory.subject || "").trim().toLowerCase() === String(op.subject || "").trim().toLowerCase()
          && String(memory.field || "").trim().toLowerCase() === String(op.field || "").trim().toLowerCase();
      });
  if (!item) {
    throw new HttpError(404, "没有找到要退役的记忆");
  }
  item.status = status;
  item.updatedAt = nowIso();
  novel.memory.updatedAt = nowIso();
  recordEvent(novel, "planning_skill_memory_retired", { memoryId: item.id, status });
  return item;
}

async function executePlanningUpsertProseDraftOp(novel, op) {
  const text = String(op.text || "").trim();
  if (!text) {
    throw new HttpError(400, "正文修订草稿不能为空");
  }
  const baseProseId = String(op.baseProseId || op.proseId || "").trim();
  const base = baseProseId ? novel.session.proseParts.find((part) => part.id === baseProseId) : null;
  if (baseProseId && !base) {
    throw new HttpError(404, "没有找到 baseProseId 对应正文");
  }
  const prose = normalizeProsePart({
    id: createId("prose"),
    createdAt: nowIso(),
    updatedAt: nowIso(),
    status: "draft",
    versionType: "agent_revision",
    baseProseId,
    branchId: baseProseId || createId("prose_branch"),
    revisionOf: baseProseId,
    turnRange: Array.isArray(op.turnRange) ? op.turnRange : base?.turnRange || [],
    text,
    raw: {
      source: "planning_skill",
      baseProseId,
      reason: String(op.reason || "")
    },
    memoryInjection: null
  });
  await appendProseVersionEventWithSnapshots(novel, prose, {
    eventType: "created",
    versionType: baseProseId ? "agent_revision" : "draft",
    nextText: prose.text,
    actor: "agent",
    summary: baseProseId ? `基于 ${baseProseId} 新建 Agent 修订草稿` : "新建正文草稿"
  });
  await ensureProseContextAsset(novel, prose, "策划 Agent 新建正文草稿后保存长正文引用");
  novel.session.proseParts.push(prose);
  recordEvent(novel, "planning_skill_prose_draft_created", { proseId: prose.id, baseProseId });
  updateTimestamp(novel);
  return prose;
}

async function executePlanningPatchProseDraftOp(novel, op) {
  const proseId = String(op.proseId || op.id || "").trim();
  if (!proseId) {
    throw new HttpError(400, "编辑正文草稿必须包含 proseId");
  }
  const prose = novel.session.proseParts.find((part) => part.id === proseId);
  if (!prose) {
    throw new HttpError(404, "没有找到正文草稿");
  }
  if (normalizeProseStatus(prose.status) === "accepted") {
    throw new HttpError(400, "已采纳正文不能由策划 skill 直接覆盖，请用 upsertProseDraft 新建修订草稿");
  }
  const status = String(op.status || "").trim();
  if (status === "discarded") {
    prose.status = "discarded";
    prose.discardedAt = nowIso();
  }
  if (Object.hasOwn(op, "text")) {
    const text = String(op.text || "").trim();
    if (!text) {
      throw new HttpError(400, "正文草稿内容不能为空");
    }
    const previousText = prose.text || "";
    prose.text = text;
    prose.status = "draft";
    prose.versionType = "agent_revision";
    prose.discardedAt = "";
    await appendProseVersionEventWithSnapshots(novel, prose, {
      eventType: "agent_revision",
      versionType: "agent_revision",
      previousText,
      nextText: prose.text,
      actor: "agent",
      summary: String(op.reason || "策划 Agent 编辑正文草稿")
    });
  }
  prose.raw = {
    ...(prose.raw && typeof prose.raw === "object" ? prose.raw : {}),
    lastPlanningSkillPatch: {
      reason: String(op.reason || ""),
      patchedAt: nowIso()
    }
  };
  prose.updatedAt = nowIso();
  await ensureProseContextAsset(novel, prose, "策划 Agent 编辑正文草稿后保存长正文引用");
  recordEvent(novel, "planning_skill_prose_draft_patched", { proseId: prose.id, status: prose.status });
  updateTimestamp(novel);
  return prose;
}

function executePlanningAnnotateTurnOp(novel, op) {
  const turnId = String(op.turnId || op.targetId || "").trim();
  const turn = turnId
    ? novel.session.turns.find((item) => item.id === turnId)
    : novel.session.turns[novel.session.turns.length - 1];
  if (!turn) {
    throw new HttpError(404, "没有找到要注释的扮演轮次");
  }
  const review = normalizeReviewRecord({
    id: createId("review"),
    createdAt: nowIso(),
    targetType: "turn",
    targetId: turn.id,
    severity: op.severity || "low",
    summary: op.summary || op.note || "策划 skill 追加注释。",
    issues: Array.isArray(op.issues) ? op.issues : [],
    recommendedAction: op.recommendedAction || "continue",
    raw: { source: "planning_skill" }
  });
  novel.session.reviews.unshift(review);
  novel.session.reviews = novel.session.reviews.slice(0, 40);
  recordEvent(novel, "planning_skill_turn_annotated", { turnId: turn.id, reviewId: review.id });
  updateTimestamp(novel);
  return review;
}

function executePlanningUpdateAiSlotOp(store, novel, op) {
  const slot = String(op.slot || op.role || "").trim();
  if (!AI_ROLE_KEYS.includes(slot)) {
    throw new HttpError(400, "AI 槽位必须是 planner、guide、minor 或 adapter");
  }
  const rolePatch = {
    providerId: String(op.providerId ?? novel.aiRoles[slot]?.providerId ?? ""),
    model: String(op.model ?? novel.aiRoles[slot]?.model ?? ""),
    temperature: op.temperature ?? novel.aiRoles[slot]?.temperature ?? 0.8
  };
  // 只把本次工具明确给出的预算字段传给 normalizeAiSetting，避免旧预算阻止“按新窗口自动推导”。
  if (hasOwnField(op, "contextWindowTokens") || hasOwnField(op, "contextWindow")) rolePatch.contextWindowTokens = op.contextWindowTokens ?? op.contextWindow;
  if (hasOwnField(op, "promptBudgetTokens")) rolePatch.promptBudgetTokens = op.promptBudgetTokens;
  if (hasOwnField(op, "compressionTriggerTokens")) rolePatch.compressionTriggerTokens = op.compressionTriggerTokens;
  if (hasOwnField(op, "responseReserveTokens") || hasOwnField(op, "outputReserveTokens")) rolePatch.responseReserveTokens = op.responseReserveTokens ?? op.outputReserveTokens;
  if (hasOwnField(op, "safetyTokens")) rolePatch.safetyTokens = op.safetyTokens;
  if (hasOwnField(op, "compactionPressureRatio")) rolePatch.compactionPressureRatio = op.compactionPressureRatio;
  const patch = { [slot]: rolePatch };
  const nextAiRoles = { ...novel.aiRoles };
  nextAiRoles[slot] = normalizeAiSetting(patch[slot], novel.aiRoles[slot]);
  validateAiRolesPatch(store, nextAiRoles, patch);
  novel.aiRoles = nextAiRoles;
  recordEvent(novel, "planning_skill_ai_slot_updated", { slot, providerId: nextAiRoles[slot].providerId, model: nextAiRoles[slot].model });
  updateTimestamp(novel);
  return { slot, providerId: nextAiRoles[slot].providerId, model: nextAiRoles[slot].model };
}

function executePlanningAddProviderModelOp(store, op) {
  const providerId = String(op.providerId || "").trim();
  const model = String(op.model || "").trim();
  if (!providerId || !model) {
    throw new HttpError(400, "添加模型必须包含 providerId 和 model");
  }
  const provider = store.providers.find((item) => item.id === providerId);
  if (!provider) {
    throw new HttpError(404, "没有找到提供商");
  }
  provider.models = uniqueStrings([...(provider.models || []), model]);
  provider.modelProfiles = normalizeProviderModelProfiles({
    ...(provider.modelProfiles || {}),
    [model]: provider.modelProfiles?.[model] || { source: "inferred" }
  });
  provider.updatedAt = nowIso();
  return { providerId, model };
}

function executePlanningApplyArchivePatchOp(novel, op, context = {}) {
  const archivePatch = op.patch && typeof op.patch === "object"
    ? op.patch
    : op.archivePatch && typeof op.archivePatch === "object"
      ? op.archivePatch
      : {
          premise: op.premise,
          background: op.background,
          outline: op.outline,
          style: op.style,
          characters: op.characters,
          scenes: op.scenes,
          clues: op.clues
        };
  if (!hasArchivePatchContent(archivePatch)) {
    throw new AgentError(400, "archive_patch.empty", "applyArchivePatch 没有可写入的档案内容", {
      expected: ["premise", "background", "outline", "style", "characters", "scenes", "clues"]
    }, true);
  }
  const sourceFiles = collectArchivePatchSourceFiles(op, context);
  const writeReport = applyArchivePatch(novel, archivePatch, { sourceFiles });
  const diagnostics = mergeArchiveDiagnostics(op.archiveDiagnostics, writeReport);
  recordEvent(novel, "planning_tool_archive_patch_applied", {
    source: context.protocol || "tool_registry",
    sourceId: context.sourceId || "",
    appliedFields: writeReport.appliedFields,
    skipped: writeReport.skipped.length,
    warnings: writeReport.warnings.length
  });
  updateTimestamp(novel);
  return {
    id: createId("archive_patch"),
    scope: "archives",
    count: writeReport.appliedFields.length,
    patch: writeReport.patch,
    writeReport,
    diagnostics,
    warnings: [...(writeReport.warnings || []).map((item) => item.reason || item.field || String(item)), ...(writeReport.skipped || []).map((item) => `${item.field || "field"}：${item.reason || "已跳过"}`)],
    appliedFields: writeReport.appliedFields
  };
}

function executePlanningInspectNovelDiagnosticsOp(novel, op = {}) {
  const scope = String(op.scope || "all");
  const limit = clampInteger(op.limit, 1, 80, 40);
  const issues = collectNovelDiagnostics(novel)
    .filter((issue) => scope === "all" || issue.scope === scope)
    .slice(0, limit);
  return {
    id: createId("novel_diag"),
    query: scope,
    scope: "novel_diagnostics",
    count: issues.length,
    warnings: issues.some((issue) => issue.severity === "high") ? ["存在高优先级资料一致性问题，写入前应先修正或向用户确认。"] : [],
    results: issues.map((issue) => ({
      id: issue.id,
      title: issue.title,
      source: { type: "novel_diagnostic", id: issue.id, scope: issue.scope },
      score: issue.severity === "high" ? 1 : issue.severity === "medium" ? 0.7 : 0.4,
      text: issue.message,
      severity: issue.severity,
      code: issue.code,
      target: issue.target,
      suggestedFix: issue.suggestedFix
    }))
  };
}

function collectNovelDiagnostics(novel) {
  return [
    ...collectArchiveDiagnosticsIssues(novel),
    ...collectArchiveDuplicateDiagnosticsIssues(novel),
    ...collectMemoryDiagnosticsIssues(novel),
    ...collectMemoryFactConflictDiagnosticsIssues(novel),
    ...collectLorebookDiagnosticsIssues(novel),
    ...collectLorebookArchiveCoverageIssues(novel),
    ...collectCharacterDiagnosticsIssues(novel),
    ...collectCharacterAgeConflictIssues(novel),
    ...collectCharacterAddressingConflictIssues(novel),
    ...collectRoleplayConfigSchemaDiagnosticsIssues(novel),
    ...collectRoleplayConfigDiagnosticsIssues(novel),
    ...collectRoleplayReferenceDiagnosticsIssues(novel),
    ...collectRoleplayVisibilityLeakIssues(novel),
    ...collectDirectorOvercontrolDiagnosticsIssues(novel),
    ...collectLorebookTriggerAuditIssues(novel),
    ...collectProseScenePollutionIssues(novel),
    ...collectPostwriteMissingIssues(novel),
    ...collectProseDiagnosticsIssues(novel)
  ].map((issue, index) => ({
    id: issue.id || `diag_${index + 1}`,
    severity: issue.severity || "medium",
    scope: issue.scope || "archive",
    code: issue.code || "diagnostic.issue",
    title: issue.title || issue.code || "资料诊断",
    message: issue.message || "",
    target: issue.target || null,
    suggestedFix: issue.suggestedFix || ""
  }));
}

function runNovelQualityGate(novel, options = {}) {
  const scope = String(options.scope || "all");
  const issues = collectNovelDiagnostics(novel)
    .filter((issue) => scope === "all" || issue.scope === scope)
    .map(enrichQualityGateIssue);
  const blocking = issues.filter((issue) => issue.gateSeverity === "blocking");
  const high = issues.filter((issue) => issue.gateSeverity === "high");
  const warnings = issues.filter((issue) => ["medium", "low"].includes(issue.gateSeverity));
  const status = blocking.length || high.length ? "blocked" : warnings.length ? "warning" : "passed";
  const previous = novel.session?.qualityGate || null;
  const result = {
    id: createId("quality_gate"),
    scope,
    status,
    checkedAt: nowIso(),
    issueCount: issues.length,
    blockingCount: blocking.length + high.length,
    warningCount: warnings.length,
    passedCount: issues.length === 0 ? 1 : 0,
    issues,
    recheck: {
      required: status !== "passed",
      scopes: uniqueStrings(issues.map((issue) => issue.recheckScope).filter(Boolean)),
      previousStatus: previous?.status || ""
    },
    summary: status === "passed"
      ? "小说资料验收通过。"
      : status === "blocked"
        ? `验收阻断：${blocking.length + high.length} 个高风险问题需要先修复。`
        : `验收警告：${warnings.length} 个问题建议修复后复检。`,
    acceptanceChain: buildQualityGateAcceptanceChain(novel, issues, options)
  };
  novel.session.qualityGate = {
    ...result,
    history: [
      ...(Array.isArray(previous?.history) ? previous.history : previous ? [previous] : []),
      {
        id: result.id,
        scope: result.scope,
        status: result.status,
        checkedAt: result.checkedAt,
        issueCount: result.issueCount,
        blockingCount: result.blockingCount,
        warningCount: result.warningCount
      }
    ].slice(-20)
  };
  return result;
}

function runNovelQualityGateExecutor(novel, options = {}) {
  const mode = String(options.mode || options.action || "diagnose").trim() || "diagnose";
  const before = runNovelQualityGate(novel, options);
  const plan = buildQualityGateFixPlan(novel, before.issues || [], options);
  const result = {
    id: createId("quality_acceptance"),
    mode,
    startedAt: nowIso(),
    before,
    plan,
    applied: [],
    skipped: [],
    after: null,
    status: before.status,
    summary: before.summary
  };
  if (mode === "preview_fix" || mode === "preview") {
    result.status = plan.safeFixes.length ? "preview_ready" : before.status;
    result.summary = plan.safeFixes.length
      ? `已生成 ${plan.safeFixes.length} 个低风险修复预览；${plan.manualFixes.length} 个问题需要 Agent 或人工确认。`
      : "没有可自动预览的低风险修复，需由 Agent 检索证据后处理。";
    novel.session.qualityGate = { ...(novel.session.qualityGate || before), executor: compactQualityGateExecutor(result) };
    return result;
  }
  if (mode === "apply_safe_fixes" || mode === "apply") {
    for (const fix of plan.safeFixes) {
      try {
        const applied = applyQualityGateSafeFix(novel, fix);
        result.applied.push(applied);
      } catch (error) {
        result.skipped.push({
          fixId: fix.id,
          issueId: fix.issueId,
          reason: error?.message || String(error)
        });
      }
    }
    result.after = runNovelQualityGate(novel, options);
    result.status = result.after.status === "passed" ? "passed" : result.after.status;
    result.summary = `已应用 ${result.applied.length} 个低风险修复，跳过 ${result.skipped.length} 个，复检状态：${result.after.status}。`;
    recordEvent(novel, "quality_gate_executor_applied", {
      executorId: result.id,
      appliedCount: result.applied.length,
      skippedCount: result.skipped.length,
      afterStatus: result.after.status
    });
    novel.session.qualityGate = { ...(result.after || before), executor: compactQualityGateExecutor(result) };
    return result;
  }
  novel.session.qualityGate = { ...(novel.session.qualityGate || before), executor: compactQualityGateExecutor(result) };
  return result;
}

function buildQualityGateAcceptanceChain(novel, issues, options = {}) {
  const plan = buildQualityGateFixPlan(novel, issues, options);
  return {
    status: issues.some((issue) => issue.blocking) ? "blocked" : issues.length ? "warning" : "passed",
    steps: [
      { id: "diagnose", label: "诊断资料问题", status: "completed", issueCount: issues.length },
      { id: "preview_fix", label: "生成修复预览", status: plan.safeFixes.length ? "ready" : "manual_required", fixCount: plan.safeFixes.length },
      { id: "apply_safe_fixes", label: "应用低风险修复", status: "pending", fixCount: plan.safeFixes.length },
      { id: "recheck", label: "修复后复检", status: "pending", scopes: uniqueStrings(issues.map((issue) => issue.recheckScope || issue.scope || "all")) }
    ],
    safeFixCount: plan.safeFixes.length,
    manualFixCount: plan.manualFixes.length,
    blockedReasons: plan.manualFixes.filter((fix) => fix.risk !== "low").slice(0, 8).map((fix) => fix.reason)
  };
}

function buildQualityGateFixPlan(novel, issues, options = {}) {
  const safeFixes = [];
  const manualFixes = [];
  for (const issue of issues || []) {
    const fix = proposeQualityGateFix(novel, issue, options);
    if (!fix) continue;
    if (fix.autoApplicable && fix.risk === "low") safeFixes.push(fix);
    else manualFixes.push(fix);
  }
  return {
    id: createId("quality_fix_plan"),
    createdAt: nowIso(),
    safeFixes,
    manualFixes,
    diff: buildQualityGateFixPlanDiff(safeFixes),
    summary: `低风险可自动修复 ${safeFixes.length} 个；需要 Agent 检索或人工确认 ${manualFixes.length} 个。`
  };
}

function proposeQualityGateFix(novel, issue) {
  const code = String(issue?.code || "");
  const target = issue?.target || {};
  if (code === "memory.visibility_missing" && target.id) {
    return {
      id: createId("qfix"),
      issueId: issue.id,
      code,
      label: "补默认记忆可见性",
      risk: "low",
      autoApplicable: true,
      tool: "patchMemory",
      target,
      patch: { visibility: ["planner", "director"] },
      reason: "只补策划/导演可见，不让角色自动知道，风险较低。"
    };
  }
  if (code === "memory.evidence_missing" && target.id) {
    return {
      id: createId("qfix"),
      issueId: issue.id,
      code,
      label: "标记无证据记忆为暂行",
      risk: "low",
      autoApplicable: true,
      tool: "patchMemory",
      target,
      patch: { status: "tentative", evidence: ["quality_gate:missing_evidence_requires_review"] },
      reason: "缺证据的长期记忆不能继续当稳定事实，只降级为暂行并标记待复核。"
    };
  }
  if (code === "lorebook.keys_missing" && target.id) {
    const entry = normalizeLorebook(novel.lorebook).entries.find((item) => item.id === target.id);
    const key = String(target.name || entry?.name || "").trim();
    return {
      id: createId("qfix"),
      issueId: issue.id,
      code,
      label: "用条目名称补世界书主关键词",
      risk: key ? "low" : "medium",
      autoApplicable: Boolean(key),
      tool: "patchLorebook",
      target,
      patch: { keys: key ? [key] : [] },
      reason: key ? "世界书条目名称可作为最低限度主关键词，后续仍建议 Agent 优化二级关键词。" : "缺少可用名称，需人工确认关键词。"
    };
  }
  if (code === "prose.postwrite_missing" && target.id) {
    return {
      id: createId("qfix"),
      issueId: issue.id,
      code,
      label: "补跑正文写后回写",
      risk: "medium",
      autoApplicable: false,
      tool: "postwriteProse",
      target,
      patch: { proseId: target.id },
      reason: "写后回写会沉淀记忆，需要 Agent 读取正文证据并按权限执行。"
    };
  }
  return {
    id: createId("qfix"),
    issueId: issue.id,
    code,
    label: issue.title || code,
    risk: issue.blocking ? "high" : "medium",
    autoApplicable: false,
    tool: diagnosticRepairToolHint(issue),
    target,
    patch: {},
    reason: issue.suggestedFix || "需要 Agent 先检索证据后再修复。"
  };
}

function buildQualityGateFixPlanDiff(fixes) {
  return (fixes || []).map((fix) => ({
    fixId: fix.id,
    issueId: fix.issueId,
    target: fix.target,
    tool: fix.tool,
    before: "(见 issue target)",
    after: JSON.stringify(fix.patch || {}, null, 2),
    reason: fix.reason
  }));
}

function applyQualityGateSafeFix(novel, fix) {
  if (!fix?.autoApplicable || fix.risk !== "low") {
    throw new HttpError(403, "该修复不是低风险自动修复");
  }
  if (fix.tool === "patchMemory") {
    const id = String(fix.target?.id || "").trim();
    const memory = (novel.memory?.items || []).find((item) => item.id === id);
    if (!memory) throw new HttpError(404, "没有找到要修复的记忆");
    Object.assign(memory, applyAllowedObjectPatch(memory, fix.patch, new Set(["visibility", "status", "evidence"])), { updatedAt: nowIso() });
    novel.memory.updatedAt = nowIso();
    return { fixId: fix.id, issueId: fix.issueId, tool: fix.tool, targetId: id, status: "applied" };
  }
  if (fix.tool === "patchLorebook") {
    const id = String(fix.target?.id || "").trim();
    const entry = (novel.lorebook?.entries || []).find((item) => item.id === id);
    if (!entry) throw new HttpError(404, "没有找到要修复的世界书条目");
    if (Array.isArray(fix.patch?.keys) && fix.patch.keys.length) entry.keys = uniqueStrings(fix.patch.keys);
    entry.updatedAt = nowIso();
    novel.lorebook.updatedAt = nowIso();
    return { fixId: fix.id, issueId: fix.issueId, tool: fix.tool, targetId: id, status: "applied" };
  }
  throw new HttpError(400, `不支持自动应用该修复工具：${fix.tool}`);
}

function compactQualityGateExecutor(result) {
  return {
    id: result.id,
    mode: result.mode,
    status: result.status,
    summary: result.summary,
    startedAt: result.startedAt,
    beforeStatus: result.before?.status || "",
    afterStatus: result.after?.status || "",
    safeFixCount: result.plan?.safeFixes?.length || 0,
    manualFixCount: result.plan?.manualFixes?.length || 0,
    appliedCount: result.applied?.length || 0,
    skippedCount: result.skipped?.length || 0
  };
}

function evaluateNovelRagQuality(novel) {
  const lorebook = normalizeLorebook(novel.lorebook);
  const triggerLogs = Array.isArray(lorebook.triggerLogs) ? lorebook.triggerLogs : [];
  const enabledEntries = lorebook.entries.filter((entry) => entry.enabled !== false);
  const broadEntries = enabledEntries.filter((entry) => isLorebookEntryTriggerTooBroad(entry));
  const missingKeyEntries = enabledEntries.filter((entry) => entry.matchMode !== "always" && !(entry.keys || []).length);
  const visibilityMismatchLogs = triggerLogs.filter((log) => {
    const entry = enabledEntries.find((item) => item.id === log.entryId);
    return entry && log.characterId && !isLorebookEntryVisibleToTask(entry, log.task, log.characterId);
  });
  const characterLogs = triggerLogs.filter((log) => log.task === "character");
  const memoryItems = normalizeMemory(novel.memory).items;
  const memoryContractIssues = collectMemoryDiagnosticsIssues(novel);
  const activeMemory = memoryItems.filter((item) => item.status === "active");
  const revisionLearnings = normalizeRevisionLearnings(novel.planning?.revisionLearnings || []);
  const preferenceRisk = revisionLearnings.filter((item) => item.status === "confirmed" && (!item.evidence?.length || item.scope === "local"));
  const triggerPrecision = enabledEntries.length
    ? clampRatio((enabledEntries.length - broadEntries.length - missingKeyEntries.length) / enabledEntries.length)
    : 1;
  const visibilityLeakRate = characterLogs.length
    ? clampRatio(visibilityMismatchLogs.length / characterLogs.length)
    : 0;
  const memoryMiswriteRate = activeMemory.length
    ? clampRatio(memoryContractIssues.filter((issue) => issue.severity === "high").length / activeMemory.length)
    : 0;
  const preferenceMisabsorbRate = revisionLearnings.length
    ? clampRatio(preferenceRisk.length / revisionLearnings.length)
    : 0;
  const score = Math.round(100 * (
    triggerPrecision * 0.35
    + (1 - visibilityLeakRate) * 0.25
    + (1 - memoryMiswriteRate) * 0.25
    + (1 - preferenceMisabsorbRate) * 0.15
  ));
  return {
    id: createId("rag_quality"),
    checkedAt: nowIso(),
    score,
    status: score >= 90 ? "passed" : score >= 72 ? "warning" : "blocked",
    metrics: {
      lorebookTriggerPrecision: roundMetric(triggerPrecision),
      lorebookBroadTriggerRisk: roundMetric(enabledEntries.length ? broadEntries.length / enabledEntries.length : 0),
      roleVisibilityLeakRate: roundMetric(visibilityLeakRate),
      memoryMiswriteRate: roundMetric(memoryMiswriteRate),
      revisionPreferenceMisabsorbRate: roundMetric(preferenceMisabsorbRate)
    },
    counts: {
      enabledLorebookEntries: enabledEntries.length,
      triggerLogs: triggerLogs.length,
      broadEntries: broadEntries.length,
      missingKeyEntries: missingKeyEntries.length,
      visibilityMismatchLogs: visibilityMismatchLogs.length,
      activeMemory: activeMemory.length,
      memoryContractIssues: memoryContractIssues.length,
      revisionLearnings: revisionLearnings.length,
      preferenceRisk: preferenceRisk.length
    },
    findings: [
      ...broadEntries.slice(0, 8).map((entry) => ({ type: "lorebook_broad_trigger", severity: "medium", title: entry.name, suggestion: "补二级关键词、缩短扫描深度或调低优先级。" })),
      ...missingKeyEntries.slice(0, 8).map((entry) => ({ type: "lorebook_missing_keys", severity: "high", title: entry.name, suggestion: "非 alwaysOn 条目必须补触发词。" })),
      ...visibilityMismatchLogs.slice(0, 8).map((log) => ({ type: "visibility_leak", severity: "high", title: log.name || log.entryId, suggestion: "检查世界书 visibility、scope 和 ownerId。" })),
      ...memoryContractIssues.slice(0, 8).map((issue) => ({ type: "memory_contract", severity: issue.severity, title: issue.title, suggestion: issue.suggestedFix || "补证据、可见性和写入状态。" })),
      ...preferenceRisk.slice(0, 8).map((item) => ({ type: "preference_absorb_risk", severity: "medium", title: item.summary || item.id, suggestion: "局部改稿偏好不要直接确认为永久作者记忆。" }))
    ]
  };
}

async function runNovelRagBenchmark(novel, options = {}) {
  const cases = buildNovelRagBenchmarkCases(novel, options);
  const results = [];
  for (const testCase of cases) {
    results.push(await runNovelRagBenchmarkCase(novel, testCase, options));
  }
  const groups = groupBy(results, (item) => item.category);
  const metrics = {};
  for (const [category, items] of groups.entries()) {
    const passed = items.filter((item) => item.passed).length;
    metrics[category] = {
      passed,
      total: items.length,
      rate: roundMetric(items.length ? passed / items.length : 1)
    };
  }
  const passedCount = results.filter((item) => item.passed).length;
  const score = Math.round(100 * (results.length ? passedCount / results.length : 1));
  return {
    id: createId("rag_benchmark"),
    checkedAt: nowIso(),
    score,
    status: score >= 90 ? "passed" : score >= 72 ? "warning" : "blocked",
    counts: {
      passed: passedCount,
      failed: results.length - passedCount,
      total: results.length
    },
    metrics,
    cases: results,
    summary: `小说域 RAG 测试集通过 ${passedCount}/${results.length}。`
  };
}

function buildNovelRagBenchmarkCases(novel, options = {}) {
  const explicit = Array.isArray(options.cases) ? options.cases : [];
  const generated = [];
  const lorebook = normalizeLorebook(novel.lorebook);
  for (const entry of lorebook.entries.filter((item) => item.enabled !== false).slice(0, 16)) {
    const key = entry.keys?.[0] || entry.secondaryKeys?.[0] || entry.name;
    if (key) {
      generated.push({
        id: `lore_should_trigger:${entry.id}`,
        category: "lorebook_should_trigger",
        task: entry.visibility?.includes("character:*") ? "character" : "director",
        characterId: entry.visibility?.find((item) => String(item).startsWith("character:") && item !== "character:*")?.split(":")[1] || "",
        query: `${key} ${limitText(entry.content, 80)}`,
        expectedEntryId: entry.id
      });
    }
    if (entry.keys?.some((item) => String(item).trim().length <= 1)) {
      generated.push({
        id: `lore_should_not_trigger_short:${entry.id}`,
        category: "lorebook_should_not_trigger",
        task: "character",
        characterId: "",
        query: "普通日常对话，没有明确专有名词。",
        expectedEntryId: entry.id
      });
    }
  }
  const characters = novel.characters || [];
  for (const entry of lorebook.entries.filter((item) => item.visibility?.some((v) => String(v).startsWith("character:") && v !== "character:*")).slice(0, 12)) {
    const owner = entry.visibility.find((item) => String(item).startsWith("character:"))?.split(":")[1] || entry.ownerId || "";
    const other = characters.find((character) => character.id && character.id !== owner);
    if (owner && other) {
      generated.push({
        id: `visibility_no_leak:${entry.id}:${other.id}`,
        category: "visibility_no_leak",
        task: "character",
        characterId: other.id,
        query: `${entry.keys?.[0] || entry.name} ${entry.name}`,
        expectedEntryId: entry.id
      });
    }
  }
  for (const item of normalizeMemory(novel.memory).items.filter((memory) => memory.status === "active").slice(0, 16)) {
    generated.push({
      id: `memory_contract:${item.id}`,
      category: "memory_write_contract",
      memoryId: item.id
    });
  }
  for (const learning of normalizeRevisionLearnings(novel.planning?.revisionLearnings || []).slice(0, 16)) {
    generated.push({
      id: `preference_absorb:${learning.id}`,
      category: "preference_absorb_contract",
      learningId: learning.id
    });
  }
  return [...explicit, ...generated].slice(0, clampInteger(options.limit, 1, 120, 60));
}

async function runNovelRagBenchmarkCase(novel, testCase, options = {}) {
  const category = String(testCase.category || testCase.type || "");
  if (category === "lorebook_should_trigger" || category === "lorebook_should_not_trigger" || category === "visibility_no_leak") {
    const pack = await buildAgentContextPack(novel, testCase.task || "character", {
      store: options.store,
      characterId: testCase.characterId || "",
      queryText: testCase.query || ""
    });
    const hit = (pack.triggeredLore || []).some((entry) => entry.id === testCase.expectedEntryId);
    const shouldHit = category === "lorebook_should_trigger";
    const passed = category === "visibility_no_leak" ? !hit : shouldHit ? hit : !hit;
    return {
      id: testCase.id || createId("rag_case"),
      category,
      passed,
      query: testCase.query || "",
      expectedEntryId: testCase.expectedEntryId || "",
      actualEntryIds: (pack.triggeredLore || []).map((entry) => entry.id),
      reason: passed ? "触发结果符合预期。" : "世界书触发与测试集预期不一致。",
      evidence: {
        strategy: pack.strategy,
        characterId: pack.characterId,
        warnings: pack.warnings || []
      }
    };
  }
  if (category === "memory_write_contract") {
    const item = (novel.memory?.items || []).find((memory) => memory.id === testCase.memoryId);
    const itemIssues = item
      ? collectMemoryDiagnosticsIssues({ ...novel, memory: { ...novel.memory, items: [item] } }).filter((issue) => issue.target?.id === item.id)
      : [{ code: "memory.missing", message: "记忆不存在" }];
    const violations = itemIssues.map((issue) => ({
      code: issue.code,
      message: issue.message || issue.title || issue.code,
      severity: issue.severity
    }));
    const passed = Boolean(item) && violations.length === 0;
    return {
      id: testCase.id || createId("rag_case"),
      category,
      passed,
      memoryId: testCase.memoryId || "",
      reason: passed ? "记忆写入合同通过。" : violations.map((item) => item.message || item.code).join("；"),
      violations
    };
  }
  if (category === "preference_absorb_contract") {
    const learning = normalizeRevisionLearnings(novel.planning?.revisionLearnings || []).find((item) => item.id === testCase.learningId);
    const risky = Boolean(learning && learning.status === "confirmed" && (!learning.evidence?.length || learning.scope === "local"));
    return {
      id: testCase.id || createId("rag_case"),
      category,
      passed: Boolean(learning) && !risky,
      learningId: testCase.learningId || "",
      reason: !learning ? "改稿学习不存在。" : risky ? "局部或无证据改稿偏好被确认为长期偏好。" : "改稿偏好吸收状态合理。"
    };
  }
  return {
    id: testCase.id || createId("rag_case"),
    category: category || "unknown",
    passed: false,
    reason: "未知 RAG 测试类型。"
  };
}

function compactNovelRagBenchmark(benchmark) {
  return {
    id: benchmark.id,
    checkedAt: benchmark.checkedAt,
    score: benchmark.score,
    status: benchmark.status,
    counts: benchmark.counts,
    metrics: benchmark.metrics,
    summary: benchmark.summary,
    failedCases: (benchmark.cases || []).filter((item) => !item.passed).slice(0, 12)
  };
}

function groupBy(items, getKey) {
  const map = new Map();
  for (const item of items || []) {
    const key = getKey(item);
    const list = map.get(key) || [];
    list.push(item);
    map.set(key, list);
  }
  return map;
}

function isLorebookEntryTriggerTooBroad(entry) {
  if (!entry || entry.matchMode === "always") return false;
  const keys = [...(entry.keys || []), ...(entry.secondaryKeys || [])].map((item) => String(item || "").trim()).filter(Boolean);
  if (keys.some((key) => key.length <= 1)) return true;
  if ((entry.keys || []).length <= 1 && !(entry.secondaryKeys || []).length && Number(entry.priority || 0) >= 100) return true;
  return Boolean(matchLorebookEntry(entry, "").diagnostics?.some((item) => item.code === "keyword_too_short" || item.code === "regex_too_broad"));
}

function isLorebookEntryVisibleToTask(entry, task, characterId) {
  return isLorebookVisibleTo(entry, task, characterId);
}

function clampRatio(value) {
  const number = Number(value);
  if (!Number.isFinite(number)) return 0;
  return Math.min(1, Math.max(0, number));
}

function roundMetric(value) {
  return Math.round(clampRatio(value) * 1000) / 1000;
}

function enrichQualityGateIssue(issue) {
  const gateSeverity = issue.severity === "blocking" ? "blocking" : issue.severity === "high" ? "high" : issue.severity === "medium" ? "medium" : "low";
  return {
    ...issue,
    gateSeverity,
    blocking: ["blocking", "high"].includes(gateSeverity),
    canAutoFix: canAutoFixNovelDiagnostic(issue),
    suggestedFix: issue.suggestedFix || suggestNovelDiagnosticFix(issue),
    repairToolHint: diagnosticRepairToolHint(issue),
    recheckScope: issue.scope || "all"
  };
}

function canAutoFixNovelDiagnostic(issue) {
  const code = String(issue?.code || "");
  return /postwrite_missing|accepted_missing_turn_range|keys_missing|visibility_missing|evidence_missing/.test(code);
}

function suggestNovelDiagnosticFix(issue) {
  if (issue.scope === "memory") return "先检索证据，再用 patchMemory/upsertMemory 补证据、状态和可见性；不确定内容保持 tentative。";
  if (issue.scope === "lorebook") return "用 patchLorebook 修正关键词、二级关键词、优先级、可见性或互斥组，修复后重新运行世界书触发审查。";
  if (issue.scope === "roleplay") return "修正扮演配置或单角色重跑，再运行固定评审链复检。";
  if (issue.scope === "prose") return "编辑正文草稿或生成 Agent 修订稿，修复事实追踪后重新运行正文审查。";
  return "先让策划 Agent 检索相关档案和长内容引用，确认后再写入修正。";
}

function diagnosticRepairToolHint(issue) {
  const scope = String(issue?.scope || "");
  if (scope === "memory") return "patchMemory";
  if (scope === "lorebook") return "patchLorebook";
  if (scope === "characters") return "updateCharacterCard";
  if (scope === "roleplay") return "runRoleplayTurn/reviewLatestTurn";
  if (scope === "prose") return "patchProseDraft/reviewLatestTurn";
  if (scope === "archive") return "patchArchiveRecord/applyArchivePatch";
  return "inspectNovelDiagnostics";
}

function collectArchiveDiagnosticsIssues(novel) {
  const archives = novel.archives || {};
  const issues = [];
  if (!String(archives.premise || "").trim()) issues.push(createNovelDiagnostic("archive", "archive.premise_empty", "核心命题为空", "策划 Agent 应先和用户确认小说核心命题，再写入档案。", "medium", { field: "premise" }));
  if (!String(archives.background || "").trim()) issues.push(createNovelDiagnostic("archive", "archive.background_empty", "世界背景为空", "需要沉淀基本世界背景，否则导演和角色扮演会缺少共同前提。", "medium", { field: "background" }));
  for (const item of [...(archives.characters || []), ...(archives.scenes || []), ...(archives.clues || [])]) {
    if (!archiveRecordKey(item)) {
      issues.push(createNovelDiagnostic("archive", "archive.record_missing_key", "档案条目缺少稳定主键", "角色、场景和线索档案必须有 name/title/key，避免后续浅合并污染。", "high", item));
    }
  }
  return issues;
}

function collectArchiveDuplicateDiagnosticsIssues(novel) {
  const archives = novel.archives || {};
  const issues = [];
  for (const collection of ["characters", "scenes", "clues"]) {
    const map = new Map();
    for (const item of archives[collection] || []) {
      const key = archiveRecordKey(item);
      if (!key) continue;
      const list = map.get(key) || [];
      list.push(item);
      map.set(key, list);
    }
    for (const [key, list] of map.entries()) {
      if (list.length <= 1) continue;
      issues.push(createNovelDiagnostic("archive", "archive.record_duplicate_key", `档案条目主键重复：${collection}/${key}`, "同一档案集合里出现重复主键会让浅合并和检索证据不稳定，应先合并或改名。", "high", {
        collection,
        key,
        count: list.length
      }));
    }
  }
  return issues;
}

function collectMemoryDiagnosticsIssues(novel) {
  return (novel.memory?.items || []).flatMap((item) => {
    const issues = [];
    if (!item.evidence?.length) issues.push(createNovelDiagnostic("memory", "memory.evidence_missing", `记忆缺少证据：${item.subject || item.id}`, "长期记忆必须能追溯到用户输入、正文、扮演记录或工具证据。", "high", { id: item.id }));
    if (!item.visibility?.length) issues.push(createNovelDiagnostic("memory", "memory.visibility_missing", `记忆缺少可见性：${item.subject || item.id}`, "记忆必须声明 planner/director/character 等可见对象，避免角色知道不该知道的信息。", "high", { id: item.id }));
    if (String(item.value || "").length > 1800) issues.push(createNovelDiagnostic("memory", "memory.value_too_large", `记忆过长：${item.subject || item.id}`, "应拆成单条稳定事实，正文原文和大段摘要放入 RAG 或长内容引用。", "medium", { id: item.id }));
    for (const violation of collectMemoryItemWriteViolations(normalizeMemoryItem(item))) {
      const severity = ["memory.stable_fact_unconfirmed", "memory.layer_visibility_mismatch", "memory.author_memory_weak_evidence"].includes(violation.code) ? "high" : "medium";
      issues.push(createNovelDiagnostic("memory", violation.code, `记忆写入合同风险：${item.subject || item.id}`, violation.message, severity, { id: item.id, field: item.field, layer: item.layer }));
    }
    return issues;
  });
}

function collectMemoryFactConflictDiagnosticsIssues(novel) {
  const activeItems = (novel.memory?.items || []).filter((item) => !["outdated", "resolved"].includes(item.status));
  const map = new Map();
  for (const item of activeItems) {
    const key = `${normalizeDiagnosticKey(item.scope)}:${normalizeDiagnosticKey(item.ownerId)}:${normalizeDiagnosticKey(item.subject)}:${normalizeDiagnosticKey(item.field)}`;
    if (!key.replace(/[:]/g, "")) continue;
    const list = map.get(key) || [];
    list.push(item);
    map.set(key, list);
  }
  const issues = [];
  for (const [key, list] of map.entries()) {
    const values = uniqueStrings(list.map((item) => item.value));
    if (values.length <= 1) continue;
    issues.push(createNovelDiagnostic("memory", "memory.fact_conflict", `长期记忆事实冲突：${list[0].subject || key}/${list[0].field || ""}`, "同一 subject+field 存在多个未退役值，会让策划、导演或角色召回互相矛盾的信息。需要用 patchMemory/retireMemory 明确有效版本。", "high", {
      key,
      memoryIds: list.map((item) => item.id),
      values: values.slice(0, 6)
    }));
  }
  return issues;
}

function collectLorebookDiagnosticsIssues(novel) {
  const entries = normalizeLorebook(novel.lorebook).entries;
  const issues = [];
  const keyMap = new Map();
  const characterIds = new Set((novel.characters || []).map((item) => item.id).filter(Boolean));
  const keywordEntries = [];
  for (const entry of entries) {
    if (entry.enabled !== false && entry.matchMode !== "always" && (!entry.keys || entry.keys.length === 0)) {
      issues.push(createNovelDiagnostic("lorebook", "lorebook.keys_missing", `世界书缺少触发词：${entry.name}`, "非 alwaysOn 条目必须有关键词，才能接近酒馆式 World Info 触发。", "high", { id: entry.id, name: entry.name }));
    }
    if (entry.scope === "character" && entry.ownerId && !characterIds.has(entry.ownerId)) {
      issues.push(createNovelDiagnostic("lorebook", "lorebook.owner_character_missing", `世界书绑定了不存在的角色：${entry.name}`, "角色私有世界书必须绑定现有角色卡，否则会被错误召回或完全不可见。", "high", { id: entry.id, ownerId: entry.ownerId, name: entry.name }));
    }
    for (const diagnostic of diagnoseLorebookEntryTriggerDesign(entry).slice(0, 6)) {
      issues.push(createNovelDiagnostic("lorebook", diagnostic.code, `世界书触发设计风险：${entry.name}`, diagnostic.message, diagnostic.severity, {
        id: entry.id,
        name: entry.name,
        key: diagnostic.key,
        details: diagnostic.details
      }));
    }
    for (const key of entry.keys || []) {
      const normalized = String(key || "").trim().toLowerCase();
      if (!normalized) continue;
      const list = keyMap.get(normalized) || [];
      list.push(entry);
      keyMap.set(normalized, list);
      keywordEntries.push({ key: normalized, rawKey: String(key || "").trim(), entry });
    }
  }
  for (const [key, list] of keyMap.entries()) {
    if (list.length > 1) {
      issues.push(createNovelDiagnostic("lorebook", "lorebook.keyword_conflict", `世界书关键词重复：${key}`, `同一关键词命中 ${list.length} 个条目，需要检查优先级、二级关键词或合并边界。`, "medium", { key, entryIds: list.map((item) => item.id) }));
    }
  }
  const shadowedPairs = [];
  for (let left = 0; left < keywordEntries.length; left += 1) {
    for (let right = left + 1; right < keywordEntries.length; right += 1) {
      const a = keywordEntries[left];
      const b = keywordEntries[right];
      if (a.entry.id === b.entry.id || a.key === b.key) continue;
      const shorter = a.key.length <= b.key.length ? a : b;
      const longer = shorter === a ? b : a;
      if (shorter.key.length < 2 || !longer.key.includes(shorter.key)) continue;
      shadowedPairs.push({
        key: shorter.rawKey,
        longerKey: longer.rawKey,
        entryIds: [shorter.entry.id, longer.entry.id],
        entryNames: [shorter.entry.name, longer.entry.name]
      });
    }
  }
  for (const pair of shadowedPairs.slice(0, 12)) {
    issues.push(createNovelDiagnostic("lorebook", "lorebook.keyword_shadowing", `世界书关键词可能互相遮蔽：${pair.key} / ${pair.longerKey}`, "短关键词会比长关键词更容易触发，可能导致世界书条目过宽召回；建议补二级关键词、提高优先级或拆分边界。", "low", pair));
  }
  return issues;
}

function diagnoseLorebookEntryTriggerDesign(entry) {
  if (!entry || entry.matchMode === "always") return [];
  if (entry.matchMode === "regex") {
    return uniqueLorebookDiagnostics((entry.keys || []).flatMap((key) => diagnoseLorebookRegexKeyword(key))).map((item) => ({
      code: item.code,
      severity: item.severity,
      key: item.key,
      message: item.message,
      details: item.details
    }));
  }
  const keys = [...(entry.keys || []), ...(entry.secondaryKeys || [])]
    .map((key) => String(key || "").trim())
    .filter(Boolean);
  const diagnostics = [];
  for (const key of keys) {
    const normalized = normalizeLorebookMatchText(key, entry.caseSensitive);
    if (normalized.length <= 1) {
      diagnostics.push(createLorebookMatchDiagnostic("keyword_too_short", `触发词“${key}”过短，容易让世界书过宽触发。`, "medium", key));
    }
    if (!isCjkKeyword(normalized) && normalized.length <= 3) {
      diagnostics.push(createLorebookMatchDiagnostic("keyword_boundary_weak", `英文或符号短触发词“${key}”需要更明确边界或二级关键词。`, "low", key));
    }
  }
  diagnostics.push(...diagnoseKeywordShadowing(keys.map((key) => ({ raw: key, normalized: normalizeLorebookMatchText(key, entry.caseSensitive) }))));
  return uniqueLorebookDiagnostics(diagnostics).map((item) => ({
    code: item.code,
    severity: item.severity,
    key: item.key,
    message: item.message,
    details: item.details
  }));
}

function collectCharacterDiagnosticsIssues(novel) {
  return (novel.characters || []).flatMap((character) => {
    const issues = [];
    if (!String(character.name || "").trim()) issues.push(createNovelDiagnostic("characters", "character.name_missing", "存在未命名角色卡", "角色卡必须有稳定名称，否则扮演配置和记忆可见性无法绑定。", "high", { id: character.id }));
    if (character.roleType === "major" && !String(character.model || "").trim() && !String(character.providerId || "").trim()) {
      issues.push(createNovelDiagnostic("characters", "character.major_model_missing", `主要角色缺少独立模型：${character.name}`, "主要角色应能单独选择提供商和模型，避免退化成次要角色群。", "medium", { id: character.id, name: character.name }));
    }
    return issues;
  });
}

function collectCharacterAgeConflictIssues(novel) {
  const records = collectCharacterDiagnosticRecords(novel);
  const byName = groupDiagnosticRecordsByName(records);
  const issues = [];
  for (const [nameKey, list] of byName.entries()) {
    const facts = [];
    for (const record of list) {
      for (const age of record.ages) {
        facts.push({ age, sourceType: record.sourceType, sourceId: record.sourceId, title: record.title });
      }
    }
    const uniqueAges = uniqueNumbers(facts.map((item) => item.age));
    if (uniqueAges.length <= 1) continue;
    const displayName = list.find((item) => item.name)?.name || nameKey;
    issues.push(createNovelDiagnostic("characters", "character.age_conflict", `角色年龄冲突：${displayName}`, `同一角色在资料中出现了 ${uniqueAges.join("、")} 岁等不同年龄。策划 Agent 应先检索证据并确认哪条设定有效，再更新角色卡、档案或世界书。`, "high", {
      name: displayName,
      ages: uniqueAges,
      facts
    }));
  }
  return issues;
}

function collectCharacterAddressingConflictIssues(novel) {
  const records = collectCharacterDiagnosticRecords(novel);
  const aliasMap = new Map();
  for (const record of records) {
    const nameKey = normalizeDiagnosticKey(record.name);
    for (const alias of record.addressing) {
      const aliasKey = normalizeDiagnosticKey(alias);
      if (!aliasKey || aliasKey === nameKey || aliasKey.length < 2) continue;
      const list = aliasMap.get(aliasKey) || [];
      list.push(record);
      aliasMap.set(aliasKey, list);
    }
  }
  const issues = [];
  for (const [aliasKey, list] of aliasMap.entries()) {
    const names = uniqueStrings(list.map((item) => item.name)).filter(Boolean);
    if (names.length <= 1) continue;
    issues.push(createNovelDiagnostic("characters", "character.address_alias_conflict", `角色称呼/别名冲突：${aliasKey}`, `同一个称呼或别名同时指向 ${names.join("、")}。角色扮演和世界书触发会因此串线，需要明确这是共用称号、误写，还是应拆成不同关键词。`, "medium", {
      alias: aliasKey,
      names,
      sources: list.map((item) => ({ sourceType: item.sourceType, sourceId: item.sourceId, title: item.title }))
    }));
  }
  return issues;
}

function collectLorebookArchiveCoverageIssues(novel) {
  const entries = normalizeLorebook(novel.lorebook).entries;
  const knownAges = collectKnownCharacterAgeFacts(novel, { includeLorebook: false });
  const issues = [];
  for (const entry of entries) {
    const entryText = [entry.name, ...(entry.keys || []), ...(entry.secondaryKeys || []), entry.content].join("\n");
    const entryAges = uniqueNumbers(extractDiagnosticAges(entryText));
    if (entryAges.length === 0) continue;
    for (const [nameKey, facts] of knownAges.entries()) {
      const displayName = facts[0]?.name || nameKey;
      if (!entryText.includes(displayName)) continue;
      const knownValues = uniqueNumbers(facts.map((item) => item.age));
      const conflicts = entryAges.filter((age) => !knownValues.includes(age));
      if (conflicts.length === 0) continue;
      issues.push(createNovelDiagnostic("lorebook", "lorebook.archive_fact_conflict", `世界书与角色档案事实冲突：${entry.name}`, `世界书条目提到 ${displayName} 的年龄为 ${entryAges.join("、")} 岁，但角色卡/档案中记录为 ${knownValues.join("、")} 岁。需要确认世界书是否覆盖旧设定，还是应修正。`, "high", {
        entryId: entry.id,
        entryName: entry.name,
        characterName: displayName,
        lorebookAges: entryAges,
        archiveAges: knownValues
      }));
    }
  }
  return issues;
}

function collectRoleplayConfigDiagnosticsIssues(novel) {
  const config = normalizeDefaultRoleplayConfigRecord(novel.planning?.defaultRoleplayConfig)?.config || {};
  const draftConfigs = (novel.planning?.roleplayDrafts || []).map((draft) => normalizeRoleplayDraftRecord(draft)?.config).filter(Boolean);
  const configs = [config, ...draftConfigs].filter((item) => item && Object.keys(item).length > 0).slice(0, 8);
  return configs.flatMap((item) => collectRoleplayConfigDiagnosticsFromConfig(novel, item));
}

function collectRoleplayConfigSchemaDiagnosticsIssues(novel) {
  const records = [
    normalizeDefaultRoleplayConfigRecord(novel.planning?.defaultRoleplayConfig),
    ...(novel.planning?.roleplayDrafts || []).map(normalizeRoleplayDraftRecord)
  ].filter((item) => item?.config);
  const schema = {
    type: "object",
    required: ["scenario"],
    properties: {
      scenario: {
        type: "object",
        properties: {
          background: { type: "string" },
          time: { type: "string" },
          place: { type: "string" },
          plotDirection: { type: "string" },
          tone: { type: "string" }
        }
      },
      aiRoles: { type: "object" },
      characters: { type: "array", items: { type: "object", required: ["name", "roleType"] } }
    }
  };
  const issues = [];
  for (const record of records.slice(0, 12)) {
    const errors = validateJsonSchemaSubset(record.config, schema, "$").slice(0, 8);
    if (errors.length > 0) {
      issues.push(createNovelDiagnostic("roleplay", "roleplay_config.schema_invalid", `扮演配置结构不完整：${record.id || "未命名配置"}`, "扮演配置必须至少包含 scenario，并且角色项需要 name/roleType；否则 Agent 启动扮演时会丢失导演或角色上下文。", "high", {
        id: record.id,
        errors
      }));
    }
  }
  return issues;
}

function collectRoleplayConfigDiagnosticsFromConfig(novel, config) {
  if (!config) return [];
  const characterNames = new Set((novel.characters || []).map((item) => String(item.name || "").trim()).filter(Boolean));
  const names = [
    ...(config.majorCharacters || config.characters || []).map((item) => item.name || item.characterName),
    ...(config.minorCharacters || []).map((item) => item.name || item.characterName)
  ].map((item) => String(item || "").trim()).filter(Boolean);
  return names
    .filter((name) => !characterNames.has(name))
    .map((name) => createNovelDiagnostic("roleplay", "roleplay_config.character_missing", `扮演配置引用了不存在的角色：${name}`, "保存或运行扮演配置前应先创建角色卡，或从配置中移除该角色。", "high", { name }));
}

function collectRoleplayReferenceDiagnosticsIssues(novel) {
  const characterIds = new Set((novel.characters || []).map((item) => item.id).filter(Boolean));
  const knownNames = new Set([
    ...(novel.characters || []).map((item) => item.name),
    ...(novel.archives?.characters || []).map((item) => item.name || item.title || item.key)
  ].map((item) => String(item || "").trim()).filter(Boolean));
  const issues = [];
  for (const turn of novel.session?.turns || []) {
    for (const performance of turn.performances || []) {
      const characterId = String(performance.characterId || "").trim();
      const name = String(performance.characterName || performance.name || performance.role || "").trim();
      if (characterId && !characterIds.has(characterId)) {
        issues.push(createNovelDiagnostic("roleplay", "roleplay.turn_character_id_missing", `扮演轮次引用了不存在的角色 ID：${characterId}`, "扮演记录需要能追溯到角色卡，否则单角色重跑和角色一致性审查无法定位对象。", "high", { turnId: turn.id, characterId, name }));
      } else if (name && !knownNames.has(name)) {
        issues.push(createNovelDiagnostic("roleplay", "roleplay.turn_character_name_missing", `扮演轮次引用了不存在的角色名：${name}`, "扮演输出里的角色名没有对应角色卡或档案，可能是临时 NPC 未沉淀，也可能是名称写错。", "medium", { turnId: turn.id, name }));
      }
    }
  }
  for (const beat of novel.session?.prewritePlan?.characterBeats || []) {
    const id = String(beat.characterId || beat.id || "").trim();
    const name = String(beat.name || "").trim();
    if (id && !characterIds.has(id)) {
      issues.push(createNovelDiagnostic("roleplay", "roleplay.prewrite_character_missing", `写前定位引用了不存在的角色 ID：${id}`, "章节写前定位属于导演统筹输入，引用失效会让后续扮演约束错位。", "high", { characterId: id, name }));
    } else if (name && !knownNames.has(name)) {
      issues.push(createNovelDiagnostic("roleplay", "roleplay.prewrite_character_name_missing", `写前定位引用了不存在的角色名：${name}`, "需要先创建角色卡/档案，或修正写前定位中的角色名称。", "medium", { characterId: id, name }));
    }
  }
  return issues.slice(0, 40);
}

function collectProseDiagnosticsIssues(novel) {
  const accepted = (novel.session?.proseParts || []).filter((part) => part.status === "accepted");
  const issues = [];
  const knownAges = collectKnownCharacterAgeFacts(novel, { includeLorebook: false });
  for (const part of accepted) {
    const hasTurnRange = Array.isArray(part.turnRange)
      ? part.turnRange.length > 0
      : Boolean(part.turnRange?.start || part.turnRange?.end);
    if (!hasTurnRange) {
      issues.push(createNovelDiagnostic("prose", "prose.accepted_missing_turn_range", `已采纳正文缺少扮演来源：${part.id}`, "正文版本应保留扮演轮次来源，方便一致性审查和单角色重跑追溯。", "medium", { id: part.id }));
    }
    if (!part.review && !part.memoryInjection) {
      issues.push(createNovelDiagnostic("prose", "prose.fact_trace_missing", `已采纳正文缺少事实追踪：${part.id}`, "已采纳正文最好保留审查记录或上下文注入摘要，方便后续追踪章节事实与档案是否一致。", "medium", { id: part.id }));
    }
    const text = String(part.text || "");
    for (const [nameKey, facts] of knownAges.entries()) {
      const displayName = facts[0]?.name || nameKey;
      if (!displayName || !text.includes(displayName)) continue;
      const proseAges = extractAgesNearName(text, displayName);
      if (proseAges.length === 0) continue;
      const knownValues = uniqueNumbers(facts.map((item) => item.age));
      const conflicts = proseAges.filter((age) => !knownValues.includes(age));
      if (conflicts.length === 0) continue;
      issues.push(createNovelDiagnostic("prose", "prose.fact_age_conflict", `正文事实与档案冲突：${displayName}`, `已采纳正文中 ${displayName} 的年龄为 ${proseAges.join("、")} 岁，但角色卡/档案记录为 ${knownValues.join("、")} 岁。需要确认正文是否已经改设定，或补充档案修订。`, "high", {
        proseId: part.id,
        characterName: displayName,
        proseAges,
        archiveAges: knownValues
      }));
    }
  }
  return issues;
}

function collectRoleplayVisibilityLeakIssues(novel) {
  const issues = [];
  for (const turn of novel.session?.turns || []) {
    const guideText = JSON.stringify(turn.guide?.parsed || turn.guide?.text || "");
    for (const performance of turn.performances || []) {
      if (performance.kind !== "major") continue;
      const character = novel.characters.find((item) => item.id === performance.characterId);
      const text = [
        performance.text || "",
        JSON.stringify(performance.parsed || {})
      ].join("\n");
      if (/forbidden_moves|director_note|available_facts/.test(text)) {
        issues.push(createNovelDiagnostic("roleplay", "roleplay.visibility.director_meta_leak", `角色输出疑似泄漏导演元信息：${performance.name}`, "角色扮演输出里出现导演字段名或元信息，说明角色 AI 可能在复述导演配置而不是扮演角色。", "medium", {
          turnId: turn.id,
          characterId: performance.characterId,
          name: performance.name
        }));
      }
      const otherCharacters = (novel.characters || []).filter((item) => item.id !== performance.characterId && item.roleType === "major");
      for (const other of otherCharacters) {
        const otherInnerPattern = new RegExp(`${escapeRegExp(other.name)}[^。！？\\n]{0,24}(想|心想|内心|打算|真正|其实)`);
        if (other.name && otherInnerPattern.test(text)) {
          issues.push(createNovelDiagnostic("roleplay", "roleplay.visibility.other_inner_thought", `角色可能知道了其他主要角色内心：${performance.name}`, "单角色扮演只能使用可观察信息，不能替其他主要角色解释内心或隐藏动机。", "high", {
            turnId: turn.id,
            characterId: performance.characterId,
            otherCharacterId: other.id
          }));
        }
      }
      if (character && guideText && text.includes(limitText(guideText, 80))) {
        issues.push(createNovelDiagnostic("roleplay", "roleplay.visibility.guide_copy", `角色输出照抄导演引导：${performance.name}`, "角色应该按导演引导自主反应，而不是把导演 JSON 或说明文本复述出来。", "medium", {
          turnId: turn.id,
          characterId: performance.characterId
        }));
      }
    }
  }
  return issues.slice(0, 40);
}

function collectDirectorOvercontrolDiagnosticsIssues(novel) {
  const issues = [];
  for (const turn of novel.session?.turns || []) {
    const audit = normalizeDirectorControlAudit(turn.directorControlAudit || auditDirectorControl(turn.guide, novel.session?.prewritePlan));
    if (audit.status === "ok") continue;
    issues.push(createNovelDiagnostic("roleplay", "roleplay.director_overcontrol", `导演引导可能过度控制：第 ${turn.index} 轮`, audit.findings.join("；") || "导演引导硬性约束偏多，可能破坏角色 AI 自主扮演。", audit.status === "overcontrolled" ? "high" : "medium", {
      turnId: turn.id,
      score: audit.score,
      findings: audit.findings
    }));
  }
  return issues;
}

function collectLorebookTriggerAuditIssues(novel) {
  const issues = [];
  for (const turn of novel.session?.turns || []) {
    const audit = normalizeContextAudit(turn.contextAudit);
    for (const character of novel.characters || []) {
      if (character.roleType !== "major") continue;
      const characterAudit = audit.characters?.[character.id];
      if (!characterAudit) continue;
      if (characterAudit.strategy !== "tavern_context") {
        issues.push(createNovelDiagnostic("roleplay", "roleplay.context.strategy_mismatch", `角色上下文策略不是酒馆式触发：${character.name}`, "主要角色扮演应使用 tavern_context，优先角色卡、触发世界书和角色可见记忆。", "medium", {
          turnId: turn.id,
          characterId: character.id,
          strategy: characterAudit.strategy
        }));
      }
      const hasCharacterLore = normalizeLorebook(novel.lorebook).entries.some((entry) => {
        if (!entry.enabled) return false;
        return isLorebookVisibleTo(entry, "character", character.id);
      });
      if (hasCharacterLore && characterAudit.triggeredLoreCount === 0) {
        issues.push(createNovelDiagnostic("lorebook", "lorebook.trigger.none_for_character", `角色没有触发任何可见世界书：${character.name}`, "如果该角色有可见世界书却长期不触发，需要检查关键词、扫描深度和角色卡文本是否能命中。", "low", {
          turnId: turn.id,
          characterId: character.id
        }));
      }
      for (const lore of characterAudit.triggeredLore || []) {
        const visibility = lore.visibility || [];
        if (!visibility.includes("character:*") && !visibility.includes(`character:${character.id}`) && !visibility.includes("planner") && !visibility.includes("director")) {
          issues.push(createNovelDiagnostic("lorebook", "lorebook.trigger.visibility_mismatch", `世界书触发可见性异常：${lore.name || lore.id}`, "角色上下文审计中出现不适配该角色可见性的世界书条目，应检查 visibility 过滤。", "high", {
            turnId: turn.id,
            characterId: character.id,
            lorebookId: lore.id
          }));
        }
      }
    }
  }
  return issues.slice(0, 40);
}

function collectProseScenePollutionIssues(novel) {
  const plan = normalizePrewritePlan(novel.session?.prewritePlan);
  if (!plan) return [];
  const issues = [];
  const backgroundTerms = uniqueStrings(plan.backgroundOnly || [])
    .map((item) => String(item || "").trim())
    .filter((item) => item.length >= 4)
    .slice(0, 12);
  const sceneAnchors = uniqueStrings(plan.foregroundAnchors || plan.sceneFocus || [])
    .map((item) => String(item || "").trim())
    .filter((item) => item.length >= 2)
    .slice(0, 12);
  for (const part of novel.session?.proseParts || []) {
    if (part.status === "discarded") continue;
    const head = String(part.text || "").slice(0, 1200);
    for (const term of backgroundTerms) {
      if (head.includes(term)) {
        issues.push(createNovelDiagnostic("prose", "prose.background_only_leaked", `正文疑似写出了后台信息：${part.id}`, "写前定位里的“后台知道但不出句”不应直接进入正文或角色认知，除非用户明确要求揭示。", part.status === "accepted" ? "high" : "medium", {
          proseId: part.id,
          term
        }));
      }
    }
    const anchorHits = sceneAnchors.filter((term) => head.includes(term));
    if (sceneAnchors.length >= 4 && anchorHits.length >= Math.min(6, sceneAnchors.length)) {
      issues.push(createNovelDiagnostic("prose", "prose.scene_anchor_overstuffed", `正文开头场景锚点过密：${part.id}`, "写前定位的场景锚点应服务行文，不应在正文开头机械堆设定。", "low", {
        proseId: part.id,
        anchorHits
      }));
    }
  }
  return issues.slice(0, 30);
}

function collectPostwriteMissingIssues(novel) {
  return (novel.session?.proseParts || [])
    .filter((part) => part.status === "accepted")
    .filter((part) => normalizePostwriteBack(part.postwriteBack).status !== "completed")
    .map((part) => createNovelDiagnostic("prose", "prose.postwrite_missing", `已采纳正文缺少写后回写：${part.id}`, "已采纳正文应执行写后回写，把坐实事实、关系变化、线索状态和审查记录沉淀到长期记忆或审计层。", "medium", {
      proseId: part.id,
      workflowId: part.workflowId || ""
    }));
}

function collectCharacterDiagnosticRecords(novel) {
  const records = [];
  for (const character of novel.characters || []) {
    records.push(buildCharacterDiagnosticRecord("character_card", character.id, character.name, character));
  }
  for (const item of novel.archives?.characters || []) {
    const key = item.name || item.title || item.key || "";
    records.push(buildCharacterDiagnosticRecord("archive_character", key, key, item));
  }
  return records.filter((record) => record.name);
}

function buildCharacterDiagnosticRecord(sourceType, sourceId, name, raw) {
  const text = collectDiagnosticText(raw, [
    "name",
    "title",
    "key",
    "description",
    "personality",
    "scenario",
    "systemPrompt",
    "postHistoryInstructions",
    "lorebook",
    "summary",
    "notes",
    "fixedFacts",
    "background"
  ]);
  return {
    sourceType,
    sourceId: String(sourceId || ""),
    name: String(name || "").trim(),
    title: `${sourceType}:${String(name || sourceId || "").trim()}`,
    ages: uniqueNumbers([
      ...extractStructuredDiagnosticAges(raw),
      ...extractDiagnosticAges(text)
    ]),
    addressing: extractDiagnosticAddressing(raw, text)
  };
}

function groupDiagnosticRecordsByName(records) {
  const map = new Map();
  for (const record of records) {
    const key = normalizeDiagnosticKey(record.name);
    if (!key) continue;
    const list = map.get(key) || [];
    list.push(record);
    map.set(key, list);
  }
  return map;
}

function collectKnownCharacterAgeFacts(novel, options = {}) {
  const records = collectCharacterDiagnosticRecords(novel);
  if (options.includeLorebook) {
    for (const entry of normalizeLorebook(novel.lorebook).entries) {
      records.push(buildCharacterDiagnosticRecord("lorebook", entry.id, entry.name, {
        name: entry.name,
        content: entry.content,
        keys: entry.keys,
        secondaryKeys: entry.secondaryKeys
      }));
    }
  }
  const map = new Map();
  for (const record of records) {
    const nameKey = normalizeDiagnosticKey(record.name);
    if (!nameKey || record.ages.length === 0) continue;
    const list = map.get(nameKey) || [];
    for (const age of record.ages) {
      list.push({ age, name: record.name, sourceType: record.sourceType, sourceId: record.sourceId });
    }
    map.set(nameKey, list);
  }
  return map;
}

function collectDiagnosticText(source, fields) {
  const parts = [];
  const data = source && typeof source === "object" ? source : {};
  for (const field of fields) {
    const value = data[field];
    if (Array.isArray(value)) {
      parts.push(value.map((item) => typeof item === "object" ? JSON.stringify(item) : String(item || "")).join("\n"));
    } else if (value && typeof value === "object") {
      parts.push(JSON.stringify(value));
    } else {
      parts.push(String(value || ""));
    }
  }
  return parts.filter(Boolean).join("\n");
}

function extractStructuredDiagnosticAges(source) {
  const data = source && typeof source === "object" ? source : {};
  const values = [];
  for (const key of ["age", "年龄"]) {
    if (!Object.hasOwn(data, key)) continue;
    values.push(data[key]);
  }
  return uniqueNumbers(values.flatMap((value) => {
    if (typeof value === "number") return [value];
    return extractDiagnosticAges(String(value || ""));
  }));
}

function extractDiagnosticAges(text) {
  const value = String(text || "");
  const ages = [];
  for (const match of value.matchAll(/(?:^|[^\d])([1-9]\d{0,2})\s*岁/g)) {
    const age = Number(match[1]);
    if (age >= 1 && age <= 120) ages.push(age);
  }
  for (const match of value.matchAll(/\b([1-9]\d{0,2})\s*(?:years?\s*old|yo)\b/gi)) {
    const age = Number(match[1]);
    if (age >= 1 && age <= 120) ages.push(age);
  }
  return uniqueNumbers(ages);
}

function extractAgesNearName(text, name) {
  const value = String(text || "");
  const escaped = escapeRegExp(String(name || ""));
  if (!escaped) return [];
  const ages = [];
  const forward = new RegExp(`${escaped}[^。！？\\n]{0,40}?([1-9]\\d{0,2})\\s*岁`, "g");
  const backward = new RegExp(`([1-9]\\d{0,2})\\s*岁[^。！？\\n]{0,40}?${escaped}`, "g");
  for (const match of value.matchAll(forward)) ages.push(Number(match[1]));
  for (const match of value.matchAll(backward)) ages.push(Number(match[1]));
  return uniqueNumbers(ages.filter((age) => age >= 1 && age <= 120));
}

function extractDiagnosticAddressing(source, text) {
  const data = source && typeof source === "object" ? source : {};
  const values = [];
  for (const key of ["alias", "aliases", "nickname", "nicknames", "title", "titles", "addressing", "appellations", "calls", "knownAs", "称呼", "别名", "绰号", "外号", "代号", "称谓"]) {
    if (Object.hasOwn(data, key)) values.push(data[key]);
  }
  for (const match of String(text || "").matchAll(/(?:称呼|别名|绰号|外号|代号|称谓)[：:]\s*([^。\n；;]+)/g)) {
    values.push(match[1]);
  }
  return uniqueStrings(values.flatMap((value) => normalizeDiagnosticAliasList(value))).slice(0, 30);
}

function normalizeDiagnosticAliasList(value) {
  if (Array.isArray(value)) return value.flatMap(normalizeDiagnosticAliasList);
  if (value && typeof value === "object") return normalizeDiagnosticAliasList(Object.values(value));
  return String(value || "")
    .split(/[，,、/；;\n]/)
    .map((item) => item.replace(/^["'“”‘’\s]+|["'“”‘’\s]+$/g, "").trim())
    .filter(Boolean);
}

function normalizeDiagnosticKey(value) {
  return String(value || "").trim().toLowerCase().replace(/\s+/g, "");
}

function uniqueNumbers(values) {
  return [...new Set((values || []).map(Number).filter(Number.isFinite))].sort((a, b) => a - b);
}

function escapeRegExp(value) {
  return String(value || "").replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function createNovelDiagnostic(scope, code, title, message, severity = "medium", target = null) {
  return {
    scope,
    code,
    title,
    message,
    severity,
    target,
    suggestedFix: novelDiagnosticSuggestedFix(code)
  };
}

function novelDiagnosticSuggestedFix(code) {
  if (code.startsWith("memory.")) return "使用 search/upsertMemory/patchMemory，并保留 evidence 与 visibility。";
  if (code.startsWith("lorebook.")) return "使用 search、patchLorebook 或 upsertLorebook 修正关键词、优先级和条目边界。";
  if (code.startsWith("character.")) return "使用 updateCharacterCard 或角色卡页面补齐稳定扮演输入。";
  if (code.startsWith("roleplay_config.")) return "重新生成或编辑扮演配置，确保所有引用角色都有角色卡。";
  if (code.startsWith("roleplay.")) return "先定位对应扮演轮次、角色卡和写前定位，再追加审查或单角色重跑。";
  if (code.startsWith("prose.")) return "先对照已采纳正文、扮演来源和档案证据，再创建修订草稿或更新档案。";
  return "先检索相关档案，再通过对应工具修正。";
}

function buildPlanningSystemPrompt() {
  return [
    buildSkillPlanningSystemPrompt(),
    "",
    "原生工具协议补充：如果当前模型提供 tools/tool_choice，你应优先用原生工具调用检索、读取、写入、审批或启动子 Agent；不要把工具调用伪装成普通回复文本。",
    "工具返回后，你必须阅读 observation，再决定继续调用工具、修正参数、请求确认或输出最终 JSON。最终回复仍必须是可解析 JSON，包含 reply、skillOps、taskPlan、taskGraph、doneCriteria、completionCheck、stopReason 等字段；若已经用原生工具完成操作，skillOps 可以为空。",
    "历史证据由后端自动调度，agentState.evidencePlan 记录了已读取的层、原因和证据 id；不要要求用户手动点击查历史。需要旧工具原文时，使用 searchContextAssets/readContextAsset。",
    "你应像 Codex 一样在同一轮中循环行动：模型提出工具调用，后端执行并回传 observation，你读取结果后继续决定下一步。不要只在开头做一次是否调用工具的判断。",
    "运行器的 runtimeGuard、工具失败、空动作提醒也会作为 observation 回到 agentState.observations；这不是让你停下的错误弹窗，而是下一步输入。你必须读它，修正工具调用、说明不写入原因、请求确认，或在确实完成后 final。",
    "reply 字段是直接给用户看的自然语言回复，不得出现 evidenceScheduler、skillOps、tool_call、tool_result、contextAsset、assetRef、runtimeGuard、completionVerifier、toolUseDecision、运行器、统一工具执行器、证据调度等内部协议词。需要描述过程时，用“读取资料、读取文件、更新资料、检查结果、等待确认”等用户能理解的动作名。",
    "如果本轮已经给出用户可读回复，但必须等待用户补一句最小选择或确认，stopReason 使用 await_user；不要用空的 continue 表示等待，也不要把普通追问标成 blocked。",
    "如果你生成了角色卡、档案、世界书、长期记忆、正文草稿、扮演配置或章节写前定位等后续可复用内容，默认应通过工具写入或生成草稿；不写入必须给出具体 noWriteReason。reply 只放摘要和下一步，不承载完整资产。"
  ].join("\n");
}

async function ensurePlanningContextCompaction(store, novel, context) {
  novel.planning = normalizePlanning(novel.planning);
  const scope = selectPlanningCompactionScope(novel);
  if (!scope.candidateMessages.length) return novel.planning.contextCompaction;
  const contextPack = context.contextPack;
  const budget = calculatePlanningContextBudget(store, novel, context.userMessage, contextPack, {
    setting: context.plannerSetting || novel.aiRoles?.planner,
    model: context.plannerSetting?.model || novel.aiRoles?.planner?.model || "",
    step: 1,
    branchId: context.run?.branchId || novel.planning.activeBranchId,
    observations: []
  });
  if (!shouldCompactPlanningContext(scope, budget)) {
    return novel.planning.contextCompaction;
  }
  appendPlanningRunEvent(novel, context.run?.id, "context_compaction", "context_budget", "开始压缩旧策划上下文", {
    candidateMessages: scope.candidateMessages.length,
    estimatedPromptTokens: budget.estimatedPromptTokens,
    estimatedPromptChars: budget.estimatedPromptChars,
    promptBudgetTokens: budget.promptBudgetTokens,
    promptBudgetChars: budget.promptBudgetChars
  });
  let compacted;
  const compactionInput = buildPlanningCompactionInput(novel, scope);
  const serializedCompactionInput = JSON.stringify(compactionInput, null, 2);
  if (serializedCompactionInput.length > PLANNING_AI_COMPACTION_MAX_INPUT_CHARS) {
    appendPlanningRunDiagnostic(novel, context.run?.id, {
      type: "context_compaction",
      code: "compaction.deterministic_large_input",
      message: "上下文压缩输入过大，已使用确定性摘要并保留长内容引用，避免阻塞 Agent 运行。",
      retryable: false,
      details: {
        inputChars: serializedCompactionInput.length,
        maxInputChars: PLANNING_AI_COMPACTION_MAX_INPUT_CHARS
      },
      createdAt: nowIso()
    });
    compacted = await enrichPlanningCompactionRecord(novel, createDeterministicPlanningCompaction(novel, scope, budget), scope, budget, {
      ...context,
      skipModelQualityReview: true
    });
  } else try {
    const result = await requestAi({
      provider: context.plannerProvider,
      model: context.plannerSetting.model,
      temperature: 0,
      systemPrompt: buildPlanningCompactionSystemPrompt(),
      messages: [
        {
          role: "user",
          content: serializedCompactionInput
        }
      ],
      signal: context.run?.abortController?.signal,
      onDiagnostic: (diagnostic) => appendPlanningRunDiagnostic(novel, context.run?.id, {
        ...diagnostic,
        type: "context_compaction"
      })
    });
    const parsed = parseLooseJson(result.text);
    if (!parsed || typeof parsed !== "object") {
      throw new AgentError(502, "compaction.invalid_json", "上下文压缩输出不是合法 JSON", safeRemoteText(result.text), true);
    }
    compacted = await enrichPlanningCompactionRecord(novel, {
      ...parsed,
      id: createId("ctx_compact"),
      strategy: "rolling_summary",
      sourceMessageCount: scope.sourceMessageCount,
      sourceFirstMessageId: scope.sourceFirstMessageId,
      sourceLastMessageId: scope.sourceLastMessageId,
      sourceHash: scope.sourceHash,
      tokenStats: {
        tokenizer: budget.tokenizer,
        promptBudgetTokens: budget.promptBudgetTokens,
        estimatedPromptTokens: budget.estimatedPromptTokens,
        estimatedPromptChars: budget.estimatedPromptChars,
        beforeTokens: scope.summarizedTokens,
        afterTokens: estimatePlanningTokens(JSON.stringify(parsed)).tokens,
        savedTokens: Math.max(0, scope.summarizedTokens - estimatePlanningTokens(JSON.stringify(parsed)).tokens)
      },
      updatedAt: nowIso()
    }, scope, budget, context);
  } catch (error) {
    if (isPlanningRunCancelledError(error)) throw error;
    appendPlanningRunDiagnostic(novel, context.run?.id, {
      type: "context_compaction",
      code: "compaction.fallback",
      message: `上下文压缩模型调用失败，已使用确定性摘要兜底：${String(error?.message || error)}`,
      retryable: true,
      createdAt: nowIso()
    });
    compacted = await enrichPlanningCompactionRecord(novel, createDeterministicPlanningCompaction(novel, scope, budget), scope, budget, context);
  }
  novel.planning.contextCompaction = compacted;
  appendPlanningRunEvent(novel, context.run?.id, "context_compacted", "context_budget", "旧策划上下文已压缩为内部摘要", {
    sourceMessageCount: compacted.sourceMessageCount,
    sourceLastMessageId: compacted.sourceLastMessageId,
    version: compacted.version,
    qualityStatus: compacted.qualityReview?.status || "",
    assetRefs: compacted.assetRefs?.length || 0
  });
  return compacted;
}

function selectPlanningCompactionScope(novel) {
  const messages = Array.isArray(novel?.planning?.messages) ? novel.planning.messages : [];
  const tailStart = Math.max(0, messages.length - PLANNING_COMPACTION_RECENT_MESSAGES);
  const existing = normalizePlanningContextCompaction(novel?.planning?.contextCompaction);
  const existingIndex = existing?.sourceLastMessageId
    ? messages.findIndex((message) => message.id === existing.sourceLastMessageId)
    : -1;
  const start = existingIndex >= 0 ? existingIndex + 1 : 0;
  const end = tailStart;
  const candidateMessages = start < end ? messages.slice(start, end) : [];
  const sourceMessages = messages.slice(0, end);
  const sourceFirstMessageId = sourceMessages[0]?.id || "";
  const sourceLastMessageId = sourceMessages[sourceMessages.length - 1]?.id || "";
  const unsummarizedText = candidateMessages.map((message) => `${message.role}\n${getPlanningMessagePromptContent(message)}\n${JSON.stringify(message.skillOpReport || {})}`).join("\n\n");
  const summarizedText = sourceMessages.map((message) => `${message.role}\n${getPlanningMessagePromptContent(message)}\n${JSON.stringify(message.skillOpReport || {})}`).join("\n\n");
  const unsummarizedStats = estimatePlanningTokens(unsummarizedText);
  const summarizedStats = estimatePlanningTokens(summarizedText);
  return {
    existing,
    messages,
    candidateMessages,
    sourceMessages,
    sourceMessageCount: sourceMessages.length,
    sourceFirstMessageId,
    sourceLastMessageId,
    sourceHash: hashText(sourceMessages.map((message) => `${message.id}:${message.updatedAt || message.createdAt || ""}`).join("|")),
    unsummarizedChars: estimatePlanningMessagesChars(candidateMessages),
    summarizedChars: estimatePlanningMessagesChars(sourceMessages),
    unsummarizedTokens: unsummarizedStats.tokens,
    summarizedTokens: summarizedStats.tokens,
    tailStart
  };
}

function shouldCompactPlanningContext(scope, budget) {
  if (!scope.candidateMessages.length || !scope.sourceLastMessageId) return false;
  const normalizedBudget = normalizePlanningBudget(budget);
  const triggerTokens = normalizedBudget.compressionTriggerTokens || Math.floor(normalizedBudget.promptBudgetTokens * normalizedBudget.compactionPressureRatio);
  const tokenToCharRatio = normalizedBudget.promptBudgetTokens > 0
    ? normalizedBudget.promptBudgetChars / normalizedBudget.promptBudgetTokens
    : 1.8;
  const triggerChars = Math.min(normalizedBudget.promptBudgetChars, Math.max(0, Math.round(triggerTokens * tokenToCharRatio)));
  const refreshTokenRoom = Math.max(1000, normalizedBudget.promptBudgetTokens - triggerTokens);
  const refreshCharRoom = Math.max(1800, normalizedBudget.promptBudgetChars - triggerChars);
  const pressure = normalizedBudget.estimatedPromptTokens > triggerTokens
    || normalizedBudget.estimatedPromptChars > triggerChars;
  const unsummarizedPressure = scope.unsummarizedTokens > refreshTokenRoom
    || scope.unsummarizedChars > refreshCharRoom;
  const staleSummary = scope.existing && scope.candidateMessages.length >= Math.ceil(PLANNING_COMPACTION_RECENT_MESSAGES / 2);
  const noSummaryLargeHistory = !scope.existing && scope.sourceMessages.length >= PLANNING_COMPACTION_RECENT_MESSAGES * 2;
  return pressure || unsummarizedPressure || staleSummary || noSummaryLargeHistory;
}

function estimatePlanningMessagesChars(messages) {
  return (Array.isArray(messages) ? messages : []).reduce((sum, message) => {
    return sum + getPlanningMessagePromptContent(message).length + JSON.stringify(message?.skillOpReport || {}).length;
  }, 0);
}

function buildPlanningCompactionSystemPrompt() {
  return [
    "你是策划线程上下文压缩 AI。",
    "你的任务是把较早的策划对话和工具结果压缩成可继续工作的内部摘要。",
    "不要写小说正文，不要新增事实，不要把未确认内容说成已确认。",
    "输出必须是 JSON 对象，字段为 summary、stableFacts、userPreferences、openQuestions、toolResults、risks。",
    "summary 用中文，保留用户目标、已确认决策、正在推进的任务和仍需追问的缺口。",
    "stableFacts 只放已确认或强证据支持的事实。",
    "toolResults 只保留工具做过什么、关键结果引用、assetRef 和可追溯 id，不要复述大段工具原文。",
    "openQuestions 放还没裁决但会影响后续策划的问题。",
    "risks 放冲突、过期内容、可见性风险和需要谨慎处理的点。",
    "如果输入里有长内容引用，只保留引用 id 和用途；需要原文的后续 Agent 会调用 readContextAsset。"
  ].join("\n");
}

function buildPlanningCompactionInput(novel, scope) {
  return {
    task: "compact_planning_context",
    novelTitle: novel.title,
    existingSummary: scope.existing ? formatPlanningCompactionForPrompt(scope.existing) : null,
    preserveRecentMessageCount: PLANNING_COMPACTION_RECENT_MESSAGES,
    sourceRange: {
      firstMessageId: scope.sourceFirstMessageId,
      lastMessageId: scope.sourceLastMessageId,
      messageCount: scope.sourceMessageCount,
      sourceHash: scope.sourceHash
    },
    tokenPressure: {
      unsummarizedTokens: scope.unsummarizedTokens,
      summarizedTokens: scope.summarizedTokens
    },
    messagesToCompact: scope.candidateMessages.map(formatPlanningMessageForCompaction)
  };
}

function formatPlanningMessageForCompaction(message) {
  const report = normalizeSkillOpReport(message.skillOpReport);
  return {
    id: message.id,
    role: message.role,
    createdAt: message.createdAt,
    content: limitText(getPlanningMessagePromptContent(message), 1600),
    archivePatchKeys: message.archivePatch && typeof message.archivePatch === "object" ? Object.keys(message.archivePatch) : [],
    toolSummary: report ? {
      searches: (report.searches || []).slice(0, 8).map((item) => ({
        type: item.type,
        query: item.query || item.relativePath || "",
        count: item.count || 0,
        topResults: (item.results || []).slice(0, 3).map((result) => ({
          id: result.id,
          title: result.title,
          source: result.source,
          assetRef: result.assetRef || null,
          relativePath: result.relativePath || ""
        }))
      })),
      applied: (report.applied || []).slice(0, 12).map((item) => ({
        type: item.type,
        id: item.id || "",
        name: item.name || item.subject || item.field || item.reason || ""
      })),
      skipped: (report.skipped || []).slice(0, 6).map((item) => ({
        type: item.type,
        reason: item.reason || ""
      })),
      assetRefs: [
        ...(report.searches || []).flatMap((item) => [
          ...(item.assetRef ? [item.assetRef] : []),
          ...(item.assetRefs || []),
          ...((item.results || []).flatMap((result) => result.assetRef ? [result.assetRef] : []))
        ])
      ].slice(0, 12)
    } : null
  };
}

function createDeterministicPlanningCompaction(novel, scope, budget = null) {
  const existing = scope.existing;
  const userMessages = scope.sourceMessages.filter((message) => message.role === "user").slice(-10);
  const assistantMessages = scope.sourceMessages.filter((message) => message.role === "assistant").slice(-10);
  const toolResults = scope.sourceMessages
    .flatMap((message) => summarizePlanningMessageToolResultsForCompaction(message))
    .filter(Boolean)
    .slice(-30);
  return normalizePlanningContextCompaction({
    id: createId("ctx_compact"),
    strategy: "deterministic_rolling_summary",
    summary: [
      existing?.summary ? `既有摘要：${existing.summary}` : "",
      userMessages.length ? `近期用户目标：${userMessages.map((message) => limitText(getPlanningMessageVisibleContent(message), 180)).join(" / ")}` : "",
      assistantMessages.length ? `近期 Agent 处理：${assistantMessages.map((message) => limitText(getPlanningMessageVisibleContent(message), 180)).join(" / ")}` : ""
    ].filter(Boolean).join("\n"),
    stableFacts: existing?.stableFacts || [],
    userPreferences: existing?.userPreferences || [],
    openQuestions: existing?.openQuestions || [],
    toolResults: uniqueStrings([...(existing?.toolResults || []), ...toolResults]).slice(-40),
    risks: existing?.risks || [],
    sourceMessageCount: scope.sourceMessageCount,
    sourceFirstMessageId: scope.sourceFirstMessageId,
    sourceLastMessageId: scope.sourceLastMessageId,
    sourceHash: scope.sourceHash,
    tokenStats: {
      tokenizer: budget?.tokenizer || "cl100k_base",
      promptBudgetTokens: budget?.promptBudgetTokens || PLANNING_CONTEXT_BUDGET_TOKENS,
      estimatedPromptTokens: budget?.estimatedPromptTokens || 0,
      estimatedPromptChars: budget?.estimatedPromptChars || 0,
      beforeTokens: scope.summarizedTokens,
      afterTokens: estimatePlanningTokens(toolResults.join("\n")).tokens,
      savedTokens: Math.max(0, scope.summarizedTokens - estimatePlanningTokens(toolResults.join("\n")).tokens)
    },
    updatedAt: nowIso()
  });
}

function summarizePlanningMessageToolResultsForCompaction(message) {
  const report = message?.skillOpReport;
  if (!report || typeof report !== "object") return [];
  const summaries = [];
  const searches = Array.isArray(report.searches) ? report.searches : [];
  for (const item of searches.slice(0, 8)) {
    summaries.push(`${planningToolLabelForSummary(item?.type)}：${limitText(item?.query || item?.relativePath || item?.id || "", 180)}（${Number(item?.count || 0)} 条）`);
  }
  const applied = Array.isArray(report.applied) ? report.applied : [];
  for (const item of applied.slice(0, 12)) {
    summaries.push(`${planningToolLabelForSummary(item?.type)}：${limitText(item?.name || item?.subject || item?.field || item?.id || item?.reason || "", 180)}`);
  }
  const skipped = Array.isArray(report.skipped) ? report.skipped : [];
  for (const item of skipped.slice(0, 4)) {
    summaries.push(`工具失败：${planningToolLabelForSummary(item?.type)}：${limitText(item?.reason || item?.message || item?.code || "", 160)}`);
  }
  return summaries;
}

function planningToolLabelForSummary(type) {
  return {
    search: "项目检索",
    searchContextAssets: "查找历史资料",
    readContextAsset: "读取历史资料",
    searchLocalFiles: "本地检索",
    readLocalFile: "读取文件",
    upsertMemory: "写入记忆",
    upsertLorebook: "写入世界书",
    markArchiveRecord: "标记档案",
    patchArchiveRecord: "编辑档案",
    generateRoleplayConfigDraft: "生成扮演配置"
  }[String(type || "")] || String(type || "工具");
}

function formatPlanningCompactionForPrompt(compaction) {
  const normalized = normalizePlanningContextCompaction(compaction);
  if (!normalized) return null;
  return {
    strategy: normalized.strategy,
    version: normalized.version,
    summary: normalized.summary,
    stableFacts: normalized.stableFacts,
    userPreferences: normalized.userPreferences,
    openQuestions: normalized.openQuestions,
    toolResults: normalized.toolResults,
    risks: normalized.risks,
    assetRefs: normalized.assetRefs,
    qualityReview: normalized.qualityReview ? {
      status: normalized.qualityReview.status,
      summary: normalized.qualityReview.summary,
      missing: normalized.qualityReview.missing
    } : null,
    sourceMessageCount: normalized.sourceMessageCount,
    sourceFirstMessageId: normalized.sourceFirstMessageId,
    sourceLastMessageId: normalized.sourceLastMessageId,
    sourceRange: normalized.sourceRange,
    tokenStats: normalized.tokenStats,
    updatedAt: normalized.updatedAt
  };
}

async function enrichPlanningCompactionRecord(novel, value, scope, budget, context = {}) {
  const existing = normalizePlanningContextCompaction(scope.existing);
  const baseVersion = existing?.version || 0;
  const normalized = normalizePlanningContextCompaction({
    ...value,
    version: baseVersion + 1,
    previousId: existing?.id || "",
    sourceFirstMessageId: scope.sourceFirstMessageId,
    sourceLastMessageId: scope.sourceLastMessageId,
    sourceMessageCount: scope.sourceMessageCount,
    sourceHash: scope.sourceHash,
    sourceRange: {
      firstMessageId: scope.sourceFirstMessageId,
      lastMessageId: scope.sourceLastMessageId,
      messageCount: scope.sourceMessageCount,
      sourceHash: scope.sourceHash
    },
    tokenStats: {
      tokenizer: budget?.tokenizer || "cl100k_base",
      promptBudgetTokens: budget?.promptBudgetTokens || PLANNING_CONTEXT_BUDGET_TOKENS,
      estimatedPromptTokens: budget?.estimatedPromptTokens || 0,
      estimatedPromptChars: budget?.estimatedPromptChars || 0,
      beforeTokens: value?.tokenStats?.beforeTokens || scope.summarizedTokens,
      afterTokens: value?.tokenStats?.afterTokens || estimatePlanningTokens(JSON.stringify(value || {})).tokens,
      savedTokens: value?.tokenStats?.savedTokens || Math.max(0, scope.summarizedTokens - estimatePlanningTokens(JSON.stringify(value || {})).tokens),
      estimated: Boolean(budget?.tokenEstimateIsFallback)
    },
    updatedAt: nowIso()
  });
  const assetRef = await writePlanningContextAsset(novel, {
    id: createId("ctx_compact_asset"),
    kind: "context_compaction",
    title: `策划上下文压缩 v${normalized.version}`,
    runId: context.run?.id || "",
    branchId: context.run?.branchId || context.branchId || "",
    messageId: context.assistantMessageId || "",
    toolType: "context_compaction"
  }, {
    compaction: normalized,
    sourceRange: normalized.sourceRange
  });
  const assetRefs = uniqueContextAssetRefs([
    ...normalizeContextAssetRefs(existing?.assetRefs || []),
    ...normalizeContextAssetRefs(value?.assetRefs || []),
    assetRef
  ]).slice(-80);
  const normalizedWithAssets = normalizePlanningContextCompaction({
    ...normalized,
    assetRefs
  });
  const qualityReview = await reviewPlanningCompactionQuality(novel, normalizedWithAssets, scope, context);
  const versionEntry = normalizePlanningCompactionVersion({
    id: normalized.id,
    version: normalized.version,
    previousId: normalized.previousId,
    sourceFirstMessageId: normalized.sourceFirstMessageId,
    sourceLastMessageId: normalized.sourceLastMessageId,
    sourceMessageCount: normalized.sourceMessageCount,
    sourceHash: normalized.sourceHash,
    summaryHash: hashText(JSON.stringify({
      summary: normalized.summary,
      stableFacts: normalized.stableFacts,
      userPreferences: normalized.userPreferences,
      openQuestions: normalized.openQuestions,
      toolResults: normalized.toolResults,
      risks: normalized.risks
    })),
    diff: buildPlanningCompactionDiff(existing, normalized),
    tokenStats: normalized.tokenStats,
    qualityStatus: qualityReview.status,
    createdAt: normalized.updatedAt
  });
  return normalizePlanningContextCompaction({
    ...normalizedWithAssets,
    assetRefs,
    qualityReview,
    versionChain: [
      ...(existing?.versionChain || []),
      versionEntry
    ].filter(Boolean).slice(-12)
  });
}

function uniqueContextAssetRefs(refs) {
  const seen = new Set();
  const result = [];
  for (const ref of normalizeContextAssetRefs(refs)) {
    if (seen.has(ref.id)) continue;
    seen.add(ref.id);
    result.push(ref);
  }
  return result;
}

function buildPlanningCompactionDiff(previous, current) {
  const diffList = (oldList, newList) => {
    const oldSet = new Set(normalizeStringList(oldList));
    return normalizeStringList(newList).filter((item) => !oldSet.has(item)).slice(0, 20);
  };
  return normalizePlanningCompactionDiff({
    addedStableFacts: diffList(previous?.stableFacts, current?.stableFacts),
    addedUserPreferences: diffList(previous?.userPreferences, current?.userPreferences),
    addedOpenQuestions: diffList(previous?.openQuestions, current?.openQuestions),
    addedRisks: diffList(previous?.risks, current?.risks),
    addedToolResults: diffList(previous?.toolResults, current?.toolResults)
  });
}

async function reviewPlanningCompactionQuality(novel, compaction, scope, context = {}) {
  const deterministic = deterministicPlanningCompactionQualityReview(compaction, scope);
  if (context.skipModelQualityReview || !context.plannerProvider || !context.plannerSetting || deterministic.status === "passed") {
    return deterministic;
  }
  try {
    const result = await requestAi({
      provider: context.plannerProvider,
      model: context.plannerSetting.model,
      temperature: 0,
      systemPrompt: buildPlanningCompactionReviewSystemPrompt(),
      messages: [{
        role: "user",
        content: JSON.stringify({
          task: "review_planning_compaction",
          novelTitle: novel.title,
          sourceRange: compaction.sourceRange,
          compaction: formatPlanningCompactionForPrompt(compaction),
          sampleMessages: scope.candidateMessages.slice(-8).map((message) => ({
            id: message.id,
            role: message.role,
            content: limitText(getPlanningMessageVisibleContent(message), 900),
            toolKeys: message.skillOpReport ? Object.keys(message.skillOpReport) : []
          })),
          deterministicReview: deterministic
        }, null, 2)
      }],
      signal: context.run?.abortController?.signal,
      onDiagnostic: (diagnostic) => appendPlanningRunDiagnostic(novel, context.run?.id, {
        ...diagnostic,
        type: "context_compaction_review"
      })
    });
    const parsed = parseLooseJson(result.text);
    if (!parsed || typeof parsed !== "object") throw new AgentError(502, "compaction_review.invalid_json", "压缩质量审查输出不是合法 JSON", safeRemoteText(result.text), true);
    const review = normalizePlanningCompactionQualityReview({
      status: parsed.status || deterministic.status,
      summary: parsed.summary || deterministic.summary,
      coverage: parsed.coverage || deterministic.coverage,
      missing: parsed.missing || deterministic.missing,
      issues: parsed.issues || deterministic.issues,
      checkedAt: nowIso()
    });
    return mergePlanningCompactionQualityReviews(deterministic, review);
  } catch (error) {
    if (isPlanningRunCancelledError(error)) throw error;
    appendPlanningRunDiagnostic(novel, context.run?.id, {
      type: "context_compaction_review",
      code: "compaction_review.fallback",
      message: `压缩质量审查模型调用失败，已使用确定性审查：${String(error?.message || error)}`,
      retryable: true,
      createdAt: nowIso()
    });
    return {
      ...deterministic,
      status: deterministic.status === "passed" ? "warning" : deterministic.status,
      summary: `${deterministic.summary || "已执行确定性审查。"} 模型审查失败，需保留审计关注。`
    };
  }
}

function deterministicPlanningCompactionQualityReview(compaction, scope) {
  const coverage = {
    summary: Boolean(String(compaction.summary || "").trim()),
    stableFacts: Array.isArray(compaction.stableFacts) && compaction.stableFacts.length > 0,
    userPreferences: Array.isArray(compaction.userPreferences) && compaction.userPreferences.length > 0,
    openQuestions: Array.isArray(compaction.openQuestions),
    toolResults: Array.isArray(compaction.toolResults),
    risks: Array.isArray(compaction.risks),
    assetRefs: Array.isArray(compaction.assetRefs)
  };
  const missing = [];
  if (!coverage.summary) missing.push("summary");
  const sourceStats = summarizePlanningCompactionSource(scope.candidateMessages);
  if (sourceStats.hasToolReport && (!compaction.toolResults || compaction.toolResults.length === 0)) missing.push("toolResults");
  if (sourceStats.hasRiskSignal && (!compaction.risks || compaction.risks.length === 0)) missing.push("risks");
  if (sourceStats.hasAssetRef && (!compaction.assetRefs || compaction.assetRefs.length === 0)) missing.push("assetRefs");
  const status = !coverage.summary ? "failed" : missing.length > 0 ? "warning" : "passed";
  return normalizePlanningCompactionQualityReview({
    status,
    summary: status === "passed" ? "压缩摘要覆盖了继续任务所需的主要层。" : "压缩摘要存在可能遗漏的层，需要后续 Agent 通过检索或长内容引用补证。",
    coverage,
    missing,
    issues: missing.map((field) => ({
      field,
      severity: field === "summary" ? "high" : "medium",
      message: `压缩摘要可能缺少 ${field} 层。`
    })),
    checkedAt: nowIso()
  });
}

function summarizePlanningCompactionSource(messages) {
  const list = Array.isArray(messages) ? messages : [];
  return {
    hasToolReport: list.some((message) => planningMessageHasToolReport(message)),
    hasRiskSignal: list.some((message) => planningMessageHasRiskSignal(message)),
    hasAssetRef: list.some((message) => planningMessageHasAssetRefSignal(message))
  };
}

function planningMessageHasToolReport(message) {
  const report = message?.skillOpReport;
  if (!report || typeof report !== "object") return false;
  return Boolean(
    report.requested
    || (Array.isArray(report.applied) && report.applied.length)
    || (Array.isArray(report.searches) && report.searches.length)
    || (Array.isArray(report.skipped) && report.skipped.length)
    || (Array.isArray(report.nativeToolCalls) && report.nativeToolCalls.length)
  );
}

function planningMessageHasRiskSignal(message) {
  const diagnostics = message?.archiveDiagnostics || message?.diagnostics || {};
  const report = message?.skillOpReport || {};
  return Boolean(
    (Array.isArray(diagnostics.conflicts) && diagnostics.conflicts.length)
    || (Array.isArray(diagnostics.corrections) && diagnostics.corrections.length)
    || (Array.isArray(report.skipped) && report.skipped.length)
    || (Array.isArray(report.warnings) && report.warnings.length)
    || (Array.isArray(message?.warnings) && message.warnings.length)
    || (Array.isArray(message?.openIssues) && message.openIssues.length)
    || Boolean(message?.error)
  );
}

function planningMessageHasAssetRefSignal(message) {
  if (!message || typeof message !== "object") return false;
  if (message.assetRef || (Array.isArray(message.assetRefs) && message.assetRefs.length)) return true;
  const report = message.skillOpReport && typeof message.skillOpReport === "object" ? message.skillOpReport : null;
  if (!report) return false;
  return Boolean(
    report.assetRef
    || (Array.isArray(report.assetRefs) && report.assetRefs.length)
    || (report.searches || []).some((item) => item.assetRef || (Array.isArray(item.assetRefs) && item.assetRefs.length) || (item.results || []).some((result) => result.assetRef))
    || (report.applied || []).some((item) => item.assetRef || (Array.isArray(item.assetRefs) && item.assetRefs.length))
    || (report.evidenceReads || []).some((item) => item.assetId)
  );
}

function objectHasKeyDeep(value, keys, depth) {
  if (!value || typeof value !== "object" || depth > 6) return false;
  if (Array.isArray(value)) {
    return value.some((item) => objectHasKeyDeep(item, keys, depth + 1));
  }
  return Object.entries(value).some(([key, child]) => {
    if (keys.has(key)) return hasNonEmptySignalValue(child);
    return objectHasKeyDeep(child, keys, depth + 1);
  });
}

function hasNonEmptySignalValue(value) {
  if (Array.isArray(value)) return value.length > 0;
  if (value && typeof value === "object") return Object.keys(value).length > 0;
  if (typeof value === "string") return Boolean(value.trim());
  return Boolean(value);
}

function buildPlanningCompactionReviewSystemPrompt() {
  return [
    "你是策划 Agent 的上下文压缩质量审查器。",
    "你只检查摘要是否足以让后续 Agent 继续任务，不能新增设定，不能改写小说。",
    "重点检查用户偏好、稳定事实、未决问题、工具证据、风险和长内容引用是否遗漏。",
    "输出严格 JSON：status=passed|warning|failed，summary 中文，coverage 对象，missing 数组，issues 数组。"
  ].join("\n");
}

function mergePlanningCompactionQualityReviews(a, b) {
  const first = normalizePlanningCompactionQualityReview(a);
  const second = normalizePlanningCompactionQualityReview(b);
  if (!first) return second;
  if (!second) return first;
  const rank = { passed: 0, warning: 1, failed: 2, fallback: 1 };
  const status = rank[second.status] > rank[first.status] ? second.status : first.status;
  return normalizePlanningCompactionQualityReview({
    status,
    summary: [first.summary, second.summary].filter(Boolean).join("\n"),
    coverage: { ...(first.coverage || {}), ...(second.coverage || {}) },
    missing: uniqueStrings([...(first.missing || []), ...(second.missing || [])]),
    issues: [...(first.issues || []), ...(second.issues || [])],
    checkedAt: nowIso()
  });
}

function buildPlanningPromptHistory(novel, branchId = "") {
  const planning = normalizePlanning(novel?.planning);
  const targetBranchId = normalizePlanningBranchId(branchId || planning.activeBranchId || "main");
  return (planning.messages || [])
    .filter((message) => normalizePlanningBranchId(message.branchId || "main") === targetBranchId)
    .slice(-PLANNING_COMPACTION_RECENT_MESSAGES)
    .map((message) => ({
    role: message.role,
    content: getPlanningMessagePromptContent(message)
  }));
}

const PLANNING_DECISION_TOOL_GROUPS = Object.freeze({
  projectEvidence: ["search", "inspectNovelDiagnostics"],
  contextAssets: ["searchContextAssets", "readContextAsset"],
  messageAttachments: ["readMessageAttachment", "inspectNovelDiagnostics"],
  workspaceEvidence: ["searchLocalFiles", "readLocalFile", "listFiles", "globFiles", "grepFiles", "indexLocalFiles"],
  webEvidence: ["webSearch", "webFetch"],
  projectFiles: ["searchFiles", "readFile", "previewPatchSet", "applyPatch", "applyPatchSet"],
  writing: ["generatePrewritePlan", "runNormalWritingWorkflow", "adaptRoleplayToProse", "postwriteProse"],
  roleplay: ["generateRoleplayConfigDraft", "generatePrewritePlan", "runRoleplayTurn", "reviewLatestTurn", "adaptRoleplayToProse", "runChapterWorkflow"]
});

function buildPlanningAgentDecisionHints(novel, userMessage, attachments = null) {
  const planning = normalizePlanning(novel?.planning);
  const signals = analyzePlanningInputSignals(novel, userMessage);
  const attachmentSignals = analyzePlanningMessageAttachments(attachments, userMessage);
  const tools = new Set();
  const signalLabels = ["model_decides_from_skill_policy"];

  if (attachmentSignals.hasAttachments) {
    signalLabels.push("message_attachments_present");
    addPlanningToolGroup(tools, "messageAttachments");
  }
  if (attachmentSignals.hasLongAttachment) {
    signalLabels.push("long_attachment");
  }
  if (attachmentSignals.hasRevisionMaterial) {
    signalLabels.push("revision_attachment");
    tools.add("upsertProseDraft");
  }
  if (signals.isLongMaterial) {
    signalLabels.push("long_input");
    addPlanningToolGroup(tools, "projectEvidence");
  }
  if (signals.hasContextAssets) {
    signalLabels.push("history_assets_available");
    addPlanningToolGroup(tools, "contextAssets");
  }
  if (signals.hasWorkspace && (signals.hasFilePath || signals.hasFileLikeToken || signals.isLongMaterial)) {
    signalLabels.push("workspace_evidence_possible");
    addPlanningToolGroup(tools, "workspaceEvidence");
  }
  if (signals.hasUrl) {
    signalLabels.push("web_source_possible");
    addPlanningToolGroup(tools, "webEvidence");
  }
  if (signals.hasDiffLikeText || signals.hasFilePath) {
    signalLabels.push("project_file_context_possible");
    addPlanningToolGroup(tools, "projectFiles");
  }
  if (/正常行文|直接写|正文草稿|章节正文/.test(String(userMessage || ""))) {
    signalLabels.push("writing_workflow_possible");
    addPlanningToolGroup(tools, "writing");
  }
  if (/扮演行文|角色扮演|跑一轮|扮演改写/.test(String(userMessage || ""))) {
    signalLabels.push("roleplay_workflow_possible");
    addPlanningToolGroup(tools, "roleplay");
  }

  return {
    intents: uniqueStrings(signalLabels).slice(0, 8),
    signals: {
      ...signals,
      attachments: {
        hasAttachments: attachmentSignals.hasAttachments,
        attachmentCount: attachmentSignals.attachmentCount,
        attachmentTextChars: attachmentSignals.attachmentTextChars,
        hasLongAttachment: attachmentSignals.hasLongAttachment,
        hasRevisionMaterial: attachmentSignals.hasRevisionMaterial,
        probableMaterialType: attachmentSignals.probableMaterialType,
        requiresEvidenceRead: attachmentSignals.requiresEvidenceRead,
        files: attachmentSignals.files.map((file) => ({
          id: file.id,
          name: file.name,
          textChars: file.textChars,
          originalChars: file.originalChars,
          materialType: file.materialType,
          truncated: file.truncated
        }))
      }
    },
    suggestedTools: Array.from(tools).slice(0, 18),
    capabilityCatalog: buildPlanningCapabilityCatalog(),
    possibleWriteTargets: [
      "archivePatch",
      "upsertMemory",
      "upsertLorebook",
      "updateCharacterCard",
      "upsertProseDraft",
      "projectFile"
    ],
    localWorkspace: planning.defaultAgentFolder || "",
    toolAvailability: summarizePlanningToolAvailability(novel),
    riskNotes: [
      "decisionHints 只描述输入结构和可用能力，不按关键词替模型决定意图。",
      "写入不是默认动作；只有稳定事实、明确修改目标或用户授权才进入写入工具。",
      "高风险编辑仍要先检索证据，必要时由后端要求人工确认。"
    ],
    instruction: "这些是后端给策划 Agent 的结构信号和工具能力清单，不是固定流程。模型必须结合 skill 的意图路由和当前证据自主判断是否调用工具、写入哪一层，以及何时收束。"
  };
}

function addPlanningToolGroup(target, groupName) {
  for (const tool of PLANNING_DECISION_TOOL_GROUPS[groupName] || []) {
    target.add(tool);
  }
}

function buildPlanningCapabilityCatalog() {
  return [
    { group: "projectEvidence", tools: PLANNING_DECISION_TOOL_GROUPS.projectEvidence, use: "检索项目内档案、角色卡、世界书、长期记忆、正文和扮演审计。" },
    { group: "contextAssets", tools: PLANNING_DECISION_TOOL_GROUPS.contextAssets, use: "读取被压缩或引用化落盘的旧运行证据。" },
    { group: "messageAttachments", tools: PLANNING_DECISION_TOOL_GROUPS.messageAttachments, use: "读取本轮用户拖入的新稿、改稿、设定文件或旧稿，并按内容决定是否诊断或沉淀。" },
    { group: "workspaceEvidence", tools: PLANNING_DECISION_TOOL_GROUPS.workspaceEvidence, use: "检索和读取当前小说 Agent 工作区及额外资料源。" },
    { group: "webEvidence", tools: PLANNING_DECISION_TOOL_GROUPS.webEvidence, use: "查询公开来源，并把来源作为证据而不是直接当成项目事实。" },
    { group: "projectFiles", tools: PLANNING_DECISION_TOOL_GROUPS.projectFiles, use: "预览和应用可审计文件补丁，写入前应先读或预览 diff。" },
    { group: "writing", tools: PLANNING_DECISION_TOOL_GROUPS.writing, use: "执行正常行文、扮演改写、写后回写等正文链路。" },
    { group: "roleplay", tools: PLANNING_DECISION_TOOL_GROUPS.roleplay, use: "准备或执行章节级导演统筹、角色扮演、审查和扮演改写链路。" }
  ];
}

function analyzePlanningInputSignals(novel, userMessage) {
  const text = String(userMessage || "");
  const lines = text.split(/\r?\n/);
  const trimmed = text.trim();
  const hasFilePath = hasPathLikeText(text);
  const hasFileLikeToken = hasFileLikeTokenText(text);
  const hasDiffLikeText = /^diff --git\b|^@@\s|^\+\+\+\s|^---\s/m.test(text);
  const compaction = normalizePlanningContextCompaction(novel?.planning?.contextCompaction);
  const planning = normalizePlanning(novel?.planning);
  return {
    charCount: text.length,
    lineCount: lines.length,
    hasCodeFence: /```/.test(text),
    hasMarkdownHeading: lines.some((line) => /^#{1,6}\s+\S/.test(line)),
    hasLongLine: lines.some((line) => line.length > 220),
    hasJsonLikeText: trimmed.startsWith("{") || trimmed.startsWith("["),
    hasUrl: /\bhttps?:\/\/\S+/i.test(text),
    hasFilePath,
    hasFileLikeToken,
    hasDiffLikeText,
    isLongMaterial: text.length > 1600 || lines.length > 28 || lines.some((line) => line.length > 420),
    hasWorkspace: Boolean(planning.defaultAgentFolder) || planning.localFileSources.length > 0,
    hasContextAssets: Boolean(compaction?.assetRefs?.length)
  };
}

function hasPathLikeText(text) {
  const value = String(text || "");
  return /(?:^|[\s"'(])(?:[A-Za-z]:[\\/]|\\\\[^\\/\s]+[\\/]|\.{1,2}[\\/]|\/[^/\s]+[\\/])/.test(value);
}

function hasFileLikeTokenText(text) {
  const value = String(text || "");
  return /(?:^|[\s"'(（])[\w.\-\u4e00-\u9fff]+?\.(?:md|markdown|json|jsonl|txt|csv|tsv|ya?ml|docx?|pdf|html?|jsx?|tsx?|mjs|cjs|css|scss|png|jpe?g|webp)(?=$|[\s"'，。；、,;)）])/i.test(value);
}

function summarizePlanningToolAvailability(novel) {
  const settings = normalizeAgentToolSettings(novel?.planning?.agentToolSettings);
  return {
    webEnabled: settings.webEnabled,
    shellEnabled: settings.shellEnabled,
    customToolsEnabled: settings.customToolsEnabled,
    mcpEnabled: settings.mcpEnabled,
    permissionMode: normalizeAgentPermissionMode(novel?.planning?.agentPermissionMode)
  };
}

function buildPlanningChatMessages(store, novel, userMessage, contextPack, agentState = {}) {
  const history = buildPlanningPromptHistory(novel, agentState.branchId || novel?.planning?.activeBranchId);
  const messageAttachmentSummary = summarizePlanningAttachmentsForPrompt(agentState.messageAttachments, userMessage);
  const budget = calculatePlanningContextBudget(store, novel, userMessage, contextPack, {
    ...agentState,
    setting: agentState.setting || novel?.aiRoles?.planner,
    messageAttachments: messageAttachmentSummary,
    model: agentState.model || novel?.aiRoles?.planner?.model || ""
  });
  const runtimeContext = buildSkillRuntimeContext(novel);
  // 策划 Agent 不能把整本世界书、全部角色卡和长正文常驻进 prompt。
  // Codex 类工具的关键是“摘要常驻 + 工具按需读证据”，完整资料应走 search/read 工具。
  const project = compactNovelForPlanningBudget(novel);
  return [
    ...history,
    {
      role: "user",
      content: JSON.stringify({
        task: "planning_chat",
        userMessage,
        contextPack: budget.exceeded ? compactContextPackForBudget(contextPack) : contextPack,
        skillRuntime: runtimeContext,
        conversationCompaction: formatPlanningCompactionForPrompt(novel.planning?.contextCompaction),
        retrievalPlan: buildLayeredRetrievalPlan(novel, userMessage, contextPack, budget),
        project,
        availableProviders: collectProviderOptions(store),
        agentState: {
          step: clampInteger(agentState.step, 1, 1000, 1),
          branchId: normalizePlanningBranchId(agentState.branchId || novel?.planning?.activeBranchId || "main"),
          observations: Array.isArray(agentState.observations) ? agentState.observations.slice(-6) : [],
          taskPlan: normalizePlanningTaskPlan(agentState.taskPlan),
          taskGraph: normalizePlanningTaskGraph(agentState.taskGraph, agentState.taskPlan),
          doneCriteria: normalizeStringList(agentState.doneCriteria).slice(0, 12),
          completionCheck: normalizePlanningCompletionVerifier(agentState.completionCheck),
          steering: normalizePlanningRunSteeringForPrompt(agentState.steering),
          evidencePlan: normalizePlanningEvidencePlan(agentState.evidencePlan),
          messageAttachments: messageAttachmentSummary,
          decisionHints: buildPlanningAgentDecisionHints(novel, userMessage, agentState.messageAttachments),
          budget,
          runProtection: {
            kind: "internal_safety_budget",
            remainingCycles: Math.max(0, PLANNING_AGENT_STEP_BUDGET - clampInteger(agentState.step, 1, 1000, 1) + 1),
            note: "这是服务端防止失控消耗的内部保护，不是任务流程。不要为了预算提前收束；只有完成、阻塞或需要确认时才停止。"
          },
          steeringRule: "steering 是用户在本次 run 运行中追加的补充消息。它不是下一条排队消息，优先级高于原始对话中尚未执行的部分；必须据此调整当前计划和后续工具调用。已经完成且不可撤销的动作要如实说明，再修正后续动作。",
          rule: "evidenceScheduler observation 是后端自动读入的历史证据，不代表你已经完成本轮工具执行；如果只有这类 observation，仍需根据用户目标决定是否调用工具。若已有非 evidenceScheduler observation，必须先阅读工具结果，再决定继续 skillOps、修正操作或输出 final。"
        }
      }, null, 2)
    }
  ];
}

function calculatePlanningContextBudget(store, novel, userMessage, contextPack, agentState = {}) {
  const contextText = buildPlanningFullContextText(store, novel, userMessage, contextPack, agentState);
  const model = agentState.model || novel?.aiRoles?.planner?.model || "";
  const contextProfile = resolvePlanningModelContextProfile(store, novel, agentState);
  const promptStats = estimatePlanningTokens(contextText, { model });
  const estimatedPromptChars = promptStats.chars;
  const estimatedPromptTokens = promptStats.tokens;
  const promptBudgetTokens = contextProfile.promptBudgetTokens;
  const promptBudgetChars = Math.max(PLANNING_CONTEXT_BUDGET_CHARS, Math.round(promptBudgetTokens * 1.8));
  const budget = {
    promptBudgetChars,
    promptBudgetTokens,
    contextWindowTokens: contextProfile.contextWindowTokens,
    responseReserveTokens: contextProfile.responseReserveTokens,
    safetyTokens: contextProfile.safetyTokens,
    compressionTriggerTokens: contextProfile.compressionTriggerTokens,
    compactionPressureRatio: contextProfile.compactionPressureRatio,
    tokenBudgetSource: contextProfile.budgetSource || contextProfile.source,
    profileSource: contextProfile.source,
    estimatedPromptChars,
    estimatedPromptTokens,
    estimatedResponseChars: 5000,
    estimatedResponseTokens: estimatePlanningTokens("x".repeat(5000), { model }).tokens,
    tokenizer: promptStats.tokenizer,
    tokenEstimateIsFallback: promptStats.estimated,
    layerBudget: estimatePlanningLayerBudget(store, novel, userMessage, contextPack, { ...agentState, model }),
    truncatedSections: [],
    exceeded: estimatedPromptTokens > promptBudgetTokens || estimatedPromptChars > promptBudgetChars
  };
  if (budget.exceeded) {
    budget.truncatedSections.push("project", "contextPack", "toolOutputs");
  }
  return normalizePlanningBudget(budget);
}

function resolvePlanningModelContextProfile(store, novel, agentState = {}) {
  const roleSetting = normalizeAiSetting(agentState.setting || novel?.aiRoles?.planner, createAiSetting());
  const model = String(agentState.model || roleSetting.model || novel?.aiRoles?.planner?.model || "");
  const providerId = String(roleSetting.providerId || novel?.aiRoles?.planner?.providerId || "");
  const provider = (store?.providers || []).find((item) => item.id === providerId);
  const profile = provider?.modelProfiles?.[model] || null;
  const runtimeWindow = normalizeContextWindowTokens(agentState.contextWindowOverrideTokens || agentState.contextWindowTokens);
  const roleWindow = normalizeContextWindowTokens(roleSetting.contextWindowTokens);
  const profileWindow = normalizeContextWindowTokens(profile?.contextWindowTokens);
  const inferredWindow = inferModelContextWindowTokens(model);
  const contextWindowTokens = runtimeWindow || roleWindow || profileWindow || inferredWindow || PLANNING_CONTEXT_OPTIMISTIC_DEFAULT_TOKENS;
  const defaultResponseReserve = Math.min(24000, Math.max(1200, Math.floor(contextWindowTokens * 0.18)));
  const roleResponseReserve = normalizeTokenBudgetOverride(roleSetting.responseReserveTokens);
  const profileResponseReserve = normalizeTokenBudgetOverride(profile?.responseReserveTokens || profile?.outputReserveTokens);
  const responseReserveTokens = clampInteger(
    roleResponseReserve || profileResponseReserve,
    1000,
    Math.max(1000, Math.floor(contextWindowTokens * 0.4)),
    defaultResponseReserve
  );
  const roleSafetyTokens = normalizeTokenBudgetOverride(roleSetting.safetyTokens);
  const profileSafetyTokens = normalizeTokenBudgetOverride(profile?.safetyTokens);
  const safetyTokens = roleSafetyTokens || profileSafetyTokens
    ? clampInteger(roleSafetyTokens || profileSafetyTokens, 0, Math.max(0, Math.floor(contextWindowTokens * 0.3)), roleSafetyTokens || profileSafetyTokens)
    : Math.max(800, Math.floor(contextWindowTokens * 0.04));
  // prompt 预算按模型窗口反推，避免用固定 32k 把 8k/16k 模型塞爆。
  const availablePromptTokens = Math.max(0, contextWindowTokens - responseReserveTokens - safetyTokens);
  const rolePromptBudget = normalizeTokenBudgetOverride(roleSetting.promptBudgetTokens);
  const profilePromptBudget = normalizeTokenBudgetOverride(profile?.promptBudgetTokens);
  const autoPromptBudgetTokens = Math.max(2000, Math.min(availablePromptTokens, Math.floor(contextWindowTokens * 0.86)));
  const promptBudgetTokens = rolePromptBudget || profilePromptBudget
    ? Math.max(1000, Math.min(rolePromptBudget || profilePromptBudget, availablePromptTokens || 1000))
    : autoPromptBudgetTokens;
  const roleRatio = clampNumber(roleSetting.compactionPressureRatio, 0, 0.98, 0);
  const profileRatio = clampNumber(profile?.compactionPressureRatio, 0, 0.98, 0);
  const compactionPressureRatio = roleRatio || profileRatio || PLANNING_COMPACTION_PRESSURE_RATIO;
  const roleCompressionTrigger = normalizeTokenBudgetOverride(roleSetting.compressionTriggerTokens);
  const profileCompressionTrigger = normalizeTokenBudgetOverride(profile?.compressionTriggerTokens);
  const compressionTriggerTokens = roleCompressionTrigger || profileCompressionTrigger
    ? Math.min(promptBudgetTokens, roleCompressionTrigger || profileCompressionTrigger)
    : Math.floor(promptBudgetTokens * compactionPressureRatio);
  const hasRoleBudgetOverride = Boolean(roleWindow || roleResponseReserve || roleSafetyTokens || rolePromptBudget || roleCompressionTrigger);
  const hasProfileBudgetOverride = Boolean(profileWindow || profileResponseReserve || profileSafetyTokens || profilePromptBudget || profileCompressionTrigger);
  return {
    model,
    providerId,
    contextWindowTokens,
    responseReserveTokens,
    safetyTokens,
    promptBudgetTokens,
    compressionTriggerTokens,
    compactionPressureRatio,
    budgetSource: hasRoleBudgetOverride ? "role_model_budget" : hasProfileBudgetOverride ? `provider_profile:${profile?.source || "manual"}` : "auto_budget",
    source: runtimeWindow ? "runtime_context_backoff" : roleWindow ? "role_model_context" : profileWindow ? `provider_profile:${profile.source || "manual"}` : inferredWindow ? "model_name_inferred" : "optimistic_default"
  };
}

function isProviderContextExceededError(error) {
  const classified = classifyAgentError(error);
  const text = `${classified.code || ""} ${classified.message || ""} ${JSON.stringify(classified.details || {})}`.toLowerCase();
  return classified.code === "provider.context_exceeded"
    || /context|token|maximum context|上下文|超限/.test(text);
}

function calculatePlanningContextBackoffWindow(budget, previousWindow = 0) {
  const currentWindow = normalizeContextWindowTokens(previousWindow || budget?.contextWindowTokens) || PLANNING_CONTEXT_OPTIMISTIC_DEFAULT_TOKENS;
  const estimatedPrompt = clampInteger(budget?.estimatedPromptTokens, 0, 2000000, Math.floor(currentWindow * 0.72));
  const byWindow = Math.floor(currentWindow * 0.58);
  const byPrompt = estimatedPrompt > 0 ? Math.floor(estimatedPrompt * 0.96) : byWindow;
  const next = Math.min(byWindow, byPrompt);
  return normalizeContextWindowTokens(Math.max(8000, next));
}

function applyProviderContextBackoffProfile(provider, model, contextWindowTokens) {
  const targetModel = String(model || "").trim();
  const windowTokens = normalizeContextWindowTokens(contextWindowTokens);
  if (!provider || !targetModel || !windowTokens) return null;
  const previous = provider.modelProfiles?.[targetModel] || {};
  const previousWindow = normalizeContextWindowTokens(previous.contextWindowTokens);
  const nextWindow = previousWindow ? Math.min(previousWindow, windowTokens) : windowTokens;
  provider.modelProfiles = normalizeProviderModelProfiles({
    ...(provider.modelProfiles || {}),
    [targetModel]: {
      ...previous,
      contextWindowTokens: nextWindow,
      responseReserveTokens: Math.min(24000, Math.max(1200, Math.floor(nextWindow * 0.18))),
      source: "auto_backoff",
      updatedAt: nowIso()
    }
  });
  return provider.modelProfiles[targetModel] || null;
}

function estimatePlanningFullContextChars(store, novel, userMessage, contextPack, agentState = {}) {
  return buildPlanningFullContextText(store, novel, userMessage, contextPack, agentState).length;
}

function buildPlanningFullContextText(store, novel, userMessage, contextPack, agentState = {}) {
  const historyTail = buildPlanningPromptHistory(novel, agentState.branchId || novel?.planning?.activeBranchId);
  const payload = {
    task: "planning_chat",
    userMessage,
    contextPack,
    skillRuntime: buildSkillRuntimeContext(novel),
    conversationCompaction: formatPlanningCompactionForPrompt(novel.planning?.contextCompaction),
    historyTail,
    project: compactNovelForPlanningBudget(novel),
    availableProviders: collectProviderOptions(store),
    agentState
  };
  return `${buildPlanningSystemPrompt()}\n${JSON.stringify(payload)}`;
}

function estimatePlanningLayerBudget(store, novel, userMessage, contextPack, agentState = {}) {
  const model = agentState.model || novel?.aiRoles?.planner?.model || "";
  const historyTail = buildPlanningPromptHistory(novel, agentState.branchId || novel?.planning?.activeBranchId);
  const layers = {
    system: buildPlanningSystemPrompt(),
    historyTail: JSON.stringify(historyTail),
    conversationCompaction: JSON.stringify(formatPlanningCompactionForPrompt(novel.planning?.contextCompaction)),
    contextPack: JSON.stringify(contextPack || {}),
    project: JSON.stringify(compactNovelForPlanningBudget(novel)),
    providers: JSON.stringify(collectProviderOptions(store)),
    contextAssets: JSON.stringify(normalizePlanningContextCompaction(novel.planning?.contextCompaction)?.assetRefs || []),
    agentState: JSON.stringify(agentState || {}),
    userMessage: String(userMessage || "")
  };
  const result = {};
  for (const [key, text] of Object.entries(layers)) {
    const stats = estimatePlanningTokens(text, { model });
    result[key] = {
      chars: stats.chars,
      tokens: stats.tokens
    };
  }
  return result;
}

function buildLayeredRetrievalPlan(novel, userMessage, contextPack, budget) {
  const compaction = normalizePlanningContextCompaction(novel.planning?.contextCompaction);
  const layerBudget = budget?.layerBudget || {};
  return {
    strategy: "layered_rag_then_asset_refs",
    instruction: "先区分 contextPack 的固定上下文、世界书触发、长期记忆、RAG 检索证据和近场历史；需要旧工具原文或被压缩历史时，优先根据 assetRefs 调用 readContextAsset，再决定是否写入档案、长期记忆或世界书。",
    layers: [
      { name: "fixed_archives", source: "archives/characters/lorebook", use: "稳定设定和角色输入", tokens: layerBudget.project?.tokens || 0 },
      { name: "agent_context_pack", source: "fixedContext + triggeredLore + structuredMemory + retrievedEvidence + recentContext", use: "本轮上下文包", tokens: layerBudget.contextPack?.tokens || 0 },
      { name: "conversation_compaction", source: "planning.contextCompaction", use: "较早策划线程摘要", tokens: layerBudget.conversationCompaction?.tokens || 0 },
      { name: "context_assets", source: "tool result assets", use: "大工具结果和压缩原文按需读取", refs: compaction?.assetRefs || [] },
      { name: "recent_tail", source: "recent planning messages", use: "最近对话原文", tokens: layerBudget.historyTail?.tokens || 0 }
    ],
    query: limitText(String(userMessage || contextPack?.query || ""), 800),
    pressure: {
      exceeded: Boolean(budget?.exceeded),
      promptBudgetTokens: budget?.promptBudgetTokens || PLANNING_CONTEXT_BUDGET_TOKENS,
      estimatedPromptTokens: budget?.estimatedPromptTokens || 0
    }
  };
}

function compactNovelForPlanningBudget(novel) {
  const base = compactNovelForPlanning(novel);
  const lorebook = normalizeLorebook(novel.lorebook);
  return {
    ...base,
    projectSummary: {
      lorebookEntries: lorebook.entries.length,
      characters: Array.isArray(novel.characters) ? novel.characters.length : 0,
      memoryItems: Array.isArray(novel.memory?.items) ? novel.memory.items.length : 0,
      recentTurns: Array.isArray(novel.session?.turns) ? novel.session.turns.length : 0,
      proseParts: Array.isArray(novel.session?.proseParts) ? novel.session.proseParts.length : 0,
      note: "这里只给策划 Agent 常驻摘要。需要完整条目、旧稿或审计原文时必须调用 search/read 工具按需读取。"
    },
    planningMessagesTail: (novel.planning?.messages || []).slice(-4).map((message) => ({
      role: message.role,
      content: limitText(getPlanningMessageVisibleContent(message), 800)
    })),
    archives: {
      ...base.archives,
      background: limitText(base.archives?.background, 2200),
      outline: limitText(base.archives?.outline, 2200),
      characters: (base.archives?.characters || []).slice(-16),
      scenes: (base.archives?.scenes || []).slice(-16),
      clues: (base.archives?.clues || []).slice(-16)
    },
    lorebook: compactLorebookForPlanningBudget(lorebook),
    characters: (novel.characters || []).slice(0, 24).map(compactCharacterForPlanningBudget),
    session: {
      turnIndex: novel.session?.turnIndex || 0,
      recentTurns: (novel.session?.turns || []).slice(-3).map(compactTurnForPrompt),
      recentProse: (novel.session?.proseParts || []).slice(-3).map((part) => ({
        id: part.id,
        status: part.status,
        text: limitText(part.text, 1000)
      }))
    },
    latestProse: limitText(base.latestProse || "", 1600)
  };
}

function compactLorebookForPlanningBudget(lorebook) {
  const normalized = normalizeLorebook(lorebook);
  const entries = normalized.entries
    .filter((entry) => entry.enabled !== false)
    .slice(0, 32)
    .map((entry) => ({
      id: entry.id,
      name: entry.name,
      keys: entry.keys,
      secondaryKeys: entry.secondaryKeys,
      scope: entry.scope,
      ownerId: entry.ownerId,
      position: entry.position,
      priority: entry.priority,
      visibility: entry.visibility,
      contentPreview: limitText(entry.content, 420)
    }));
  return {
    settings: normalized.settings,
    count: normalized.entries.length,
    included: entries.length,
    omitted: Math.max(0, normalized.entries.length - entries.length),
    entries
  };
}

function compactCharacterForPlanningBudget(character) {
  const card = characterCardForPrompt(character);
  return {
    id: character.id,
    name: card.name,
    roleType: card.roleType,
    description: limitText(card.description, 700),
    personality: limitText(card.personality, 700),
    scenario: limitText(card.scenario, 700),
    firstMessage: limitText(card.firstMessage, 400),
    exampleDialog: limitText(card.exampleDialog, 700),
    systemPrompt: limitText(card.systemPrompt, 500),
    postHistoryInstructions: limitText(card.postHistoryInstructions, 500),
    tags: card.tags,
    lorebookPreview: limitText(card.lorebook, 500)
  };
}

function compactContextPackForBudget(contextPack) {
  const pack = contextPack && typeof contextPack === "object" ? contextPack : {};
  return {
    ...pack,
    triggeredLore: (pack.triggeredLore || []).slice(0, 8).map((item) => ({ ...item, text: limitText(item.text, 700) })),
    structuredMemory: (pack.structuredMemory || pack.structured || []).slice(0, 12).map((item) => ({ ...item, value: limitText(item.value, 700), evidence: (item.evidence || []).slice(0, 2) })),
    retrievedEvidence: (pack.retrievedEvidence || pack.retrieved || []).slice(0, 8).map((item) => ({ ...item, text: limitText(item.text, 700) })),
    structured: undefined,
    retrieved: undefined,
    recentContext: (pack.recentContext || []).slice(-4).map((item) => ({ ...item, text: limitText(item.text, 700) })),
    promptSections: (pack.promptSections || []).slice(0, 24).map((item) => ({ ...item, text: limitText(item.text, 700) }))
  };
}

async function inspectPlanningContextAssets(novel, options = {}) {
  const root = await ensureContextAssetRoot(novel);
  const files = await listContextAssetFiles(root);
  const targetBranchId = options.branchId ? normalizePlanningBranchId(options.branchId) : "";
  const planning = normalizePlanning(novel?.planning);
  const runBranchById = new Map((planning.runs || []).map((run) => [run.id, normalizePlanningBranchId(run.branchId || "main")]));
  const messageBranchById = new Map((planning.messages || []).map((message) => [message.id, normalizePlanningBranchId(message.branchId || "main")]));
  const assets = [];
  for (const filePath of files.slice(-200)) {
    const raw = await fs.readFile(filePath, "utf8").catch(() => "");
    const parsed = parseLooseJson(raw);
    if (!parsed || typeof parsed !== "object") continue;
    const sourceRunId = String(parsed.sourceRunId || "");
    const sourceMessageId = String(parsed.sourceMessageId || "");
    const rawBranchId = parsed.branchId || runBranchById.get(sourceRunId) || messageBranchById.get(sourceMessageId) || "";
    const branchId = rawBranchId ? normalizePlanningBranchId(rawBranchId) : "";
    if (targetBranchId && (!branchId || branchId !== targetBranchId)) continue;
    assets.push({
      id: String(parsed.id || ""),
      kind: String(parsed.kind || ""),
      title: String(parsed.title || ""),
      relativePath: path.relative(root, filePath).replace(/\\/g, "/"),
      chars: Number(parsed.chars || 0),
      tokens: Number(parsed.tokens || 0),
      branchId,
      sourceRunId,
      sourceMessageId,
      sourceToolType: String(parsed.sourceToolType || ""),
      createdAt: String(parsed.createdAt || "")
    });
  }
  const kinds = {};
  for (const asset of assets) {
    kinds[asset.kind || "unknown"] = (kinds[asset.kind || "unknown"] || 0) + 1;
  }
  return {
    root,
    branchId: targetBranchId,
    count: assets.length,
    totalChars: assets.reduce((sum, item) => sum + (item.chars || 0), 0),
    totalTokens: assets.reduce((sum, item) => sum + (item.tokens || 0), 0),
    kinds,
    assets: assets
      .sort((a, b) => String(b.createdAt).localeCompare(String(a.createdAt)))
      .slice(0, clampInteger(options.limit, 1, 80, 30))
  };
}

async function revertPlanningContextCompactionToVersion(novel, body = {}) {
  novel.planning = normalizePlanning(novel.planning);
  const current = normalizePlanningContextCompaction(novel.planning.contextCompaction);
  if (!current) {
    throw new HttpError(404, "当前没有可回滚的压缩摘要");
  }
  const targetVersion = clampInteger(body.version, 1, 100000, 0);
  const targetId = String(body.id || body.compactionId || "").trim();
  const targetEntry = [...(current.versionChain || [])]
    .reverse()
    .find((entry) => (targetVersion && entry.version === targetVersion) || (targetId && entry.id === targetId));
  if (!targetEntry) {
    throw new HttpError(404, "没有找到指定压缩版本");
  }
  if (targetEntry.id === current.id) {
    return { restored: false, compaction: current, reason: "已经是目标压缩版本" };
  }
  const candidates = (current.assetRefs || []).filter((asset) => asset.kind === "context_compaction");
  for (const assetRef of candidates.reverse()) {
    const asset = await readPlanningContextAsset(novel, assetRef.id).catch(() => null);
    const compaction = normalizePlanningContextCompaction(asset?.payload?.compaction || asset?.compaction || null);
    if (!compaction) continue;
    if (compaction.id === targetEntry.id || compaction.version === targetEntry.version) {
      const restored = normalizePlanningContextCompaction({
        ...compaction,
        versionChain: (current.versionChain || []).filter((entry) => entry.version <= compaction.version),
        assetRefs: uniqueContextAssetRefs([
          ...(compaction.assetRefs || []),
          assetRef
        ]),
        updatedAt: nowIso()
      });
      novel.planning.contextCompaction = restored;
      recordEvent(novel, "planning_context_compaction_reverted", {
        fromVersion: current.version,
        toVersion: restored.version,
        compactionId: restored.id
      });
      updateTimestamp(novel);
      return { restored: true, compaction: restored };
    }
  }
  throw new HttpError(404, "指定压缩版本缺少可恢复快照资产，无法单独回滚");
}

async function extractArchivesFromPlanning(store, novel) {
  novel.planning = normalizePlanning(novel.planning);
  const plannerSetting = novel.aiRoles.planner;
  const plannerProvider = getConfiguredProvider(store, plannerSetting, "策划助手 AI");
  const result = await requestAi({
    provider: plannerProvider,
    model: plannerSetting.model,
    temperature: plannerSetting.temperature,
    systemPrompt: buildArchiveExtractionSystemPrompt(),
    messages: [
      {
        role: "user",
        content: buildArchiveExtractionUserPrompt(novel)
      }
    ]
  });
  const parsed = parseLooseJson(result.text);
  const archivePatch = parsed?.archivePatch || parsed?.archives || parsed;
  if (!archivePatch || typeof archivePatch !== "object") {
    throw new HttpError(502, "档案提取没有返回可识别的结构化 JSON", safeRemoteText(result.text));
  }
  const archiveDiagnostics = normalizeArchiveDiagnostics(parsed?.archiveDiagnostics || parsed?.diagnostics);
  const toolReport = await executePlanningSkillOps(store, novel, [{
    type: "applyArchivePatch",
    patch: archivePatch,
    archiveDiagnostics,
    reason: "旧档案提取接口兼容：通过统一工具执行器写入档案"
  }], {
    sourceType: "extract_archives",
    sourceId: "",
    queryText: "从现有策划对话提取并沉淀档案",
    protocol: "tool_registry_compat"
  });
  const writeReport = extractArchiveWriteReportFromToolReport(toolReport);
  const appliedArchivePatch = writeReport?.patch || archivePatch;
  const mergedDiagnostics = mergeArchiveDiagnostics(archiveDiagnostics, writeReport);
  const assistantRecord = {
    id: createId("msg"),
    role: "assistant",
    content: "已根据现有策划对话重新整理项目档案。下面是本次实际写入、跳过和需要继续确认的内容。",
    createdAt: nowIso(),
    archivePatch: appliedArchivePatch,
    archiveDiagnostics: mergedDiagnostics,
    skillOps: [{ type: "applyArchivePatch", reason: "旧档案提取接口兼容：通过统一工具执行器写入档案" }],
    skillOpReport: compactSkillOpReportForStorage(toolReport),
    raw: result.raw
  };
  assistantRecord.skillOpReport.sourceId = assistantRecord.id;
  novel.planning.messages.push(assistantRecord);
  recordEvent(novel, "archives_extracted", {
    source: "planning_chat",
    messageId: assistantRecord.id,
    conflictCount: archiveDiagnostics?.conflicts?.length || 0,
    correctionCount: archiveDiagnostics?.corrections?.length || 0
  });
  updateTimestamp(novel);
  return { archivePatch: appliedArchivePatch, archiveDiagnostics: mergedDiagnostics, message: assistantRecord, raw: result.raw, text: result.text };
}

function buildArchiveExtractionSystemPrompt() {
  return buildSkillArchiveExtractionSystemPrompt();
}

function buildArchiveExtractionUserPrompt(novel) {
  return JSON.stringify({
    task: "extract_archives",
    skillRuntime: buildSkillRuntimeContext(novel),
    project: compactNovelForPlanning(novel),
    planningMessages: novel.planning.messages.map((message) => ({
      role: message.role,
      content: message.content
    }))
  }, null, 2);
}

async function generateRoleplayConfigDraft(store, novel) {
  const plannerSetting = novel.aiRoles.planner;
  const plannerProvider = getConfiguredProvider(store, plannerSetting, "策划助手 AI");
  const result = await requestAi({
    provider: plannerProvider,
    model: plannerSetting.model,
    temperature: plannerSetting.temperature,
    systemPrompt: buildRoleplayConfigSystemPrompt(),
    messages: [
      {
        role: "user",
        content: buildRoleplayConfigUserPrompt(store, novel)
      }
    ]
  });
  const parsed = parseLooseJson(result.text);
  const rawConfig = parsed?.config || parsed?.roleplayConfig || parsed;
  if (!rawConfig || typeof rawConfig !== "object") {
    throw new HttpError(502, "扮演配置生成没有返回可识别的结构化 JSON", safeRemoteText(result.text));
  }
  const config = normalizeRoleplayConfig(rawConfig, store, novel);
  const draft = {
    id: createId("draft"),
    createdAt: nowIso(),
    config,
    raw: result.raw
  };
  novel.planning.roleplayDrafts.unshift(draft);
  novel.planning.roleplayDrafts = novel.planning.roleplayDrafts.slice(0, 10);
  recordEvent(novel, "roleplay_config_generated", { draftId: draft.id });
  updateTimestamp(novel);
  return draft;
}

function buildRoleplayConfigSystemPrompt() {
  return buildSkillRoleplayConfigSystemPrompt();
}

function buildRoleplayConfigUserPrompt(store, novel) {
  return JSON.stringify({
    task: "generate_roleplay_config",
    skillRuntime: buildSkillRuntimeContext(novel),
    project: compactNovelForPlanning(novel),
    defaultRoleplayConfig: novel.planning?.defaultRoleplayConfig || null,
    availableProviders: collectProviderOptions(store),
    rule: "主要角色需要独立 providerId 和 model；次要角色不单独配置 providerId 和 model。若 defaultRoleplayConfig 存在，它只代表这本书最近一次成功保存的配置，可作为默认基线；本次生成的新草案不要直接视为已保存配置。"
  }, null, 2);
}

async function applyRoleplayConfig(store, novel, body) {
  const config = resolveRoleplayConfigBody(novel, body);
  const normalizedConfig = normalizeRoleplayConfig(config, store, novel);
  applyRoleplayConfigToNovel(novel, normalizedConfig);
  setDefaultRoleplayConfig(novel, normalizedConfig, {
    source: body.config ? "saved_inline" : body.draftId ? "saved_draft" : "saved_default",
    sourceDraftId: body.draftId || ""
  });
  projectArchivesToMemory(novel, { type: "archive", id: "roleplay_config" });
  for (const character of novel.characters) {
    projectCharacterToMemory(novel, character, { type: "character_card", id: character.id });
  }
  recordEvent(novel, "roleplay_config_applied", {
    draftId: body.draftId || "",
    runAfter: Boolean(body.runAfter)
  });
  updateTimestamp(novel);
  let turn = null;
  if (body.runAfter) {
    turn = await runRoleplayTurn(store, novel);
  }
  return { applied: normalizedConfig, turn };
}

function resolveRoleplayConfigBody(novel, body) {
  if (body.config && typeof body.config === "object") {
    return body.config;
  }
  const draftId = String(body.draftId || "").trim();
  if (!draftId) {
    const defaultConfig = novel.planning?.defaultRoleplayConfig?.config;
    if (defaultConfig && typeof defaultConfig === "object") {
      return defaultConfig;
    }
  }
  const draft = draftId
    ? novel.planning.roleplayDrafts.find((item) => item.id === draftId)
    : novel.planning.roleplayDrafts[0];
  if (!draft) {
    const defaultConfig = !draftId ? novel.planning?.defaultRoleplayConfig?.config : null;
    if (defaultConfig && typeof defaultConfig === "object") {
      return defaultConfig;
    }
    throw new HttpError(400, "没有可采纳的扮演配置草案或默认配置");
  }
  return draft.config;
}

function setDefaultRoleplayConfig(novel, config, meta = {}) {
  novel.planning = normalizePlanning(novel.planning);
  novel.planning.defaultRoleplayConfig = normalizeDefaultRoleplayConfigRecord({
    id: createId("roleplay_default"),
    source: meta.source || "manual",
    sourceDraftId: meta.sourceDraftId || "",
    updatedAt: nowIso(),
    config
  });
}

function normalizeRoleplayConfig(config, store, novel) {
  const fallback = pickFallbackAiSetting(store, novel.aiRoles.planner || novel.aiRoles.guide);
  const scenario = {
    background: String(config.scenario?.background ?? novel.scenario.background ?? ""),
    time: String(config.scenario?.time ?? novel.scenario.time ?? ""),
    place: String(config.scenario?.place ?? novel.scenario.place ?? ""),
    plotDirection: String(config.scenario?.plotDirection ?? novel.scenario.plotDirection ?? ""),
    tone: String(config.scenario?.tone ?? novel.scenario.tone ?? "")
  };
  const aiRoles = {
    guide: normalizeDraftAiSetting(config.aiRoles?.guide, novel.aiRoles.guide, fallback),
    minor: normalizeDraftAiSetting(config.aiRoles?.minor, novel.aiRoles.minor, fallback),
    adapter: normalizeDraftAiSetting(config.aiRoles?.adapter, novel.aiRoles.adapter, fallback)
  };
  const sourceCharacters = collectRoleplayConfigCharacterSources(config, novel);
  const characters = sourceCharacters
    .map((character) => normalizeDraftCharacter(character, store, fallback))
    .filter((character) => character.name);
  return { scenario, aiRoles, characters };
}

function collectRoleplayConfigCharacterSources(config, novel) {
  const explicitCharacters = [
    ...normalizeRoleplayConfigCharacterArray(config.characters),
    ...normalizeRoleplayConfigCharacterArray(config.majorCharacters).map((item) => ({ ...item, roleType: "major" })),
    ...normalizeRoleplayConfigCharacterArray(config.minorCharacters).map((item) => ({ ...item, roleType: "minor" }))
  ];
  if (explicitCharacters.length > 0) {
    return explicitCharacters;
  }
  return normalizeRoleplayConfigCharacterArray(novel.archives?.characters);
}

function normalizeRoleplayConfigCharacterArray(value) {
  return Array.isArray(value) ? value.filter((item) => item && typeof item === "object") : [];
}

function normalizeDraftAiSetting(next, previous, fallback) {
  const base = normalizeAiSetting(next, previous?.providerId || previous?.model ? previous : fallback);
  return {
    providerId: base.providerId || fallback.providerId,
    model: base.model || fallback.model,
    temperature: clampTemperature(base.temperature ?? fallback.temperature)
  };
}

function normalizeDraftCharacter(character, store, fallback) {
  const source = character && typeof character === "object" ? character : {};
  const card = normalizeCardLikeInput(character);
  const roleType = card.roleType === "minor" ? "minor" : "major";
  const setting = normalizeDraftAiSetting(source, null, fallback);
  return {
    id: String(source.id || ""),
    roleType,
    name: card.name,
    description: card.description,
    personality: card.personality,
    scenario: card.scenario,
    firstMessage: card.firstMessage,
    exampleDialog: card.exampleDialog,
    systemPrompt: card.systemPrompt,
    postHistoryInstructions: card.postHistoryInstructions,
    lorebook: card.lorebook,
    tags: card.tags.length > 0 ? uniqueStrings(card.tags) : splitTags(source.tags),
    providerId: roleType === "major" ? setting.providerId : "",
    model: roleType === "major" ? setting.model : "",
    temperature: roleType === "major" ? setting.temperature : 0.8
  };
}

function pickFallbackAiSetting(store, previous) {
  if (previous?.providerId && previous?.model) {
    return normalizeAiSetting(previous, createAiSetting());
  }
  const provider = store.providers.find((item) => item.id === MOCK_PROVIDER_ID) || store.providers[0];
  return {
    providerId: provider?.id || "",
    model: provider?.models?.[0] || "",
    temperature: 0.75
  };
}

function collectProviderOptions(store) {
  return store.providers.map((provider) => ({
    providerId: provider.id,
    name: provider.name,
    endpointKind: provider.endpointKind,
    models: provider.models || [],
    modelProfiles: provider.modelProfiles || {}
  }));
}

function applyRoleplayConfigToNovel(novel, config) {
  novel.scenario = {
    ...novel.scenario,
    ...config.scenario
  };
  novel.aiRoles = {
    ...novel.aiRoles,
    guide: normalizeAiSetting(config.aiRoles.guide, novel.aiRoles.guide),
    minor: normalizeAiSetting(config.aiRoles.minor, novel.aiRoles.minor),
    adapter: normalizeAiSetting(config.aiRoles.adapter, novel.aiRoles.adapter)
  };
  for (const characterConfig of config.characters) {
    const existing = novel.characters.find((character) => character.id === characterConfig.id)
      || novel.characters.find((character) => character.name === characterConfig.name);
    if (existing) {
      Object.assign(existing, normalizeCharacter({
        ...existing,
        ...characterConfig,
        id: existing.id,
        createdAt: existing.createdAt,
        updatedAt: nowIso()
      }));
    } else {
      novel.characters.push(normalizeCharacter({
        ...createDefaultCharacter(characterConfig.roleType),
        ...characterConfig,
        id: createId("char"),
        createdAt: nowIso(),
        updatedAt: nowIso()
      }));
    }
  }
  applyArchivePatch(novel, {
    background: config.scenario.background,
    outline: config.scenario.plotDirection,
    style: config.scenario.tone,
    characters: config.characters.map(characterArchiveFromCharacter)
  });
}

function applyArchivePatch(novel, archivePatch, options = {}) {
  const writeReport = prepareArchivePatchForWrite(novel, archivePatch, options);
  const patch = writeReport.patch;
  const next = {
    ...novel.archives,
    characters: [...(novel.archives.characters || [])],
    scenes: [...(novel.archives.scenes || [])],
    clues: [...(novel.archives.clues || [])]
  };
  for (const key of ["premise", "background", "outline", "style"]) {
    if (typeof patch[key] === "string") {
      next[key] = patch[key].trim();
    }
  }
  next.characters = mergeArchiveArray(next.characters, patch.characters);
  next.scenes = mergeArchiveArray(next.scenes, patch.scenes);
  next.clues = mergeArchiveArray(next.clues, patch.clues);
  next.updatedAt = nowIso();
  novel.archives = normalizeArchives(next, novel.scenario, novel.characters);
  if (typeof patch.background === "string") novel.scenario.background = patch.background.trim();
  if (typeof patch.outline === "string") novel.scenario.plotDirection = patch.outline.trim();
  if (typeof patch.style === "string") novel.scenario.tone = patch.style.trim();
  return writeReport;
}

function prepareArchivePatchForWrite(novel, archivePatch, options = {}) {
  const source = archivePatch && typeof archivePatch === "object" ? archivePatch : {};
  const patch = {};
  const appliedFields = [];
  const skipped = [];
  for (const key of ["premise", "background", "outline", "style"]) {
    if (!Object.hasOwn(source, key)) continue;
    const value = String(source[key] || "").trim();
    if (!value) {
      skipped.push({ field: key, reason: "空值不会覆盖已有档案" });
      continue;
    }
    if (archiveTextLooksTemplate(value)) {
      skipped.push({ field: key, reason: "模板占位文本不能写入档案" });
      continue;
    }
    patch[key] = value;
    appliedFields.push(key);
  }
  for (const [key, type] of [["characters", "character"], ["scenes", "scene"], ["clues", "clue"]]) {
    if (!Array.isArray(source[key])) continue;
    const records = source[key]
      .map((item) => normalizeArchiveRecordForWrite(type, item))
      .filter((item) => {
        if (item.record) return true;
        skipped.push({ field: key, reason: item.reason || "记录不满足写入合同" });
        return false;
      })
      .map((item) => item.record);
    if (records.length > 0) {
      patch[key] = records;
      appliedFields.push(key);
    }
  }
  const diff = buildArchivePatchDiff(novel, patch, { sourceFiles: options.sourceFiles || [] });
  const preview = summarizeArchivePatchDiff(diff, appliedFields);
  return {
    patch,
    appliedFields,
    skipped,
    warnings: detectArchivePatchWarnings(novel, patch),
    diff,
    preview,
    risk: classifyArchivePatchRisk(diff),
    rollbackPlan: buildArchivePatchRollbackPlan(diff)
  };
}

function collectArchivePatchSourceFiles(op = {}, context = {}) {
  const names = [];
  const add = (value) => {
    const raw = String(value || "").trim();
    if (!raw) return;
    if (/\.(md|markdown|txt|json|jsonl|ya?ml|csv)$/i.test(raw) || /^[A-Za-z]:\\/.test(raw)) {
      names.push(raw.replace(/\\/g, "/").split("/").filter(Boolean).pop() || raw);
    }
  };
  const visit = (value, depth = 0) => {
    if (!value || depth > 5) return;
    if (typeof value === "string") {
      add(value);
      return;
    }
    if (Array.isArray(value)) {
      value.slice(0, 80).forEach((item) => visit(item, depth + 1));
      return;
    }
    if (typeof value !== "object") return;
    for (const key of ["sourceFile", "source", "path", "relativePath", "title", "query"]) {
      if (typeof value[key] === "string") add(value[key]);
    }
    for (const key of ["archiveDiagnostics", "evidencePlan", "reads", "topResults", "assetRefs", "results", "source"]) {
      if (value[key]) visit(value[key], depth + 1);
    }
  };
  visit(op.archiveDiagnostics || op.diagnostics);
  visit(context.evidencePlan);
  return uniqueStrings(names).slice(0, 20);
}

function compactArchiveDiffValue(value) {
  if (value === null || value === undefined) return value;
  if (typeof value === "string") return limitText(value, 1200);
  if (Array.isArray(value)) return value.slice(0, 20).map(compactArchiveDiffValue);
  if (typeof value !== "object") return value;
  const result = {};
  for (const [key, item] of Object.entries(value)) {
    if (["raw", "text", "content"].includes(key)) {
      result[key] = limitText(String(item || ""), 900);
    } else {
      result[key] = compactArchiveDiffValue(item);
    }
  }
  return result;
}

function archiveValueChanged(before, after) {
  return JSON.stringify(before ?? null) !== JSON.stringify(after ?? null);
}

function buildArchivePatchDiff(novel, patch, options = {}) {
  const archives = normalizeArchives(novel?.archives, novel?.scenario, novel?.characters);
  const sourceFiles = normalizeStringList(options.sourceFiles).slice(0, 20);
  const changes = [];
  for (const key of ["premise", "background", "outline", "style"]) {
    if (typeof patch[key] !== "string") continue;
    const before = String(archives[key] || "");
    const after = String(patch[key] || "");
    if (!archiveValueChanged(before, after)) continue;
    changes.push({
      id: `archives.${key}`,
      field: key,
      kind: "text",
      action: before ? "replace" : "create",
      before: compactArchiveDiffValue(before),
      after: compactArchiveDiffValue(after),
      sourceFiles
    });
  }
  for (const [field, label] of [["characters", "角色"], ["scenes", "场景"], ["clues", "线索"]]) {
    const incoming = Array.isArray(patch[field]) ? patch[field] : [];
    const existing = Array.isArray(archives[field]) ? archives[field] : [];
    for (const record of incoming) {
      const key = archiveRecordKey(record);
      const before = key ? existing.find((item) => archiveRecordKey(item) === key) || null : null;
      const after = before ? { ...before, ...record } : record;
      const changedFields = uniqueStrings(Object.keys({ ...(before || {}), ...(after || {}) }).filter((name) => archiveValueChanged(before?.[name], after?.[name])));
      if (before && changedFields.length === 0) continue;
      changes.push({
        id: `archives.${field}.${key || createId("record")}`,
        field,
        label,
        key: key || String(record.name || record.title || record.key || ""),
        title: String(record.name || record.title || record.key || ""),
        kind: "record",
        action: before ? "update" : "create",
        changedFields,
        before: compactArchiveDiffValue(before),
        after: compactArchiveDiffValue(after),
        sourceFiles: normalizeStringList(record.sourceFiles || record.sources || record.evidenceFiles || sourceFiles).slice(0, 20)
      });
    }
  }
  return {
    changes,
    totals: {
      created: changes.filter((item) => item.action === "create").length,
      updated: changes.filter((item) => ["update", "replace"].includes(item.action)).length,
      textFields: changes.filter((item) => item.kind === "text").length,
      records: changes.filter((item) => item.kind === "record").length
    },
    sourceFiles
  };
}

function summarizeArchivePatchDiff(diff, appliedFields = []) {
  const changes = Array.isArray(diff?.changes) ? diff.changes : [];
  const byField = changes.reduce((map, item) => {
    map[item.field] = (map[item.field] || 0) + 1;
    return map;
  }, {});
  const parts = Object.entries(byField).map(([field, count]) => `${field} ${count} 项`);
  return {
    summary: parts.length ? `准备写入 ${appliedFields.length} 类档案：${parts.join("、")}` : "没有产生可见差异",
    changedFields: Object.keys(byField),
    changeCount: changes.length,
    created: diff?.totals?.created || 0,
    updated: diff?.totals?.updated || 0,
    sourceFiles: normalizeStringList(diff?.sourceFiles).slice(0, 12)
  };
}

function classifyArchivePatchRisk(diff) {
  const totals = diff?.totals || {};
  const changeCount = Number(diff?.changes?.length || 0);
  const updated = Number(totals.updated || 0);
  if (changeCount >= 20 || updated >= 8) {
    return {
      level: "review_recommended",
      reason: "本次会覆盖或新增较多稳定档案，建议在过程详情中查看 diff 和来源后继续。"
    };
  }
  return {
    level: "low",
    reason: "本次写入未触发大范围覆盖阈值。"
  };
}

function buildArchivePatchRollbackPlan(diff) {
  const changes = Array.isArray(diff?.changes) ? diff.changes : [];
  return {
    mode: "archive_node_snapshot",
    supported: true,
    changeCount: changes.length,
    nodes: changes.map((item) => ({
      id: item.id,
      field: item.field,
      key: item.key || "",
      action: item.action,
      previousValue: compactArchiveDiffValue(item.before),
      nextValue: compactArchiveDiffValue(item.after)
    })).slice(0, 80)
  };
}

function normalizeArchiveRecordForWrite(type, raw) {
  if (!raw || typeof raw !== "object") {
    return { record: null, reason: "记录不是对象" };
  }
  const record = {};
  for (const [key, value] of Object.entries(raw)) {
    if (value === null || value === undefined) continue;
    if (typeof value === "string") {
      const text = value.trim();
      if (text) record[key] = text;
      continue;
    }
    if (Array.isArray(value)) {
      const list = value.map((item) => typeof item === "string" ? item.trim() : item).filter((item) => item !== "" && item !== null && item !== undefined);
      if (list.length > 0) record[key] = list;
      continue;
    }
    record[key] = value;
  }
  const key = archiveRecordKey(record);
  if (!key && type !== "clue") {
    return { record: null, reason: `${type} 缺少 name/title/key，无法稳定合并` };
  }
  if (type === "clue" && !key) {
    return { record: null, reason: "clue 缺少 name/title/key，无法稳定追踪铺垫回收" };
  }
  if (archiveRecordLooksTemplate(record)) {
    return { record: null, reason: `${type} 是模板占位或含待确认占位语，不能写入档案` };
  }
  if (!record.status) {
    record.status = type === "clue" ? "active" : "confirmed";
  }
  if (!record.confidence) {
    record.confidence = "medium";
  }
  return { record, reason: "" };
}

function archiveTextLooksTemplate(text) {
  const value = String(text || "").trim();
  return memoryTextLooksPlaceholder(value);
}

function archiveRecordLooksTemplate(record) {
  const key = String(record.name || record.title || record.key || "").trim();
  if (memorySubjectLooksPlaceholder(key)) return true;
  const payload = JSON.stringify(record);
  return archiveTextLooksTemplate(payload);
}

function detectArchivePatchWarnings(novel, patch) {
  const warnings = [];
  for (const character of patch.characters || []) {
    const existing = findCharacterByName(novel, character.name);
    if (existing && character.roleType && character.roleType !== existing.roleType) {
      warnings.push({
        field: `characters.${character.name}.roleType`,
        reason: `档案角色类型 ${character.roleType} 与角色卡 ${existing.roleType} 不一致`
      });
    }
  }
  for (const clue of patch.clues || []) {
    if (clue.status === "resolved" && !clue.payoff) {
      warnings.push({
        field: `clues.${clue.name || clue.title}.payoff`,
        reason: "线索标记为 resolved 但缺少 payoff"
      });
    }
  }
  return warnings;
}

function mergeArchiveArray(existing, incoming) {
  if (!Array.isArray(incoming)) return existing;
  const result = [...existing];
  for (const rawItem of incoming) {
    if (!rawItem || typeof rawItem !== "object") continue;
    const item = { ...rawItem };
    const key = archiveRecordKey(item);
    const index = key ? result.findIndex((current) => archiveRecordKey(current) === key) : -1;
    if (index >= 0) {
      result[index] = { ...result[index], ...item };
    } else {
      result.push(item);
    }
  }
  return normalizeArchiveList(result);
}

function archiveRecordKey(item) {
  return String(item.name || item.title || item.key || "").trim().toLowerCase();
}

function compactNovelForPlanning(novel) {
  return {
    title: novel.title,
    scenario: novel.scenario,
    aiRoles: novel.aiRoles,
    archives: novel.archives,
    lorebook: normalizeLorebook(novel.lorebook),
    memory: {
      items: (novel.memory?.items || []).slice(-30).map(projectMemoryItemForPack)
    },
    characters: novel.characters.map(characterCardForPrompt),
    session: {
      proseParts: (novel.session.proseParts || []).slice(-10).map((part) => ({
        id: part.id,
        status: part.status,
        turnRange: part.turnRange,
        text: limitText(part.text, 800)
      })),
      reviews: (novel.session.reviews || []).slice(0, 10)
    },
    recentTurns: novel.session.turns.slice(-3).map(compactTurnForPrompt),
    latestProse: getAcceptedProseParts(novel).slice(-1).map((part) => part.text).join("\n")
  };
}

function rebuildNovelMemory(novel) {
  const beforeCount = Array.isArray(novel.memory.items) ? novel.memory.items.length : 0;
  const projectionSourceTypes = new Set(["archive", "character_card", "prose_part", "roleplay_turn"]);
  // 重建记忆不能再把档案、角色卡、正文机械复制成记忆；这些内容属于固定上下文或 RAG 证据层。
  novel.memory.items = (novel.memory.items || [])
    .map(normalizeMemoryItem)
    .filter((item) => !projectionSourceTypes.has(item.source?.type || ""));
  novel.memory.lastInjection = null;
  novel.memory.vectorIndex = {
    ...normalizeVectorIndex(novel.memory.vectorIndex),
    documents: [],
    sourceHash: "",
    documentCount: 0,
    chunkCount: 0,
    stale: true,
    updatedAt: ""
  };
  novel.memory.updatedAt = nowIso();
  return {
    itemCount: novel.memory.items.length,
    removedProjectionCount: beforeCount - novel.memory.items.length,
    note: "已清理机械投影记忆；需要长期事实时请使用记忆整理 AI 或 upsertMemory 写入有证据的单条事实"
  };
}

function projectArchivesToMemory(novel, source) {
  void novel;
  void source;
  return {
    skipped: true,
    reason: "档案属于固定上下文和 RAG 证据层，不再机械投影成长期记忆"
  };
}

function projectCharacterToMemory(novel, character, source) {
  void novel;
  void character;
  void source;
  return {
    skipped: true,
    reason: "角色卡是角色固定上下文，不再自动复制到长期记忆"
  };
}

function projectTurnToMemory(novel, turn) {
  // 扮演原文属于事件日志和检索证据，不是稳定长期记忆。需要长期沉淀时由记忆整理 AI 提取“状态变化 / 关系变化 / 时间线事实”。
  return turn;
}

function projectProseToMemory(novel, prose) {
  void novel;
  void prose;
  return {
    skipped: true,
    reason: "正文原文属于正文库和 RAG 证据层，长期记忆只保存从正文中提取出的事实变化"
  };
}

function findProsePart(novel, proseId) {
  const prose = novel.session.proseParts.find((item) => item.id === proseId);
  if (!prose) {
    throw new HttpError(404, "没有找到正文片段");
  }
  return prose;
}

function buildProseVersionTree(novel) {
  const proseParts = (novel.session?.proseParts || []).map(normalizeProsePart);
  const nodes = proseParts.map((prose) => ({
    id: prose.id,
    proseId: prose.id,
    parentId: prose.baseProseId || "",
    branchId: prose.branchId || prose.id,
    workflowId: prose.workflowId || "",
    versionType: prose.versionType,
    status: prose.status,
    title: `${prose.versionType} / ${prose.status}`,
    textHash: hashText(prose.text || ""),
    textLength: String(prose.text || "").length,
    turnRange: prose.turnRange || [],
    createdAt: prose.createdAt,
    updatedAt: prose.updatedAt,
    acceptedAt: prose.acceptedAt || "",
    discardedAt: prose.discardedAt || "",
    canRollback: (prose.versionHistory || []).length > 1,
    versionCount: (prose.versionHistory || []).length,
    latestVersion: prose.versionHistory?.[prose.versionHistory.length - 1] || null,
    assetRefs: uniqueContextAssetRefs([
      ...(prose.assetRef ? [prose.assetRef] : []),
      ...(prose.assetRefs || []),
      ...(prose.versionHistory || []).flatMap((event) => [
        event.assetRef,
        event.previousAssetRef,
        event.nextAssetRef,
        event.previousSnapshot?.assetRef,
        event.nextSnapshot?.assetRef
      ].filter(Boolean))
    ]),
    preview: limitText(prose.text || "", 220)
  }));
  const links = nodes
    .filter((node) => node.parentId)
    .map((node) => ({
      id: `${node.parentId}->${node.id}`,
      from: node.parentId,
      to: node.id,
      type: "revision"
    }));
  const branches = [...new Set(nodes.map((node) => node.branchId || node.id))]
    .map((branchId) => ({
      id: branchId,
      count: nodes.filter((node) => node.branchId === branchId).length,
      acceptedCount: nodes.filter((node) => node.branchId === branchId && node.status === "accepted").length
    }));
  return {
    nodes,
    links,
    branches,
    stats: {
      total: nodes.length,
      drafts: nodes.filter((node) => node.status === "draft").length,
      accepted: nodes.filter((node) => node.status === "accepted").length,
      discarded: nodes.filter((node) => node.status === "discarded").length,
      branched: nodes.filter((node) => node.parentId).length
    }
  };
}

function buildProseDiff(novel, proseId, fromId = "") {
  const prose = findProsePart(novel, proseId);
  const from = String(fromId || prose.baseProseId || "").trim();
  const base = from ? findProsePart(novel, from) : null;
  const fromText = base ? base.text || "" : "";
  const toText = prose.text || "";
  return {
    proseId: prose.id,
    fromProseId: base?.id || "",
    fromLabel: base ? `prose:${base.id}` : "empty",
    toLabel: `prose:${prose.id}`,
    fromHash: hashText(fromText),
    toHash: hashText(toText),
    changed: fromText !== toText,
    diff: buildClientUnifiedDiff(base ? `prose:${base.id}` : "empty", fromText, `prose:${prose.id}`, toText),
    versionHistory: prose.versionHistory || []
  };
}

async function revertProseVersion(novel, proseId, targetVersionId = "") {
  const prose = findProsePart(novel, proseId);
  const targetId = String(targetVersionId || "").trim();
  const target = targetId
    ? (prose.versionHistory || []).find((event) => event.id === targetId)
    : [...(prose.versionHistory || [])].reverse().find((event) => event.previousHash);
  if (!target) {
    throw new HttpError(404, "没有找到可回滚的正文版本点");
  }
  const baseText = await resolveProseVersionText(novel, prose, target);
  if (baseText === null || baseText === undefined) {
    throw new HttpError(409, "该版本点没有可恢复文本；只能查看 diff，不能精确回滚");
  }
  const previousText = prose.text || "";
  prose.text = baseText;
  prose.status = "draft";
  prose.versionType = "reverted";
  prose.updatedAt = nowIso();
  prose.acceptedAt = "";
  prose.discardedAt = "";
  const event = await appendProseVersionEventWithSnapshots(novel, prose, {
    eventType: "reverted",
    versionType: "reverted",
    previousText,
    nextText: baseText,
    actor: "user",
    summary: `回滚到版本点 ${target.id}`
  });
  recordEvent(novel, "prose_version_reverted", { proseId: prose.id, targetVersionId: target.id, versionEventId: event.id });
  updateTimestamp(novel);
  return { proseId: prose.id, targetVersionId: target.id, versionEventId: event.id };
}

async function resolveProseVersionText(novel, prose, versionEvent) {
  const direct = await resolveProseVersionSnapshotText(novel, versionEvent.nextSnapshot || null, versionEvent.nextAssetRef || null);
  if (direct !== null) return direct;
  if (versionEvent.eventType === "created") return prose.text || "";
  const previous = await resolveProseVersionSnapshotText(novel, versionEvent.previousSnapshot || null, versionEvent.previousAssetRef || null);
  if (previous !== null && hashText(previous) === versionEvent.previousHash) return previous;
  const diff = String(versionEvent.diff || "");
  if (!diff || !versionEvent.previousHash) return "";
  const current = String(prose.text || "");
  if (hashText(current) === versionEvent.previousHash) return current;
  const previousLines = [];
  for (const line of diff.split(/\r?\n/)) {
    if (line.startsWith("---") || line.startsWith("+++")) continue;
    if (line.startsWith("-")) previousLines.push(line.slice(1));
    if (line.startsWith(" ") && previousLines.length < 20000) previousLines.push(line.slice(1));
  }
  const recovered = previousLines.join("\n").trim();
  return recovered && hashText(recovered) === versionEvent.previousHash ? recovered : "";
}

async function resolveProseVersionSnapshotText(novel, snapshot, assetRef) {
  const source = snapshot && typeof snapshot === "object" ? snapshot : null;
  if (source?.text && !source.truncated) return String(source.text);
  const ref = assetRef || source?.assetRef || null;
  if (!ref?.id) return null;
  const asset = await readPlanningContextAsset(novel, ref.id);
  const payload = asset.payload && typeof asset.payload === "object" ? asset.payload : {};
  const text = typeof payload.text === "string" ? payload.text : typeof asset.payloadText === "string" ? asset.payloadText : "";
  if (!text) return null;
  const expectedHash = source?.hash || ref.hash || "";
  if (expectedHash && hashText(text) !== expectedHash) {
    throw new HttpError(409, `正文版本快照 hash 不匹配：${ref.id}`);
  }
  return text;
}

async function updateProseText(novel, prose, text) {
  const nextText = String(text || "").trim();
  if (!nextText) {
    throw new HttpError(400, "正文内容不能为空");
  }
  const previousText = prose.text || "";
  prose.text = nextText;
  prose.versionType = "user_edit";
  prose.updatedAt = nowIso();
  await appendProseVersionEventWithSnapshots(novel, prose, {
    eventType: "user_edit",
    versionType: "user_edit",
    previousText,
    nextText,
    actor: "user",
    summary: "用户编辑正文"
  });
  const learning = learnFromProseRevision(novel, prose, previousText, nextText, prose.status === "accepted" ? nextText : "");
  if (learning) {
    prose.revisionLearningIds = uniqueStrings([...(prose.revisionLearningIds || []), learning.id]);
  }
  if (prose.status === "accepted") {
    markMemoryItemsFromSource(novel, "prose_part", prose.id, "outdated");
    markMemoryItemsFromSource(novel, "memory_consolidation", prose.id, "outdated");
    projectProseToMemory(novel, prose);
  }
  if (prose.text.length >= PROSE_ASSETIZE_CHARS) {
    await ensureProseContextAsset(novel, prose, "用户编辑长正文后保存引用");
  }
  recordEvent(novel, "prose_updated", { proseId: prose.id, status: prose.status });
  updateTimestamp(novel);
}

function learnFromProseRevision(novel, prose, aiDraftText, userEditText, acceptedText = "") {
  const before = String(aiDraftText || "").trim();
  const after = String(userEditText || "").trim();
  if (!before || !after || before === after) return null;
  novel.planning = normalizePlanning(novel.planning);
  const diff = summarizeProseRevisionDiff(before, after);
  const learning = normalizeRevisionLearning({
    proseId: prose.id,
    workflowId: prose.workflowId || "",
    status: acceptedText ? "tentative" : "candidate",
    scope: diff.transferablePreference ? "style" : "local",
    summary: diff.summary,
    removed: diff.removed,
    kept: diff.kept,
    intensified: diff.intensified,
    aiTasteIssues: diff.aiTasteIssues,
    transferablePreference: diff.transferablePreference,
    evidence: [`prose:${prose.id}`, `before:${hashText(before).slice(0, 12)}`, `after:${hashText(after).slice(0, 12)}`],
    source: {
      aiDraftHash: hashText(before),
      userEditHash: hashText(after),
      acceptedHash: acceptedText ? hashText(acceptedText) : ""
    }
  });
  novel.planning.revisionLearnings = normalizeRevisionLearnings([...(novel.planning.revisionLearnings || []), learning]);
  recordEvent(novel, "revision_learning_created", {
    proseId: prose.id,
    learningId: learning.id,
    status: learning.status
  });
  return learning;
}

function summarizeProseRevisionDiff(before, after) {
  const beforeSentences = splitChineseSentences(before);
  const afterSentences = splitChineseSentences(after);
  const removed = beforeSentences.filter((line) => !after.includes(line)).slice(0, 8);
  const kept = beforeSentences.filter((line) => after.includes(line)).slice(0, 8);
  const intensified = afterSentences.filter((line) => !before.includes(line)).slice(0, 8);
  const aiTasteIssues = [];
  if (/仿佛|像是|空气|沉默|复杂|某种|无法言说|说不清/.test(before) && !/仿佛|像是|空气|沉默|复杂|某种|无法言说|说不清/.test(after)) {
    aiTasteIssues.push("用户删弱了泛化氛围词或 AI 味表达。");
  }
  if (after.length < before.length * 0.75) aiTasteIssues.push("用户明显压缩了正文，偏好更克制的句量。");
  if ((after.match(/“/g) || []).length > (before.match(/“/g) || []).length) aiTasteIssues.push("用户增加了对话密度。");
  const transferablePreference = aiTasteIssues.length
    ? aiTasteIssues.join(" ")
    : intensified.length > 0 ? "用户本次改稿加入了更具体的动作或承接信息，暂作为局部候选偏好。" : "";
  return {
    summary: `本次改稿删除 ${removed.length} 处、保留 ${kept.length} 处、新增/加重 ${intensified.length} 处。`,
    removed,
    kept,
    intensified,
    aiTasteIssues,
    transferablePreference
  };
}

function splitChineseSentences(text) {
  return String(text || "")
    .split(/(?<=[。！？!?])\s*|\n+/)
    .map((line) => line.trim())
    .filter((line) => line.length >= 6)
    .slice(0, 80);
}

function updateRevisionLearning(novel, learningId, patch = {}) {
  novel.planning = normalizePlanning(novel.planning);
  const id = String(learningId || "");
  const index = (novel.planning.revisionLearnings || []).findIndex((item) => item.id === id);
  if (index < 0) throw new HttpError(404, "没有找到改稿学习条目");
  const current = novel.planning.revisionLearnings[index];
  const next = normalizeRevisionLearning({
    ...current,
    ...patch,
    id: current.id,
    updatedAt: nowIso()
  });
  novel.planning.revisionLearnings[index] = next;
  if (next.status === "confirmed" && next.transferablePreference) {
    upsertMemoryItem(novel, {
      layer: "author_memory",
      scope: "planner",
      category: "style_preference",
      subject: novel.title,
      field: `revision_preference_${next.id}`,
      value: next.transferablePreference,
      status: "active",
      visibility: ["planner", "director", "adapter"],
      evidence: next.evidence,
      source: { type: "revision_learning", id: next.id }
    });
  }
  recordEvent(novel, "revision_learning_updated", {
    learningId: next.id,
    status: next.status
  });
  updateTimestamp(novel);
  return next;
}

async function acceptProsePart(store, novel, prose) {
  if (prose.status === "discarded") {
    throw new HttpError(400, "已废弃的正文不能直接采纳，请先重新生成或复制为新草稿");
  }
  const previousText = prose.text || "";
  prose.status = "accepted";
  prose.versionType = "accepted";
  prose.acceptedAt = prose.acceptedAt || nowIso();
  prose.discardedAt = "";
  prose.updatedAt = nowIso();
  await appendProseVersionEventWithSnapshots(novel, prose, {
    eventType: "accepted",
    versionType: "accepted",
    previousText,
    nextText: prose.text || "",
    actor: "user",
    summary: "正文被采纳为当前有效稿"
  });
  for (const id of prose.revisionLearningIds || []) {
    const learning = novel.planning?.revisionLearnings?.find((item) => item.id === id);
    if (learning && learning.status === "candidate") {
      learning.status = "tentative";
      learning.updatedAt = nowIso();
    }
  }
  markMemoryItemsFromSource(novel, "prose_part", prose.id, "outdated");
  projectProseToMemory(novel, prose);
  await ensureProseContextAsset(novel, prose, "正文采纳后保存长正文引用");
  const result = await postwriteProsePart(store, novel, prose, { reason: "正文采纳后写后回写" });
  recordEvent(novel, "prose_accepted", {
    proseId: prose.id,
    turnRange: prose.turnRange,
    memoryItems: result.createdOrUpdated,
    warning: result.warning || ""
  });
  updateTimestamp(novel);
  return result;
}

async function postwriteProsePart(store, novel, prose, options = {}) {
  let memoryResult;
  try {
    memoryResult = await consolidateNovelMemory(store, novel, {
      sourceKinds: ["accepted_prose", "postwrite_backfill"],
      proseId: prose.id,
      reason: options.reason || "正文采纳后提取坐实事实"
    });
  } catch (error) {
    const warning = error instanceof HttpError ? error.message : "记忆整理失败";
    memoryResult = {
      createdOrUpdated: 0,
      items: [],
      warning
    };
    recordEvent(novel, "memory_consolidation_failed", {
      proseId: prose.id,
      warning,
      details: error.details || null
    });
  }
  let review = null;
  try {
    review = await runReviewChain(store, novel, {
      targetType: "prose",
      targetId: prose.id,
      reason: "正文采纳后写后一致性审查"
    });
  } catch (error) {
    recordEvent(novel, "postwrite_review_failed", {
      proseId: prose.id,
      reason: error instanceof HttpError ? error.message : String(error.message || error)
    });
  }
  prose.postwriteBack = normalizePostwriteBack({
    status: memoryResult.warning ? "failed" : "completed",
    updatedAt: nowIso(),
    memoryItems: memoryResult.createdOrUpdated || 0,
    reviewId: review?.id || "",
    summary: memoryResult.warning
      ? `写后回写部分失败：${memoryResult.warning}`
      : `写后回写完成，更新 ${memoryResult.createdOrUpdated || 0} 条长期记忆。`,
    result: {
      memory: {
        createdOrUpdated: memoryResult.createdOrUpdated || 0,
        itemIds: (memoryResult.items || []).map((item) => item.id)
      },
      reviewId: review?.id || ""
    }
  });
  const workflow = findChapterWorkflow(novel, prose.workflowId);
  if (workflow) {
    workflow.proseIds = addWorkflowId(workflow.proseIds, prose.id);
    if (review?.id) workflow.reviewIds = addWorkflowId(workflow.reviewIds, review.id);
    workflow.writeBack = prose.postwriteBack;
    workflow.status = memoryResult.warning ? "blocked" : "completed";
    updateChapterWorkflowStep(workflow, "postwrite", {
      status: memoryResult.warning ? "blocked" : "completed",
      summary: prose.postwriteBack.summary,
      artifactIds: uniqueStrings([...(workflow.steps?.postwrite?.artifactIds || []), prose.id, review?.id].filter(Boolean))
    });
  }
  recordEvent(novel, "postwrite_completed", {
    proseId: prose.id,
    workflowId: prose.workflowId || "",
    memoryItems: memoryResult.createdOrUpdated || 0,
    reviewId: review?.id || "",
    warning: memoryResult.warning || ""
  });
  updateTimestamp(novel);
  return {
    ...memoryResult,
    postwriteBack: prose.postwriteBack,
    review
  };
}

async function discardProsePart(novel, prose) {
  const previousText = prose.text || "";
  prose.status = "discarded";
  prose.versionType = "discarded";
  prose.discardedAt = nowIso();
  prose.updatedAt = nowIso();
  await appendProseVersionEventWithSnapshots(novel, prose, {
    eventType: "discarded",
    versionType: "discarded",
    previousText,
    nextText: prose.text || "",
    actor: "user",
    summary: "正文被废弃"
  });
  markMemoryItemsFromSource(novel, "prose_part", prose.id, "outdated");
  markMemoryItemsFromSource(novel, "memory_consolidation", prose.id, "outdated");
  recordEvent(novel, "prose_discarded", { proseId: prose.id, turnRange: prose.turnRange });
  updateTimestamp(novel);
}

function retireSessionMemory(novel) {
  const sourceTypes = new Set(["roleplay_turn", "prose_part", "memory_consolidation"]);
  for (const item of novel.memory.items || []) {
    if (!sourceTypes.has(item.source?.type)) continue;
    item.status = "outdated";
    item.updatedAt = nowIso();
  }
  novel.memory.updatedAt = nowIso();
}

function retireCharacterMemory(novel, characterId) {
  const targetVisibility = `character:${characterId}`;
  for (const item of novel.memory.items || []) {
    if (item.ownerId !== characterId && !(item.visibility || []).includes(targetVisibility) && !(item.source?.type === "character_card" && item.source?.id === characterId)) {
      continue;
    }
    item.status = "outdated";
    item.updatedAt = nowIso();
  }
  novel.memory.updatedAt = nowIso();
}

function markMemoryItemsFromSource(novel, sourceType, sourceId, status) {
  const nextStatus = normalizeMemoryStatus(status);
  for (const item of novel.memory.items || []) {
    if (item.source?.type !== sourceType) continue;
    if (String(item.source?.id || "") !== String(sourceId || "")) continue;
    item.status = nextStatus;
    item.updatedAt = nowIso();
  }
  novel.memory.updatedAt = nowIso();
}

function getAcceptedProseParts(novel) {
  return (novel.session.proseParts || []).filter((part) => normalizeProseStatus(part.status) === "accepted");
}

async function consolidateNovelMemory(store, novel, options = {}) {
  const plannerSetting = novel.aiRoles.planner;
  const plannerProvider = getConfiguredProvider(store, plannerSetting, "记忆整理 AI");
  const result = await requestAi({
    provider: plannerProvider,
    model: plannerSetting.model,
    temperature: Math.min(0.45, clampTemperature(plannerSetting.temperature)),
    systemPrompt: buildMemoryConsolidationSystemPrompt(),
    messages: [
      {
        role: "user",
        content: buildMemoryConsolidationUserPrompt(novel, options)
      }
    ]
  });
  const parsed = parseLooseJson(result.text);
  const rawItems = Array.isArray(parsed?.items) ? parsed.items : Array.isArray(parsed?.memoryItems) ? parsed.memoryItems : [];
  if (!Array.isArray(rawItems)) {
    throw new HttpError(502, "记忆整理没有返回可识别的 items 数组", safeRemoteText(result.text));
  }
  const sourceId = options.proseId || options.turnId || createId("batch");
  const sourceType = options.proseId ? "memory_consolidation" : "memory_consolidation";
  let createdOrUpdated = 0;
  const items = [];
  for (const raw of rawItems.slice(0, 24)) {
    const item = normalizeConsolidatedMemoryItem(novel, raw, {
      sourceType,
      sourceId,
      sourceKinds: options.sourceKinds || []
    });
    if (!item.value) continue;
    const saved = upsertMemoryItem(novel, item);
    items.push(saved);
    createdOrUpdated += 1;
  }
  recordEvent(novel, "memory_consolidated", {
    sourceKinds: options.sourceKinds || [],
    sourceId,
    itemCount: createdOrUpdated,
    reason: options.reason || ""
  });
  updateTimestamp(novel);
  return {
    createdOrUpdated,
    items,
    raw: result.raw
  };
}

function normalizeConsolidatedMemoryItem(novel, raw, meta) {
  const source = raw && typeof raw === "object" ? raw : {};
  const matchedCharacter = source.ownerId
    ? novel.characters.find((character) => character.id === source.ownerId)
    : findCharacterByName(novel, source.characterName || source.ownerName || source.subject);
  const scope = source.scope || (matchedCharacter ? "character" : "global");
  const category = source.category || inferMemoryCategoryFromField(source.field, scope);
  const evidence = normalizeEvidenceList(source.evidence);
  const visibility = Array.isArray(source.visibility) && source.visibility.length > 0
    ? source.visibility
    : inferConsolidatedVisibility(scope, matchedCharacter, category);
  return normalizeMemoryItem({
    layer: source.layer || inferMemoryLayer({ scope, category, status: source.status || "tentative", visibility, source: { type: meta.sourceType, id: meta.sourceId } }),
    scope,
    ownerId: matchedCharacter?.id || source.ownerId || "",
    category,
    subject: source.subject || matchedCharacter?.name || "整理记忆",
    field: source.field || "fact",
    value: source.value || source.fact || source.summary || "",
    status: source.status || "tentative",
    visibility,
    source: { type: meta.sourceType, id: meta.sourceId },
    evidence
  });
}

function inferMemoryCategoryFromField(field, scope) {
  const value = String(field || "").toLowerCase();
  if (scope === "character") return "character_state";
  if (value.includes("关系") || value.includes("relationship")) return "relationship";
  if (value.includes("伏笔") || value.includes("线索") || value.includes("clue")) return "open_loop";
  if (value.includes("时间") || value.includes("timeline")) return "timeline";
  if (value.includes("文风") || value.includes("style")) return "style_preference";
  return "scene_fact";
}

function inferConsolidatedVisibility(scope, character, category) {
  if (scope === "character" && character?.id) {
    return ["planner", "director", "adapter", `character:${character.id}`];
  }
  if (category === "world_rule" || category === "scene_fact") {
    return ["planner", "director", "adapter", "minor", "character:*"];
  }
  return ["planner", "director", "adapter"];
}

function buildMemoryConsolidationSystemPrompt() {
  return [
    "你是小说项目的记忆整理 AI。",
    "你的职责是从已发生扮演记录和已采纳正文里提取会影响后续创作的长期记忆；稳定档案只作为判断背景，不要机械投影成记忆。",
    "不要把未采纳草稿当成事实，不要把猜测升级为确认事实。",
    "如果事实来自扮演输出但尚未被正文采纳，status 使用 tentative；如果来自已采纳正文，可以使用 active。",
    "角色内心、私有目标和主观关系判断必须放入对应角色可见记忆，不要让其他角色可见。",
    "输出 JSON，格式为 {\"items\": []}。每个 item 包括 scope、ownerId 或 characterName、layer、category、subject、field、value、status、visibility、evidence。",
    "layer 只能是 stable_fact、tentative_judgment、character_visible、author_memory、run_audit、roleplay_state。无法确认时用 tentative_judgment，不要把草稿或猜测写成 stable_fact。",
    "category 只能是 user_intent、world_rule、character_state、relationship、timeline、open_loop、scene_fact、style_preference、draft_evidence。",
    "active 记忆不要使用 draft_evidence 兜底分类；每条 value 必须是单条可执行约束或事实，不要写档案块、工具报告、JSON/YAML、普通摘要或空泛总结。"
  ].join("\n");
}

function buildMemoryConsolidationUserPrompt(novel, options = {}) {
  const acceptedProse = getAcceptedProseParts(novel);
  const sourceKinds = options.sourceKinds || ["recent_turns", "accepted_prose"];
  const targetProse = options.proseId
    ? acceptedProse.filter((part) => part.id === options.proseId)
    : acceptedProse.slice(-3);
  return JSON.stringify({
    task: "consolidate_memory",
    reason: options.reason || "整理近期可持续影响后续创作的事实",
    sourceKinds,
    project: {
      title: novel.title,
      scenario: novel.scenario,
      archives: novel.archives,
      characters: novel.characters.map((character) => ({
        id: character.id,
        name: character.name,
        roleType: character.roleType,
        description: character.description,
        personality: character.personality
      }))
    },
    recentTurns: novel.session.turns.slice(-4).map(compactTurnForPrompt),
    acceptedProse: targetProse.map((part) => ({
      id: part.id,
      turnRange: part.turnRange,
      text: part.text
    })),
    existingMemory: (novel.memory.items || [])
      .filter((item) => item.status === "active" || item.status === "tentative")
      .slice(-40)
      .map(projectMemoryItemForPack)
  }, null, 2);
}

function exportLorebookToSillyTavern(novel) {
  const lorebook = normalizeLorebook(novel.lorebook);
  return {
    spec: "lorebook_v1",
    spec_version: "1.0",
    data: {
      name: `${novel.title || "未命名小说"} World Info`,
      description: "由扮演法小说工作台导出的独立世界书。",
      scan_depth: lorebook.settings.scanDepth,
      token_budget: lorebook.settings.maxCharsPerEntry,
      recursive_scanning: lorebook.settings.recursiveScanning,
      extensions: {
        [PROJECT_EXTENSION_KEY]: {
          source: "roleplay-novel-studio",
          exportedAt: nowIso()
        }
      },
      entries: lorebook.entries.map(toSillyTavernLorebookEntry)
    }
  };
}

function toSillyTavernLorebookEntry(entry, index) {
  const normalized = normalizeLorebookEntry(entry);
  return {
    id: normalized.id,
    uid: index,
    comment: normalized.name,
    content: normalized.content,
    keys: normalized.keys,
    keysecondary: normalized.secondaryKeys,
    enabled: normalized.enabled,
    disable: normalized.enabled === false,
    constant: normalized.matchMode === "always",
    selective: normalized.secondaryKeys.length > 0,
    use_regex: normalized.matchMode === "regex",
    insertion_order: normalized.priority,
    position: toSillyTavernLorebookPosition(normalized.position),
    token_budget: normalized.tokenBudget,
    case_sensitive: normalized.caseSensitive,
    extensions: {
      [PROJECT_EXTENSION_KEY]: {
        id: normalized.id,
        scope: normalized.scope,
        ownerId: normalized.ownerId,
        visibility: normalized.visibility,
        matchMode: normalized.matchMode,
        source: normalized.source
      }
    }
  };
}

function toSillyTavernLorebookPosition(position) {
  const map = {
    before_character: "before_char",
    after_character: "after_char",
    before_memory: "before_author_note",
    after_memory: "after_author_note"
  };
  return map[position] || "after_char";
}

function importLorebookFromSillyTavern(novel, payload, options = {}) {
  novel.lorebook = normalizeLorebook(novel.lorebook);
  const mode = options.mode === "replace" ? "replace" : "append";
  const book = extractLorebookData(payload);
  const rawEntries = collectImportedLorebookEntries(book);
  if (rawEntries.length === 0) {
    throw new HttpError(400, "没有识别到可导入的世界书条目");
  }
  const replaced = mode === "replace" ? novel.lorebook.entries.length : 0;
  if (mode === "replace") {
    novel.lorebook.entries = [];
  }
  const importedSettings = {};
  if (book.scan_depth !== undefined) importedSettings.scanDepth = book.scan_depth;
  if (book.token_budget !== undefined) importedSettings.maxCharsPerEntry = book.token_budget;
  if (book.recursive_scanning !== undefined) importedSettings.recursiveScanning = book.recursive_scanning;
  if (Object.keys(importedSettings).length > 0) {
    novel.lorebook.settings = normalizeLorebookSettings({
      ...novel.lorebook.settings,
      ...importedSettings
    });
  }
  const imported = [];
  rawEntries.forEach((raw, index) => {
    const entry = normalizeImportedLorebookEntry(raw.entry, {
      index,
      uid: raw.uid,
      bookName: book.name || book.title || "导入世界书"
    });
    // 酒馆世界书里常见禁用的分组分隔条目，可能只有 comment 没有 content。
    // 这类条目不参与触发，但属于原始结构，导入时不能丢，否则条目数会和来源对不上。
    if (!entry.content && !entry.name) return;
    const saved = upsertLorebookEntry(novel, entry);
    imported.push(saved);
  });
  if (imported.length === 0) {
    throw new HttpError(400, "世界书 JSON 中没有可用内容");
  }
  novel.lorebook.updatedAt = nowIso();
  return {
    mode,
    replaced,
    importedCount: imported.length,
    entries: imported
  };
}

function extractLorebookData(payload) {
  const source = payload && typeof payload === "object" ? payload : {};
  if (source.data && typeof source.data === "object" && (source.data.entries || source.data.name)) {
    return source.data;
  }
  return source;
}

function collectImportedLorebookEntries(book) {
  const entries = book?.entries;
  if (Array.isArray(entries)) {
    return entries.map((entry, index) => ({ uid: entry.uid ?? entry.id ?? index, entry }));
  }
  if (entries && typeof entries === "object") {
    return Object.entries(entries).map(([uid, entry]) => ({ uid, entry }));
  }
  return [];
}

function normalizeImportedLorebookEntry(rawEntry, context) {
  const source = rawEntry && typeof rawEntry === "object" ? rawEntry : {};
  const extension = source.extensions?.[PROJECT_EXTENSION_KEY] && typeof source.extensions[PROJECT_EXTENSION_KEY] === "object"
    ? source.extensions[PROJECT_EXTENSION_KEY]
    : {};
  const scope = normalizeLorebookScope(extension.scope || source.scope);
  const ownerId = String(extension.ownerId || source.ownerId || "");
  const matchMode = extension.matchMode || source.matchMode || source.match_mode || (truthyFlag(source.constant) ? "always" : truthyFlag(source.use_regex) ? "regex" : "any");
  const importedSource = normalizeLorebookSource(extension.source || source.source || {
    type: "lorebook_import",
    id: String(context.uid ?? context.index)
  });
  if (!importedSource.id) {
    importedSource.id = String(context.uid ?? context.index);
  }
  return {
    id: createId("lore"),
    name: String(source.name || source.comment || source.title || `${context.bookName} ${context.index + 1}`).trim(),
    enabled: truthyFlag(source.disable) ? false : !falsyFlag(source.enabled),
    scope,
    ownerId,
    keys: normalizeKeywordList(source.keys ?? source.key ?? source.primaryKeys),
    secondaryKeys: normalizeKeywordList(source.secondaryKeys ?? source.secondary_keys ?? source.keysecondary ?? source.keySecondary),
    content: String(source.content || "").trim(),
    position: source.position || "after_char",
    priority: source.priority ?? source.order ?? source.insertion_order ?? context.index,
    tokenBudget: source.tokenBudget ?? source.token_budget ?? 600,
    matchMode,
    caseSensitive: Boolean(source.caseSensitive ?? source.case_sensitive),
    visibility: Array.isArray(extension.visibility) ? extension.visibility : normalizeLorebookVisibility(source.visibility, scope, ownerId),
    source: importedSource,
    createdAt: nowIso(),
    updatedAt: nowIso()
  };
}

function upsertLorebookEntry(novel, rawEntry) {
  novel.lorebook = normalizeLorebook(novel.lorebook);
  const entry = normalizeLorebookEntry(rawEntry);
  if (!entry.content && entry.enabled) {
    throw new HttpError(400, "启用的世界书内容不能为空");
  }
  if (!entry.content && !entry.name) {
    throw new HttpError(400, "世界书内容和名称不能同时为空");
  }
  if (!entry.name) {
    entry.name = entry.keys[0] || "未命名世界书条目";
  }
  const index = entry.id
    ? novel.lorebook.entries.findIndex((current) => current.id === entry.id)
    : -1;
  if (index >= 0) {
    novel.lorebook.entries[index] = {
      ...entry,
      createdAt: novel.lorebook.entries[index].createdAt || entry.createdAt,
      updatedAt: nowIso()
    };
  } else {
    novel.lorebook.entries.push(entry);
  }
  novel.lorebook.entries = novel.lorebook.entries
    .map(normalizeLorebookEntry)
    .sort((a, b) => b.priority - a.priority || String(b.updatedAt || "").localeCompare(String(a.updatedAt || "")));
  novel.lorebook.updatedAt = nowIso();
  return novel.lorebook.entries.find((current) => current.id === entry.id) || entry;
}

function upsertMemoryItem(novel, rawItem) {
  novel.memory = normalizeMemory(novel.memory);
  const item = normalizeMemoryItem(rawItem);
  assertMemoryItemWriteConstraints(item);
  retireConflictingMemoryItems(novel, item);
  const existingIndex = item.id
    ? novel.memory.items.findIndex((current) => current.id === item.id)
    : -1;
  const key = memoryItemKey(item);
  const sameKeyIndex = existingIndex >= 0
    ? existingIndex
    : novel.memory.items.findIndex((current) => memoryItemKey(current) === key && current.status !== "outdated");
  if (sameKeyIndex >= 0) {
    const existing = novel.memory.items[sameKeyIndex];
    novel.memory.items[sameKeyIndex] = normalizeMemoryItem({
      ...existing,
      ...item,
      id: existing.id,
      evidence: uniqueStrings([...(existing.evidence || []), ...(item.evidence || [])]).slice(0, 8),
      updatedAt: nowIso()
    });
    novel.memory.updatedAt = nowIso();
    return novel.memory.items[sameKeyIndex];
  }
  novel.memory.items.push(item);
  novel.memory.updatedAt = nowIso();
  return item;
}

function assertMemoryItemWriteConstraints(item) {
  if (!item.subject) {
    throw new HttpError(400, "记忆 subject 不能为空；记忆必须有明确主体");
  }
  if (!item.field) {
    throw new HttpError(400, "记忆 field 不能为空；记忆必须说明事实类型或变化字段");
  }
  if (!item.value) {
    throw new HttpError(400, "记忆 value 不能为空；不要写入空泛或无内容的记忆");
  }
  if (!Array.isArray(item.visibility) || item.visibility.length === 0) {
    throw new HttpError(400, "记忆 visibility 不能为空；必须声明哪些 Agent / 角色可见");
  }
  const violations = collectMemoryItemWriteViolations(item);
  if (violations.length > 0) {
    throw new HttpError(400, `记忆写入不符合长期记忆合同：${violations.map((violation) => violation.message).join("；")}`, {
      violations,
      expected: "长期记忆只存单条稳定事实、状态变化、关系变化、时间线事实、开放问题或写作偏好；不要存档案块、测试输出、工具报告、占位语或整段摘要"
    });
  }
}

function collectMemoryItemWriteViolations(item) {
  const violations = [];
  const sourceType = String(item.source?.type || "");
  const subject = String(item.subject || "").trim();
  const field = String(item.field || "").trim();
  const value = String(item.value || "").trim();
  const evidence = Array.isArray(item.evidence) ? item.evidence.filter(Boolean) : [];
  const activeLike = ["active", "tentative", "resolved"].includes(String(item.status || "active"));
  const aiSource = AI_MEMORY_SOURCE_TYPES.has(sourceType);
  const layer = normalizeMemoryLayer(item.layer);
  const visibility = Array.isArray(item.visibility) ? item.visibility.map((entry) => String(entry || "").trim()).filter(Boolean) : [];
  if (value.length > 1800) {
    violations.push({
      code: "memory.value_too_large",
      message: "value 过长，像整段资料或正文摘要，不能直接进入长期记忆"
    });
  }
  if (activeLike && evidence.length === 0) {
    violations.push({
      code: "memory.evidence_required",
      message: "长期记忆必须提供 evidence；没有证据的内容只能留在诊断、草案或 RAG 证据层"
    });
  }
  if (aiSource && item.status === "active" && item.category === "draft_evidence") {
    violations.push({
      code: "memory.category_too_vague",
      message: "active 记忆不能使用 draft_evidence 兜底分类，必须选择明确类别"
    });
  }
  if (activeLike && MEMORY_FORBIDDEN_FACT_FIELDS.has(field)) {
    violations.push({
      code: "memory.field_is_archive_blob",
      message: `field=${field} 表示整块档案或原始块，应写入档案/RAG，不应写入长期记忆`
    });
  }
  if (activeLike && aiSource && memorySubjectLooksPlaceholder(subject)) {
    violations.push({
      code: "memory.template_subject",
      message: `主体“${subject}”是模板占位名，不是可沉淀的真实事实主体`
    });
  }
  if (activeLike && aiSource && memoryTextLooksPlaceholder(value)) {
    violations.push({
      code: "memory.placeholder_text",
      message: "value 含占位语或待确认模板语，不能作为稳定记忆"
    });
  }
  if (activeLike && memoryTextLooksLikeArchiveBlock(value)) {
    violations.push({
      code: "memory.archive_block",
      message: "value 看起来是角色/场景/线索档案块，不能整块塞进长期记忆"
    });
  }
  if (activeLike && memoryTextLooksLikeRawStructuredBlob(value)) {
    violations.push({
      code: "memory.raw_structured_blob",
      message: "value 看起来是 JSON/YAML/工具输出块，应作为 RAG 证据或审计引用保存"
    });
  }
  if (activeLike && memoryTextLooksLikeDocumentBlob(value)) {
    violations.push({
      code: "memory.value_blob_like",
      message: "value 像 Markdown 大纲、工具报告或多段资料块，长期记忆只接受单条事实或约束"
    });
  }
  if (activeLike && layer === "stable_fact" && item.status === "active" && !memoryWriteHasStableEvidence(item, sourceType, evidence)) {
    violations.push({
      code: "memory.stable_fact_unconfirmed",
      message: "stable_fact/active 必须来自已采纳正文、人工确认或明确证据，不能把推测直接升级为稳定事实"
    });
  }
  if (activeLike && ["character_visible", "roleplay_state"].includes(layer) && !memoryHasCharacterVisibility(item, visibility)) {
    violations.push({
      code: "memory.layer_visibility_mismatch",
      message: "角色可见记忆或扮演态记忆必须绑定 ownerId 或 character:* / character:<id> 可见范围"
    });
  }
  if (activeLike && layer === "author_memory" && !memoryWriteHasAuthorEvidence(item, sourceType, evidence)) {
    violations.push({
      code: "memory.author_memory_weak_evidence",
      message: "作者级记忆必须来自用户偏好、用户确认或改稿学习，不能从普通推测中写成长期偏好"
    });
  }
  if (activeLike && item.scope === "character" && !item.ownerId && /^角色$|^主要角色$|^次要角色$/.test(subject)) {
    violations.push({
      code: "memory.character_subject_too_generic",
      message: "角色记忆必须指向具体角色名或 ownerId，不能写泛化主体"
    });
  }
  return violations;
}

function memoryTextLooksPlaceholder(text) {
  return MEMORY_PLACEHOLDER_PATTERNS.some((pattern) => pattern.test(text));
}

function memorySubjectLooksPlaceholder(subject) {
  const value = String(subject || "").trim();
  if (!value) return false;
  if (PLACEHOLDER_ENTITY_PATTERN.test(value)) return true;
  return /^(?:角色|人物|场景|地点|线索|组织|势力|事件|信号)(?:[一二三四五六七八九十甲乙丙丁]|\d+)$/.test(value);
}

function memoryTextLooksLikeArchiveBlock(text) {
  const lines = String(text || "").split(/\r?\n/).map((line) => line.trim()).filter(Boolean);
  if (lines.length < 3) return false;
  const markerCount = lines.filter((line) => {
    const match = line.match(/^([a-zA-Z_][\w-]*|[\u4e00-\u9fa5]{1,8})[：:]/);
    if (!match) return false;
    return MEMORY_ARCHIVE_BLOCK_MARKERS.includes(match[1]);
  }).length;
  return markerCount >= 3;
}

function memoryTextLooksLikeRawStructuredBlob(text) {
  const value = String(text || "").trim();
  if (!value) return false;
  if (/^```/.test(value)) return true;
  if ((value.startsWith("{") && value.endsWith("}")) || (value.startsWith("[") && value.endsWith("]"))) {
    return value.length > 120 || /"[^"]+"\s*:/.test(value);
  }
  const yamlLikeLines = value.split(/\r?\n/).filter((line) => /^\s*[-\w\u4e00-\u9fa5]+\s*:\s+/.test(line));
  return yamlLikeLines.length >= 4;
}

function memoryTextLooksLikeDocumentBlob(text) {
  const value = String(text || "").trim();
  if (!value) return false;
  const lines = value.split(/\r?\n/).map((line) => line.trim()).filter(Boolean);
  if (lines.length >= 5 && lines.filter((line) => /^(#{1,6}\s+|[-*]\s+|\d+[.)、]\s+)/.test(line)).length >= 3) return true;
  if (/^(工具|执行|检索|搜索|审计|诊断|报告|结果)[：:]/.test(value) && lines.length >= 3) return true;
  if (/(skillOpReport|toolCallId|stdout|stderr|unifiedDiff|@@\s+-\d+)/.test(value)) return true;
  if (lines.length >= 4 && lines.some((line) => line.length > 120) && /(?:大纲|角色|场景|线索|世界书|档案)[：:]/.test(value)) return true;
  return false;
}

function memoryWriteHasStableEvidence(item, sourceType, evidence) {
  if (MEMORY_CONFIRMED_SOURCE_TYPES.has(sourceType)) return true;
  if (String(item.source?.id || "").startsWith("user_")) return true;
  return evidence.some((entry) => /(?:用户确认|人工确认|已采纳正文|accepted_prose|prose:|user_confirm|manual|正文采纳|采纳正文)/i.test(String(entry || "")));
}

function memoryHasCharacterVisibility(item, visibility) {
  if (item.ownerId) return true;
  return visibility.some((entry) => entry === "character:*" || entry.startsWith("character:"));
}

function memoryWriteHasAuthorEvidence(item, sourceType, evidence) {
  if (!MEMORY_AUTHOR_SOURCE_TYPES.has(sourceType)) return false;
  if (String(item.category || "") === "style_preference" && sourceType === "revision_learning") return true;
  if (String(item.category || "") === "user_intent" && sourceType === "planning_chat") return true;
  return evidence.some((entry) => /(?:用户要求|用户偏好|用户确认|改稿|revision|before:|after:|user_confirm|manual)/i.test(String(entry || "")));
}

function retireConflictingMemoryItems(novel, nextItem) {
  const key = memoryItemKey(nextItem);
  for (const item of novel.memory.items || []) {
    if (item.id === nextItem.id) continue;
    if (memoryItemKey(item) !== key) continue;
    if (item.value === nextItem.value) continue;
    if (item.status === "outdated" || item.status === "contradicted") continue;
    item.status = "outdated";
    item.updatedAt = nowIso();
  }
}

function memoryItemKey(item) {
  return [
    item.scope || "global",
    item.ownerId || "",
    item.category || "draft_evidence",
    String(item.subject || "").trim().toLowerCase(),
    String(item.field || "").trim().toLowerCase()
  ].join("|");
}

function findCharacterByName(novel, name) {
  const normalizedName = String(name || "").trim().toLowerCase();
  if (!normalizedName) return null;
  return novel.characters.find((character) => character.name.trim().toLowerCase() === normalizedName) || null;
}

function summarizeArchiveRecord(record) {
  if (!record || typeof record !== "object") return "";
  const pairs = Object.entries(record)
    .filter(([, value]) => value !== null && value !== undefined && String(value).trim() !== "")
    .map(([key, value]) => `${key}：${typeof value === "object" ? JSON.stringify(value) : String(value)}`);
  return pairs.join("\n");
}

function memoryLayerForTask(task) {
  if (task === "character") return ["character_visible", "roleplay_state", "stable_fact"];
  if (task === "minor") return ["stable_fact", "roleplay_state", "tentative_judgment"];
  if (task === "director") return ["stable_fact", "tentative_judgment", "roleplay_state", "run_audit"];
  if (task === "adapter") return ["stable_fact", "character_visible", "roleplay_state", "author_memory"];
  return ["stable_fact", "tentative_judgment", "author_memory", "run_audit"];
}

function buildMemoryLayerStats(items) {
  return (items || []).reduce((acc, item) => {
    const layer = normalizeMemoryLayer(item.layer || inferMemoryLayer(item));
    acc[layer] = (acc[layer] || 0) + 1;
    return acc;
  }, {});
}

async function buildAgentContextPack(novel, task, options = {}) {
  const normalizedTask = normalizeMemoryTask(task);
  const characterId = String(options.characterId || "");
  const settings = normalizeMemorySettings(novel.memory?.settings);
  const lorebookSettings = normalizeLorebookSettings(novel.lorebook?.settings);
  const query = buildMemoryQuery(novel, normalizedTask, { ...options, characterId });
  const strategy = memoryStrategyForTask(normalizedTask);
  const runtimeDirective = buildRuntimeDirectiveForTask(novel, normalizedTask, characterId, options);
  const fixedContext = buildFixedContext(novel, normalizedTask, characterId);
  const recentContext = buildRecentContext(novel, normalizedTask, characterId);
  const lorebookScan = buildLorebookScan(novel, normalizedTask, characterId, query, lorebookSettings, recentContext);
  if (settings.enabled === false) {
    return createAgentContextPack({
      task: normalizedTask,
      strategy,
      characterId,
      query,
      lorebookScan,
      fixedContext,
      triggeredLore: [],
      structuredMemory: [],
      retrievedEvidence: [],
      recentContext,
      runtimeDirective,
      warnings: ["记忆系统已关闭"],
      settings,
      lorebookSettings
    });
  }
  const visibleItems = (novel.memory?.items || [])
    .map(normalizeMemoryItem)
    .filter((item) => isMemoryVisibleTo(item, normalizedTask, characterId));
  const warnings = visibleItems
    .filter((item) => item.status === "contradicted")
    .slice(0, 8)
    .map((item) => `存在冲突记忆：${item.subject} / ${item.field}`);
  const activeItems = visibleItems.filter((item) => item.status === "active" || item.status === "tentative" || item.status === "resolved");
  const preferredLayers = new Set(memoryLayerForTask(normalizedTask));
  const structuredLimit = memoryStructuredLimitForTask(settings, normalizedTask);
  const structuredMemory = rankMemoryItems(activeItems, query, normalizedTask)
    .filter((item) => preferredLayers.has(item.layer) || normalizedTask === "planner")
    .slice(0, structuredLimit)
    .map(projectMemoryItemForPack);
  const triggeredLore = collectTriggeredLore(novel, normalizedTask, characterId, lorebookScan.text, lorebookSettings);
  const documents = collectRagSources(novel, normalizedTask, characterId);
  const retrievedLimit = memoryRetrievedLimitForTask(settings, normalizedTask);
  const retrieval = await retrieveRagEvidence(options.store, novel, normalizedTask, characterId, query, documents, settings, retrievedLimit);
  warnings.push(...retrieval.warnings);
  const retrievedEvidence = retrieval.items.map((item) => ({
    id: item.document.id,
    title: item.document.title,
    source: item.document.source,
    score: Number(item.score.toFixed(4)),
    bm25Score: Number((item.bm25Score || 0).toFixed(4)),
    vectorScore: Number((item.vectorScore || 0).toFixed(4)),
    rerankScore: Number((item.rerankScore || 0).toFixed(4)),
    retrievalMode: item.retrievalMode,
    text: limitText(item.document.text, settings.maxEvidenceChars)
  }));
  return createAgentContextPack({
    task: normalizedTask,
    strategy,
    characterId,
    query,
    lorebookScan,
    fixedContext,
    triggeredLore,
    structuredMemory,
    retrievedEvidence,
    recentContext,
    runtimeDirective,
    warnings,
    settings: {
      ...settings,
      maxStructuredItems: structuredLimit,
      maxRetrievedItems: retrievedLimit,
      memoryLayerStats: buildMemoryLayerStats(visibleItems),
      preferredMemoryLayers: Array.from(preferredLayers)
    },
    lorebookSettings
  });
}

function createAgentContextPack({
  task,
  strategy,
  characterId,
  query,
  lorebookScan,
  fixedContext,
  triggeredLore,
  structuredMemory,
  retrievedEvidence,
  recentContext,
  runtimeDirective,
  warnings,
  settings,
  lorebookSettings
}) {
  const normalizedStructuredMemory = Array.isArray(structuredMemory) ? structuredMemory : [];
  const normalizedRetrievedEvidence = Array.isArray(retrievedEvidence) ? retrievedEvidence : [];
  return {
    task,
    strategy,
    characterId,
    query,
    lorebookScan,
    fixedContext,
    triggeredLore,
    structuredMemory: normalizedStructuredMemory,
    retrievedEvidence: normalizedRetrievedEvidence,
    recentContext,
    runtimeDirective,
    promptSections: assemblePromptSections(fixedContext, triggeredLore, normalizedStructuredMemory, normalizedRetrievedEvidence, recentContext),
    layers: {
      fixedContext,
      triggeredLore,
      structuredMemory: normalizedStructuredMemory,
      retrievedEvidence: normalizedRetrievedEvidence,
      recentContext,
      runtimeDirective
    },
    warnings,
    budget: {
      structuredMemory: settings.maxStructuredItems,
      retrievedEvidence: settings.maxRetrievedItems,
      evidenceChars: settings.maxEvidenceChars,
      triggeredLore: lorebookSettings.maxTriggeredEntries,
      loreChars: lorebookSettings.maxCharsPerEntry,
      recursiveScanning: lorebookSettings.recursiveScanning,
      memoryLayerStats: settings.memoryLayerStats || {},
      preferredMemoryLayers: settings.preferredMemoryLayers || []
    },
    builtAt: nowIso()
  };
}

function memoryStrategyForTask(task) {
  const strategies = {
    planner: "project_rag",
    director: "orchestration_rag",
    character: "tavern_context",
    minor: "group_tavern_context",
    adapter: "faithful_adaptation"
  };
  return strategies[task] || "orchestration_rag";
}

function buildRuntimeDirectiveForTask(novel, task, characterId, options = {}) {
  if (options.runtimeDirective && typeof options.runtimeDirective === "object") {
    return normalizeCharacterRuntimeDirective(options.runtimeDirective);
  }
  if (task !== "character" && task !== "minor") return null;
  if (task === "minor") {
    const plan = normalizePrewritePlan(novel.session?.prewritePlan);
    return normalizeCharacterRuntimeDirective({
      characterId: "minor_group",
      name: "次要角色群",
      currentGoal: plan?.summary || novel.scenario?.plotDirection || "服务当前场景压力，不抢主要角色选择。",
      visibleFacts: [
        ...(plan?.foregroundAnchors || []),
        ...(plan?.continuityAnchors || [])
      ],
      forbiddenKnowledge: plan?.backgroundOnly || [],
      forbiddenMoves: [
        "不能替主要角色做关键决定。",
        "不能让路人说出超出身份的信息。",
        ...(plan?.softBoundaries || [])
      ],
      observationFocus: plan?.sceneFocus || [],
      notes: plan?.directorNote || ""
    });
  }
  const character = novel.characters.find((item) => item.id === characterId);
  if (!character) return null;
  const plan = normalizePrewritePlan(novel.session?.prewritePlan);
  const byId = plan?.runtimeDirectives?.[character.id];
  const byName = plan?.runtimeDirectives?.[character.name];
  const beat = (plan?.characterBeats || []).find((item) => item.characterId === character.id || item.name === character.name);
  return normalizeCharacterRuntimeDirective({
    characterId: character.id,
    name: character.name,
    currentGoal: byId?.currentGoal || byName?.currentGoal || beat?.attention || "按角色卡和当前场景压力自主反应。",
    visibleFacts: uniqueStrings([
      ...(byId?.visibleFacts || []),
      ...(byName?.visibleFacts || []),
      ...(plan?.foregroundAnchors || []),
      ...(plan?.continuityAnchors || [])
    ]),
    forbiddenKnowledge: uniqueStrings([
      ...(byId?.forbiddenKnowledge || []),
      ...(byName?.forbiddenKnowledge || []),
      ...(plan?.backgroundOnly || [])
    ]),
    forbiddenMoves: uniqueStrings([
      ...(byId?.forbiddenMoves || []),
      ...(byName?.forbiddenMoves || []),
      beat?.avoidForcing || "",
      ...(plan?.softBoundaries || []),
      "不能知道其他主要角色内心。",
      "不能知道作者隐藏设定或未来大纲。"
    ]),
    observationFocus: uniqueStrings([
      ...(byId?.observationFocus || []),
      ...(byName?.observationFocus || []),
      ...(plan?.sceneFocus || [])
    ]),
    notes: byId?.notes || byName?.notes || plan?.directorNote || ""
  });
}

function memoryStructuredLimitForTask(settings, task) {
  if (task === "character" || task === "minor") {
    return Math.min(settings.maxStructuredItems, 10);
  }
  return settings.maxStructuredItems;
}

function memoryRetrievedLimitForTask(settings, task) {
  if (task === "character" || task === "minor") {
    return Math.min(settings.maxRetrievedItems, 5);
  }
  return settings.maxRetrievedItems;
}

function normalizeMemoryTask(task) {
  const value = String(task || "").trim();
  return ["planner", "director", "character", "minor", "adapter"].includes(value) ? value : "director";
}

function buildMemoryQuery(novel, task, options = {}) {
  if (options.queryText) return String(options.queryText);
  const character = options.characterId ? novel.characters.find((item) => item.id === options.characterId) : null;
  const scenario = novel.scenario || {};
  const recentTurn = novel.session.turns[novel.session.turns.length - 1];
  const parts = [
    novel.title,
    scenario.time,
    scenario.place,
    scenario.plotDirection,
    scenario.tone,
    character?.name,
    character?.description,
    task === "adapter" ? "忠实改写 最近正文 角色选择" : "",
    task === "director" ? "剧情推进 时间线 场景压力 伏笔" : "",
    task === "minor" ? "次要角色 场景信息 阻碍 线索" : "",
    recentTurn ? formatAiRecordContent(recentTurn.guide) : ""
  ].filter(Boolean);
  return limitText(parts.join("\n"), 2000);
}

// 世界书触发要接近酒馆的扫描逻辑：不是只看当前用户 query，而是把当前任务、最近对话/扮演和场景摘要一起作为触发文本。
function buildLorebookScan(novel, task, characterId, query, settings, recentContext) {
  const scanSources = [
    { title: "当前查询", text: query },
    ...collectLorebookScanSources(novel, task, characterId, settings.scanDepth, recentContext)
  ];
  const text = limitText(scanSources.map((item) => `${item.title}\n${item.text}`).join("\n\n"), 12000);
  return {
    depth: settings.scanDepth,
    sourceCount: scanSources.length,
    text
  };
}

function collectLorebookScanSources(novel, task, characterId, scanDepth, recentContext) {
  const scenario = novel.scenario || {};
  const sources = [
    {
      title: "当前场景",
      text: [scenario.background, scenario.time, scenario.place, scenario.plotDirection, scenario.tone].filter(Boolean).join("\n")
    }
  ];
  if (task === "planner") {
    sources.push(...novel.planning.messages.slice(-scanDepth).map((message) => ({
      title: `最近策划对话：${message.role}`,
      text: getPlanningMessageVisibleContent(message)
    })));
  } else if (recentContext.length > 0) {
    sources.push(...recentContext.map((item) => ({
      title: item.title,
      text: item.text
    })));
  }
  if (task === "character" && characterId) {
    const character = novel.characters.find((item) => item.id === characterId);
    if (character) {
      sources.push({
        title: "当前角色卡扫描层",
        text: [character.name, character.description, character.personality, character.scenario, character.lorebook, (character.tags || []).join(" ")].filter(Boolean).join("\n")
      });
    }
  }
  if (task === "minor") {
    sources.push({
      title: "次要角色池扫描层",
      text: novel.characters
        .filter((character) => character.roleType === "minor")
        .map((character) => [character.name, character.description, character.personality, character.scenario, character.lorebook].filter(Boolean).join("\n"))
        .join("\n\n")
    });
  }
  return sources.filter((item) => String(item.text || "").trim());
}

function assemblePromptSections(fixedContext, triggeredLore, structuredMemory, retrievedEvidence, recentContext) {
  const loreByPosition = groupLoreByPosition(triggeredLore);
  return [
    ...loreSections(loreByPosition.before_character, "世界书：角色卡前"),
    ...fixedContext.map((item) => ({
      layer: "fixed_context",
      title: item.title,
      text: item.text,
      source: item.source
    })),
    ...loreSections(loreByPosition.after_character, "世界书：角色卡后"),
    ...loreSections(loreByPosition.before_memory, "世界书：记忆前"),
    ...structuredMemory.map((item) => ({
      layer: "structured_memory",
      title: `长期记忆：${[item.subject, item.field].filter(Boolean).join(" / ") || item.category}`,
      text: item.value,
      source: item.source
    })),
    ...retrievedEvidence.map((item) => ({
      layer: "retrieved_evidence",
      title: item.title,
      text: item.text,
      source: item.source
    })),
    ...loreSections(loreByPosition.after_memory, "世界书：记忆后"),
    ...recentContext.map((item) => ({
      layer: "recent_context",
      title: item.title,
      text: item.text,
      source: item.source
    }))
  ];
}

function groupLoreByPosition(triggeredLore) {
  const groups = {
    before_character: [],
    after_character: [],
    before_memory: [],
    after_memory: []
  };
  for (const item of triggeredLore || []) {
    const position = groups[item.position] ? item.position : "after_character";
    groups[position].push(item);
  }
  return groups;
}

function loreSections(items, layer) {
  return (items || []).map((item) => ({
    layer,
    title: item.name,
    text: item.text,
    source: item.source,
    matchedKeys: item.matchedKeys,
    score: item.score
  }));
}

function buildFixedContext(novel, task, characterId) {
  const archives = novel.archives || {};
  const scenario = novel.scenario || {};
  if (task === "character") {
    const character = novel.characters.find((item) => item.id === characterId);
    if (!character) return [];
    return [{
      title: "角色卡固定层",
      text: JSON.stringify({
        name: character.name,
        description: character.description,
        personality: character.personality,
        scenario: character.scenario,
        firstMessage: character.firstMessage,
        exampleDialog: character.exampleDialog,
        systemPrompt: character.systemPrompt,
        postHistoryInstructions: character.postHistoryInstructions,
        lorebook: character.lorebook,
        tags: character.tags
      }, null, 2),
      source: { type: "character_card", id: character.id }
    }];
  }
  if (task === "minor") {
    return [{
      title: "次要角色池",
      text: JSON.stringify(novel.characters
        .filter((character) => character.roleType === "minor")
        .map((character) => ({
          name: character.name,
          description: character.description,
          personality: character.personality,
          scenario: character.scenario,
          lorebook: character.lorebook
        })), null, 2),
      source: { type: "minor_character_pool", id: "" }
    }];
  }
  if (task === "adapter") {
    return [{
      title: "改写固定约束",
      text: JSON.stringify({
        style: archives.style || scenario.tone || "",
        scenario,
        acceptedProseTail: getAcceptedProseParts(novel).slice(-1).map((part) => limitText(part.text, 1500)).join("\n")
      }, null, 2),
      source: { type: "adapter_context", id: "" }
    }];
  }
  return [{
    title: task === "planner" ? "策划项目档案" : "导演统筹档案",
    text: JSON.stringify({
      premise: archives.premise,
      background: archives.background || scenario.background,
      outline: archives.outline || scenario.plotDirection,
      style: archives.style || scenario.tone,
      scenario,
      characters: novel.characters.map((character) => ({
        id: character.id,
        name: character.name,
        roleType: character.roleType,
        description: character.description,
        personality: character.personality,
        scenario: character.scenario
      }))
    }, null, 2),
    source: { type: "archive", id: task }
  }];
}

function buildRecentContext(novel, task, characterId) {
  const scanDepth = normalizeLorebookSettings(novel.lorebook?.settings).scanDepth;
  if (task === "planner") {
    return novel.planning.messages.slice(-scanDepth).map((message) => ({
      title: `策划对话：${message.role}`,
      text: limitText(getPlanningMessageVisibleContent(message), 1200),
      source: { type: "planning_chat", id: message.id }
    }));
  }
  const turns = novel.session.turns.slice(-scanDepth);
  if (task === "character") {
    return turns.map((turn) => ({
      title: `第 ${turn.index} 轮角色可见历史`,
      text: JSON.stringify(compactTurnForCharacterPrompt(turn, characterId), null, 2),
      source: { type: "roleplay_turn", id: turn.id }
    }));
  }
  return turns.map((turn) => ({
    title: `第 ${turn.index} 轮历史`,
    text: JSON.stringify(compactTurnForPrompt(turn), null, 2),
    source: { type: "roleplay_turn", id: turn.id }
  }));
}

function collectTriggeredLore(novel, task, characterId, query, settings) {
  const lorebook = normalizeLorebook(novel.lorebook);
  const eligibleEntries = lorebook.entries
    .filter((entry) => entry.enabled)
    .filter((entry) => !isLorebookEntryExpired(entry))
    .filter((entry) => !isLorebookEntryCoolingDown(novel, entry, task, characterId))
    .filter((entry) => isLorebookVisibleTo(entry, task, characterId));
  const triggered = new Map();
  const scanQueue = [{ text: String(query || ""), depth: 0 }];
  while (scanQueue.length > 0 && triggered.size < settings.maxTriggeredEntries) {
    const current = scanQueue.shift();
    const matches = eligibleEntries
      .filter((entry) => !triggered.has(entry.id))
      .map((entry) => ({ entry, match: matchLorebookEntry(entry, current.text) }))
      .filter((item) => item.match.matched)
      .sort(compareLorebookMatches);
    for (const item of matches) {
      if (triggered.size >= settings.maxTriggeredEntries) break;
      const projected = projectTriggeredLore(item.entry, item.match, settings, current.depth);
      triggered.set(item.entry.id, projected);
      // 酒馆的递归扫描会让已触发条目的正文继续参与下一轮关键词匹配，适合“地点 -> 规则 -> 暗号”这类链式设定。
      if (settings.recursiveScanning) {
        scanQueue.push({ text: item.entry.content, depth: current.depth + 1 });
      }
    }
    if (!settings.recursiveScanning) break;
  }
  return applyLorebookTriggerExclusions(Array.from(triggered.values()));
}

function applyLorebookTriggerExclusions(items) {
  const byId = new Map(items.map((item) => [item.id, item]));
  for (const item of items) {
    for (const overrideId of item.overrides || []) {
      if (overrideId !== item.id) byId.delete(overrideId);
    }
  }
  const bestByGroup = new Map();
  const ungrouped = [];
  for (const item of byId.values()) {
    if (!item.exclusiveGroup) {
      ungrouped.push(item);
      continue;
    }
    const current = bestByGroup.get(item.exclusiveGroup);
    if (!current || compareTriggeredLoreForExclusion(item, current) < 0) {
      bestByGroup.set(item.exclusiveGroup, item);
    }
  }
  return [...ungrouped, ...bestByGroup.values()].sort((a, b) => b.score - a.score || b.priority - a.priority);
}

function compareTriggeredLoreForExclusion(a, b) {
  return b.score - a.score || b.priority - a.priority || String(b.id).localeCompare(String(a.id));
}

function isLorebookEntryExpired(entry) {
  if (!entry.expiresAt) return false;
  const time = Date.parse(entry.expiresAt);
  return Number.isFinite(time) && time <= Date.now();
}

function isLorebookEntryCoolingDown(novel, entry, task, characterId) {
  if (!entry.cooldownTurns) return false;
  const logs = Array.isArray(novel.lorebook?.triggerLogs) ? novel.lorebook.triggerLogs : [];
  const last = [...logs].reverse().find((log) => log.entryId === entry.id && log.task === task && String(log.characterId || "") === String(characterId || ""));
  if (!last) return false;
  const currentTurn = Number(novel.session?.turnIndex || 0);
  const lastTurn = Number(last.turnIndex || 0);
  return currentTurn - lastTurn < entry.cooldownTurns;
}

function compareLorebookMatches(a, b) {
  return b.match.score - a.match.score
    || b.entry.priority - a.entry.priority
    || String(b.entry.updatedAt || "").localeCompare(String(a.entry.updatedAt || ""));
}

function projectTriggeredLore(entry, match, settings, recursiveDepth) {
  return {
    id: entry.id,
    name: entry.name,
    scope: entry.scope,
    ownerId: entry.ownerId,
    keys: entry.keys,
    secondaryKeys: entry.secondaryKeys,
    position: entry.position,
    priority: entry.priority,
    cooldownTurns: entry.cooldownTurns,
    exclusiveGroup: entry.exclusiveGroup,
    overrides: entry.overrides,
    expiresAt: entry.expiresAt,
    score: Number(match.score.toFixed(4)),
    matchedKeys: match.matchedKeys,
    matchDetail: match.matchDetail || null,
    diagnostics: match.diagnostics || [],
    recursiveDepth,
    visibility: entry.visibility,
    text: limitText(entry.content, Math.min(entry.tokenBudget, settings.maxCharsPerEntry)),
    source: { type: "lorebook", id: entry.id }
  };
}

function isLorebookVisibleTo(entry, task, characterId) {
  const visibility = entry.visibility || [];
  if (visibility.includes(task)) return true;
  if (task === "character") {
    return visibility.includes(`character:${characterId}`) || visibility.includes("character:*");
  }
  if (task === "minor") {
    return visibility.includes("minor");
  }
  return false;
}

function matchLorebookEntry(entry, query) {
  if (entry.matchMode === "always") {
    return {
      matched: true,
      score: 10000 + entry.priority,
      matchedKeys: ["始终注入"],
      matchDetail: {
        mode: "always",
        primary: { matched: true, required: 0, matches: [] },
        secondary: { matched: true, required: 0, matches: [] },
        diagnostics: []
      },
      diagnostics: []
    };
  }
  const scanText = normalizeLorebookMatchText(query, entry.caseSensitive);
  const primaryMatched = matchKeywords(entry.keys, scanText, entry.matchMode, { caseSensitive: entry.caseSensitive, group: "primary" });
  if (!primaryMatched.matched) {
    return {
      matched: false,
      score: 0,
      matchedKeys: [],
      matchDetail: buildLorebookMatchDetail(entry.matchMode, primaryMatched, null),
      diagnostics: primaryMatched.diagnostics
    };
  }
  const secondaryMatched = entry.secondaryKeys.length > 0
    ? matchKeywords(entry.secondaryKeys, scanText, "any", { caseSensitive: entry.caseSensitive, group: "secondary" })
    : { matched: true, score: 0, matchedKeys: [], matches: [], diagnostics: [] };
  if (!secondaryMatched.matched) {
    return {
      matched: false,
      score: 0,
      matchedKeys: primaryMatched.matchedKeys,
      matchDetail: buildLorebookMatchDetail(entry.matchMode, primaryMatched, secondaryMatched),
      diagnostics: [...primaryMatched.diagnostics, ...secondaryMatched.diagnostics]
    };
  }
  const contentWeight = Math.min(4, tokenizeChineseText(entry.content).length / 120);
  const score = entry.priority + primaryMatched.score * 10 + secondaryMatched.score * 4 + contentWeight;
  const diagnostics = [...primaryMatched.diagnostics, ...secondaryMatched.diagnostics];
  return {
    matched: true,
    score,
    matchedKeys: [...primaryMatched.matchedKeys, ...secondaryMatched.matchedKeys],
    matchDetail: buildLorebookMatchDetail(entry.matchMode, primaryMatched, secondaryMatched, contentWeight),
    diagnostics
  };
}

function normalizeLorebookMatchText(text, caseSensitive = false) {
  const value = String(text || "").normalize("NFKC").replace(/\s+/g, " ").trim();
  return caseSensitive ? value : value.toLowerCase();
}

function buildLorebookMatchDetail(mode, primary, secondary, contentWeight = 0) {
  return {
    mode,
    primary: {
      matched: Boolean(primary?.matched),
      required: primary?.required || 0,
      matches: (primary?.matches || []).slice(0, 20)
    },
    secondary: secondary ? {
      matched: Boolean(secondary.matched),
      required: secondary.required || 0,
      matches: (secondary.matches || []).slice(0, 20)
    } : { matched: true, required: 0, matches: [] },
    contentWeight: Number((contentWeight || 0).toFixed(4)),
    diagnostics: uniqueLorebookDiagnostics([...(primary?.diagnostics || []), ...(secondary?.diagnostics || [])])
  };
}

function matchKeywords(keys, text, matchMode, options = {}) {
  const sourceKeys = Array.isArray(keys) ? keys.map((key) => String(key || "").trim()).filter(Boolean) : [];
  if (sourceKeys.length === 0) {
    return { matched: false, score: 0, matchedKeys: [], matches: [], diagnostics: [], required: 0 };
  }
  if (matchMode === "regex") {
    const result = matchRegexKeywordSet(sourceKeys, text, options);
    return {
      ...result,
      matched: result.matches.length > 0,
      matchedKeys: result.matches.map((item) => item.key),
      score: result.matches.reduce((sum, item) => sum + item.score, 0),
      required: sourceKeys.length
    };
  }
  const plan = buildKeywordMatchPlan(sourceKeys, text, options);
  const matched = matchMode === "all" ? plan.matches.length === sourceKeys.length : plan.matches.length > 0;
  return {
    matched,
    score: plan.matches.reduce((sum, item) => sum + item.score, 0),
    matchedKeys: plan.matches.map((item) => item.key),
    matches: plan.matches,
    diagnostics: plan.diagnostics,
    required: sourceKeys.length
  };
}

function buildKeywordMatchPlan(keys, normalizedText, options = {}) {
  const normalizedKeys = keys
    .map((key) => ({
      raw: key,
      normalized: normalizeLorebookMatchText(key, options.caseSensitive)
    }))
    .filter((item) => item.normalized)
    .sort((a, b) => b.normalized.length - a.normalized.length || a.raw.localeCompare(b.raw));
  const matches = [];
  const diagnostics = [];
  for (const item of normalizedKeys) {
    const match = matchKeywordInText(item.raw, item.normalized, normalizedText, options);
    diagnostics.push(...match.diagnostics);
    if (match.matched) matches.push(match.record);
  }
  diagnostics.push(...diagnoseKeywordShadowing(normalizedKeys));
  return {
    matches,
    diagnostics: uniqueLorebookDiagnostics(diagnostics)
  };
}

function matchKeywordInText(rawKey, normalizedKey, normalizedText, options = {}) {
  const diagnostics = [];
  if (normalizedKey.length <= 1) {
    diagnostics.push(createLorebookMatchDiagnostic("keyword_too_short", `${options.group || "keyword"} 触发词过短：${rawKey}`, "low", rawKey));
  }
  const positions = findKeywordPositions(normalizedText, normalizedKey).slice(0, 12);
  if (positions.length === 0) {
    return { matched: false, record: null, diagnostics };
  }
  const boundaryHits = positions.filter((position) => hasKeywordBoundary(normalizedText, normalizedKey, position));
  const hasBoundary = boundaryHits.length > 0 || isCjkKeyword(normalizedKey);
  if (!hasBoundary && normalizedKey.length <= 3) {
    diagnostics.push(createLorebookMatchDiagnostic("keyword_boundary_weak", `短触发词缺少清晰边界：${rawKey}`, "low", rawKey));
  }
  const firstIndex = positions[0];
  const score = Math.max(1, Math.min(6, normalizedKey.length / 2)) + Math.min(3, positions.length * 0.35) + (hasBoundary ? 1 : 0);
  return {
    matched: true,
    record: {
      key: rawKey,
      group: options.group || "keyword",
      index: firstIndex,
      hitCount: positions.length,
      boundary: hasBoundary,
      score: Number(score.toFixed(3))
    },
    diagnostics
  };
}

function findKeywordPositions(text, keyword) {
  const positions = [];
  if (!keyword) return positions;
  let index = 0;
  while (index <= text.length) {
    const found = text.indexOf(keyword, index);
    if (found < 0) break;
    positions.push(found);
    index = found + Math.max(1, keyword.length);
  }
  return positions;
}

function hasKeywordBoundary(text, keyword, index) {
  const before = index <= 0 ? "" : text[index - 1];
  const after = index + keyword.length >= text.length ? "" : text[index + keyword.length];
  return !isAsciiWordChar(before) && !isAsciiWordChar(after);
}

function isAsciiWordChar(char) {
  return Boolean(char && /[a-z0-9_]/i.test(char));
}

function isCjkKeyword(text) {
  return /[\u3400-\u9fff]/.test(text);
}

function diagnoseKeywordShadowing(keys) {
  const diagnostics = [];
  for (let left = 0; left < keys.length; left += 1) {
    for (let right = left + 1; right < keys.length; right += 1) {
      const longer = keys[left];
      const shorter = keys[right];
      if (shorter.normalized.length < 2 || !longer.normalized.includes(shorter.normalized)) continue;
      diagnostics.push(createLorebookMatchDiagnostic(
        "keyword_shadowing",
        `短触发词可能遮蔽长触发词：${shorter.raw} / ${longer.raw}`,
        "low",
        shorter.raw
      ));
    }
  }
  return diagnostics.slice(0, 12);
}

function matchRegexKeywordSet(keys, text, options = {}) {
  const matches = [];
  const diagnostics = [];
  for (const key of keys) {
    const risk = diagnoseLorebookRegexKeyword(key, options);
    diagnostics.push(...risk);
    try {
      const regex = buildLorebookRegex(key);
      const match = regex.exec(text);
      if (!match) continue;
      matches.push({
        key,
        group: options.group || "regex",
        index: match.index || 0,
        hitCount: 1,
        boundary: false,
        score: Math.max(1, Math.min(5, String(match[0] || key).length / 2))
      });
    } catch (error) {
      diagnostics.push(createLorebookMatchDiagnostic("regex_invalid", `正则触发词无效：${key}`, "high", key, { error: error.message }));
    }
  }
  return { matches, diagnostics: uniqueLorebookDiagnostics(diagnostics) };
}

function diagnoseLorebookRegexKeyword(keyword, options = {}) {
  const value = String(keyword || "").trim();
  const diagnostics = [];
  if (!value) {
    diagnostics.push(createLorebookMatchDiagnostic("regex_empty", "空正则触发词不会稳定工作", "high", keyword));
    return diagnostics;
  }
  if (value.length <= 2 || value === ".*" || value === "/.*/") {
    diagnostics.push(createLorebookMatchDiagnostic("regex_too_broad", `正则触发词过宽：${value}`, "high", keyword));
  }
  if (/^\W*$/.test(value.replace(/^\/|\/[dgimsuvy]*$/g, ""))) {
    diagnostics.push(createLorebookMatchDiagnostic("regex_low_signal", `正则触发词语义信息不足：${value}`, "medium", keyword));
  }
  if (!options.caseSensitive && /[A-Z]/.test(value)) {
    diagnostics.push(createLorebookMatchDiagnostic("regex_case_normalized", `正则将在非区分大小写扫描文本上运行：${value}`, "low", keyword));
  }
  return diagnostics;
}

function createLorebookMatchDiagnostic(code, message, severity = "low", key = "", details = null) {
  return {
    code: `lorebook.match.${code}`,
    severity,
    key: String(key || ""),
    message,
    details
  };
}

function uniqueLorebookDiagnostics(items) {
  const map = new Map();
  for (const item of items || []) {
    if (!item) continue;
    const key = `${item.code}|${item.key}|${item.message}`;
    if (!map.has(key)) map.set(key, item);
  }
  return Array.from(map.values()).slice(0, 30);
}

function buildLorebookRegex(keyword) {
  const value = String(keyword || "");
  const match = value.match(/^\/([\s\S]*)\/([dgimsuvy]*)$/);
  if (match) {
    return new RegExp(match[1], match[2]);
  }
  return new RegExp(value);
}

function isMemoryVisibleTo(item, task, characterId) {
  if (item.status === "outdated") return false;
  const visibility = item.visibility || [];
  if (visibility.includes(task)) return true;
  if (task === "character") {
    return visibility.includes(`character:${characterId}`) || visibility.includes("character:*");
  }
  if (task === "minor") {
    return visibility.includes("minor");
  }
  return false;
}

function rankMemoryItems(items, query, task) {
  const queryTokens = new Set(tokenizeChineseText(query));
  return [...items].sort((a, b) => {
    const scoreA = scoreMemoryItem(a, queryTokens, task);
    const scoreB = scoreMemoryItem(b, queryTokens, task);
    if (scoreB !== scoreA) return scoreB - scoreA;
    return String(b.updatedAt || "").localeCompare(String(a.updatedAt || ""));
  });
}

function scoreMemoryItem(item, queryTokens, task) {
  const tokens = tokenizeChineseText([item.subject, item.field, item.value, item.category].join("\n"));
  let score = 0;
  for (const token of tokens) {
    if (queryTokens.has(token)) score += 1;
  }
  if (task === "director" && ["timeline", "scene_fact", "open_loop", "world_rule"].includes(item.category)) score += 3;
  if (task === "character" && ["character_state", "relationship", "scene_fact"].includes(item.category)) score += 3;
  if (task === "minor" && ["scene_fact", "world_rule", "relationship"].includes(item.category)) score += 2;
  if (task === "adapter" && ["style_preference", "draft_evidence", "timeline"].includes(item.category)) score += 3;
  if (memoryLayerForTask(task).includes(item.layer)) score += 2;
  if (item.status === "tentative") score -= 1;
  if (item.status === "resolved") score -= 0.5;
  return score;
}

function projectMemoryItemForPack(item) {
  return {
    id: item.id,
    layer: item.layer,
    scope: item.scope,
    ownerId: item.ownerId,
    category: item.category,
    subject: item.subject,
    field: item.field,
    value: item.value,
    status: item.status,
    visibility: item.visibility,
    source: item.source,
    evidence: item.evidence,
    updatedAt: item.updatedAt
  };
}

function collectRagSources(novel, task, characterId) {
  return collectAllMemoryDocuments(novel).filter((document) => {
    if ((task === "character" || task === "minor") && document.source?.type === "lorebook") {
      return false;
    }
    return isDocumentVisibleTo(document, task, characterId);
  });
}

function collectPlanningSearchDocuments(store, novel, options = {}) {
  const documents = [...collectAllMemoryDocuments(novel, options)];
  const addDocument = (id, title, text, source, visibility = ["planner"]) => {
    const value = limitText(String(text || "").trim(), PLANNING_SEARCH_DOCUMENT_MAX_CHARS);
    if (!value) return;
    documents.push({ id, title, text: value, source, visibility });
  };
  if (!options.lightweight) {
    for (const provider of store.providers || []) {
      addDocument(
        `provider_${provider.id}`,
        `提供商：${provider.name}`,
        JSON.stringify({
          id: provider.id,
          name: provider.name,
          baseUrl: provider.baseUrl,
          endpointKind: provider.endpointKind,
          modelQueryPath: provider.modelQueryPath,
          models: provider.models || [],
          builtin: Boolean(provider.builtin),
          hasKey: Boolean(provider.apiKey),
          maskedKey: provider.apiKey ? maskSecret(provider.apiKey) : ""
        }, null, 2),
        { type: "provider_config", id: provider.id }
      );
    }
    addDocument(
      `ai_roles_${novel.id}`,
      "AI 槽位配置",
      JSON.stringify(novel.aiRoles || {}, null, 2),
      { type: "ai_role_config", id: novel.id }
    );
  }
  if (novel.planning?.defaultRoleplayConfig?.config) {
    addDocument(
      `roleplay_default_${novel.id}`,
      "默认扮演配置",
      JSON.stringify(novel.planning.defaultRoleplayConfig, null, 2),
      { type: "roleplay_config_default", id: novel.id }
    );
  }
  for (const draft of (novel.planning?.roleplayDrafts || []).slice(0, options.lightweight ? 3 : Infinity)) {
    addDocument(
      `roleplay_draft_${draft.id}`,
      `扮演配置草案：${draft.id}`,
      JSON.stringify(draft.config || draft.raw || draft, null, 2),
      { type: "roleplay_config_draft", id: draft.id }
    );
  }
  const proseParts = Number.isFinite(options.recentProse)
    ? (novel.session?.proseParts || []).slice(-options.recentProse)
    : (novel.session?.proseParts || []);
  for (const prose of proseParts) {
    const status = normalizeProseStatus(prose.status);
    if (status === "accepted") continue;
    addDocument(
      `prose_draft_${prose.id}`,
      `正文草稿 ${prose.turnRange?.join("-") || prose.id} · ${status}`,
      prose.text,
      { type: "prose_part", id: prose.id }
    );
  }
  return documents;
}

function collectAllMemoryDocuments(novel, options = {}) {
  const documents = [];
  const addDocument = (id, title, text, source, visibility = ["planner", "director", "adapter", "minor", "character:*"]) => {
    const value = limitText(String(text || "").trim(), PLANNING_SEARCH_DOCUMENT_MAX_CHARS);
    if (!value) return;
    documents.push({ id, title, text: value, source, visibility });
  };
  addDocument("archive_premise", "核心命题", novel.archives?.premise, { type: "archive", id: "premise" }, ["planner", "director", "adapter"]);
  addDocument("archive_background", "世界背景", novel.archives?.background, { type: "archive", id: "background" });
  addDocument("archive_outline", "大纲", novel.archives?.outline, { type: "archive", id: "outline" }, ["planner", "director", "adapter"]);
  addDocument("archive_style", "文风", novel.archives?.style, { type: "archive", id: "style" }, ["planner", "director", "adapter"]);
  for (const [index, item] of (novel.archives?.characters || []).entries()) {
    const key = archiveRecordKey(item);
    addDocument(`archive_character_${key || index}`, `角色档案：${item.name || item.title || item.key || "未命名角色"}`, summarizeArchiveRecord(item), { type: "archive", id: `characters:${key || index}` }, ["planner", "director", "adapter"]);
  }
  for (const [index, item] of (novel.archives?.scenes || []).entries()) {
    const key = archiveRecordKey(item);
    addDocument(`archive_scene_${key || index}`, `场景档案：${item.name || item.title || item.place || item.key || "未命名场景"}`, summarizeArchiveRecord(item), { type: "archive", id: `scenes:${key || index}` });
  }
  for (const [index, item] of (novel.archives?.clues || []).entries()) {
    const key = archiveRecordKey(item);
    addDocument(`archive_clue_${key || index}`, `线索档案：${item.name || item.title || item.key || "未命名线索"}`, summarizeArchiveRecord(item), { type: "archive", id: `clues:${key || index}` }, ["planner", "director", "adapter"]);
  }
  for (const item of novel.memory?.items || []) {
    const memory = normalizeMemoryItem(item);
    addDocument(
      `memory_${memory.id}`,
      `记忆：${memory.subject} / ${memory.field}`,
      [memory.value, ...(memory.evidence || [])].filter(Boolean).join("\n"),
      { type: "memory", id: memory.id },
      memory.visibility
    );
  }
  for (const entry of normalizeLorebook(novel.lorebook).entries) {
    if (!entry.enabled) continue;
    addDocument(`lore_${entry.id}`, `世界书：${entry.name}`, entry.content, { type: "lorebook", id: entry.id }, entry.visibility);
  }
  for (const character of novel.characters || []) {
    const visibility = ["planner", "director", "adapter", `character:${character.id}`];
    addDocument(`character_${character.id}`, `角色卡：${character.name}`, JSON.stringify(characterCardForPrompt(character), null, 2), { type: "character_card", id: character.id }, visibility);
  }
  const turns = Number.isFinite(options.recentTurns)
    ? (novel.session.turns || []).slice(-options.recentTurns)
    : (novel.session.turns || []);
  for (const turn of turns) {
    addDocument(`turn_${turn.id}_guide`, `第 ${turn.index} 轮导演引导`, JSON.stringify(turn.guide?.parsed || turn.guide?.text || "", null, 2), { type: "roleplay_turn", id: turn.id }, ["planner", "director", "adapter", "minor", "character:*"]);
    for (const record of turn.performances || []) {
      if (record.kind === "major") {
        addDocument(
          `turn_${turn.id}_${record.characterId}_private`,
          `第 ${turn.index} 轮：${record.name} 私有扮演`,
          formatAiRecordContent(record),
          { type: "roleplay_turn", id: turn.id },
          ["planner", "director", "adapter", `character:${record.characterId}`]
        );
        addDocument(
          `turn_${turn.id}_${record.characterId}_public`,
          `第 ${turn.index} 轮：${record.name} 可观察行动`,
          JSON.stringify(publicPerformanceForPrompt(record), null, 2),
          { type: "roleplay_turn", id: turn.id },
          ["planner", "director", "adapter", "minor", "character:*"]
        );
      } else {
        addDocument(
          `turn_${turn.id}_minor`,
          `第 ${turn.index} 轮：次要角色群`,
          formatAiRecordContent(record),
          { type: "roleplay_turn", id: turn.id },
          ["planner", "director", "adapter", "minor", "character:*"]
        );
      }
    }
  }
  const reviews = Number.isFinite(options.recentReviews)
    ? (novel.session.reviews || []).slice(-options.recentReviews)
    : (novel.session.reviews || []);
  for (const review of reviews) {
    addDocument(
      `review_${review.id}`,
      `审查注释：${review.targetType} ${review.targetId}`,
      JSON.stringify(review, null, 2),
      { type: "review", id: review.id },
      ["planner", "director", "adapter"]
    );
  }
  const proseParts = Number.isFinite(options.recentProse)
    ? (novel.session.proseParts || []).slice(-options.recentProse)
    : (novel.session.proseParts || []);
  for (const prose of proseParts) {
    if (normalizeProseStatus(prose.status) !== "accepted") continue;
    addDocument(`prose_${prose.id}`, `正文片段 ${prose.turnRange?.join("-") || ""}`, prose.text, { type: "prose_part", id: prose.id }, ["planner", "director", "adapter"]);
  }
  if (options.includePlanningHistory !== false) {
    const messages = Number.isFinite(options.recentPlanningMessages)
      ? (novel.planning.messages || []).slice(-options.recentPlanningMessages)
      : (novel.planning.messages || []);
    for (const message of messages) {
      addDocument(`planning_${message.id}`, `策划对话：${message.role}`, summarizePlanningMessageForSearch(message), { type: "planning_chat", id: message.id }, ["planner", "director", "adapter"]);
      if (message.skillOpReport) {
        addDocument(
          `planning_${message.id}_skill_ops`,
          `策划 Skill 执行结果`,
          summarizeSkillOpReportForSearch(message.skillOpReport),
          { type: "planning_skill_ops", id: message.id },
          ["planner", "director", "adapter"]
        );
      }
    }
  }
  return documents;
}

function summarizePlanningMessageForSearch(message) {
  const role = String(message?.role || "");
  const content = limitText(getPlanningMessageVisibleContent(message), role === "user" ? 1800 : 1200);
  const lines = [
    `role=${role}`,
    message?.runId ? `runId=${message.runId}` : "",
    message?.branchId ? `branch=${message.branchId}` : "",
    message?.compressedInContext ? "已进入上下文压缩摘要" : "",
    content
  ].filter(Boolean);
  if (message?.taskPlan?.length) {
    lines.push(`任务计划：${limitText(JSON.stringify(message.taskPlan), 600)}`);
  }
  if (message?.completionVerifier) {
    lines.push(`完成判定：${limitText(JSON.stringify(message.completionVerifier), 600)}`);
  }
  if (message?.selfReview) {
    lines.push(`自检：${limitText(JSON.stringify(message.selfReview), 600)}`);
  }
  return limitText(lines.join("\n"), PLANNING_SEARCH_DOCUMENT_MAX_CHARS);
}

function summarizeSkillOpReportForSearch(report) {
  const normalized = normalizeSkillOpReport(report);
  if (!normalized) return "";
  const lines = [];
  for (const item of normalized.searches || []) {
    lines.push([
      `检索工具：${item.type || "search"}`,
      item.query ? `query=${limitText(item.query, 180)}` : "",
      item.scope ? `scope=${item.scope}` : "",
      item.count !== undefined ? `count=${item.count}` : "",
      ...(item.assetRef ? [`asset=${item.assetRef.id}`] : []),
      ...(Array.isArray(item.assetRefs) ? item.assetRefs.map((asset) => `asset=${asset.id}`) : [])
    ].filter(Boolean).join("；"));
    for (const result of (item.results || []).slice(0, 6)) {
      lines.push([
        result.code ? `诊断=${result.code}` : "",
        result.title ? `标题=${limitText(result.title, 120)}` : "",
        result.source?.type ? `来源=${result.source.type}` : "",
        result.assetRef?.id ? `asset=${result.assetRef.id}` : "",
        result.text ? `片段=${limitText(result.text, 180)}` : ""
      ].filter(Boolean).join("；"));
    }
  }
  for (const item of normalized.applied || []) {
    lines.push([
      `写入工具：${item.type || item.name || "applied"}`,
      item.id ? `id=${item.id}` : "",
      item.patchId ? `patch=${item.patchId}` : "",
      item.patchSetId ? `patchSet=${item.patchSetId}` : "",
      item.assetRef?.id ? `asset=${item.assetRef.id}` : "",
      Array.isArray(item.assetRefs) ? item.assetRefs.map((asset) => `asset=${asset.id}`).join("；") : "",
      item.reason ? `原因=${limitText(item.reason, 160)}` : ""
    ].filter(Boolean).join("；"));
  }
  for (const item of normalized.skipped || []) {
    lines.push([
      `跳过工具：${item.type || "unknown"}`,
      item.code ? `code=${item.code}` : "",
      item.reason ? `原因=${limitText(item.reason, 200)}` : "",
      item.suggestedFix ? `建议=${limitText(item.suggestedFix, 160)}` : ""
    ].filter(Boolean).join("；"));
  }
  for (const read of normalized.evidenceReads || []) {
    lines.push([
      `证据读取：${read.layer || ""}`,
      read.toolType ? `tool=${read.toolType}` : "",
      read.query ? `query=${limitText(read.query, 160)}` : "",
      read.assetId ? `asset=${read.assetId}` : ""
    ].filter(Boolean).join("；"));
  }
  return limitText(lines.filter(Boolean).join("\n"), 6000);
}

function isDocumentVisibleTo(document, task, characterId) {
  const visibility = document.visibility || [];
  if (task === "character") {
    return visibility.includes(`character:${characterId}`) || visibility.includes("character:*");
  }
  if (task === "minor") {
    return visibility.includes("minor");
  }
  return visibility.includes(task);
}

async function retrieveRagEvidence(store, novel, task, characterId, query, documents, settings, limit) {
  const warnings = [];
  const mode = settings.retrievalMode;
  const candidateLimit = Math.max(limit, settings.maxVectorCandidates);
  const bm25Items = mode === "vector" ? [] : bm25Search(documents, query, candidateLimit);
  let vectorItems = [];
  if (settings.vectorEnabled && mode !== "bm25") {
    try {
      vectorItems = await vectorSearchMemory(store, novel, task, characterId, query, settings, candidateLimit);
    } catch (error) {
      warnings.push(error instanceof HttpError ? error.message : `向量检索失败：${error.message || error}`);
    }
  }
  if (settings.vectorEnabled && mode !== "bm25" && vectorItems.length === 0) {
    warnings.push("向量检索没有返回结果，请确认已重建向量索引并配置了可用的 embedding 模型");
  }
  const merged = mergeRetrievalCandidates(bm25Items, vectorItems);
  const reranked = await rerankMemoryCandidates(store, settings, task, query, merged, limit, warnings);
  return {
    items: reranked.slice(0, limit),
    warnings
  };
}

async function vectorSearchMemory(store, novel, task, characterId, query, settings, limit) {
  const index = normalizeVectorIndex(novel.memory?.vectorIndex);
  if (index.documents.length === 0) {
    return [];
  }
  const currentHash = calculateVectorSourceHash(collectAllMemoryDocuments(novel), settings);
  if (index.sourceHash !== currentHash || index.stale) {
    throw new HttpError(409, "向量索引已过期，需要重新构建");
  }
  const querySettings = {
    ...settings,
    embeddingProviderId: index.embeddingProviderId,
    embeddingModel: index.embeddingModel
  };
  const embeddingResult = await embedTexts(store, querySettings, [query]);
  const queryEmbedding = embeddingResult.embeddings[0] || [];
  if (queryEmbedding.length === 0) {
    return [];
  }
  return index.documents
    .filter((document) => {
      if ((task === "character" || task === "minor") && document.source?.type === "lorebook") {
        return false;
      }
      return isDocumentVisibleTo(document, task, characterId);
    })
    .map((document) => ({
      document: {
        id: document.documentId || document.id,
        title: document.chunkIndex > 0 ? `${document.title} #${document.chunkIndex + 1}` : document.title,
        text: document.text,
        source: document.source,
        visibility: document.visibility
      },
      score: cosineSimilarity(queryEmbedding, document.embedding)
    }))
    .filter((item) => item.score > 0)
    .sort((a, b) => b.score - a.score)
    .slice(0, limit);
}

function mergeRetrievalCandidates(bm25Items, vectorItems) {
  const merged = new Map();
  const maxBm25 = Math.max(0.0001, ...bm25Items.map((item) => item.score || 0));
  const maxVector = Math.max(0.0001, ...vectorItems.map((item) => item.score || 0));
  for (const item of bm25Items) {
    const key = item.document.id;
    const current = merged.get(key) || {
      document: item.document,
      bm25Score: 0,
      vectorScore: 0,
      retrievalMode: []
    };
    current.bm25Score = Math.max(current.bm25Score, item.score / maxBm25);
    current.retrievalMode = uniqueStrings([...current.retrievalMode, "bm25"]);
    merged.set(key, current);
  }
  for (const item of vectorItems) {
    const key = item.document.id;
    const current = merged.get(key) || {
      document: item.document,
      bm25Score: 0,
      vectorScore: 0,
      retrievalMode: []
    };
    current.vectorScore = Math.max(current.vectorScore, item.score / maxVector);
    current.retrievalMode = uniqueStrings([...current.retrievalMode, "vector"]);
    merged.set(key, current);
  }
  return Array.from(merged.values()).map((item) => ({
    ...item,
    score: item.bm25Score * 0.45 + item.vectorScore * 0.55,
    retrievalMode: item.retrievalMode.join("+")
  })).sort((a, b) => b.score - a.score);
}

async function rerankMemoryCandidates(store, settings, task, query, candidates, limit, warnings) {
  if (candidates.length === 0) return [];
  const candidateLimit = Math.max(limit, settings.maxVectorCandidates);
  const trimmed = candidates.slice(0, candidateLimit);
  if (settings.projectSearchFastPath) {
    return trimmed.slice(0, limit);
  }
  if (!settings.rerankEnabled) {
    return trimmed.slice(0, limit);
  }
  if (settings.rerankProviderId && settings.rerankModel) {
    try {
      return await aiRerankMemoryCandidates(store, settings, task, query, trimmed, limit);
    } catch (error) {
      warnings.push(error instanceof HttpError ? error.message : `AI 重排失败：${error.message || error}`);
    }
  }
  return localRerankMemoryCandidates(task, query, trimmed).slice(0, limit);
}

async function aiRerankMemoryCandidates(store, settings, task, query, candidates, limit) {
  const provider = findProvider(store, settings.rerankProviderId);
  const result = await requestAi({
    provider,
    model: settings.rerankModel,
    temperature: 0,
    systemPrompt: buildRerankSystemPrompt(),
    messages: [
      {
        role: "user",
        content: JSON.stringify({
          task,
          query,
          limit,
          candidates: candidates.map((item, index) => ({
            id: item.document.id,
            index,
            title: item.document.title,
            source: item.document.source,
            bm25Score: Number((item.bm25Score || 0).toFixed(4)),
            vectorScore: Number((item.vectorScore || 0).toFixed(4)),
            text: limitText(item.document.text, 700)
          }))
        }, null, 2)
      }
    ]
  });
  const parsed = parseLooseJson(result.text);
  const ranked = Array.isArray(parsed?.ranked) ? parsed.ranked : Array.isArray(parsed?.items) ? parsed.items : [];
  if (ranked.length === 0) {
    throw new HttpError(502, "AI 重排没有返回 ranked 数组", safeRemoteText(result.text));
  }
  const order = new Map();
  ranked.forEach((item, index) => {
    order.set(String(item.id || item.documentId || ""), {
      index,
      score: Number(item.score ?? (ranked.length - index))
    });
  });
  return candidates.map((item, index) => {
    const rankedItem = order.get(item.document.id);
    const rerankScore = rankedItem ? rankedItem.score : Math.max(0, 0.1 - index / 1000);
    return {
      ...item,
      rerankScore,
      score: item.score * 0.35 + rerankScore * 0.65
    };
  }).sort((a, b) => b.score - a.score);
}

function localRerankMemoryCandidates(task, query, candidates) {
  const queryTokens = new Set(tokenizeChineseText(query));
  return candidates.map((item) => {
    const documentTokens = tokenizeChineseText(`${item.document.title}\n${item.document.text}`);
    const overlap = documentTokens.filter((token) => queryTokens.has(token)).length;
    const sourceWeight = memorySourceRerankWeight(task, item.document.source);
    const rerankScore = overlap * 0.08 + sourceWeight + item.bm25Score * 0.25 + item.vectorScore * 0.35;
    return {
      ...item,
      rerankScore,
      score: item.score * 0.55 + rerankScore * 0.45
    };
  }).sort((a, b) => b.score - a.score);
}

function memorySourceRerankWeight(task, source) {
  const type = source?.type || "";
  if (task === "director" && ["archive", "lorebook", "roleplay_turn"].includes(type)) return 0.4;
  if (task === "character" && ["character_card", "roleplay_turn"].includes(type)) return 0.35;
  if (task === "planner" && ["planning_chat", "archive"].includes(type)) return 0.35;
  if (task === "adapter" && ["prose_part", "roleplay_turn"].includes(type)) return 0.4;
  return 0.1;
}

function buildRerankSystemPrompt() {
  return [
    "你是小说项目的检索重排 AI。",
    "你只负责根据 query 和 task 判断哪些候选证据最应该进入本次上下文。",
    "不能发明候选外的新证据，也不能把角色不可见信息提升给角色。",
    "输出 JSON：{\"ranked\":[{\"id\":\"候选 id\",\"score\":0到1,\"reason\":\"一句话理由\"}]}。",
    "score 越高代表越相关，ranked 最多返回输入 limit 条。"
  ].join("\n");
}

async function rebuildVectorIndex(store, novel) {
  const settings = normalizeMemorySettings(novel.memory?.settings);
  const sourceDocuments = collectAllMemoryDocuments(novel);
  const chunks = sourceDocuments.flatMap((document) => chunkMemoryDocument(document, settings.vectorChunkChars));
  if (chunks.length === 0) {
    novel.memory.vectorIndex = {
      ...createDefaultVectorIndex(),
      sourceHash: calculateVectorSourceHash(sourceDocuments, settings),
      stale: false,
      updatedAt: nowIso()
    };
    return summarizeVectorIndex(novel.memory.vectorIndex);
  }
  const texts = chunks.map((chunk) => `${chunk.title}\n${chunk.text}`);
  const embeddingResult = await embedTexts(store, settings, texts);
  const now = nowIso();
  const documents = chunks.map((chunk, index) => ({
    ...chunk,
    embedding: embeddingResult.embeddings[index] || [],
    hash: hashText(`${chunk.title}\n${chunk.text}`),
    tokenCount: tokenizeChineseText(chunk.text).length,
    updatedAt: now
  })).filter((chunk) => chunk.embedding.length > 0);
  novel.memory.vectorIndex = normalizeVectorIndex({
    documents,
    sourceHash: calculateVectorSourceHash(sourceDocuments, settings),
    embeddingProviderId: settings.embeddingProviderId,
    embeddingModel: settings.embeddingModel,
    embeddingBackend: embeddingResult.backend,
    dimensions: embeddingResult.dimensions,
    documentCount: sourceDocuments.length,
    chunkCount: documents.length,
    stale: false,
    updatedAt: now
  });
  novel.memory.updatedAt = now;
  recordEvent(novel, "vector_index_rebuilt", summarizeVectorIndex(novel.memory.vectorIndex));
  updateTimestamp(novel);
  return summarizeVectorIndex(novel.memory.vectorIndex);
}

function chunkMemoryDocument(document, chunkChars) {
  const text = String(document.text || "").trim();
  if (!text) return [];
  const size = clampInteger(chunkChars, 240, 2400, 900);
  const overlap = Math.min(120, Math.floor(size * 0.15));
  const chunks = [];
  let start = 0;
  while (start < text.length) {
    const end = Math.min(text.length, start + size);
    const chunkText = text.slice(start, end).trim();
    if (chunkText) {
      chunks.push({
        id: `${document.id}#${chunks.length}`,
        documentId: document.id,
        chunkIndex: chunks.length,
        title: document.title,
        text: chunkText,
        source: document.source,
        visibility: document.visibility || ["planner", "director", "adapter", "minor", "character:*"]
      });
    }
    if (end >= text.length) break;
    start = Math.max(end - overlap, start + 1);
  }
  return chunks;
}

function calculateVectorSourceHash(documents, settings) {
  const normalizedSettings = normalizeMemorySettings(settings);
  const payload = {
    embeddingProviderId: normalizedSettings.embeddingProviderId,
    embeddingModel: normalizedSettings.embeddingModel,
    chunkChars: normalizedSettings.vectorChunkChars,
    documents: documents.map((document) => ({
      id: document.id,
      title: document.title,
      textHash: hashText(document.text),
      visibility: document.visibility,
      source: document.source
    }))
  };
  return hashText(JSON.stringify(payload));
}

function summarizeVectorIndex(index) {
  const vectorIndex = normalizeVectorIndex(index);
  return {
    documentCount: vectorIndex.documentCount,
    chunkCount: vectorIndex.chunkCount,
    embeddingBackend: vectorIndex.embeddingBackend,
    embeddingProviderId: vectorIndex.embeddingProviderId,
    embeddingModel: vectorIndex.embeddingModel,
    dimensions: vectorIndex.dimensions,
    stale: vectorIndex.stale,
    updatedAt: vectorIndex.updatedAt
  };
}

async function embedTexts(store, settings, texts) {
  const inputs = texts.map((text) => String(text || ""));
  if (inputs.length === 0) {
    return { embeddings: [], dimensions: 0, backend: "empty" };
  }
  if (!settings.embeddingProviderId || !settings.embeddingModel) {
    const embeddings = inputs.map((text) => createLocalEmbedding(text));
    return { embeddings, dimensions: embeddings[0]?.length || 256, backend: "local_hash" };
  }
  const provider = findProvider(store, settings.embeddingProviderId);
  if (isMockProvider(provider)) {
    const embeddings = inputs.map((text) => createLocalEmbedding(text));
    return { embeddings, dimensions: embeddings[0]?.length || 256, backend: "mock_local_hash" };
  }
  ensureProviderReady(provider, "embedding 调用");
  const endpoint = joinUrl(provider.baseUrl, "/embeddings");
  const embeddings = [];
  for (let start = 0; start < inputs.length; start += 64) {
    const batch = inputs.slice(start, start + 64);
    const response = await fetch(endpoint, {
      method: "POST",
      headers: {
        "authorization": `Bearer ${provider.apiKey}`,
        "content-type": "application/json",
        "accept": "application/json"
      },
      body: JSON.stringify({
        model: settings.embeddingModel,
        input: batch
      })
    });
    const text = await response.text();
    if (!response.ok) {
      throw new HttpError(response.status, buildProviderErrorMessage(response.status, text, settings.embeddingModel), safeRemoteText(text));
    }
    const payload = parseRemoteJson(text);
    const batchEmbeddings = extractEmbeddings(payload);
    if (batchEmbeddings.length !== batch.length) {
      throw new HttpError(502, "embedding 响应数量与输入数量不一致", safeRemoteText(text));
    }
    embeddings.push(...batchEmbeddings);
  }
  return {
    embeddings,
    dimensions: embeddings[0]?.length || 0,
    backend: "openai_compatible_embeddings"
  };
}

function extractEmbeddings(payload) {
  if (Array.isArray(payload?.data)) {
    return payload.data
      .sort((a, b) => Number(a.index || 0) - Number(b.index || 0))
      .map((item) => Array.isArray(item.embedding) ? item.embedding.map(Number).filter(Number.isFinite) : []);
  }
  if (Array.isArray(payload?.embeddings)) {
    return payload.embeddings.map((item) => Array.isArray(item) ? item.map(Number).filter(Number.isFinite) : []);
  }
  return [];
}

function createLocalEmbedding(text) {
  const dimensions = 256;
  const vector = new Array(dimensions).fill(0);
  const tokens = tokenizeChineseText(text);
  const frequencies = countTokens(tokens);
  for (const [token, count] of frequencies.entries()) {
    const digest = crypto.createHash("sha256").update(token).digest();
    const index = digest.readUInt16BE(0) % dimensions;
    const sign = digest[2] % 2 === 0 ? 1 : -1;
    vector[index] += sign * Math.log(1 + count);
  }
  return normalizeVector(vector);
}

function normalizeVector(vector) {
  const norm = Math.sqrt(vector.reduce((sum, value) => sum + value * value, 0));
  if (!norm) return vector;
  return vector.map((value) => Number((value / norm).toFixed(8)));
}

function cosineSimilarity(a, b) {
  const length = Math.min(a.length, b.length);
  if (length === 0) return 0;
  let dot = 0;
  let normA = 0;
  let normB = 0;
  for (let index = 0; index < length; index += 1) {
    dot += a[index] * b[index];
    normA += a[index] * a[index];
    normB += b[index] * b[index];
  }
  if (!normA || !normB) return 0;
  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
}

function hashText(text) {
  return crypto.createHash("sha256").update(String(text || "")).digest("hex");
}

function bm25Search(documents, query, limit) {
  const queryWeights = buildBm25QueryWeights(query);
  if (documents.length === 0 || queryWeights.length === 0) return [];
  const docs = documents.map((document) => ({
    document,
    tokens: tokenizeChineseText(`${document.title}\n${document.text}`)
  }));
  const avgLength = docs.reduce((sum, item) => sum + item.tokens.length, 0) / Math.max(1, docs.length);
  const documentFrequency = new Map();
  const docTokenSets = docs.map((item) => new Set(item.tokens));
  for (const { token } of queryWeights) {
    let count = 0;
    for (const tokenSet of docTokenSets) {
      if (tokenSet.has(token)) count += 1;
    }
    documentFrequency.set(token, count);
  }
  const docFrequencies = docs.map((item) => countTokens(item.tokens));
  const k1 = 1.5;
  const b = 0.75;
  return docs.map((item, index) => {
    const frequencies = docFrequencies[index];
    let score = 0;
    for (const { token, weight } of queryWeights) {
      const frequency = frequencies.get(token) || 0;
      if (frequency === 0) continue;
      const df = documentFrequency.get(token) || 0;
      const idf = Math.log(1 + (docs.length - df + 0.5) / (df + 0.5));
      const denominator = frequency + k1 * (1 - b + b * (item.tokens.length / Math.max(1, avgLength)));
      score += weight * idf * ((frequency * (k1 + 1)) / denominator);
    }
    return { document: item.document, score };
  }).filter((item) => item.score > 0)
    .sort((a, b) => b.score - a.score)
    .slice(0, limit);
}

function buildBm25QueryWeights(query) {
  const frequencies = countTokens(tokenizeChineseText(query));
  return [...frequencies.entries()]
    .map(([token, count]) => ({
      token,
      weight: 1 + Math.log1p(Math.max(0, count - 1))
    }))
    .sort((a, b) => b.weight - a.weight || b.token.length - a.token.length)
    .slice(0, 96);
}

function tokenizeChineseText(text) {
  const value = String(text || "").toLowerCase();
  const tokens = [];
  const words = value.match(/[a-z0-9_]+|[\u4e00-\u9fa5]+/g) || [];
  for (const word of words) {
    if (/^[\u4e00-\u9fa5]+$/.test(word)) {
      if (word.length <= 2) {
        tokens.push(word);
      } else {
        for (let index = 0; index < word.length - 1; index += 1) {
          tokens.push(word.slice(index, index + 2));
        }
        tokens.push(word);
      }
    } else {
      tokens.push(word);
    }
  }
  return tokens.filter((token) => token.length > 0);
}

function countTokens(tokens) {
  const result = new Map();
  for (const token of tokens) {
    result.set(token, (result.get(token) || 0) + 1);
  }
  return result;
}

function limitText(text, maxLength) {
  const value = String(text || "");
  if (value.length <= maxLength) return value;
  return `${value.slice(0, maxLength)}...`;
}

async function generatePrewritePlan(store, novel, body = {}) {
  const guideSetting = novel.aiRoles.guide;
  const guideProvider = getConfiguredProvider(store, guideSetting, "导演 AI");
  const userIntent = String(body.intent || body.query || "").trim();
  const workflow = getOrCreateChapterWorkflow(novel, {
    workflowId: body.workflowId,
    chapterLabel: body.chapterLabel,
    intent: userIntent,
    mode: body.mode || "roleplay_prose",
    forceNew: body.forceNew === true
  });
  workflow.status = "planning";
  updateChapterWorkflowStep(workflow, "prewrite", {
    status: "running",
    summary: userIntent || "正在生成章节写前定位"
  });
  const contextPack = await buildAgentContextPack(novel, "director", {
    store,
    queryText: userIntent || "章节写前定位 场景统筹 角色自由度 连续性"
  });
  const result = await requestAi({
    provider: guideProvider,
    model: guideSetting.model,
    temperature: Math.min(0.65, clampTemperature(guideSetting.temperature)),
    systemPrompt: buildPrewritePlanSystemPrompt(workflow.mode),
    messages: [
      {
        role: "user",
        content: buildPrewritePlanUserPrompt(novel, contextPack, userIntent)
      }
    ]
  });
  const parsed = parseLooseJson(result.text);
  if (!parsed || typeof parsed !== "object") {
    throw new HttpError(502, "写前定位没有返回可识别的 JSON", safeRemoteText(result.text));
  }
  const plan = normalizePrewritePlan({
    id: createId("prewrite"),
    workflowId: workflow.id,
    createdAt: nowIso(),
    updatedAt: nowIso(),
    chapterLabel: parsed.chapterLabel || parsed.chapter || body.chapterLabel || "当前章节",
    sourceIntent: userIntent,
    summary: parsed.summary || parsed.directorIntent || "",
    archiveCallouts: parsed.archiveCallouts || parsed.archive_callouts || [],
    foregroundAnchors: parsed.foregroundAnchors || parsed.foreground_anchors || [],
    backgroundOnly: parsed.backgroundOnly || parsed.background_only || [],
    paragraphPlan: parsed.paragraphPlan || parsed.paragraph_plan || [],
    sceneFocus: parsed.sceneFocus || parsed.scene_focus || [],
    softBoundaries: parsed.softBoundaries || parsed.soft_boundaries || [],
    continuityAnchors: parsed.continuityAnchors || parsed.continuity_anchors || [],
    characterBeats: parsed.characterBeats || parsed.character_beats || [],
    runtimeDirectives: parsed.runtimeDirectives || parsed.characterRuntimeDirectives || parsed.runtime_directives || {},
    openQuestions: parsed.openQuestions || parsed.open_questions || [],
    directorNote: parsed.directorNote || parsed.director_note || "",
    memoryInjection: contextPack,
    raw: result.raw
  });
  novel.session.prewritePlan = plan;
  workflow.chapterLabel = plan.chapterLabel;
  workflow.intent = userIntent || workflow.intent;
  workflow.prewritePlanId = plan.id;
  workflow.contextAudits = [...(workflow.contextAudits || []), buildContextAuditFromInjection({ director: contextPack })].slice(-12);
  workflow.status = "draft";
  updateChapterWorkflowStep(workflow, "prewrite", {
    status: "completed",
    summary: plan.summary || "写前定位已生成",
    artifactIds: addWorkflowId(workflow.steps?.prewrite?.artifactIds, plan.id)
  });
  updateChapterWorkflowStep(workflow, "context", {
    status: "completed",
    summary: "导演上下文包已构建",
    artifactIds: addWorkflowId(workflow.steps?.context?.artifactIds, plan.id)
  });
  recordEvent(novel, "prewrite_plan_generated", { planId: plan.id, workflowId: workflow.id, chapterLabel: plan.chapterLabel });
  updateTimestamp(novel);
  return plan;
}

function buildPrewritePlanSystemPrompt(mode = "roleplay_prose") {
  const isNormalWriting = normalizeChapterWorkflowMode(mode) === "normal_prose";
  return [
    "你是章节写前定位导演 AI。",
    isNormalWriting
      ? "你的职责是在正常行文前做基本统筹：确认本章/本段的职责、承接、留白、场景压力、连续性锚点和正文 Agent 可前台落笔的内容。"
      : "你的职责是在扮演前做基本统筹：确认本章/本段的场景压力、连续性锚点、角色可自由发挥的空间。",
    "你不能替角色做具体选择，不能写正文，也不能把写前定位变成硬性分镜。",
    isNormalWriting
      ? "输出要帮助正文 Agent 慢写正文：哪些资料能前台出句，哪些后台知道但本章不写，哪些角色边界不能越过。"
      : "输出要帮助后续导演引导和角色扮演保持方向，但必须保留角色 AI 的自主反应。",
    "输入中的 contextPack 是本轮上下文包，不是一个把所有资料混在一起的上下文桶。",
    "contextPack 分为角色卡固定层 fixedContext、世界书触发层 triggeredLore、长期记忆层 structuredMemory、RAG 检索证据层 retrievedEvidence、近场历史层 recentContext。",
    "长期记忆层是有证据的稳定事实；RAG 检索证据层只是一轮临时证据，冲突和审查风险要转成提醒，不要强行裁决未确认事实。",
    "输出必须像项目的 06-写前定位 文件：先给本章职责，再列档案调用摘录、前台锚点、后台知道但不出句、段落组计划。",
    "档案调用摘录只写本章真正生效的约束；后台知道但不出句只能给导演和改写器，不能泄漏成角色全知。",
    "输出 JSON，字段包括 chapterLabel、summary、archiveCallouts、foregroundAnchors、backgroundOnly、paragraphPlan、sceneFocus、softBoundaries、continuityAnchors、characterBeats、openQuestions、directorNote。",
    "paragraphPlan 每项包含 purpose、source、avoid。",
    "characterBeats 每项包含 characterId、name、attention、avoidForcing。",
    "runtimeDirectives 是每个主要角色的运行时可见性指令，key 使用 characterId；每项包含 currentGoal、visibleFacts、forbiddenKnowledge、forbiddenMoves、observationFocus。"
  ].join("\n");
}

function buildPrewritePlanUserPrompt(novel, contextPack, userIntent) {
  return JSON.stringify({
    request: userIntent || "为接下来的章节/片段生成写前定位",
    contextPack,
    novel: {
      title: novel.title,
      scenario: novel.scenario,
      archives: novel.archives
    },
    characters: novel.characters.map((character) => ({
      id: character.id,
      name: character.name,
      roleType: character.roleType,
      description: character.description,
      personality: character.personality,
      scenario: character.scenario
    })),
    recentTurns: novel.session.turns.slice(-5).map(compactTurnForPrompt),
    acceptedProseTail: getAcceptedProseParts(novel).slice(-1).map((part) => limitText(part.text, 1800)).join("\n")
  }, null, 2);
}

async function runReviewChain(store, novel, body = {}) {
  const target = resolveReviewTarget(novel, body);
  const workflow = findChapterWorkflow(novel, body.workflowId || target.turn?.workflowId || target.prose?.workflowId || novel.session?.prewritePlan?.workflowId);
  if (workflow) {
    workflow.status = "reviewing";
    updateChapterWorkflowStep(workflow, "review", {
      status: "running",
      summary: body.reason || "正在进行一致性审查"
    });
  }
  const guideSetting = novel.aiRoles.guide;
  const guideProvider = getConfiguredProvider(store, guideSetting, "审查链 AI");
  const contextPack = await buildAgentContextPack(novel, "director", {
    store,
    queryText: `审查 ${target.targetType} ${target.label} 连续性 角色边界 世界规则`
  });
  const result = await requestAi({
    provider: guideProvider,
    model: guideSetting.model,
    temperature: Math.min(0.35, clampTemperature(guideSetting.temperature)),
    systemPrompt: buildReviewSystemPrompt(),
    messages: [
      {
        role: "user",
        content: buildReviewUserPrompt(novel, target, contextPack, body.reason || "")
      }
    ]
  });
  const parsed = parseLooseJson(result.text) || {};
  const localIssues = buildLocalReviewIssues(novel, target);
  const deterministicChain = buildDeterministicReviewChain(novel, target);
  const review = normalizeReviewRecord({
    id: createId("review"),
    workflowId: workflow?.id || "",
    createdAt: nowIso(),
    targetType: target.targetType,
    targetId: target.targetId,
    severity: parsed.severity || inferReviewSeverity([...(parsed.issues || []), ...localIssues]),
    summary: parsed.summary || "审查已完成。",
    issues: [...localIssues, ...deterministicChain.flatMap((item) => item.issues || []), ...(Array.isArray(parsed.issues) ? parsed.issues : [])],
    chain: [
      ...deterministicChain,
      {
        type: "model_review",
        label: "模型综合审查",
        status: inferReviewSeverity(parsed.issues || []) === "ok" ? "passed" : "warning",
        severity: inferReviewSeverity(parsed.issues || []),
        summary: parsed.summary || "模型审查已完成。",
        issues: Array.isArray(parsed.issues) ? parsed.issues : []
      }
    ],
    recommendedAction: parsed.recommendedAction || parsed.recommended_action || "continue",
    memoryInjection: contextPack,
    raw: result.raw
  });
  novel.session.reviews.unshift(review);
  novel.session.reviews = novel.session.reviews.slice(0, 40);
  if (target.turn) {
    target.turn.review = review;
    target.turn.transcript = buildRoleplayTranscriptFromTurn(target.turn, { modelTrace: target.turn.modelTrace || {} });
  }
  if (target.prose) {
    target.prose.review = review;
  }
  if (workflow) {
    workflow.reviewIds = addWorkflowId(workflow.reviewIds, review.id);
    workflow.status = review.severity === "high" || review.severity === "blocking" ? "blocked" : "draft";
    updateChapterWorkflowStep(workflow, "review", {
      status: review.severity === "high" || review.severity === "blocking" ? "warning" : "completed",
      summary: review.summary || "审查已完成",
      artifactIds: addWorkflowId(workflow.steps?.review?.artifactIds, review.id)
    });
  }
  recordEvent(novel, "review_completed", {
    reviewId: review.id,
    workflowId: workflow?.id || "",
    targetType: review.targetType,
    targetId: review.targetId,
    severity: review.severity
  });
  updateTimestamp(novel);
  return review;
}

function resolveReviewTarget(novel, body = {}) {
  const targetType = String(body.targetType || "turn");
  if (targetType === "prose") {
    const prose = body.targetId
      ? findProsePart(novel, body.targetId)
      : [...novel.session.proseParts].reverse().find((part) => normalizeProseStatus(part.status) !== "discarded");
    if (!prose) throw new HttpError(400, "没有可审查的正文片段");
    return {
      targetType: "prose",
      targetId: prose.id,
      label: `正文片段 ${prose.turnRange?.join("-") || prose.id}`,
      prose,
      payload: {
        prose: {
          id: prose.id,
          status: prose.status,
          turnRange: prose.turnRange,
          text: prose.text
        }
      }
    };
  }
  const turn = body.targetId
    ? novel.session.turns.find((item) => item.id === body.targetId)
    : novel.session.turns[novel.session.turns.length - 1];
  if (!turn) throw new HttpError(400, "没有可审查的扮演轮次");
  return {
    targetType: "turn",
    targetId: turn.id,
    label: `第 ${turn.index} 轮`,
    turn,
    payload: {
      turn: compactTurnForPrompt(turn)
    }
  };
}

function buildReviewSystemPrompt() {
  return [
    "你是小说连续性审查 AI。",
    "你的职责是审查扮演记录或正文片段是否破坏角色边界、时间线、世界规则、伏笔状态和已采纳事实。",
    "你不能重写正文，不能替角色补完动机，只能指出问题、证据和最小修正建议。",
    "如果问题需要单角色重跑，recommendedAction 使用 rerun_character；如果只需人工编辑，使用 edit；如果可以继续，使用 continue。",
    "输出 JSON，格式为 {\"severity\":\"ok|low|medium|high|blocking\",\"summary\":\"...\",\"recommendedAction\":\"continue|edit|rerun_character|rerun_turn\",\"issues\":[]}。",
    "issues 每项包括 type、target、severity、description、evidence、suggestion、blocking。"
  ].join("\n");
}

function buildReviewUserPrompt(novel, target, contextPack, reason) {
  return JSON.stringify({
    request: reason || "审查最近内容的一致性和角色边界",
    targetType: target.targetType,
    targetId: target.targetId,
    target: target.payload,
    prewritePlan: novel.session.prewritePlan,
    contextPack,
    project: {
      title: novel.title,
      scenario: novel.scenario,
      archives: novel.archives,
      characters: novel.characters.map((character) => ({
        id: character.id,
        name: character.name,
        roleType: character.roleType,
        description: character.description,
        personality: character.personality
      }))
    },
    recentReviews: novel.session.reviews.slice(0, 5).map((review) => ({
      targetType: review.targetType,
      targetId: review.targetId,
      severity: review.severity,
      summary: review.summary
    }))
  }, null, 2);
}

function buildLocalReviewIssues(novel, target) {
  const issues = [];
  if (target.turn) {
    const majorCharacters = novel.characters.filter((character) => character.roleType === "major");
    const majorRecords = target.turn.performances.filter((record) => record.kind === "major");
    for (const character of majorCharacters) {
      if (!majorRecords.some((record) => record.characterId === character.id)) {
        issues.push({
          type: "missing_character_performance",
          target: character.name,
          severity: "high",
          description: "主要角色缺少本轮扮演记录。",
          evidence: `第 ${target.turn.index} 轮没有 ${character.name} 的输出。`,
          suggestion: "重跑该角色或整轮扮演。",
          blocking: true
        });
      }
    }
    for (const record of majorRecords) {
      const parsed = record.parsed || {};
      if (!parsed.speech && !parsed.action) {
        issues.push({
          type: "thin_character_output",
          target: record.name,
          severity: "medium",
          description: "角色输出缺少可供改写使用的台词或动作。",
          evidence: limitText(record.text, 300),
          suggestion: "单角色重跑时要求补充可观察行动和必要台词。",
          blocking: false
        });
      }
    }
  }
  if (target.prose && !String(target.prose.text || "").trim()) {
    issues.push({
      type: "empty_prose",
      target: target.label,
      severity: "blocking",
      description: "正文片段为空。",
      evidence: "",
      suggestion: "重新改写或人工补全文本。",
      blocking: true
    });
  }
  return issues;
}

function buildDeterministicReviewChain(novel, target) {
  const checks = [
    buildReviewChainItem("character_consistency", "角色一致性审查", collectCharacterConsistencyReviewIssues(novel, target)),
    buildReviewChainItem("lorebook_trigger", "世界书触发审查", collectLorebookTriggerReviewIssues(novel, target)),
    buildReviewChainItem("director_overcontrol", "导演过控审查", target.turn ? collectDirectorOvercontrolDiagnosticsIssues({ ...novel, session: { ...novel.session, turns: [target.turn] } }).map(diagnosticIssueToReviewIssue) : []),
    buildReviewChainItem("roleplay_output", "扮演输出审查", target.turn ? buildLocalReviewIssues(novel, target) : []),
    buildReviewChainItem("prose_fact", "正文事实审查", target.prose ? collectProseDiagnosticsIssues({ ...novel, session: { ...novel.session, proseParts: [target.prose] } }).map(diagnosticIssueToReviewIssue) : []),
    buildReviewChainItem("prose_style", "正文风格审查", target.prose ? collectProseStyleReviewIssues(novel, target.prose) : []),
    buildReviewChainItem("preference_learning", "用户偏好吸收审查", target.prose ? collectPreferenceLearningReviewIssues(novel, target.prose) : [])
  ];
  return checks;
}

function buildReviewChainItem(type, label, issues) {
  const normalizedIssues = (issues || []).map(normalizeReviewIssue);
  const severity = inferReviewSeverity(normalizedIssues);
  return normalizeReviewChainItem({
    type,
    label,
    status: severity === "ok" ? "passed" : severity === "low" ? "warning" : "failed",
    severity,
    summary: normalizedIssues.length ? `发现 ${normalizedIssues.length} 个问题。` : "未发现阻断问题。",
    issues: normalizedIssues
  });
}

function diagnosticIssueToReviewIssue(issue) {
  return {
    type: issue.code || issue.type || "diagnostic",
    target: typeof issue.target === "string" ? issue.target : JSON.stringify(issue.target || {}),
    severity: issue.severity || "medium",
    description: issue.message || issue.title || "",
    evidence: issue.title || "",
    suggestion: issue.suggestedFix || "",
    blocking: issue.severity === "high" || issue.severity === "blocking"
  };
}

function collectCharacterConsistencyReviewIssues(novel, target) {
  if (!target.turn) return [];
  return collectRoleplayVisibilityLeakIssues({ ...novel, session: { ...novel.session, turns: [target.turn] } }).map(diagnosticIssueToReviewIssue);
}

function collectLorebookTriggerReviewIssues(novel, target) {
  if (!target.turn) return [];
  return collectLorebookTriggerAuditIssues({ ...novel, session: { ...novel.session, turns: [target.turn] } }).map(diagnosticIssueToReviewIssue);
}

function collectProseStyleReviewIssues(novel, prose) {
  void novel;
  const issues = [];
  const text = String(prose.text || "");
  if (/这段文字来自本地模拟提供商|本地模拟/.test(text)) {
    issues.push({
      type: "prose_style.mock_text",
      target: prose.id,
      severity: "medium",
      description: "正文中仍包含本地模拟或工具说明，不应进入最终正文。",
      evidence: "命中本地模拟说明文本。",
      suggestion: "用真实正文 Agent 重写或人工删除说明。",
      blocking: false
    });
  }
  if ((prose.paragraphGroups || []).some((group) => Object.values(group.checks || {}).some((check) => check?.status === "failed"))) {
    issues.push({
      type: "prose_style.paragraph_group_failed",
      target: prose.id,
      severity: "high",
      description: "段落组自检存在 failed 项。",
      evidence: "paragraphGroups.checks",
      suggestion: "整组重写，不只换词。",
      blocking: true
    });
  }
  return issues;
}

function collectPreferenceLearningReviewIssues(novel, prose) {
  const learnings = (novel.planning?.revisionLearnings || []).filter((item) => (prose.revisionLearningIds || []).includes(item.id));
  if (!learnings.length) return [];
  return learnings
    .filter((item) => item.status === "candidate" && item.transferablePreference)
    .map((item) => ({
      type: "preference_learning.unconfirmed",
      target: item.id,
      severity: "low",
      description: "本次改稿提取了可迁移偏好，但尚未确认，不能直接写成永久规则。",
      evidence: item.transferablePreference,
      suggestion: "保留为候选或暂行偏好，累计多次证据后再确认。",
      blocking: false
    }));
}

function inferReviewSeverity(issues) {
  const severities = issues.map((issue) => normalizeReviewSeverity(issue.severity));
  if (severities.includes("blocking")) return "blocking";
  if (severities.includes("high")) return "high";
  if (severities.includes("medium")) return "medium";
  if (severities.includes("low")) return "low";
  return "ok";
}

async function rerunTurnCharacter(store, novel, turnId, characterId) {
  const turn = novel.session.turns.find((item) => item.id === turnId);
  if (!turn) throw new HttpError(404, "没有找到扮演轮次");
  const character = novel.characters.find((item) => item.id === characterId && item.roleType === "major");
  if (!character) throw new HttpError(404, "没有找到可单独重跑的主要角色");
  const recordIndex = turn.performances.findIndex((record) => record.kind === "major" && record.characterId === characterId);
  if (recordIndex < 0) throw new HttpError(404, "该轮次没有这个角色的扮演记录");
  const provider = getConfiguredProvider(store, character, `主要角色：${character.name}`);
  const modelTrace = buildModelTrace(provider, character, `character:${character.name}`);
  const contextPack = await buildAgentContextPack(novel, "character", {
    store,
    characterId: character.id,
    queryText: `${character.name}\n重跑第 ${turn.index} 轮扮演\n${formatAiRecordContent(turn.guide)}`
  });
  const result = await requestAi({
    provider,
    model: character.model,
    temperature: character.temperature,
    systemPrompt: buildCharacterSystemPrompt(character),
    messages: [
      {
        role: "user",
        content: buildCharacterRerunUserPrompt(novel, character, turn, contextPack)
      }
    ]
  });
  const previous = turn.performances[recordIndex];
  const next = {
    ...buildAiRecord("major", character.name, result, character.id),
    rerunAt: nowIso(),
    rerunCount: Number(previous.rerunCount || 0) + 1,
    rerunReason: "单角色重跑",
    rerunHistory: [
      ...(previous.rerunHistory || []),
      {
        at: nowIso(),
        text: previous.text,
        parsed: previous.parsed
      }
    ].slice(-5)
  };
  turn.performances[recordIndex] = next;
  turn.updatedAt = nowIso();
  turn.memoryInjection = turn.memoryInjection || { director: null, characters: {}, minor: null };
  turn.memoryInjection.characters = turn.memoryInjection.characters || {};
  turn.memoryInjection.characters[character.id] = contextPack;
  turn.contextAudit = buildContextAuditFromInjection(turn.memoryInjection);
  turn.modelTrace = turn.modelTrace || { director: null, characters: {}, minor: null };
  turn.modelTrace.characters = turn.modelTrace.characters || {};
  turn.modelTrace.characters[character.id] = modelTrace;
  turn.transcript = buildRoleplayTranscriptFromTurn(turn, { modelTrace: turn.modelTrace });
  const workflow = findChapterWorkflow(novel, turn.workflowId);
  if (workflow) {
    workflow.contextAudits = [...(workflow.contextAudits || []), turn.contextAudit].slice(-12);
    updateChapterWorkflowStep(workflow, "context", {
      status: "completed",
      summary: `已重建 ${character.name} 的角色上下文`,
      artifactIds: addWorkflowId(workflow.steps?.context?.artifactIds, turn.id)
    });
    updateChapterWorkflowStep(workflow, "review", {
      status: "running",
      summary: "单角色重跑后等待审查"
    });
  }
  markMemoryItemsFromSource(novel, "roleplay_turn", turn.id, "outdated");
  projectTurnToMemory(novel, turn);
  recordEvent(novel, "character_rerun_completed", {
    turnId: turn.id,
    turnIndex: turn.index,
    characterId: character.id,
    name: character.name
  });
  let review = null;
  try {
    review = await runReviewChain(store, novel, {
      targetType: "turn",
      targetId: turn.id,
      reason: "单角色重跑后审查一致性"
    });
  } catch (error) {
    recordEvent(novel, "review_failed", {
      targetType: "turn",
      targetId: turn.id,
      reason: error instanceof HttpError ? error.message : String(error.message || error)
    });
  }
  turn.transcript = buildRoleplayTranscriptFromTurn(turn, { modelTrace: turn.modelTrace });
  updateTimestamp(novel);
  return { turn, performance: next, review };
}

function buildCharacterRerunUserPrompt(novel, character, turn, contextPack) {
  return JSON.stringify({
    request: `重跑第 ${turn.index} 轮中 ${character.name} 的扮演。只替换这个角色，不改其他角色已经输出的内容。`,
    contextPack,
    novelScenario: novel.scenario,
    prewritePlan: novel.session.prewritePlan,
    directorGuide: turn.guide?.parsed || turn.guide?.text,
    previousOwnOutput: turn.performances.find((record) => record.characterId === character.id)?.parsed || turn.performances.find((record) => record.characterId === character.id)?.text || "",
    fixedOtherPerformances: turn.performances
      .filter((record) => record.characterId !== character.id)
      .map(publicPerformanceForPrompt),
    recentTurns: novel.session.turns
      .filter((item) => item.id !== turn.id)
      .slice(-4)
      .map((item) => compactTurnForCharacterPrompt(item, character.id))
  }, null, 2);
}

function appendLorebookTriggerLogs(novel, turn) {
  novel.lorebook = normalizeLorebook(novel.lorebook);
  const settings = normalizeLorebookSettings(novel.lorebook.settings);
  const logs = Array.isArray(novel.lorebook.triggerLogs) ? novel.lorebook.triggerLogs : [];
  const addLogs = (task, characterId, pack) => {
    for (const lore of pack?.triggeredLore || []) {
      logs.push({
        id: createId("lore_log"),
        turnId: turn.id,
        workflowId: turn.workflowId || "",
        turnIndex: turn.index,
        task,
        characterId: characterId || "",
        entryId: lore.id,
        name: lore.name,
        matchedKeys: lore.matchedKeys || [],
        matchDetail: lore.matchDetail || null,
        diagnostics: lore.diagnostics || [],
        position: lore.position,
        score: lore.score || 0,
        reason: buildLorebookTriggerReason(task, lore),
        createdAt: nowIso()
      });
    }
  };
  addLogs("director", "", turn.memoryInjection?.director);
  for (const [characterId, pack] of Object.entries(turn.memoryInjection?.characters || {})) {
    addLogs("character", characterId, pack);
  }
  addLogs("minor", "minor_group", turn.memoryInjection?.minor);
  novel.lorebook.triggerLogs = logs.slice(-settings.triggerLogLimit);
  novel.lorebook.updatedAt = nowIso();
}

function buildLorebookTriggerReason(task, lore) {
  const detail = lore?.matchDetail || {};
  if (detail.mode === "always") return `${task} 上下文扫描命中：始终注入`;
  const primary = (detail.primary?.matches || []).map((item) => `${item.key}@${item.index}`);
  const secondary = (detail.secondary?.matches || []).map((item) => `${item.key}@${item.index}`);
  const parts = [];
  if (primary.length) parts.push(`主触发 ${primary.join("、")}`);
  if (secondary.length) parts.push(`次触发 ${secondary.join("、")}`);
  const diagnostics = (lore?.diagnostics || []).filter((item) => item.severity !== "low").map((item) => item.code).slice(0, 3);
  if (diagnostics.length) parts.push(`诊断 ${diagnostics.join("、")}`);
  return `${task} 上下文扫描命中：${parts.join("；") || (lore?.matchedKeys || []).join("、") || "关键词命中"}`;
}

async function runRoleplayTurn(store, novel, body = {}) {
  const guideSetting = novel.aiRoles.guide;
  const guideProvider = getConfiguredProvider(store, guideSetting, "导演 AI");
  const majorCharacters = novel.characters.filter((character) => character.roleType === "major");
  const minorCharacters = novel.characters.filter((character) => character.roleType === "minor");
  const missing = collectRoleplayMissing(store, novel, majorCharacters, minorCharacters);
  if (missing.length > 0) {
    throw new HttpError(400, "扮演配置不完整", missing);
  }

  const turnIndex = novel.session.turnIndex + 1;
  const prewriteWorkflow = findChapterWorkflow(novel, novel.session?.prewritePlan?.workflowId);
  const reusablePrewriteWorkflowId = prewriteWorkflow?.mode === "roleplay_prose" ? novel.session?.prewritePlan?.workflowId : "";
  const workflow = getOrCreateChapterWorkflow(novel, {
    workflowId: body.workflowId || reusablePrewriteWorkflowId,
    chapterLabel: body.chapterLabel || novel.session?.prewritePlan?.chapterLabel || `第 ${turnIndex} 轮`,
    intent: body.intent || body.reason || novel.session?.prewritePlan?.sourceIntent || "",
    mode: "roleplay_prose"
  });
  workflow.status = "roleplaying";
  updateChapterWorkflowStep(workflow, "roleplay", {
    status: "running",
    summary: `正在运行第 ${turnIndex} 轮扮演`
  });
  const guideContextPack = await buildAgentContextPack(novel, "director", { store, queryText: `第 ${turnIndex} 轮导演引导` });
  const guideResult = await requestAi({
    provider: guideProvider,
    model: guideSetting.model,
    temperature: guideSetting.temperature,
    systemPrompt: buildGuideSystemPrompt(),
    messages: [
      {
        role: "user",
        content: buildGuideUserPrompt(novel, turnIndex, guideContextPack)
      }
    ]
  });

  const guideRecord = buildAiRecord("guide", "导演 AI", guideResult);
  recordEvent(novel, "guide_completed", { turnIndex, guide: compactAiRecordForEvent(guideRecord) });
  const memoryInjection = {
    director: guideContextPack,
    characters: {},
    minor: null
  };
  const modelTrace = {
    director: buildModelTrace(guideProvider, guideSetting, "director"),
    characters: {},
    minor: null
  };

  // 主要角色之间可以并行扮演，因为每个主要角色只依据同一个导演引导做自己的选择。
  const performancePromises = majorCharacters.map(async (character) => {
    const provider = getConfiguredProvider(store, character, `主要角色：${character.name}`);
    modelTrace.characters[character.id] = buildModelTrace(provider, character, `character:${character.name}`);
    const characterContextPack = await buildAgentContextPack(novel, "character", {
      store,
      characterId: character.id,
      queryText: `${character.name}\n第 ${turnIndex} 轮扮演\n${formatAiRecordContent(guideRecord)}`
    });
    memoryInjection.characters[character.id] = characterContextPack;
    const result = await requestAi({
      provider,
      model: character.model,
      temperature: character.temperature,
      systemPrompt: buildCharacterSystemPrompt(character),
      messages: [
        {
          role: "user",
          content: buildCharacterUserPrompt(novel, character, guideRecord, turnIndex, characterContextPack)
        }
      ]
    });
    return buildAiRecord("major", character.name, result, character.id);
  });

  if (minorCharacters.length > 0) {
    performancePromises.push((async () => {
      const minorSetting = novel.aiRoles.minor;
      const provider = getConfiguredProvider(store, minorSetting, "次要角色群 AI");
      modelTrace.minor = buildModelTrace(provider, minorSetting, "minor_group");
      const minorContextPack = await buildAgentContextPack(novel, "minor", {
        store,
        queryText: `第 ${turnIndex} 轮次要角色群\n${minorCharacters.map((item) => item.name).join(" ")}\n${formatAiRecordContent(guideRecord)}`
      });
      memoryInjection.minor = minorContextPack;
      const result = await requestAi({
        provider,
        model: minorSetting.model,
        temperature: minorSetting.temperature,
        systemPrompt: buildMinorSystemPrompt(minorCharacters),
        messages: [
          {
            role: "user",
            content: buildMinorUserPrompt(novel, minorCharacters, guideRecord, turnIndex, minorContextPack)
          }
        ]
      });
      return buildAiRecord("minor_group", "次要角色群", result);
    })());
  }

  const performances = await Promise.all(performancePromises);
  for (const performance of performances) {
    recordEvent(novel, "performance_completed", {
      turnIndex,
      performance: compactAiRecordForEvent(performance)
    });
  }

  const turn = {
    id: createId("turn"),
    workflowId: workflow.id,
    index: turnIndex,
    createdAt: nowIso(),
    updatedAt: nowIso(),
    guide: guideRecord,
    performances,
    memoryInjection,
    contextAudit: buildContextAuditFromInjection(memoryInjection),
    directorControlAudit: auditDirectorControl(guideRecord, novel.session.prewritePlan),
    modelTrace
  };
  turn.transcript = buildRoleplayTranscriptFromTurn(turn, { modelTrace });
  await ensureTurnTranscriptContextAsset(novel, turn, "扮演轮次完成后保存 transcript 引用");
  novel.session.turnIndex = turnIndex;
  novel.session.turns.push(turn);
  workflow.turnIds = addWorkflowId(workflow.turnIds, turn.id);
  workflow.contextAudits = [...(workflow.contextAudits || []), turn.contextAudit].slice(-12);
  updateChapterWorkflowStep(workflow, "context", {
    status: "completed",
    summary: "导演、主要角色和次要角色上下文包已构建",
    artifactIds: addWorkflowId(workflow.steps?.context?.artifactIds, turn.id)
  });
  updateChapterWorkflowStep(workflow, "roleplay", {
    status: "completed",
    summary: `第 ${turnIndex} 轮扮演已完成`,
    artifactIds: addWorkflowId(workflow.steps?.roleplay?.artifactIds, turn.id)
  });
  projectTurnToMemory(novel, turn);
  novel.memory.lastInjection = memoryInjection;
  recordEvent(novel, "turn_completed", { turnId: turn.id, workflowId: workflow.id, turnIndex });
  appendLorebookTriggerLogs(novel, turn);
  try {
    turn.review = await runReviewChain(store, novel, {
      targetType: "turn",
      targetId: turn.id,
      workflowId: workflow.id,
      reason: "本轮扮演完成后自动审查一致性"
    });
  } catch (error) {
    recordEvent(novel, "review_failed", {
      targetType: "turn",
      targetId: turn.id,
      reason: error instanceof HttpError ? error.message : String(error.message || error)
    });
  }
  updateTimestamp(novel);
  return turn;
}

async function adaptLatestRoleplay(store, novel, body = {}) {
  if (novel.session.turns.length === 0) {
    throw new HttpError(400, "还没有扮演记录，不能改写为小说");
  }
  const adapterSetting = novel.aiRoles.adapter;
  const adapterProvider = getConfiguredProvider(store, adapterSetting, "小说改写 AI");
  const explicitWorkflowId = String(body.workflowId || "").trim();
  // Agent 指定章节工作流时，改写只能使用该工作流内的扮演记录，避免跨章节串线。
  const selectedWorkflow = findChapterWorkflow(novel, body.workflowId);
  const selectedTurn = selectedWorkflow?.turnIds?.length
    ? [...novel.session.turns].reverse().find((turn) => selectedWorkflow.turnIds.includes(turn.id))
    : null;
  if (explicitWorkflowId && !selectedWorkflow) {
    throw new HttpError(404, "没有找到指定的章节工作流");
  }
  if (explicitWorkflowId && selectedWorkflow?.mode === "normal_prose") {
    throw new HttpError(400, "指定章节工作流是正常行文链路，不能作为扮演改写来源");
  }
  if (explicitWorkflowId && (!selectedWorkflow.turnIds?.length || !selectedTurn)) {
    throw new HttpError(400, "指定章节工作流还没有扮演轮次，不能改写为正文");
  }
  const workflow = getOrCreateChapterWorkflow(novel, {
    workflowId: body.workflowId || selectedTurn?.workflowId || novel.session.turns[novel.session.turns.length - 1]?.workflowId || novel.session?.prewritePlan?.workflowId,
    chapterLabel: body.chapterLabel || selectedWorkflow?.chapterLabel || novel.session?.prewritePlan?.chapterLabel || "当前章节",
    intent: body.intent || body.reason || selectedWorkflow?.intent || "",
    mode: "roleplay_prose"
  });
  workflow.status = "adapting";
  updateChapterWorkflowStep(workflow, "adapt", {
    status: "running",
    summary: "正在将最近扮演改写为正文"
  });
  const adapterContextPack = await buildAgentContextPack(novel, "adapter", { store, queryText: "改写最近三轮扮演为小说正文" });
  const sourceTurns = selectedWorkflow?.turnIds?.length
    ? novel.session.turns.filter((turn) => selectedWorkflow.turnIds.includes(turn.id)).slice(-3)
    : novel.session.turns.slice(-3);
  const result = await requestAi({
    provider: adapterProvider,
    model: adapterSetting.model,
    temperature: adapterSetting.temperature,
    systemPrompt: buildAdapterSystemPrompt(novel),
    messages: [
      {
        role: "user",
        content: buildAdapterUserPrompt(novel, adapterContextPack, sourceTurns)
      }
    ]
  });
  const parsedAdapter = parseLooseJson(result.text);
  const normalizedAdapter = normalizeAdapterResult(parsedAdapter, result.text, sourceTurns);
  const repairedAdapter = await repairFailedParagraphGroups(store, novel, adapterProvider, adapterSetting, normalizedAdapter, adapterContextPack, sourceTurns, workflow);
  const prose = {
    id: createId("prose"),
    workflowId: workflow.id,
    createdAt: nowIso(),
    updatedAt: nowIso(),
    status: "draft",
    versionType: "draft",
    baseProseId: "",
    branchId: "",
    revisionOf: "",
    versionHistory: [],
    acceptedAt: "",
    discardedAt: "",
    turnRange: sourceTurns.length
      ? [sourceTurns[0].index, sourceTurns[sourceTurns.length - 1].index]
      : [Math.max(1, novel.session.turnIndex - 2), novel.session.turnIndex],
    text: repairedAdapter.text,
    adaptationPlan: repairedAdapter.adaptationPlan,
    paragraphGroups: repairedAdapter.paragraphGroups,
    raw: result.raw,
    memoryInjection: adapterContextPack,
    postwriteBack: normalizePostwriteBack(null)
  };
  prose.branchId = prose.id;
    await appendProseVersionEventWithSnapshots(novel, prose, {
      eventType: "created",
      versionType: "draft",
      nextText: prose.text,
    actor: "agent",
    summary: "正文 Agent 根据扮演记录生成草稿"
  });
  await ensureProseContextAsset(novel, prose, "正文 Agent 生成草稿后保存长正文引用");
  novel.session.proseParts.push(prose);
  workflow.proseIds = addWorkflowId(workflow.proseIds, prose.id);
  const adapterAudit = buildContextAuditFromInjection({ adapter: adapterContextPack });
  workflow.contextAudits = [...(workflow.contextAudits || []), adapterAudit].slice(-12);
  workflow.status = "draft";
  updateChapterWorkflowStep(workflow, "adapt", {
    status: "completed",
    summary: "正文草稿已生成，等待人工编辑或采纳",
    artifactIds: addWorkflowId(workflow.steps?.adapt?.artifactIds, prose.id)
  });
  novel.memory.lastInjection = adapterContextPack;
  recordEvent(novel, "prose_created", { proseId: prose.id, workflowId: workflow.id, turnRange: prose.turnRange });
  updateTimestamp(novel);
  return prose;
}

function normalizeNormalWritingWorkflowSteps(value) {
  const source = Array.isArray(value) && value.length > 0 ? value : ["prewrite", "draft", "review"];
  const aliases = {
    write: "draft",
    prose: "draft",
    adapt: "draft",
    writing: "draft",
    check: "review"
  };
  const allowed = new Set(["prewrite", "draft", "review", "postwrite"]);
  return uniqueStrings(source.map((item) => aliases[String(item || "").trim()] || String(item || "").trim()).filter((item) => allowed.has(item)));
}

async function runNormalWritingWorkflow(store, novel, body = {}) {
  const steps = normalizeNormalWritingWorkflowSteps(body.steps);
  const result = {
    workflow: null,
    plan: null,
    prose: null,
    review: null,
    postwrite: null
  };
  let workflow = getOrCreateChapterWorkflow(novel, {
    workflowId: body.workflowId,
    chapterLabel: body.chapterLabel,
    intent: body.intent || body.query || "",
    mode: "normal_prose",
    forceNew: body.forceNew === true
  });
  if (workflow.mode !== "normal_prose") {
    throw new HttpError(400, "指定章节工作流是扮演行文链路，不能作为正常行文来源");
  }
  workflow.mode = "normal_prose";
  if (steps.includes("prewrite")) {
    result.plan = await generatePrewritePlan(store, novel, {
      ...body,
      workflowId: workflow.id,
      mode: "normal_prose",
      forceNew: false
    });
    workflow = findChapterWorkflow(novel, result.plan.workflowId) || workflow;
  }
  if (steps.includes("draft")) {
    result.prose = await generateNormalWritingDraft(store, novel, {
      ...body,
      workflowId: workflow.id,
      chapterLabel: workflow.chapterLabel,
      intent: body.intent || body.query || workflow.intent || ""
    });
    workflow = findChapterWorkflow(novel, result.prose.workflowId) || workflow;
  }
  if (steps.includes("review")) {
    const prose = result.prose || [...(novel.session.proseParts || [])].reverse().find((part) => part.workflowId === workflow.id && normalizeProseStatus(part.status) !== "discarded");
    if (!prose) {
      throw new HttpError(400, "正常行文审查需要先生成正文草稿");
    }
    result.review = await runReviewChain(store, novel, {
      targetType: "prose",
      targetId: prose.id,
      workflowId: workflow.id,
      reason: body.reviewReason || "正常行文正文审查"
    });
    workflow = findChapterWorkflow(novel, workflow.id) || workflow;
  }
  if (steps.includes("postwrite")) {
    const prose = result.prose || [...(novel.session.proseParts || [])].reverse().find((part) => part.workflowId === workflow.id && part.status === "accepted");
    if (!prose) throw new HttpError(400, "没有可写后回写的已采纳正文");
    if (prose.status !== "accepted") {
      throw new HttpError(400, "写后回写需要先采纳正文，不能直接把未确认草稿沉淀为长期事实");
    }
    result.postwrite = await postwriteProsePart(store, novel, prose, { reason: body.reason || "正常行文链路写后回写" });
  }
  result.workflow = workflow || null;
  recordEvent(novel, "normal_writing_workflow_run_completed", {
    workflowId: workflow?.id || "",
    steps
  });
  updateTimestamp(novel);
  return result;
}

async function generateNormalWritingDraft(store, novel, body = {}) {
  const adapterSetting = novel.aiRoles.adapter;
  const adapterProvider = getConfiguredProvider(store, adapterSetting, "正常行文正文 AI");
  const userIntent = String(body.intent || body.query || "").trim();
  let workflow = getOrCreateChapterWorkflow(novel, {
    workflowId: body.workflowId,
    chapterLabel: body.chapterLabel,
    intent: userIntent,
    mode: "normal_prose",
    forceNew: body.forceNew === true
  });
  if (workflow.mode !== "normal_prose") {
    throw new HttpError(400, "指定章节工作流是扮演行文链路，不能作为正常行文来源");
  }
  workflow.mode = "normal_prose";
  workflow.status = "writing";
  updateChapterWorkflowStep(workflow, "adapt", {
    status: "running",
    summary: "正在按写前定位直接生成正文草稿"
  });
  let plan = novel.session?.prewritePlan?.workflowId === workflow.id ? novel.session.prewritePlan : null;
  if (!plan && body.ensurePrewrite !== false) {
    plan = await generatePrewritePlan(store, novel, {
      intent: userIntent || workflow.intent || "为正常行文生成写前定位",
      chapterLabel: body.chapterLabel || workflow.chapterLabel,
      workflowId: workflow.id,
      mode: "normal_prose",
      forceNew: false
    });
    workflow = findChapterWorkflow(novel, plan.workflowId) || workflow;
  }
  const queryText = [
    userIntent || workflow.intent || "正常行文",
    plan?.summary || "",
    "章节正文 直接写作 已采纳正文 档案 记忆 世界书 用户文风 连续性"
  ].filter(Boolean).join("\n");
  const contextPack = await buildAgentContextPack(novel, "adapter", { store, queryText });
  const result = await requestAi({
    provider: adapterProvider,
    model: adapterSetting.model,
    temperature: Math.min(0.68, clampTemperature(adapterSetting.temperature)),
    systemPrompt: buildNormalWritingSystemPrompt(novel),
    messages: [
      {
        role: "user",
        content: buildNormalWritingUserPrompt(novel, contextPack, workflow, plan, userIntent)
      }
    ]
  });
  const parsedAdapter = parseLooseJson(result.text);
  const normalizedAdapter = normalizeAdapterResult(parsedAdapter, result.text, []);
  normalizedAdapter.adaptationPlan = normalizeProseAdaptationPlan({
    ...normalizedAdapter.adaptationPlan,
    mode: "normal_prose_direct_write",
    sourceTurnIds: [],
    prewritePlanId: plan?.id || workflow.prewritePlanId || ""
  });
  const repairedAdapter = await repairFailedParagraphGroups(store, novel, adapterProvider, adapterSetting, normalizedAdapter, contextPack, [], workflow);
  repairedAdapter.adaptationPlan = normalizeProseAdaptationPlan({
    ...repairedAdapter.adaptationPlan,
    mode: repairedAdapter.adaptationPlan?.repairStatus && repairedAdapter.adaptationPlan.repairStatus !== "not_needed"
      ? `normal_prose_${repairedAdapter.adaptationPlan.mode}`
      : "normal_prose_direct_write",
    sourceTurnIds: [],
    prewritePlanId: plan?.id || workflow.prewritePlanId || ""
  });
  const prose = {
    id: createId("prose"),
    workflowId: workflow.id,
    createdAt: nowIso(),
    updatedAt: nowIso(),
    status: "draft",
    versionType: "draft",
    baseProseId: "",
    branchId: "",
    revisionOf: "",
    versionHistory: [],
    acceptedAt: "",
    discardedAt: "",
    turnRange: [],
    text: repairedAdapter.text,
    adaptationPlan: repairedAdapter.adaptationPlan,
    paragraphGroups: repairedAdapter.paragraphGroups,
    raw: {
      source: "normal_writing_workflow",
      modelRaw: result.raw
    },
    memoryInjection: contextPack,
    postwriteBack: normalizePostwriteBack(null)
  };
  prose.branchId = prose.id;
  await appendProseVersionEventWithSnapshots(novel, prose, {
    eventType: "created",
    versionType: "draft",
    nextText: prose.text,
    actor: "agent",
    summary: "正文 Agent 按正常行文链路生成草稿"
  });
  await ensureProseContextAsset(novel, prose, "正常行文正文 Agent 生成草稿后保存长正文引用");
  novel.session.proseParts.push(prose);
  workflow.proseIds = addWorkflowId(workflow.proseIds, prose.id);
  const adapterAudit = buildContextAuditFromInjection({ adapter: contextPack });
  workflow.contextAudits = [...(workflow.contextAudits || []), adapterAudit].slice(-12);
  workflow.status = "draft";
  updateChapterWorkflowStep(workflow, "context", {
    status: "completed",
    summary: "正文 Agent 上下文包已构建",
    artifactIds: addWorkflowId(workflow.steps?.context?.artifactIds, prose.id)
  });
  updateChapterWorkflowStep(workflow, "adapt", {
    status: "completed",
    summary: "正常行文正文草稿已生成，等待审查、人工编辑或采纳",
    artifactIds: addWorkflowId(workflow.steps?.adapt?.artifactIds, prose.id)
  });
  novel.memory.lastInjection = contextPack;
  recordEvent(novel, "normal_prose_created", { proseId: prose.id, workflowId: workflow.id, prewritePlanId: plan?.id || "" });
  updateTimestamp(novel);
  return prose;
}

function buildNormalWritingSystemPrompt(novel) {
  return [
    "你是正常行文正文 Agent。",
    "你的职责不是把扮演记录改写成正文，而是直接依据写前定位、项目档案、记忆、世界书、已采纳正文尾巴和用户文风要求生成本章正文草稿。",
    "你拥有作者/正文 Agent 的统筹视角，可以读取全局档案和后台设定，但不能把后台知道的信息无理由写到前台，也不能让角色突然知道自己不可见的信息。",
    "写作顺序必须是：先读写前定位，再判断本章只负责什么、承接什么、留给下一章什么；然后按段落组慢写，每组写完做功能检、角色检、场景检、承接检和风格检。",
    "正常行文允许直接组织叙事节奏、删减资料、合并段落和调整出场顺序；但不能替角色做突兀选择，不能覆盖已采纳正文事实，不能把用户单次改稿偏好写成永久硬设定。",
    "输入中的 contextPack 分为角色卡固定层 fixedContext、世界书触发层 triggeredLore、长期记忆层 structuredMemory、RAG 检索证据层 retrievedEvidence、近场历史层 recentContext。",
    "长期记忆层是有证据的稳定事实；RAG 检索证据只是一轮临时证据，冲突时要保守处理并在 checks 或 adaptationPlan 中说明。",
    "输出 JSON：adaptationPlan、paragraphGroups、text。",
    "adaptationPlan.mode 必须体现 normal_prose_direct_write；paragraphGroups 每项包含 purpose、sourceTurnIds、keptPerformanceIds、text、checks。",
    "正常行文没有扮演来源，因此 sourceTurnIds 和 keptPerformanceIds 可以为空数组，但每个段落组必须说明它服务的章节功能。",
    "",
    `小说名：${novel.title}`,
    `整体基调：${novel.scenario.tone || "未指定"}`
  ].join("\n");
}

