async function runChapterWorkflow(store, novel, body = {}) {
  const steps = Array.isArray(body.steps) && body.steps.length > 0
    ? uniqueStrings(body.steps)
    : ["prewrite", "roleplay", "review", "adapt"];
  const result = {
    workflow: null,
    plan: null,
    turn: null,
    review: null,
    prose: null,
    postwrite: null
  };
  let workflow = getOrCreateChapterWorkflow(novel, {
    workflowId: body.workflowId,
    chapterLabel: body.chapterLabel,
    intent: body.intent || body.query || "",
    mode: "roleplay_prose",
    forceNew: body.forceNew === true
  });
  if (workflow.mode !== "roleplay_prose") {
    throw new HttpError(400, "指定章节工作流是正常行文链路，不能作为扮演行文来源");
  }
  if (steps.includes("prewrite")) {
    result.plan = await generatePrewritePlan(store, novel, {
      ...body,
      workflowId: workflow.id,
      mode: "roleplay_prose",
      forceNew: false
    });
    workflow = findChapterWorkflow(novel, result.plan.workflowId) || workflow;
  }
  if (steps.includes("roleplay")) {
    result.turn = await runRoleplayTurn(store, novel, {
      workflowId: workflow.id,
      chapterLabel: workflow.chapterLabel,
      intent: body.intent || body.query || workflow.intent || ""
    });
    workflow = findChapterWorkflow(novel, result.turn.workflowId) || workflow;
  }
  if (steps.includes("review")) {
    const targetTurn = result.turn || novel.session.turns[novel.session.turns.length - 1];
    if (targetTurn) {
      result.review = targetTurn.review && body.forceReview !== true
        ? targetTurn.review
        : await runReviewChain(store, novel, {
          targetType: "turn",
          targetId: targetTurn.id,
          workflowId: targetTurn.workflowId || workflow.id,
          reason: body.reviewReason || "章节工作流触发审查"
        });
    }
  }
  if (steps.includes("adapt")) {
    result.prose = await adaptLatestRoleplay(store, novel, {
      workflowId: workflow.id,
      chapterLabel: workflow.chapterLabel,
      intent: body.intent || body.query || workflow.intent || ""
    });
    workflow = findChapterWorkflow(novel, result.prose.workflowId) || workflow;
  }
  if (steps.includes("postwrite")) {
    const prose = result.prose || [...(novel.session.proseParts || [])].reverse().find((part) => part.status === "accepted");
    if (!prose) throw new HttpError(400, "没有可写后回写的已采纳正文");
    if (prose.status !== "accepted") {
      throw new HttpError(400, "写后回写需要先采纳正文，不能直接把未确认草稿沉淀为长期事实");
    }
    result.postwrite = await postwriteProsePart(store, novel, prose, { reason: body.reason || "章节工作流写后回写" });
  }
  result.workflow = workflow || null;
  recordEvent(novel, "chapter_workflow_run_completed", {
    workflowId: workflow?.id || "",
    steps
  });
  updateTimestamp(novel);
  return result;
}

function collectRoleplayMissing(store, novel, majorCharacters, minorCharacters) {
  const missing = [];
  collectAiSettingMissing(store, novel.aiRoles.guide, "导演 AI", missing);
  for (const character of majorCharacters) {
    collectAiSettingMissing(store, character, `主要角色：${character.name}`, missing);
  }
  if (minorCharacters.length > 0) {
    collectAiSettingMissing(store, novel.aiRoles.minor, "次要角色群 AI", missing);
  }
  collectAiSettingMissing(store, novel.aiRoles.adapter, "小说改写 AI", missing, false);
  if (majorCharacters.length === 0 && minorCharacters.length === 0) {
    missing.push("至少需要一个角色");
  }
  return missing;
}

function collectAiSettingMissing(store, setting, label, missing, requireForTurn = true) {
  if (!requireForTurn && (!setting?.providerId || !setting?.model)) {
    return;
  }
  if (!setting?.providerId) {
    missing.push(`${label} 缺少提供商`);
    return;
  }
  const provider = store.providers.find((item) => item.id === setting.providerId);
  if (!provider) {
    missing.push(`${label} 的提供商不存在`);
    return;
  }
  if (!provider.apiKey && !isMockProvider(provider)) missing.push(`${label} 的提供商缺少 key`);
  if (!provider.baseUrl) missing.push(`${label} 的提供商缺少 baseUrl`);
  if (!setting.model) missing.push(`${label} 缺少模型`);
}

function getConfiguredProvider(store, setting, label) {
  const missing = [];
  collectAiSettingMissing(store, setting, label, missing);
  if (missing.length > 0) {
    throw new HttpError(400, `${label} 配置不完整`, missing);
  }
  return store.providers.find((item) => item.id === setting.providerId);
}

function buildAiRecord(kind, name, result, characterId = "") {
  const parsed = parseLooseJson(result.text);
  return {
    kind,
    characterId,
    name,
    text: result.text,
    parsed,
    raw: result.raw
  };
}

function buildModelTrace(provider, setting, role) {
  return {
    role: String(role || ""),
    providerId: String(provider?.id || setting?.providerId || ""),
    providerName: String(provider?.name || ""),
    endpointKind: String(provider?.endpointKind || ""),
    model: String(setting?.model || ""),
    temperature: Number.isFinite(Number(setting?.temperature)) ? Number(setting.temperature) : 0,
    contextWindowTokens: clampInteger(setting?.contextWindowTokens || provider?.modelProfiles?.[setting?.model]?.contextWindowTokens, 0, 10000000, 0)
  };
}

function buildRoleplayTranscriptFromTurn(turn, options = {}) {
  const memoryInjection = turn.memoryInjection || {};
  const modelTrace = options.modelTrace || {};
  const actors = (turn.performances || []).map((performance) => {
    const pack = performance.characterId
      ? memoryInjection.characters?.[performance.characterId]
      : performance.kind === "minor_group" ? memoryInjection.minor : null;
    const trace = performance.characterId ? modelTrace.characters?.[performance.characterId] : modelTrace.minor;
    return normalizeTranscriptActor({
      kind: performance.kind,
      characterId: performance.characterId || "",
      name: performance.name || "",
      providerId: trace?.providerId || "",
      model: trace?.model || "",
      contextSummary: summarizeContextPackForAudit(pack),
      runtimeDirective: pack?.runtimeDirective || null,
      inputSummary: pack ? summarizeContextPackInput(pack) : "",
      outputSummary: summarizeAiRecordOutput(performance),
      accepted: performance.accepted !== false,
      rerunCount: performance.rerunCount || 0,
      rerunReason: performance.rerunReason || "",
      outputHash: hashText(formatAiRecordContent(performance))
    });
  });
  return normalizeRoleplayTranscript({
    id: turn.transcript?.id || createId("transcript"),
    turnId: turn.id,
    workflowId: turn.workflowId,
    turnIndex: turn.index,
    createdAt: turn.createdAt || nowIso(),
    director: normalizeTranscriptActor({
      kind: "guide",
      name: "导演 AI",
      providerId: modelTrace.director?.providerId || "",
      model: modelTrace.director?.model || "",
      contextSummary: summarizeContextPackForAudit(memoryInjection.director),
      inputSummary: memoryInjection.director ? summarizeContextPackInput(memoryInjection.director) : "",
      outputSummary: summarizeAiRecordOutput(turn.guide),
      accepted: true,
      outputHash: hashText(formatAiRecordContent(turn.guide))
    }),
    actors,
    review: turn.review ? {
      reviewId: turn.review.id,
      severity: turn.review.severity,
      summary: turn.review.summary,
      recommendedAction: turn.review.recommendedAction
    } : null,
    accepted: true,
    rerunSummary: actors.filter((actor) => actor.rerunCount > 0).map((actor) => `${actor.name} 重跑 ${actor.rerunCount} 次${actor.rerunReason ? `：${actor.rerunReason}` : ""}`),
    audit: {
      directorControlAudit: turn.directorControlAudit || null,
      visibilityRiskCount: countTranscriptVisibilityRisks(turn),
      builtAt: nowIso()
    }
  });
}

function summarizeContextPackInput(pack) {
  if (!pack || typeof pack !== "object") return "";
  return [
    `策略：${pack.strategy || ""}`,
    `世界书：${(pack.triggeredLore || []).map((item) => item.name || item.id).join("、") || "无"}`,
    `长期记忆：${(pack.structuredMemory || []).map((item) => `${item.subject}/${item.field}`).join("、") || "无"}`,
    `检索证据：${(pack.retrievedEvidence || []).map((item) => item.title || item.id).join("、") || "无"}`,
    pack.runtimeDirective?.currentGoal ? `当前目标：${pack.runtimeDirective.currentGoal}` : "",
    pack.runtimeDirective?.forbiddenKnowledge?.length ? `禁知：${pack.runtimeDirective.forbiddenKnowledge.join("、")}` : ""
  ].filter(Boolean).join("\n");
}

function summarizeAiRecordOutput(record) {
  const parsed = record?.parsed && typeof record.parsed === "object" ? record.parsed : null;
  if (parsed) {
    return limitText(JSON.stringify(parsed), 1200);
  }
  return limitText(record?.text || "", 1200);
}

function countTranscriptVisibilityRisks(turn) {
  return collectRoleplayVisibilityLeakIssues({ characters: [], session: { turns: [turn] } }).length;
}

function compactAiRecordForEvent(record) {
  return {
    kind: record.kind,
    characterId: record.characterId,
    name: record.name,
    parsed: record.parsed,
    text: record.text
  };
}

function formatAiRecordContent(record) {
  if (!record) return "";
  if (record.parsed) return JSON.stringify(record.parsed, null, 2);
  return String(record.text || "");
}

