function normalizeAdapterResult(parsed, fallbackText, sourceTurns = []) {
  if (parsed && typeof parsed === "object" && (parsed.text || parsed.paragraphGroups || parsed.adaptationPlan)) {
    const paragraphGroups = normalizeProseParagraphGroups(parsed.paragraphGroups || parsed.groups);
    const text = String(parsed.text || paragraphGroups.map((group) => group.text).filter(Boolean).join("\n\n") || fallbackText || "").trim();
    return {
      text,
      adaptationPlan: normalizeProseAdaptationPlan({
        ...(parsed.adaptationPlan || parsed.plan || {}),
        mode: parsed.adaptationPlan?.mode || parsed.plan?.mode || "paragraph_group_slow_write",
        sourceTurnIds: uniqueStrings(sourceTurns.map((turn) => turn.id)),
        paragraphGroupCount: paragraphGroups.length,
        createdAt: nowIso()
      }),
      paragraphGroups: paragraphGroups.length > 0 ? paragraphGroups : buildFallbackParagraphGroups(text, sourceTurns)
    };
  }
  const text = String(fallbackText || "").trim();
  return {
    text,
    adaptationPlan: normalizeProseAdaptationPlan({
      mode: "single_pass_fallback",
      sourceTurnIds: uniqueStrings(sourceTurns.map((turn) => turn.id)),
      preserve: ["保留本轮扮演中已发生的角色选择"],
      merge: ["将导演压力、主要角色反应和次要角色线索合并为正文"],
      delete: ["删除扮演 JSON 痕迹和元说明"],
      reorder: [],
      paragraphGroupCount: text ? 1 : 0,
      selfCheckSummary: "模型未返回段落组结构，后端按单组正文兜底；需要真实段落级严修时应重跑正文 Agent。",
      createdAt: nowIso()
    }),
    paragraphGroups: buildFallbackParagraphGroups(text, sourceTurns)
  };
}

async function repairFailedParagraphGroups(store, novel, provider, adapterSetting, adapterResult, contextPack, sourceTurns = [], workflow = null) {
  void store;
  const normalized = {
    text: String(adapterResult?.text || ""),
    adaptationPlan: normalizeProseAdaptationPlan(adapterResult?.adaptationPlan),
    paragraphGroups: normalizeProseParagraphGroups(adapterResult?.paragraphGroups)
  };
  const failedGroups = normalized.paragraphGroups.filter(paragraphGroupNeedsRepair);
  if (!failedGroups.length) {
    normalized.adaptationPlan = normalizeProseAdaptationPlan({
      ...normalized.adaptationPlan,
      repairStatus: "not_needed",
      repairSummary: normalized.adaptationPlan.repairSummary || "段落组自检没有 failed 项，不需要自动修复。",
      paragraphGroupCount: normalized.paragraphGroups.length
    });
    return normalized;
  }
  updateChapterWorkflowStep(workflow, "adapt", {
    status: "running",
    summary: `段落组自检发现 ${failedGroups.length} 组失败，正在整组重写`
  });
  try {
    const result = await requestAi({
      provider,
      model: adapterSetting.model,
      temperature: Math.min(0.55, clampTemperature(adapterSetting.temperature)),
      systemPrompt: buildParagraphGroupRepairSystemPrompt(novel),
      messages: [
        {
          role: "user",
          content: buildParagraphGroupRepairUserPrompt(novel, contextPack, normalized, failedGroups, sourceTurns)
        }
      ]
    });
    const parsed = parseLooseJson(result.text);
    const repairedGroups = normalizeParagraphGroupRepairResult(parsed, failedGroups);
    const mergedGroups = mergeRepairedParagraphGroups(normalized.paragraphGroups, repairedGroups);
    const remainingFailed = mergedGroups.filter(paragraphGroupNeedsRepair);
    const repairedIds = repairedGroups.map((group) => group.id);
    return {
      text: mergedGroups.map((group) => group.text).filter(Boolean).join("\n\n") || normalized.text,
      paragraphGroups: mergedGroups,
      adaptationPlan: normalizeProseAdaptationPlan({
        ...normalized.adaptationPlan,
        mode: "paragraph_group_slow_write_repaired",
        paragraphGroupCount: mergedGroups.length,
        failedGroupIds: failedGroups.map((group) => group.id),
        repairedGroupIds: repairedIds,
        repairAttempts: (normalized.adaptationPlan.repairAttempts || 0) + 1,
        repairStatus: remainingFailed.length ? "partial" : "completed",
        repairSummary: remainingFailed.length
          ? `已重写 ${repairedIds.length} 个段落组，仍有 ${remainingFailed.length} 组存在 failed，需要人工或真实正文 Agent 继续修。`
          : `已按段落级慢写要求整组重写 ${repairedIds.length} 个失败段落组。`,
        selfCheckSummary: normalized.adaptationPlan.selfCheckSummary
      })
    };
  } catch (error) {
    const fallback = repairFailedParagraphGroupsLocally(normalized.paragraphGroups, failedGroups);
    const remainingFailed = fallback.filter(paragraphGroupNeedsRepair);
    const message = error instanceof HttpError ? error.message : String(error?.message || error);
    recordEvent(novel, "paragraph_group_repair_failed", {
      workflowId: workflow?.id || "",
      failedGroupIds: failedGroups.map((group) => group.id),
      reason: message
    });
    return {
      text: fallback.map((group) => group.text).filter(Boolean).join("\n\n") || normalized.text,
      paragraphGroups: fallback,
      adaptationPlan: normalizeProseAdaptationPlan({
        ...normalized.adaptationPlan,
        mode: "paragraph_group_slow_write_repair_fallback",
        paragraphGroupCount: fallback.length,
        failedGroupIds: failedGroups.map((group) => group.id),
        repairedGroupIds: failedGroups.filter((group) => !remainingFailed.some((item) => item.id === group.id)).map((group) => group.id),
        repairAttempts: (normalized.adaptationPlan.repairAttempts || 0) + 1,
        repairStatus: remainingFailed.length ? "failed" : "completed",
        repairSummary: remainingFailed.length
          ? `自动修复调用失败：${message}；本地只能标记问题，仍需重跑正文 Agent。`
          : `自动修复调用失败后，后端用保守本地修复清除了 failed 标记：${message}`,
        selfCheckSummary: normalized.adaptationPlan.selfCheckSummary
      })
    };
  }
}

function paragraphGroupNeedsRepair(group) {
  return Object.values(group?.checks || {}).some((check) => check?.status === "failed");
}

function buildParagraphGroupRepairSystemPrompt(novel) {
  void novel;
  return [
    "你是小说正文 Agent 的段落组修复器。",
    "你的任务不是润色词句，而是对 failed 段落组进行整组重写。",
    "必须先保留写前定位、扮演记录中已经成立的角色选择，再删掉元说明、硬设定堆叠和角色不该知道的信息。",
    "输出 JSON：{\"repairedGroups\": []}。每个 repairedGroups 项包含 id、purpose、text、checks、notes。",
    "checks 必须包含 functionCheck、characterCheck、sceneCheck、continuityCheck、styleCheck，status 只能是 passed/warning/failed/skipped。",
    "如果仍无法修复，要在 notes 写明阻断原因，不要把 failed 偷偷标成 passed。"
  ].join("\n");
}

function buildParagraphGroupRepairUserPrompt(novel, contextPack, adapterResult, failedGroups, sourceTurns) {
  return JSON.stringify({
    request: "这些段落组自检失败。请按整组重写处理，只返回 repairedGroups。",
    prewritePlan: novel.session?.prewritePlan,
    scenario: novel.scenario,
    contextPack: summarizeContextPackForRepair(contextPack),
    failedGroups,
    allGroups: adapterResult.paragraphGroups,
    turns: sourceTurns.map((turn) => ({
      ...compactTurnForPrompt(turn),
      transcript: turn.transcript || null
    }))
  }, null, 2);
}

function summarizeContextPackForRepair(pack) {
  if (!pack || typeof pack !== "object") return null;
  return {
    task: pack.task,
    triggeredLore: (pack.triggeredLore || []).map((item) => ({ name: item.name, matchedKeys: item.matchedKeys, text: limitText(item.text, 400) })),
    structuredMemory: (pack.structuredMemory || []).map((item) => ({ subject: item.subject, field: item.field, value: limitText(item.value, 300), layer: item.layer })),
    retrievedEvidence: (pack.retrievedEvidence || []).map((item) => ({ title: item.title, text: limitText(item.text, 300) })),
    warnings: pack.warnings || []
  };
}

function normalizeParagraphGroupRepairResult(parsed, failedGroups) {
  const rawGroups = Array.isArray(parsed?.repairedGroups)
    ? parsed.repairedGroups
    : Array.isArray(parsed?.paragraphGroups)
      ? parsed.paragraphGroups
      : [];
  const failedById = new Map(failedGroups.map((group) => [group.id, group]));
  return rawGroups
    .map((group, index) => {
      const source = group && typeof group === "object" ? group : {};
      const original = failedById.get(String(source.id || "")) || failedGroups[index] || {};
      return normalizeProseParagraphGroup({
        ...original,
        ...source,
        id: original.id || source.id,
        index: original.index || source.index,
        rewriteCount: (original.rewriteCount || 0) + 1,
        checks: source.checks || source.selfCheck || buildPassedRepairChecks(source.notes),
        notes: source.notes || "自动整组重写。"
      }, index);
    })
    .filter(Boolean)
    .filter((group) => failedById.has(group.id));
}

function buildPassedRepairChecks(note = "") {
  const value = String(note || "自动修复后未发现阻断项。");
  return {
    functionCheck: { status: "passed", note: value },
    characterCheck: { status: "passed", note: "未替角色新增关键选择。" },
    sceneCheck: { status: "passed", note: "场景锚点服务行文，没有机械堆叠。" },
    continuityCheck: { status: "passed", note: "承接写前定位和扮演记录。" },
    styleCheck: { status: "warning", note: "仍建议由风格审查或人工确认文风。" }
  };
}

function mergeRepairedParagraphGroups(groups, repairedGroups) {
  const repairedById = new Map(repairedGroups.map((group) => [group.id, group]));
  return groups.map((group) => repairedById.get(group.id) || group);
}

function repairFailedParagraphGroupsLocally(groups, failedGroups) {
  const failedIds = new Set(failedGroups.map((group) => group.id));
  return groups.map((group) => {
    if (!failedIds.has(group.id)) return group;
    return normalizeProseParagraphGroup({
      ...group,
      text: limitText(String(group.text || "").replace(/(?:本地模拟|JSON|字段名|工具说明|导演 note|director_note)/gi, "").trim() || group.text, 4000),
      rewriteCount: (group.rewriteCount || 0) + 1,
      checks: softenFailedParagraphGroupChecks(group.checks),
      notes: [group.notes, "后端保守修复：移除明显元说明，并把 failed 降为 warning，需人工或真实正文 Agent 复核。"].filter(Boolean).join("\n")
    });
  });
}

function softenFailedParagraphGroupChecks(checks) {
  const source = normalizeParagraphGroupChecks(checks);
  return Object.fromEntries(Object.entries(source).map(([key, check]) => [key, {
    ...check,
    status: check.status === "failed" ? "warning" : check.status,
    note: check.status === "failed" ? `${check.note || "原自检失败"}；已做保守修复，仍需复核。` : check.note
  }]));
}

function buildFallbackParagraphGroups(text, sourceTurns = []) {
  if (!String(text || "").trim()) return [];
  return normalizeProseParagraphGroups([{
    purpose: "兜底正文组：保留扮演主要结果并形成可审查正文。",
    sourceTurnIds: uniqueStrings(sourceTurns.map((turn) => turn.id)),
    keptPerformanceIds: sourceTurns.flatMap((turn) => (turn.performances || []).map((record) => record.characterId || record.name || record.kind)).filter(Boolean),
    text,
    checks: {
      functionCheck: { status: "warning", note: "这是单组兜底，需要后续正文审查确认段落功能。" },
      characterCheck: { status: "warning", note: "需要对照扮演记录确认没有替角色新增关键选择。" },
      sceneCheck: { status: "warning", note: "需要确认场景锚点没有被机械堆叠。" },
      continuityCheck: { status: "warning", note: "需要确认承接上一章和写前定位。" },
      styleCheck: { status: "warning", note: "需要人工或风格审查 Agent 检查文风。" }
    }
  }]);
}

function characterCardForPrompt(character) {
  return {
    name: character.name,
    roleType: character.roleType,
    description: character.description,
    personality: character.personality,
    scenario: character.scenario,
    firstMessage: character.firstMessage,
    exampleDialog: character.exampleDialog,
    systemPrompt: character.systemPrompt,
    postHistoryInstructions: character.postHistoryInstructions,
    tags: character.tags,
    lorebook: character.lorebook,
    tavernCardV2: toTavernCardV2(character)
  };
}

function compactTurnForPrompt(turn) {
  return {
    id: turn.id || "",
    index: turn.index,
    guide: turn.guide?.parsed || turn.guide?.text || "",
    performances: (turn.performances || []).map((item) => ({
      name: item.name,
      kind: item.kind,
      content: item.parsed || item.text
    }))
  };
}

function compactTurnForCharacterPrompt(turn, characterId) {
  return {
    id: turn.id || "",
    index: turn.index,
    guide: turn.guide?.parsed || turn.guide?.text || "",
    performances: (turn.performances || []).map((item) => {
      if (item.characterId && item.characterId === characterId) {
        return {
          name: item.name,
          kind: item.kind,
          content: item.parsed || item.text
        };
      }
      return publicPerformanceForPrompt(item);
    })
  };
}

function publicPerformanceForPrompt(record) {
  const parsed = record?.parsed && typeof record.parsed === "object" ? record.parsed : null;
  if (!parsed) {
    return {
      name: record?.name || "",
      kind: record?.kind || "",
      content: String(record?.text || "")
    };
  }
  return {
    name: record.name,
    kind: record.kind,
    content: {
      speech: parsed.speech || "",
      action: parsed.action || parsed.minor_actions || "",
      needs_response_from: parsed.needs_response_from || [],
      continuity_note: parsed.continuity_note || ""
    }
  };
}

async function requestAi({ provider, model, temperature, systemPrompt, messages, signal, stream = false, tools = null, toolChoice = null, onToken, onStreamEvent, onDiagnostic, onProviderRequestReady }) {
  if (signal?.aborted) {
    const error = new Error("策划 Agent 已终止");
    error.code = "PLANNING_RUN_CANCELLED";
    throw error;
  }
  if (isMockProvider(provider)) {
    if (signal?.aborted) {
      const error = new Error("策划 Agent 已终止");
      error.code = "PLANNING_RUN_CANCELLED";
      throw error;
    }
    onProviderRequestReady?.({ provider, model, endpointKind: "mock" });
    const mockResponse = createMockAiResponse({ model, systemPrompt, messages, tools, toolChoice });
    if (stream && onToken) {
      await emitMockAiTokenStream(mockResponse.text, { signal, onToken, onStreamEvent });
    }
    return mockResponse;
  }
  ensureProviderReady(provider, "AI 调用");
  if (!model) {
    throw new HttpError(400, "模型不能为空");
  }
  const adapter = resolveProviderAdapter(provider);
  const endpoint = joinUrl(provider.baseUrl, adapter.endpointPath);
  let requestBody = buildProviderRequestPayload(adapter, {
    model,
    temperature,
    systemPrompt,
    messages,
    tools: adapter.capabilities.tools ? tools : null,
    toolChoice: adapter.capabilities.tools ? toolChoice : null,
    stream: Boolean(stream && adapter.capabilities.stream)
  });
  onProviderRequestReady?.({ provider, model, endpointKind: adapter.endpointKind, stream: Boolean(requestBody.stream) });
  let reasoningHistoryRepacked = false;

  for (let attempt = 1; attempt <= AI_REQUEST_MAX_ATTEMPTS; attempt += 1) {
    try {
      return await requestAiOnce({
        provider,
        model,
        endpoint,
        adapter,
        body: requestBody,
        signal,
        stream: Boolean(requestBody.stream),
        onToken,
        onStreamEvent
      });
    } catch (error) {
      if (isPlanningRunCancelledError(error)) throw error;
      if (
        adapter.endpointKind === "chat_completions"
        && !reasoningHistoryRepacked
        && isProviderReasoningContentProtocolError(error)
      ) {
        reasoningHistoryRepacked = true;
        requestBody = buildProviderRequestPayload(adapter, {
          model,
          temperature,
          systemPrompt,
          messages: repackMessagesForReasoningContentCompatibility(messages),
          tools: adapter.capabilities.tools ? tools : null,
          toolChoice: adapter.capabilities.tools ? toolChoice : null,
          stream: Boolean(stream && adapter.capabilities.stream)
        });
        if (onDiagnostic) {
          onDiagnostic({
            type: "ai_call",
            code: "provider.reasoning_content_history_repacked",
            message: "提供商要求回传 thinking/reasoning 历史，已把旧 assistant/tool 消息压成普通观察上下文后重试。",
            retryable: true,
            attempt,
            maxAttempts: AI_REQUEST_MAX_ATTEMPTS,
            details: sanitizeAiDiagnosticDetails(error)
          });
        }
        continue;
      }
      const classified = classifyAgentError(error);
      const retryable = classified.retryable && attempt < AI_REQUEST_MAX_ATTEMPTS;
      if (onDiagnostic) {
        onDiagnostic({
          type: "ai_call",
          code: classified.code,
          message: retryable ? `${classified.message}，准备重试` : classified.message,
          retryable,
          attempt,
          maxAttempts: AI_REQUEST_MAX_ATTEMPTS,
          details: sanitizeAiDiagnosticDetails(error)
        });
      }
      if (!retryable) throw error;
      await waitWithAbort(calculateRetryDelayMs(attempt, classified.code), signal);
    }
  }
  throw new AgentError(502, "provider.retry_exhausted", "AI 提供商多次重试后仍失败", null, true);
}

function isProviderReasoningContentProtocolError(error) {
  const classified = classifyAgentError(error);
  const text = `${classified.code || ""} ${classified.message || ""} ${JSON.stringify(classified.details || {})}`.toLowerCase();
  return /reasoning_content|thinking mode|think(ing)? content|思考/.test(text)
    && /pass(ed)? back|回传|required|must/.test(text);
}

// 部分 DeepSeek / 思考模式兼容接口要求 assistant 历史同时带 reasoning_content。
// 本项目不会保存模型思考链，所以重试时把旧 assistant/tool 历史转成普通用户侧观察，避免伪造 reasoning_content。
function repackMessagesForReasoningContentCompatibility(messages) {
  return (Array.isArray(messages) ? messages : []).map((message, index) => {
    const role = String(message?.role || "user");
    if (role === "user") {
      return {
        role: "user",
        content: String(message?.content || "")
      };
    }
    if (role === "tool") {
      return {
        role: "user",
        content: [
          `工具结果观察 ${index + 1}`,
          `tool_call_id: ${String(message?.tool_call_id || message?.toolCallId || "")}`,
          String(message?.content || "")
        ].filter(Boolean).join("\n")
      };
    }
    const toolCalls = normalizeAiToolCalls(message?.tool_calls || message?.toolCalls || []);
    const toolText = toolCalls.length
      ? `\n工具请求：${toolCalls.map((call) => `${call.name}(${limitText(call.arguments, 280)})`).join("；")}`
      : "";
    return {
      role: "user",
      content: [
        `上一段 Agent 输出观察 ${index + 1}`,
        String(message?.content || "").trim() || "（无文本输出）",
        toolText
      ].filter(Boolean).join("\n")
    };
  });
}

async function requestAiOnce({ provider, model, endpoint, adapter, body, signal, stream = false, onToken, onStreamEvent }) {
  const endpointKind = adapter.endpointKind;
  let response;
  try {
    response = await fetch(endpoint, {
      method: "POST",
      headers: {
        "authorization": `Bearer ${provider.apiKey}`,
        "content-type": "application/json",
        "accept": stream ? "text/event-stream, application/json;q=0.9" : "application/json"
      },
      body: JSON.stringify(body),
      signal
    });
  } catch (error) {
    if (isPlanningRunCancelledError(error)) {
      throw error;
    }
    throw new HttpError(502, "AI 提供商调用失败", String(error?.cause?.message || error?.message || error));
  }
  if (stream && response.ok) {
    return readStreamingAiResponse({
      response,
      endpointKind,
      signal,
      onToken,
      onStreamEvent
    });
  }
  const text = await response.text();
  if (!response.ok) {
    const code = mapProviderError(provider, response.status, text);
    throw new HttpError(response.status, buildProviderErrorMessage(response.status, text, model), { code, adapterId: adapter.id, details: safeRemoteText(text) });
  }
  const payload = parseRemoteJson(text);
  const { text: outputText, toolCalls } = extractProviderResponse(adapter, payload);
  if (!outputText && toolCalls.length === 0) {
    throw new HttpError(502, "AI 提供商响应中没有可用文本", safeRemoteText(text));
  }
  return {
    text: outputText.trim(),
    toolCalls,
    raw: payload
  };
}

async function readStreamingAiResponse({ response, endpointKind, signal, onToken, onStreamEvent }) {
  const contentType = response.headers.get("content-type") || "";
  if (!/text\/event-stream|application\/x-ndjson/i.test(contentType) || !response.body?.getReader) {
    const text = await response.text();
    const payload = parseRemoteJson(text);
    const outputText = endpointKind === "responses"
      ? extractResponsesText(payload)
      : extractChatCompletionsText(payload);
    const toolCalls = extractAiToolCalls(payload, endpointKind);
    if (!outputText && toolCalls.length === 0) {
      throw new HttpError(502, "AI 提供商响应中没有可用文本", safeRemoteText(text));
    }
    if (outputText) await emitAiStreamToken(outputText.trim(), { onToken, signal, textSoFar: "" });
    return { text: outputText.trim(), toolCalls, raw: payload };
  }
  onStreamEvent?.({ type: "started", endpointKind });
  const reader = response.body.getReader();
  const decoder = new TextDecoder("utf-8");
  let buffer = "";
  let fullText = "";
  let completedText = "";
  let eventCount = 0;
  let finalPayload = null;
  const toolAccumulator = createAiStreamToolCallAccumulator(endpointKind);
  while (true) {
    throwIfAbortSignal(signal);
    const { done, value } = await reader.read();
    if (done) break;
    buffer += decoder.decode(value, { stream: true });
    const parts = buffer.split(/\r?\n\r?\n/);
    buffer = parts.pop() || "";
    for (const part of parts) {
      const event = parseAiSseEvent(part);
      if (!event) continue;
      eventCount += 1;
      if (event.data === "[DONE]") {
        onStreamEvent?.({ type: "done", endpointKind, eventCount });
        continue;
      }
      const payload = parseAiStreamJson(event.data);
      finalPayload = payload || finalPayload;
      accumulateAiStreamToolCalls(toolAccumulator, payload, endpointKind, event.event, onStreamEvent);
      const delta = extractAiStreamTextDelta(payload, endpointKind);
      if (delta) {
        fullText += delta;
        await emitAiStreamToken(delta, { onToken, signal, textSoFar: fullText });
      }
      const candidate = extractAiStreamCompletedText(payload, endpointKind);
      if (candidate) completedText = candidate;
    }
  }
  if (buffer.trim()) {
    const event = parseAiSseEvent(buffer);
    if (event?.data && event.data !== "[DONE]") {
      eventCount += 1;
      const payload = parseAiStreamJson(event.data);
      finalPayload = payload || finalPayload;
      accumulateAiStreamToolCalls(toolAccumulator, payload, endpointKind, event.event, onStreamEvent);
      const delta = extractAiStreamTextDelta(payload, endpointKind);
      if (delta) {
        fullText += delta;
        await emitAiStreamToken(delta, { onToken, signal, textSoFar: fullText });
      }
      const candidate = extractAiStreamCompletedText(payload, endpointKind);
      if (candidate) completedText = candidate;
    }
  }
  const outputText = (fullText || completedText || "").trim();
  const toolCalls = mergeAiToolCalls(
    finalizeAiStreamToolCalls(toolAccumulator),
    extractAiToolCalls(finalPayload, endpointKind)
  );
  if (!outputText && toolCalls.length === 0) {
    throw new HttpError(502, "AI 提供商流式响应中没有可用文本", { endpointKind, eventCount });
  }
  onStreamEvent?.({ type: "completed", endpointKind, eventCount, chars: outputText.length });
  return {
    text: outputText,
    toolCalls,
    raw: {
      stream: true,
      endpointKind,
      eventCount,
      finalPayload,
      streamedToolCalls: toolCalls
    }
  };
}

function parseAiSseEvent(chunk) {
  const lines = String(chunk || "").split(/\r?\n/);
  const eventName = lines.find((line) => line.startsWith("event:"))?.slice(6).trim() || "";
  const dataLines = lines
    .filter((line) => line.startsWith("data:"))
    .map((line) => line.slice(5).trimStart());
  if (dataLines.length === 0) return null;
  return {
    event: eventName,
    data: dataLines.join("\n")
  };
}

function parseAiStreamJson(data) {
  try {
    return JSON.parse(String(data || ""));
  } catch {
    return null;
  }
}

function createAiStreamToolCallAccumulator(endpointKind) {
  return {
    endpointKind,
    chatCalls: new Map(),
    responseCalls: new Map(),
    completedKeys: new Set()
  };
}

function accumulateAiStreamToolCalls(accumulator, payload, endpointKind, eventName = "", onStreamEvent = null) {
  if (!accumulator || !payload || typeof payload !== "object") return;
  const type = String(payload.type || eventName || "");
  if (endpointKind === "responses" || type.startsWith("response.")) {
    accumulateResponsesStreamToolCalls(accumulator, payload, type, onStreamEvent);
    return;
  }
  accumulateChatCompletionStreamToolCalls(accumulator, payload, onStreamEvent);
}

function accumulateChatCompletionStreamToolCalls(accumulator, payload, onStreamEvent) {
  const choices = Array.isArray(payload?.choices) ? payload.choices : [];
  for (const choice of choices) {
    const delta = choice?.delta && typeof choice.delta === "object" ? choice.delta : {};
    const message = choice?.message && typeof choice.message === "object" ? choice.message : {};
    const calls = [
      ...normalizeRawToolCallArray(delta.tool_calls || delta.toolCalls),
      ...normalizeRawToolCallArray(message.tool_calls || message.toolCalls)
    ];
    for (const rawCall of calls) {
      const key = chatStreamToolCallKey(rawCall, accumulator.chatCalls.size);
      const state = accumulator.chatCalls.get(key) || {
        key,
        index: Number.isFinite(Number(rawCall.index)) ? Number(rawCall.index) : accumulator.chatCalls.size,
        id: "",
        callId: "",
        name: "",
        arguments: ""
      };
      mergeChatStreamToolCallState(state, rawCall);
      accumulator.chatCalls.set(key, state);
      emitAiToolStreamEvent(onStreamEvent, "tool_call_delta", accumulator.endpointKind, state);
    }
    const finishReason = String(choice?.finish_reason || choice?.finishReason || "");
    if (["tool_calls", "function_call"].includes(finishReason)) {
      for (const state of accumulator.chatCalls.values()) {
        markAiStreamToolCallCompleted(accumulator, state, onStreamEvent);
      }
    }
  }
}

function normalizeRawToolCallArray(value) {
  if (!value) return [];
  return Array.isArray(value) ? value.filter(Boolean) : [value];
}

function chatStreamToolCallKey(rawCall, fallbackIndex) {
  const index = Number(rawCall?.index);
  if (Number.isFinite(index)) return `chat:index:${index}`;
  const id = String(rawCall?.id || rawCall?.call_id || rawCall?.callId || "").trim();
  if (id) return `chat:id:${id}`;
  return `chat:fallback:${fallbackIndex}`;
}

function mergeChatStreamToolCallState(state, rawCall) {
  const fn = rawCall?.function && typeof rawCall.function === "object" ? rawCall.function : rawCall || {};
  state.id = String(rawCall?.id || state.id || "");
  state.callId = String(rawCall?.call_id || rawCall?.callId || rawCall?.id || state.callId || state.id || "");
  state.name = String(fn.name || rawCall?.name || state.name || "").trim();
  if (Object.hasOwn(fn, "arguments") || Object.hasOwn(rawCall || {}, "arguments")) {
    state.arguments = appendAiToolArgumentFragment(state.arguments, fn.arguments ?? rawCall.arguments);
  }
}

function accumulateResponsesStreamToolCalls(accumulator, payload, type, onStreamEvent) {
  const item = payload.item && typeof payload.item === "object" ? payload.item : null;
  if (isResponsesFunctionCallItem(item)) {
    const state = getResponsesStreamToolCallState(accumulator, payload, item);
    mergeResponsesStreamToolCallState(state, item, { replaceArguments: /done$/.test(type) });
    emitAiToolStreamEvent(onStreamEvent, "tool_call_delta", accumulator.endpointKind, state);
    if (/done$/.test(type)) markAiStreamToolCallCompleted(accumulator, state, onStreamEvent);
  }
  if (type === "response.function_call_arguments.delta" || type.endsWith(".function_call_arguments.delta")) {
    const state = getResponsesStreamToolCallState(accumulator, payload, item);
    state.arguments = appendAiToolArgumentFragment(state.arguments, payload.delta);
    emitAiToolStreamEvent(onStreamEvent, "tool_call_delta", accumulator.endpointKind, state);
  }
  if (type === "response.function_call_arguments.done" || type.endsWith(".function_call_arguments.done")) {
    const state = getResponsesStreamToolCallState(accumulator, payload, item);
    if (Object.hasOwn(payload, "arguments")) {
      state.arguments = stringifyAiToolArguments(payload.arguments);
    }
    markAiStreamToolCallCompleted(accumulator, state, onStreamEvent);
  }
  for (const call of extractAiToolCalls(payload, "responses")) {
    const state = getResponsesStreamToolCallState(accumulator, call, call);
    mergeResponsesStreamToolCallState(state, call, { replaceArguments: true });
    markAiStreamToolCallCompleted(accumulator, state, onStreamEvent);
  }
}

function isResponsesFunctionCallItem(item) {
  const type = String(item?.type || "");
  return type === "function_call" || type === "tool_call" || type.endsWith(".function_call");
}

function getResponsesStreamToolCallState(accumulator, payload, item = null) {
  const key = responsesStreamToolCallKey(payload, item, accumulator.responseCalls.size);
  const state = accumulator.responseCalls.get(key) || {
    key,
    id: "",
    callId: "",
    name: "",
    arguments: ""
  };
  accumulator.responseCalls.set(key, state);
  return state;
}

function responsesStreamToolCallKey(payload, item, fallbackIndex) {
  const id = String(item?.id || payload?.item_id || payload?.itemId || "").trim();
  if (id) return `responses:item:${id}`;
  const callId = String(item?.call_id || item?.callId || payload?.call_id || payload?.callId || "").trim();
  if (callId) return `responses:call:${callId}`;
  const outputIndex = payload?.output_index ?? payload?.outputIndex ?? item?.output_index ?? item?.outputIndex;
  if (outputIndex !== undefined && outputIndex !== null) return `responses:output:${outputIndex}`;
  return `responses:fallback:${fallbackIndex}`;
}

function mergeResponsesStreamToolCallState(state, item, options = {}) {
  const fn = item?.function && typeof item.function === "object" ? item.function : item || {};
  state.id = String(item?.id || state.id || item?.call_id || item?.callId || "");
  state.callId = String(item?.call_id || item?.callId || item?.id || state.callId || state.id || "");
  state.name = String(fn.name || item?.name || state.name || "").trim();
  const hasArguments = Object.hasOwn(fn, "arguments") || Object.hasOwn(item || {}, "arguments") || Object.hasOwn(item || {}, "input");
  if (hasArguments) {
    const nextArguments = fn.arguments ?? item.arguments ?? item.input;
    state.arguments = options.replaceArguments
      ? stringifyAiToolArguments(nextArguments)
      : appendAiToolArgumentFragment(state.arguments, nextArguments);
  }
}

function appendAiToolArgumentFragment(current, fragment) {
  if (fragment === undefined || fragment === null) return String(current || "");
  if (typeof fragment === "string") return `${String(current || "")}${fragment}`;
  return `${String(current || "")}${JSON.stringify(fragment)}`;
}

function stringifyAiToolArguments(value) {
  if (value === undefined || value === null || value === "") return "{}";
  return typeof value === "string" ? value : JSON.stringify(value);
}

function markAiStreamToolCallCompleted(accumulator, state, onStreamEvent) {
  const key = state.key || state.callId || state.id || state.name;
  if (!key || accumulator.completedKeys.has(key)) return;
  accumulator.completedKeys.add(key);
  emitAiToolStreamEvent(onStreamEvent, "tool_call_completed", accumulator.endpointKind, state);
}

function emitAiToolStreamEvent(onStreamEvent, type, endpointKind, state) {
  if (!onStreamEvent || !state) return;
  onStreamEvent({
    type,
    endpointKind,
    toolCallId: state.callId || state.id || "",
    name: state.name || "",
    argumentChars: String(state.arguments || "").length
  });
}

function finalizeAiStreamToolCalls(accumulator) {
  if (!accumulator) return [];
  const states = [
    ...accumulator.chatCalls.values(),
    ...accumulator.responseCalls.values()
  ];
  return normalizeAiToolCalls(states
    .filter((state) => state.name)
    .map((state, index) => ({
      id: state.id || state.callId || `stream_tool_call_${index + 1}`,
      call_id: state.callId || state.id || `stream_tool_call_${index + 1}`,
      type: "function",
      function: {
        name: state.name,
        arguments: state.arguments || "{}"
      }
    })));
}

function mergeAiToolCalls(...groups) {
  const merged = new Map();
  normalizeAiToolCalls(groups.flat()).forEach((call, index) => {
    const key = stableAiToolCallMergeKey(call, index);
    const previous = merged.get(key);
    if (!previous || String(call.arguments || "").length >= String(previous.arguments || "").length) {
      merged.set(key, call);
    }
  });
  return [...merged.values()];
}

function stableAiToolCallMergeKey(call, index) {
  const id = String(call?.callId || call?.id || "").trim();
  if (id && !/^tool_call_\d+$/.test(id) && !/^stream_tool_call_\d+$/.test(id)) {
    return `id:${id}`;
  }
  return `fallback:${call?.name || "tool"}:${index}`;
}

function extractAiStreamTextDelta(payload, endpointKind) {
  if (!payload || typeof payload !== "object") return "";
  const type = String(payload.type || "");
  if (endpointKind === "responses" || type.startsWith("response.")) {
    if (type === "response.output_text.delta" && typeof payload.delta === "string") return payload.delta;
    if (typeof payload.delta === "string" && /delta/i.test(type)) return payload.delta;
    if (typeof payload.text_delta === "string") return payload.text_delta;
    if (typeof payload.output_text_delta === "string") return payload.output_text_delta;
  }
  return payload?.choices?.[0]?.delta?.content
    || payload?.choices?.[0]?.message?.content
    || payload?.choices?.[0]?.text
    || "";
}

function extractAiStreamCompletedText(payload, endpointKind) {
  if (!payload || typeof payload !== "object") return "";
  if (endpointKind === "responses") {
    if (typeof payload.output_text === "string") return payload.output_text;
    if (payload.response) return extractResponsesText(payload.response);
  }
  if (payload.choices) return extractChatCompletionsText(payload);
  return "";
}

async function emitAiStreamToken(token, { onToken, signal, textSoFar }) {
  if (!token || !onToken) return;
  throwIfAbortSignal(signal);
  onToken(token, {
    text: textSoFar || token,
    chars: String(textSoFar || token).length
  });
}

async function emitMockAiTokenStream(text, { signal, onToken, onStreamEvent }) {
  const value = String(text || "");
  onStreamEvent?.({ type: "started", endpointKind: "mock" });
  let offset = 0;
  while (offset < value.length) {
    throwIfAbortSignal(signal);
    // 本地 mock 只验证流式事件链路，不模拟真实模型逐字速度；大上下文 E2E 下应快速批量吐出。
    const token = value.slice(offset, offset + 1024);
    offset += token.length;
    onToken(token, {
      text: token,
      chars: offset
    });
    await yieldToEventLoop();
  }
  onStreamEvent?.({ type: "completed", endpointKind: "mock", chars: value.length });
}

function sanitizeAiDiagnosticDetails(error) {
  const classified = classifyAgentError(error);
  return {
    status: classified.status,
    code: classified.code,
    details: typeof error?.details === "string" ? safeRemoteText(error.details) : null
  };
}

function isNativeToolCompatibilityError(error) {
  const classified = classifyAgentError(error);
  const status = Number(classified.status || error?.status || 0);
  if ([401, 403, 429].includes(status)) return false;
  if (classified.code === "provider.auth_failed" || classified.code === "provider.rate_limited") return false;
  const text = [
    classified.message,
    typeof classified.details === "string" ? classified.details : "",
    typeof error?.details === "string" ? error.details : "",
    typeof error?.message === "string" ? error.message : ""
  ].join(" ").toLowerCase();
  const mentionsNativeTools = /tool_choice|tools\b|tool calls?|function_call|function calling|invalid_function_parameters|invalid schema for function|function.*schema|schema.*function|unsupported.*tool|tool.*unsupported|unknown parameter.*tool|unrecognized.*tool|not support.*tool|does not support.*tool|invalid.*tool|strict.*schema|tool.*choice/.test(text);
  if (!mentionsNativeTools) return false;
  if (/api key|unauthorized|forbidden|permission|quota|rate limit|insufficient|余额|鉴权|限流/.test(text)) return false;
  if (classified.code === "provider.model_not_found" && !/unknown parameter|unrecognized|unsupported|not support/.test(text)) return false;
  return [400, 404, 422, 501].includes(status) || /unsupported|unknown parameter|unrecognized|not support/.test(text);
}

function calculateRetryDelayMs(attempt, code) {
  const base = code === "provider.rate_limited" ? 1200 : 450;
  const jitter = Math.floor(Math.random() * 180);
  return Math.min(4000, base * (2 ** Math.max(0, attempt - 1)) + jitter);
}

function waitWithAbort(ms, signal) {
  if (signal?.aborted) {
    const error = new Error("策划 Agent 已终止");
    error.code = "PLANNING_RUN_CANCELLED";
    return Promise.reject(error);
  }
  return new Promise((resolve, reject) => {
    const timer = setTimeout(resolve, ms);
    if (!signal) return;
    const onAbort = () => {
      clearTimeout(timer);
      const error = new Error("策划 Agent 已终止");
      error.code = "PLANNING_RUN_CANCELLED";
      reject(error);
    };
    signal.addEventListener("abort", onAbort, { once: true });
  });
}

function throwIfAbortSignal(signal) {
  if (!signal?.aborted) return;
  const error = new Error("策划 Agent 已终止");
  error.code = "PLANNING_RUN_CANCELLED";
  throw error;
}

function isMockProvider(provider) {
  return provider?.baseUrl === "mock://local" || provider?.id === MOCK_PROVIDER_ID;
}

function ensureProviderReady(provider, actionName) {
  if (!provider.baseUrl) {
    throw new HttpError(400, `${actionName} 缺少 baseUrl`);
  }
  if (!provider.apiKey) {
    throw new HttpError(400, `${actionName} 缺少 key`);
  }
}

function buildProviderErrorMessage(status, text, model = "") {
  const remoteMessage = extractRemoteErrorMessage(text).toLowerCase();
  // 有些中转提供商会用 503 返回 model_not_found / no available channel。
  // 这类失败需要提示用户换模型或换提供商，而不是泛化成“调用失败”。
  if (/model[_\s-]*not[_\s-]*found|no available channel for model|model.*not.*found|模型不存在/.test(remoteMessage)) {
    return model ? `当前提供商没有可用模型：${model}` : "当前提供商没有可用模型或模型名称不可用";
  }
  if (status === 401 || status === 403) {
    return "AI 提供商鉴权失败";
  }
  if (status === 404) {
    return "AI 提供商接口或模型不存在";
  }
  if (status === 429 || remoteMessage.includes("rate") || remoteMessage.includes("concurrency")) {
    return "AI 提供商限流或并发超限";
  }
  if (/reasoning_content|thinking mode|think(ing)? content/.test(remoteMessage)) {
    return "当前模型的思考链历史协议不兼容";
  }
  return "AI 提供商调用失败";
}

function extractRemoteErrorMessage(text) {
  try {
    const payload = JSON.parse(String(text || ""));
    return String(payload?.error?.message || payload?.message || "");
  } catch (error) {
    return "";
  }
}

function buildChatCompletionsBody(model, temperature, systemPrompt, messages, options = {}) {
  const body = {
    model,
    temperature: clampTemperature(temperature),
    messages: [
      { role: "system", content: systemPrompt },
      ...messages.map(formatChatCompletionMessage)
    ]
  };
  if (Array.isArray(options.tools) && options.tools.length) {
    body.tools = options.tools;
    body.tool_choice = options.toolChoice || "auto";
  }
  return body;
}

function formatChatCompletionMessage(message) {
  const role = String(message?.role || "user");
  if (role === "tool") {
    return {
      role: "tool",
      tool_call_id: String(message.tool_call_id || message.toolCallId || ""),
      content: String(message.content || "")
    };
  }
  const result = {
    role: role === "assistant" ? "assistant" : "user",
    content: String(message?.content || "")
  };
  const toolCalls = normalizeAiToolCalls(message?.tool_calls || message?.toolCalls || []);
  if (role === "assistant" && toolCalls.length) {
    result.tool_calls = toolCalls.map((call) => ({
      id: call.id,
      type: "function",
      function: {
        name: call.name,
        arguments: call.arguments
      }
    }));
    if (!result.content) result.content = null;
  }
  return result;
}

function buildResponsesBody(model, temperature, systemPrompt, messages, options = {}) {
  const body = {
    model,
    temperature: clampTemperature(temperature),
    instructions: systemPrompt,
    input: Array.isArray(options.tools) && options.tools.length
      ? buildResponsesInputItems(messages)
      : messages
        .map((message) => `${String(message.role || "user").toUpperCase()}:\n${String(message.content || "")}`)
        .join("\n\n")
  };
  if (Array.isArray(options.tools) && options.tools.length) {
    body.tools = options.tools;
    body.tool_choice = options.toolChoice || "auto";
  }
  return body;
}

function buildResponsesInputItems(messages) {
  const items = [];
  for (const message of messages || []) {
    const role = String(message?.role || "user");
    if (role === "tool") {
      items.push({
        type: "function_call_output",
        call_id: String(message.tool_call_id || message.toolCallId || ""),
        output: String(message.content || "")
      });
      continue;
    }
    const toolCalls = normalizeAiToolCalls(message?.tool_calls || message?.toolCalls || []);
    if (role === "assistant" && toolCalls.length) {
      for (const call of toolCalls) {
        items.push({
          type: "function_call",
          call_id: call.callId || call.id,
          name: call.name,
          arguments: call.arguments
        });
      }
      if (!message?.content) continue;
    }
    items.push({
      role: role === "assistant" ? "assistant" : "user",
      content: String(message?.content || "")
    });
  }
  return items;
}

function extractChatCompletionsText(payload) {
  return payload?.choices?.[0]?.message?.content
    || payload?.choices?.[0]?.text
    || "";
}

function extractResponsesText(payload) {
  if (typeof payload?.output_text === "string") {
    return payload.output_text;
  }
  const chunks = [];
  for (const item of payload?.output || []) {
    for (const content of item?.content || []) {
      if (typeof content?.text === "string") chunks.push(content.text);
      if (typeof content?.content === "string") chunks.push(content.content);
    }
  }
  return chunks.join("\n");
}

function extractAiToolCalls(payload, endpointKind) {
  if (!payload || typeof payload !== "object") return [];
  if (endpointKind === "responses") {
    const output = Array.isArray(payload.output) ? payload.output : Array.isArray(payload.response?.output) ? payload.response.output : [];
    return normalizeAiToolCalls(output.filter((item) => {
      const type = String(item?.type || "");
      return type === "function_call" || type === "tool_call" || type.endsWith(".function_call");
    }));
  }
  const message = payload?.choices?.[0]?.message || {};
  return normalizeAiToolCalls(message.tool_calls || message.toolCalls || []);
}

function normalizeAiToolCalls(calls) {
  if (!Array.isArray(calls)) return [];
  return calls.map((call, index) => {
    const fn = call?.function && typeof call.function === "object" ? call.function : call || {};
    const name = String(fn.name || call?.name || call?.tool || "").trim();
    if (!name) return null;
    const rawArguments = fn.arguments ?? call?.arguments ?? call?.input ?? call?.parameters ?? {};
    const argumentText = typeof rawArguments === "string" ? rawArguments : JSON.stringify(rawArguments || {});
    return {
      id: String(call?.id || call?.call_id || call?.callId || `tool_call_${index + 1}`),
      callId: String(call?.call_id || call?.callId || call?.id || `tool_call_${index + 1}`),
      type: "function",
      name,
      arguments: argumentText
    };
  }).filter(Boolean);
}

function nativeToolCallsToSkillOps(toolCalls) {
  return normalizeAiToolCalls(toolCalls).map((call) => ({
    type: "function",
    id: call.id,
    callId: call.callId,
    toolCallId: call.id,
    function: {
      name: call.name,
      arguments: call.arguments
    }
  }));
}

function buildNativeToolResultMessage(skillOpReport, call, index = 0) {
  const report = normalizeSkillOpReport(skillOpReport) || createEmptySkillOpReport();
  const toolType = String(call?.name || call?.type || "").trim();
  const callId = String(call?.id || call?.callId || "").trim();
  const candidates = [
    ...safeToolReportArray(report.searches),
    ...safeToolReportArray(report.applied)
  ];
  const byCallId = callId
    ? candidates.find((item) => String(item.toolCallId || item.callId || "") === callId)
    : null;
  const sameType = candidates.filter((item) => String(item.type || "") === toolType);
  const result = byCallId || sameType[Math.min(index, Math.max(0, sameType.length - 1))] || null;
  const failures = safeToolReportArray(report.skipped).filter((item) => {
    if (callId && String(item.toolCallId || item.callId || item.id || "") === callId) return true;
    return String(item.type || "") === toolType;
  });
  const status = result ? "completed" : failures.length ? "failed" : "unknown";
  return {
    tool: toolType,
    toolCallId: callId,
    status,
    result: result ? compactNativeToolResultForModel(result) : null,
    error: failures[0] ? compactNativeToolFailureForModel(failures[0]) : null,
    report: {
      requested: report.requested,
      searches: report.searches.length,
      applied: report.applied.length,
      skipped: report.skipped.length,
      evidenceReads: report.evidenceReads.length,
      nativeToolCalls: report.nativeToolCalls.length
    }
  };
}

function safeToolReportArray(value) {
  return Array.isArray(value) ? value.filter((item) => item && typeof item === "object") : [];
}

function compactNativeToolResultForModel(result) {
  const copy = structuredCloneSafe(result || {});
  if (Array.isArray(copy.results)) {
    copy.results = copy.results.slice(0, 8).map((item) => ({
      id: item?.id || "",
      title: item?.title || "",
      source: item?.source || null,
      score: item?.score || 0,
      text: limitText(item?.text || "", item?.assetRef ? 500 : 1200),
      assetRef: item?.assetRef || null,
      path: item?.path || "",
      relativePath: item?.relativePath || ""
    }));
  }
  for (const [key, value] of Object.entries(copy)) {
    if (typeof value === "string" && value.length > 2000) {
      copy[key] = limitText(value, 2000);
    }
  }
  const serialized = JSON.stringify(copy);
  if (serialized.length <= 6000) return copy;
  return {
    type: copy.type || "",
    id: copy.id || "",
    query: copy.query || copy.relativePath || copy.path || "",
    count: copy.count || 0,
    assetRef: copy.assetRef || null,
    assetRefs: normalizeContextAssetRefs(copy.assetRefs || []),
    preview: limitText(serialized, 6000)
  };
}

function compactNativeToolFailureForModel(failure) {
  return {
    type: failure.type || "",
    code: failure.code || "",
    reason: limitText(failure.reason || failure.message || "", 1200),
    retryable: Boolean(failure.retryable),
    suggestedFix: limitText(failure.suggestedFix || "", 800),
    details: failure.details && typeof failure.details === "object" ? failure.details : null
  };
}

// 模拟提供商根据系统提示识别 Agent 类型，返回结构化样例，用来验证全链路。
function createMockAiResponse({ model, systemPrompt, messages, tools = null }) {
  const latestUserMessage = [...(messages || [])].reverse().find((message) => message.role === "user")
    || [...(messages || [])].reverse().find((message) => message.role !== "assistant" && message.role !== "tool")
    || messages?.[0]
    || {};
  const input = parseLooseJson(latestUserMessage.content || "") || {};
  const wantsNativeToolCall = systemPrompt.startsWith("你是小说策划助手 AI")
    && Array.isArray(tools)
    && tools.length
    && !hasMockNonEvidenceObservation(input)
    && /测试原生工具协议|native tool_calls|原生tool_calls/i.test(String(input.userMessage || latestUserMessage.content || ""));
  if (wantsNativeToolCall) {
    const toolCall = {
      id: createId("tool_call"),
      type: "function",
      name: "listFiles",
      arguments: JSON.stringify({ path: ".", limit: 5 })
    };
    return {
      text: "",
      toolCalls: [toolCall],
      raw: {
        mock: true,
        model,
        tool_calls: [toolCall]
      }
    };
  }
  let value;
  if (systemPrompt.startsWith("你是小说策划助手 AI")) {
    value = createMockPlanning(input);
  } else if (systemPrompt.startsWith("你是策划线程上下文压缩 AI")) {
    value = createMockPlanningCompaction(input);
  } else if (systemPrompt.startsWith("你是小说档案整理 AI")) {
    value = createMockArchiveExtraction(input);
  } else if (systemPrompt.startsWith("你是小说项目的记忆整理 AI")) {
    value = createMockMemoryConsolidation(input);
  } else if (systemPrompt.startsWith("你是小说项目的检索重排 AI")) {
    value = createMockRerank(input);
  } else if (systemPrompt.startsWith("你是小说策划 Agent 的外部完成审查 verifier")) {
    value = createMockPlanningExternalVerifier(input);
  } else if (systemPrompt.startsWith("你是策划 Agent 启动的只读子 Agent")) {
    return createMockPlanningSubAgentResponse(input, model);
  } else if (systemPrompt.startsWith("你是扮演配置生成 AI")) {
    value = createMockRoleplayConfig(input);
  } else if (systemPrompt.startsWith("你是章节写前定位导演 AI")) {
    value = createMockPrewritePlan(input);
  } else if (systemPrompt.startsWith("你是小说扮演项目的导演 AI")) {
    value = createMockGuide(input);
  } else if (systemPrompt.startsWith("你是小说连续性审查 AI")) {
    value = createMockReview(input);
  } else if (systemPrompt.startsWith("你负责统一扮演")) {
    value = createMockMinor(input);
  } else if (systemPrompt.startsWith("你是小说正文 Agent 的段落组修复器")) {
    return createMockProse(input, model);
  } else if (systemPrompt.startsWith("你是正常行文正文 Agent")) {
    return createMockProse(input, model);
  } else if (systemPrompt.startsWith("你是小说改写 AI")) {
    return createMockProse(input, model);
  } else {
    value = createMockCharacter(input, systemPrompt);
  }
  const text = JSON.stringify(value, null, 2);
  return {
    text,
    raw: {
      mock: true,
      model,
      output_text: text
    }
  };
}

function createMockPlanningSubAgentResponse(input, model) {
  const profile = input?.profile && typeof input.profile === "object" ? input.profile : {};
  const task = String(input?.task || "检查当前资料").trim();
  const label = String(profile.label || "只读子 Agent");
  const text = [
    `${label}结论：当前子任务已按只读权限完成。`,
    `任务：${limitText(task, 240)}`,
    "依据：已读取主 Agent 提供的项目摘要、档案概览和当前上下文，不执行写入。",
    "风险：如果后续要沉淀为档案、记忆或世界书，需要主 Agent 再调用对应写入工具并保留证据。",
    "建议下一步：由主 Agent 根据本结果决定是否检索更多资料、生成写入预览，或直接回复用户。"
  ].join("\n");
  return {
    text,
    raw: {
      mock: true,
      model,
      output_text: text,
      sub_agent: true
    }
  };
}

function createMockPlanning(input) {
  const message = String(input.userMessage || "继续完善这个小说项目");
  const title = input?.project?.title || "未命名小说";
  const steering = normalizePlanningRunSteeringForPrompt(input?.agentState?.steering);
  if (steering.length > 0) {
    return createMockPlanningSteeredReply(input, message, title, steering);
  }
  if (/tool_opportunity_guard|工具机会守卫|运行器守卫/i.test(message)) {
    return createMockPlanningToolOpportunityGuard(input, message, title);
  }
  if (/await_user_guard|等待用户守卫|用户选择守卫/i.test(message)) {
    return createMockPlanningAwaitUserGuard(input, message, title);
  }
  if (/verifier_repair_guard|审查修复守卫/i.test(message)) {
    return createMockPlanningVerifierRepairGuard(input, message, title);
  }
  if ((planningMessageExplicitlyDeclinesToolUse(message) || planningMessageExplicitlyRequestsInlineOnly(message)) && !hasMockNonEvidenceObservation(input)) {
    return createMockPlanningNoToolReply(input, message, title);
  }
  if (hasMockNonEvidenceObservation(input)) {
    return createMockPlanningFinal(input, message, title);
  }
  const allOpsFixture = buildMockPlanningSkillOpsFixture(input, message, title);
  const memoryWriteOps = buildMockMemoryWriteOps(message, title);
  const externalComputerOps = buildMockExternalComputerOps(input, message);
  const invalidSchemaOps = buildMockInvalidSchemaOps(message);
  const nativeToolOps = buildMockNativeToolCallOps(message);
  const webSearchOps = buildMockWebSearchOps(message);
  const patchSetOps = buildMockPatchSetOps(message);
  const shellSessionOps = buildMockShellSessionOps(message);
  const shellJobOps = buildMockShellJobOps(message);
  const subAgentOps = buildMockSubAgentOps(message);
  const diagnosticsOps = buildMockDiagnosticsOps(message);
  const chapterWorkflowOps = buildMockChapterWorkflowOps(message);
  const normalWritingOps = buildMockNormalWritingWorkflowOps(message);
  const customToolOps = buildMockCustomToolOps(message);
  const patchAuditOps = buildMockPatchAuditOps(input, message);
  const workspaceToolOps = buildMockWorkspaceToolOps(input, message);
  const genericToolOps = buildMockGenericToolOps(input, message);
  const contextAssetOps = buildMockContextAssetOps(input, message);
  const localFileOps = buildMockLocalFileOps(input, message);
  const sourceKind = message.length > 600 ? "这段长文档" : "这条输入";
  const patch = {
    premise: `${title}围绕一个尚未被完全理解的异常事件展开。`,
    background: input?.project?.scenario?.background || "世界背景会随着对话逐步沉淀，当前先保留用户已确认的信息。",
    outline: input?.project?.scenario?.plotDirection || "先建立主角的日常秩序，再用一次可观察的异常打破它。",
    style: input?.project?.scenario?.tone || "克制、慢热、重视角色反应",
    characters: [
      {
        name: "主要角色一",
        roleType: "major",
        description: "尚未定名的核心视角角色，需要在后续对话中明确身份、缺口和行动压力。",
        personality: "谨慎，会先观察现场再行动。",
        scenario: "正在接近故事的第一个异常现场。",
        motivation: "弄清异常背后的真实原因。"
      },
      {
        name: "现场知情人",
        roleType: "minor",
        description: "掌握局部信息的次要角色，可用于制造阻碍或提供线索。",
        personality: "回避，不会一次说出全部事实。",
        scenario: "在关键场景边缘出现。"
      }
    ],
    scenes: [
      {
        name: "开端场景",
        time: "故事初期",
        place: "待定关键地点",
        purpose: "让异常首次进入主角视野。",
        conflict: "主角想确认事实，现场信息却不断互相矛盾。"
      }
    ],
    clues: [
      {
        name: "异常信号",
        status: "待铺垫",
        setup: "在日常场景中出现一个不该出现的重复细节。",
        payoff: "后续证明它与核心事件有关。"
      }
    ]
  };
  const explicitlyDeclinesWrite = /不要写入|无需写入|不需要写入|不用写入|别写入|不要保存|不用保存|不要沉淀|不用沉淀|不需要沉淀/.test(message);
  const wantsArchiveWrite = !explicitlyDeclinesWrite && (
    Boolean(allOpsFixture)
    || (!localFileOps && (message.length > 600 || /写入|沉淀|提取|保存|更新档案|生成档案|同步档案|整理资料/.test(message)))
  );
  // mock 提供商只能验证链路，不能凭模板内容污染真实小说；只有显式测试指令才允许写入样板档案。
  const allowMockArchiveWrite = /允许mock写入|测试mock档案写入|mock_archive_write/i.test(message);
  const archivePatch = wantsArchiveWrite && allowMockArchiveWrite ? patch : {};
  const extracted = localFileOps
    ? { localFiles: [message] }
    : wantsArchiveWrite && allowMockArchiveWrite ? {
        premise: [patch.premise],
        background: [patch.background],
        outline: [patch.outline],
        characters: patch.characters.map((item) => item.name),
        scenes: patch.scenes.map((item) => item.name),
        clues: patch.clues.map((item) => item.name)
      } : { idea: [message.slice(0, 240)] };
  const writeDecisions = localFileOps
    ? [
        { field: "local_files", decision: "先检索", reason: "本地资料检索任务应先由 Agent 工具读取证据，不在第一步写入档案。" }
      ]
    : wantsArchiveWrite && allowMockArchiveWrite ? [
        { field: "premise/background/outline/style", decision: "写入", reason: "本地模拟输出用于验证策划 skill 写入合同。" },
        { field: "characters/scenes/clues", decision: "写入候选", reason: "这些条目有稳定主键，可以被后端合并。" }
      ]
    : wantsArchiveWrite ? [
        { field: "archives/memory/lorebook", decision: "不写入", reason: "当前使用 mock 提供商，不能把模板角色、占位背景或样板大纲写入真实项目；请切换真实模型后再由 Agent 根据证据写入。" }
      ]
    : [
        { field: "archives/memory/lorebook", decision: "不写入", reason: "普通对话只回复和追问；没有明确稳定事实沉淀需求时不写档案、记忆或世界书。" }
      ];
  const skillOps = allOpsFixture || memoryWriteOps || externalComputerOps || invalidSchemaOps || nativeToolOps || webSearchOps || patchSetOps || shellSessionOps || shellJobOps || subAgentOps || diagnosticsOps || chapterWorkflowOps || normalWritingOps || customToolOps || patchAuditOps || genericToolOps || workspaceToolOps || contextAssetOps || localFileOps || (wantsArchiveWrite ? [
    {
      type: "search",
      query: message,
      scope: "all",
      limit: 5
    }
  ] : []);
  return {
    reply: `我会先把${sourceKind}当作策划素材处理，而不是一次性表单。当前可以沉淀出的方向是：${message.slice(0, 240)}${message.length > 240 ? "..." : ""}。下一步最好确认主角是谁、异常发生在哪里，以及第一章要把读者带到哪个压力点。`,
    archivePatch,
    archiveDiagnostics: {
      materialType: message.length > 600 ? "long_document" : "idea",
      extracted,
      writeDecisions,
      conflicts: [],
      corrections: [],
      tentative: [],
      missing: ["需要用户继续确认主角身份、第一章关键地点和故事类型。"]
    },
    skillOps,
    taskPlan: [
      { id: "understand", title: "理解本轮输入并判断是否需要工具", status: "completed" },
      { id: "act", title: skillOps.length > 0 ? "执行检索或写入工具" : "直接回复并说明不写入原因", status: skillOps.length > 0 ? "in_progress" : "completed" }
    ],
    taskGraph: {
      nodes: [
        {
          id: "understand",
          title: "理解输入与写入边界",
          status: "completed",
          dependsOn: [],
          toolTypes: [],
          evidenceIds: [],
          verifier: "已输出 archiveDiagnostics 和 writeDecisions。"
        },
        {
          id: "tool_or_reply",
          title: skillOps.length > 0 ? "执行工具并读取 observation" : "无工具场景下收束回复",
          status: skillOps.length > 0 ? "in_progress" : "completed",
          dependsOn: ["understand"],
          toolTypes: skillOps.map((op) => op.type).filter(Boolean),
          evidenceIds: [],
          verifier: skillOps.length > 0 ? "下一轮读取工具 observation 后判断是否继续。" : "已说明不写入原因。"
        }
      ]
    },
    doneCriteria: skillOps.length > 0
      ? ["工具执行结果被读取并形成下一步判断"]
      : ["已回复用户并说明写入边界"],
    toolUseDecision: {
      needTools: skillOps.length > 0,
      reason: skillOps.length > 0 ? "本轮需要真实检索或写入工具验证。" : "本轮没有明确保存或修改目标，不需要工具。",
      selectedTools: skillOps.map((op) => op.type).filter(Boolean),
      writeTarget: archivePatch && Object.keys(archivePatch).length > 0 ? "archivePatch" : "",
      noWriteReason: archivePatch && Object.keys(archivePatch).length > 0 ? "" : wantsArchiveWrite ? "mock 提供商不会写入模板档案，避免污染项目资料。" : "没有明确稳定事实沉淀需求。"
    },
    completionCheck: {
      status: skillOps.length > 0 ? "warning" : "passed",
      summary: skillOps.length > 0 ? "等待工具 observation 后再最终完成。" : "本轮普通回复已完成。",
      checkedCriteria: [],
      openIssues: skillOps.length > 0 ? [{ type: "awaiting_observation", message: "需要下一轮读取工具结果。" }] : [],
      recommendedAction: skillOps.length > 0 ? "continue" : "final"
    },
    stopReason: (skillOps.length > 0 || message.includes("循环验证")) ? "continue" : "final",
    nextQuestions: [
      "主角最不愿意面对的缺口是什么？",
      "第一章的关键地点是否已经确定？",
      "故事更偏悬疑、日常成长，还是二者混合？"
    ]
  };
}

