function createMockPlanningExternalVerifier(input) {
  const deterministic = input.deterministicVerifier || {};
  const taskGraphNodes = Array.isArray(input.taskGraph?.nodes) ? input.taskGraph.nodes : [];
  const skipped = Array.isArray(input.toolReport?.skipped) ? input.toolReport.skipped : [];
  const unresolved = taskGraphNodes.filter((node) => ["pending", "in_progress", "blocked"].includes(String(node.status || "")));
  const failed = deterministic.status === "failed" || unresolved.some((node) => node.status === "blocked");
  return {
    status: failed ? "failed" : skipped.length > 0 || unresolved.length > 0 ? "warning" : "passed",
    summary: failed
      ? "模拟 verifier 认为任务仍存在阻断项。"
      : skipped.length > 0 || unresolved.length > 0
        ? "模拟 verifier 认为还有需要关注的未闭合项。"
        : "模拟 verifier 未发现明显未完成项。",
    checkedCriteria: (input.doneCriteria || []).map((criterion) => ({
      criterion,
      status: failed ? "failed" : "passed"
    })),
    openIssues: [
      ...unresolved.map((node) => ({
        type: "task_graph_unresolved",
        severity: node.status === "blocked" ? "high" : "medium",
        message: `任务节点未闭合：${node.title || node.id}`
      })),
      ...skipped.map((item) => ({
        type: "tool_skipped",
        severity: item.retryable ? "medium" : "low",
        message: item.reason || "存在跳过的工具调用"
      }))
    ],
    unresolvedNodeIds: unresolved.map((node) => node.id).filter(Boolean),
    recommendedAction: failed ? "block_and_resume_after_fix" : skipped.length || unresolved.length ? "review_or_continue" : "final"
  };
}

