function buildMockGenericToolOps(input, message) {
  const wantsGenericTools = /测试通用工具|通用工具|listFiles|globFiles|grepFiles|readFile/i.test(message);
  const wantsIndex = /结构化索引|indexLocalFiles|本地索引|LSP/i.test(message);
  const wantsWriteGuard = /测试写文件覆盖|写文件覆盖|writeFile覆盖/i.test(message);
  const sources = input.skillRuntime?.localFileSources || [];
  if (wantsWriteGuard && sources.length > 0) {
    return [
      { type: "writeFile", path: "existing.txt", text: "模拟器尝试覆盖已有文件，但没有提供 overwrite。", reason: "验证 writeFile 覆盖保护" }
    ];
  }
  if (wantsIndex && sources.length > 0) {
    return [
      { type: "indexLocalFiles", path: ".", limit: 30, maxCharsPerFile: 4000, buildVector: /向量|vector|embedding/i.test(message) }
    ];
  }
  if (!wantsGenericTools || sources.length === 0) return null;
  return [
    { type: "listFiles", path: ".", limit: 20 },
    { type: "globFiles", path: ".", pattern: "**/user_ideas.md", limit: 5 },
    { type: "grepFiles", path: ".", query: "用户思路", limit: 5 },
    { type: "readFile", relativePath: "user_ideas.md", maxChars: 2000 }
  ];
}

function extractMockExternalPath(message) {
  const text = String(message || "");
  const quoted = text.match(/(?:外部路径|externalPath)\s*[:=：]\s*["“](.+?)["”]/i);
  if (quoted?.[1]) return quoted[1].trim();
  const line = text.match(/(?:外部路径|externalPath)\s*[:=：]\s*([^\r\n]+)/i);
  if (!line?.[1]) return "";
  return line[1].replace(/[。；;，,]\s*$/, "").trim().replace(/^["']|["']$/g, "");
}

function extractMockExternalFileName(message) {
  const text = String(message || "");
  const quoted = text.match(/(?:外部文件|externalFile)\s*[:=：]\s*["“](.+?)["”]/i);
  if (quoted?.[1]) return quoted[1].trim();
  const line = text.match(/(?:外部文件|externalFile)\s*[:=：]\s*([^\r\n]+)/i);
  if (!line?.[1]) return "";
  return line[1].replace(/[。；;，,]\s*$/, "").trim().replace(/^["']|["']$/g, "");
}

function buildMockExternalComputerOps(input, message) {
  if (!/测试外部电脑操作|外部路径|externalPath/i.test(message)) return null;
  const externalPath = extractMockExternalPath(message);
  if (!externalPath) return null;
  if (/外部列读|先列后读|listFilesThenRead/i.test(message)) {
    const fileName = extractMockExternalFileName(message) || "notes.md";
    return [
      {
        type: "listFiles",
        path: externalPath,
        limit: 20
      },
      {
        type: "readFile",
        path: path.join(externalPath, fileName),
        maxChars: 2000
      }
    ];
  }
  if (/外部shell|外部命令|runShell/i.test(message)) {
    return [{
      type: "runShell",
      command: process.platform === "win32" ? "dir" : "ls",
      cwd: externalPath
    }];
  }
  if (/外部写入|writeFile/i.test(message)) {
    return [{
      type: "writeFile",
      path: externalPath,
      text: `外部电脑操作审批验证\n时间：${nowIso()}\n`
    }];
  }
  return [{
    type: "readFile",
    path: externalPath,
    maxChars: 2000
  }];
}

function buildMockWorkspaceToolOps(input, message) {
  if (/测试写文件覆盖|写文件覆盖|writeFile覆盖/i.test(message)) return null;
  const wantsWorkspaceTools = /测试工作区工具|工作区写入保护|workspace工具|writeFile|patchFile|runShell/i.test(message);
  const sources = input.skillRuntime?.localFileSources || [];
  if (!wantsWorkspaceTools || sources.length === 0) return null;
  const ops = [
    {
      type: "writeFile",
      path: "agent-workspace-check.txt",
      text: `Agent 工作区写入验证\n时间：${nowIso()}\n`,
      requireHumanApproval: true
    },
    {
      type: "patchFile",
      path: "agent-workspace-check.txt",
      patches: [
        { op: "append", text: "补丁验证：patchFile 已追加内容。\n" }
      ],
      requireHumanApproval: true
    }
  ];
  if (/shell|runShell|命令/i.test(message)) {
    ops.push({
      type: "runShell",
      command: process.platform === "win32" ? "dir" : "ls",
      cwd: ".",
      timeoutMs: 5000,
      requireHumanApproval: true
    });
  }
  return ops;
}

function createMockPlanningCompaction(input) {
  const messages = Array.isArray(input.messagesToCompact) ? input.messagesToCompact : [];
  const userGoals = messages.filter((message) => message.role === "user").slice(-6).map((message) => limitText(message.content, 120));
  const assistantNotes = messages.filter((message) => message.role === "assistant").slice(-6).map((message) => limitText(message.content, 120));
  const toolResults = messages
    .flatMap((message) => [
      ...((message.toolSummary?.searches || []).map((item) => `${planningToolLabelForSummary(item.type)}：${item.query || item.id || ""}`)),
      ...((message.toolSummary?.applied || []).map((item) => `${planningToolLabelForSummary(item.type)}：${item.name || item.id || ""}`))
    ])
    .filter(Boolean)
    .slice(-20);
  return {
    summary: [
      input.existingSummary?.summary ? `既有摘要：${input.existingSummary.summary}` : "",
      userGoals.length ? `用户目标：${userGoals.join("；")}` : "",
      assistantNotes.length ? `Agent 处理：${assistantNotes.join("；")}` : ""
    ].filter(Boolean).join("\n") || "当前较早策划对话主要是围绕小说设定、资料检索和 Agent 工具验证展开。",
    stableFacts: input.existingSummary?.stableFacts || [],
    userPreferences: input.existingSummary?.userPreferences || [],
    openQuestions: input.existingSummary?.openQuestions || [],
    toolResults,
    risks: input.existingSummary?.risks || []
  };
}

function buildMockLocalFileOps(input, message) {
  if (planningMessageExplicitlyDeclinesToolUse(message)) return null;
  const wantsLocalFiles = /(?:检索|读取|打开|查看|索引|搜索).{0,12}(?:本地|文件|资料|旧稿|目录|文件夹|user_ideas)|(?:本地|文件|资料|旧稿|目录|文件夹|user_ideas).{0,12}(?:检索|读取|打开|查看|索引|搜索)/i.test(message);
  const sources = input.skillRuntime?.localFileSources || [];
  if (!wantsLocalFiles || sources.length === 0) return null;
  return [
    {
      type: "searchLocalFiles",
      query: message.includes("user_ideas") ? "user_ideas" : message.slice(0, 80),
      limit: 5
    }
  ];
}

function planningMessageExplicitlyDeclinesToolUse(message) {
  return /(?:不|无需|不用|不要|别)(?:再)?(?:检索|搜索|读取|打开|查看|调用工具)/.test(String(message || ""));
}

function buildMockContextAssetOps(input, message) {
  if (!/测试上下文资产|测试历史证据|检索上下文资产|查找历史证据|读取上下文资产|读取证据原文|context asset|assetRef/i.test(String(message || ""))) return null;
  const explicitAssetId = String(message || "").match(/(?:assetId|资产id|资产 ID)[:：]\s*([a-zA-Z0-9_:-]+)/)?.[1] || "";
  if (explicitAssetId) {
    return [{
      type: "readContextAsset",
      assetId: explicitAssetId,
      maxChars: 4000
    }];
  }
  const query = extractMockContextAssetQuery(message);
  return [{
    type: "searchContextAssets",
    query,
    kind: /压缩/.test(message) ? "context_compaction" : "",
    limit: 5
  }];
}

function extractMockContextAssetQuery(message) {
  const text = String(message || "");
  const explicit = text.match(/(?:query|关键词|检索词)\s*[:=：]\s*([^\r\n，。；;]+)/i)?.[1];
  if (explicit) return explicit.trim();
  const afterKeyword = text.match(/(?:检索上下文资产|查找历史证据)\s*[:：]?\s*([^\r\n，。；;]+)/)?.[1];
  if (afterKeyword) {
    return afterKeyword
      .replace(/然后(?:读取上下文资产|读取证据原文).*/g, "")
      .replace(/并(?:读取上下文资产|读取证据原文).*/g, "")
      .trim() || "工具结果";
  }
  if (/user_ideas/i.test(text)) return "user_ideas";
  return "工具结果";
}

function collectMockObservedToolTypes(input) {
  const observations = Array.isArray(input?.agentState?.observations) ? input.agentState.observations : [];
  return new Set(observations.flatMap((observation) => [
    ...((observation.searches || []).map((item) => item?.type)),
    ...((observation.applied || []).map((item) => item?.type)),
    ...((observation.preflights || []).map((item) => item?.type)),
    ...((observation.skipped || []).map((item) => item?.type)),
    ...((observation.nativeToolCalls || []).map((item) => item?.type)),
    ...((observation.nativeToolCalls || []).map(() => "function"))
  ]).filter(Boolean).map(String));
}

function selectPendingMockExplicitToolOps(input, message, title) {
  const candidates = [
    buildMockPlanningSkillOpsFixture(input, message, title),
    buildMockMemoryWriteOps(message, title),
    buildMockExternalComputerOps(input, message),
    buildMockInvalidSchemaOps(message),
    buildMockNativeToolCallOps(message),
    buildMockWebSearchOps(message),
    buildMockPatchSetOps(message),
    buildMockShellSessionOps(message),
    buildMockShellJobOps(message),
    buildMockSubAgentOps(message),
    buildMockDiagnosticsOps(message),
    buildMockChapterWorkflowOps(message),
    buildMockCustomToolOps(message),
    buildMockPatchAuditOps(input, message),
    buildMockWorkspaceToolOps(input, message),
    buildMockGenericToolOps(input, message),
    buildMockContextAssetOps(input, message),
    buildMockLocalFileOps(input, message)
  ].filter((ops) => Array.isArray(ops) && ops.length > 0);
  if (!candidates.length) return null;
  const observedTypes = collectMockObservedToolTypes(input);
  const pending = candidates.find((ops) => ops.some((op) => op?.type && !observedTypes.has(String(op.type))));
  return pending || null;
}

function buildMockPendingToolContinuation(ops, reason) {
  const selectedTools = ops.map((op) => op.type).filter(Boolean);
  return {
    reply: reason,
    archivePatch: {},
    archiveDiagnostics: { materialType: "tool", extracted: {}, writeDecisions: [], conflicts: [], corrections: [], tentative: [], missing: [] },
    skillOps: ops,
    taskPlan: [{ id: "run_explicit_tool", title: "继续执行用户明确要求的工具", status: "in_progress" }],
    taskGraph: {
      nodes: [{
        id: "run_explicit_tool",
        title: "继续执行用户明确要求的工具",
        status: "in_progress",
        dependsOn: [],
        toolTypes: selectedTools,
        evidenceIds: [],
        verifier: "当前 observation 尚未包含该目标工具，必须继续调用统一工具执行器。"
      }]
    },
    doneCriteria: ["目标工具执行并返回 observation"],
    toolUseDecision: {
      needTools: true,
      reason,
      selectedTools,
      skippedTools: [],
      noWriteReason: "本轮按用户目标调用工具；是否写入由工具权限和写入合同决定。"
    },
    completionCheck: {
      status: "warning",
      summary: "等待目标工具 observation。",
      checkedCriteria: [],
      openIssues: [{ type: "awaiting_explicit_tool", message: "用户明确要求的工具尚未执行。" }],
      recommendedAction: "continue"
    },
    stopReason: "continue",
    nextQuestions: []
  };
}

