function hasMockNonEvidenceObservation(input) {
  const observations = Array.isArray(input?.agentState?.observations) ? input.agentState.observations : [];
  return observations.some((item) => item && item.evidenceScheduler !== true);
}

function buildMockMemoryWriteOps(message, title) {
  if (/测试记忆写入拒绝|memory_blob_reject|记忆污染拒绝/i.test(String(message || ""))) {
    return [{
      type: "upsertMemory",
      item: {
        scope: "planner",
        category: "draft_evidence",
        subject: title,
        field: "summary_blob",
        value: "```json\n{\"toolCallId\":\"bad\",\"stdout\":\"整段工具报告不应写入长期记忆\",\"archive\":{\"characters\":[{\"name\":\"占位角色\"}]}}\n```",
        status: "active",
        visibility: ["planner", "director", "adapter"],
        evidence: ["测试记忆污染拒绝"]
      }
    }];
  }
  if (!/测试记忆写入|memory_write_only|只写记忆/i.test(String(message || ""))) return null;
  return [{
    type: "upsertMemory",
    item: {
      scope: "planner",
      category: "user_intent",
      subject: title,
      field: "e2e_memory_write",
      value: "本地模拟器写入一条带证据、可见性和状态的长期记忆，用于验证 Agent 工具链。",
      status: "active",
      visibility: ["planner", "director", "adapter"],
      evidence: ["用户确认：测试记忆写入"]
    }
  }];
}

function buildMockPlanningSkillOpsFixture(input, message, title) {
  if (!message.includes("测试全部skillops")) return null;
  const project = input.project || {};
  const memory = project.memory?.items?.[0] || null;
  const lorebook = project.lorebook?.entries?.[0] || null;
  const scene = project.archives?.scenes?.[0] || null;
  const provider = (input.availableProviders || []).find((item) => item.providerId === MOCK_PROVIDER_ID)
    || (input.availableProviders || [])[0]
    || null;
  const draft = project.session?.proseParts?.find((item) => item.status !== "accepted") || null;
  const latestTurn = project.recentTurns?.[project.recentTurns.length - 1] || null;
  const allowMockWrites = /允许mock写入|mock_write/i.test(message);
  const ops = [
    { type: "search", query: "模型 世界书 正文 扮演记录", scope: "all", limit: 8 },
    { type: "search", query: "provider_mock_local local-roleplay-mock 模型", scope: "providers", limit: 8 }
  ];
  if (allowMockWrites) {
    ops.push({
      type: "upsertMemory",
      item: {
        scope: "planner",
        category: "user_intent",
        subject: title,
        field: "skill_ops_fixture",
        value: "本地模拟器用于验证策划 skillOps 全链路。",
        status: "active",
        visibility: ["planner", "director", "adapter"],
        evidence: ["用户确认：测试全部skillops"]
      }
    });
    ops.push({
      type: "upsertLorebook",
      entry: {
        name: "SkillOps 测试世界书",
        keys: ["SkillOps测试"],
        content: "这是本地模拟器写入的世界书条目，用于验证策划 skill 可审计写入。",
        visibility: ["planner", "director", "adapter", "minor", "character:*"]
      }
    });
    ops.push({
      type: "upsertProseDraft",
      text: "这是本地模拟器创建的正文修订草稿。",
      reason: "验证策划 skill 只能新建草稿，不覆盖已采纳正文。"
    });
  }
  if (allowMockWrites && memory?.id) {
    ops.push({
      type: "patchMemory",
      memoryId: memory.id,
      patch: {
        evidence: [...(memory.evidence || []), "本地模拟器补充的记忆证据"]
      }
    });
  }
  if (allowMockWrites && lorebook?.id) {
    ops.push({
      type: "patchLorebook",
      entryId: lorebook.id,
      patch: {
        keys: [...(lorebook.keys || []), "模拟编辑"],
        content: `${lorebook.content || "旧世界书内容"}\n本地模拟器已验证世界书路径编辑。`
      }
    });
  }
  if (allowMockWrites && scene?.name) {
    ops.push({
      type: "patchArchiveRecord",
      collection: "scenes",
      key: scene.name,
      patches: [
        { op: "append", path: "fixedFacts", value: "本地模拟器补充的场景固定事实" }
      ]
    });
  }
  if (allowMockWrites && provider?.providerId && provider?.models?.[0]) {
    ops.push(
      {
        type: "addProviderModel",
        providerId: provider.providerId,
        model: "local-roleplay-mock-skillops"
      },
      {
        type: "updateAiSlot",
        slot: "guide",
        providerId: provider.providerId,
        model: provider.models[0],
        temperature: 0.7
      }
    );
  }
  if (allowMockWrites && draft?.id) {
    ops.push({
      type: "patchProseDraft",
      proseId: draft.id,
      text: `${draft.text || "旧草稿"}\n本地模拟器已验证草稿可被策划 skill 编辑。`,
      reason: "验证未采纳草稿可编辑"
    });
  }
  if (allowMockWrites && message.includes("删除退役")) {
    if (memory?.id) {
      ops.push({
        type: "retireMemory",
        memoryId: memory.id,
        status: "outdated"
      });
    }
    if (scene?.name) {
      ops.push({
        type: "deleteArchiveRecord",
        collection: "scenes",
        key: scene.name,
        reason: "本地模拟器验证档案条目可审计删除"
      });
    }
    if (lorebook?.id) {
      ops.push({
        type: "deleteLorebook",
        entryId: lorebook.id,
        reason: "本地模拟器验证世界书条目可审计删除"
      });
    }
  }
  if (allowMockWrites && latestTurn?.id) {
    ops.push({
      type: "annotateTurn",
      turnId: latestTurn.id,
      severity: "low",
      summary: "本地模拟器验证策划 skill 可以给扮演轮次追加审查注释。",
      recommendedAction: "continue",
      issues: []
    });
  }
  return ops;
}

